-- V13: AI-generated plain-language opinions for EU food additives
-- Generated by Claude Sonnet from eu_additives data

ALTER TABLE aggregate.eu_additives ADD COLUMN opinion_en TEXT;
ALTER TABLE aggregate.eu_additives ADD COLUMN opinion_lt TEXT;
ALTER TABLE aggregate.eu_additives ADD COLUMN opinion_generated_at TIMESTAMP;

UPDATE aggregate.eu_additives SET opinion_en = 'These are sugar alcohols — a family of sweeteners that occur naturally in some fruits but are mostly produced industrially for use in food. They provide sweetness with fewer calories than regular sugar and don''t cause tooth decay, which is why you''ll find them in sugar-free gums, candies, diet desserts, jams, and bakery products. Common members of this group include sorbitol, xylitol, maltitol, and erythritol. They are generally considered safe by food authorities worldwide. However, consuming larger amounts can cause digestive discomfort — bloating, gas, or a laxative effect — because the body doesn''t fully absorb them. Sensitive individuals or those with irritable bowel syndrome may want to keep an eye on how much they consume.', opinion_lt = 'Tai vadinamieji cukraus alkoholiai — saldiniklių grupė, kurie kai kuriais atvejais randami natūraliai vaisiuose, tačiau maisto pramonėje dažniausiai gaminami dirbtinai. Jie suteikia saldumą su mažiau kalorijų nei įprastas cukrus ir nesukelia ėduonies, todėl dažnai naudojami beciukrėse kramtomose gumose, saldainiuose, dietiniuose desertuose, dželejuose ir kepiniuose. Žinomiausi šios grupės atstovai — sorbitolis, ksilitolis, maltitolis ir eritritolis. Maisto saugos institucijos juos laiko saugiais. Tačiau suvalgius didesnį kiekį gali atsirasti virškinimo problemų — pilvo pūtimas, dujos ar viduriavimas, nes organizmas jų pilnai nepasisavina. Jautrūs žmonės ar turintys dirgliosios žarnos sindromą turėtų stebėti, kiek jų suvalgo.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 319758;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a regulatory grouping rather than a single additive — it covers a range of approved colourants that food manufacturers can use freely at their own discretion ("quantum satis" means "as much as needed") in certain food categories. These colours may be natural, nature-identical, or synthetic depending on the specific one used, and their job is simply to make food look more appealing or consistent. You''ll find them in baked goods, dairy products, mustard, noodles, and similar everyday foods. Since this is a group label, the safety profile varies by individual colour — if you want to know whether a specific dye is concerning, check the actual E-number listed on the ingredient label.', opinion_lt = 'Tai ne vienas priedas, o reguliavimo grupė — ji apima įvairius patvirtintus dažiklius, kuriuos gamintojai tam tikruose maisto produktuose gali naudoti pagal savo nuožiūrą ("quantum satis" reiškia "tiek, kiek reikia"). Šie dažikliai gali būti natūralios, gamtai identiškos arba sintetinės kilmės — tai priklauso nuo konkretaus naudojamo dažiklio. Jų paskirtis paprasta: kad maistas atrodytų patraukliau ir tolygiau. Jų randama kepiniuose, pieno produktuose, garstyčiose, makaronuose ir panašiuose produktuose. Kadangi tai grupinis žymėjimas, saugumas skiriasi priklausomai nuo konkretaus dažiklio — jei norite žinoti, ar konkretus dažiklis kelia susirūpinimą, patikrinkite tikslų E numerį ant produkto etiketės.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 318488;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural sweetener derived from a small fruit grown in Southeast Asia. It contains zero calories and is many times sweeter than sugar, so only tiny amounts are needed. It is used in low-sugar and diet products as a sugar substitute. It has a long history of use in traditional Chinese cuisine and is generally considered safe with no significant health concerns raised so far.', opinion_lt = 'Tai natūralus saldiklis, gaunamas iš nedidelio Pietryčių Azijoje auginamo vaisiaus. Jame nėra kalorijų, o saldumas yra daug kartų didesnis nei cukraus, todėl reikia labai mažų kiekių. Naudojamas mažai cukraus turinčiuose ir dietiniuose produktuose kaip cukraus pakaitalas. Turi ilgą vartojimo istoriją tradicinėje kinų virtuvėje ir laikomas saugiu — kol kas rimtesnių sveikatos problemų su juo nesiejama.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 364810;
UPDATE aggregate.eu_additives SET opinion_en = 'This additive does not appear in standard food safety databases or official EU authorisation lists. It is possible the name is misspelled, unofficial, or refers to a non-food substance. With only one authorised food category and no verifiable data available, it is not possible to provide a reliable assessment.', opinion_lt = 'Šis priedas nerandamas standartinėse maisto saugos duomenų bazėse ar oficialiuose ES leidimų sąrašuose. Gali būti, kad pavadinimas parašytas neteisingai, yra neoficialus arba žymi ne maisto medžiagą. Turint tik vieną leidžiamą maisto kategoriją ir jokių patikimų duomenų, patikimo vertinimo pateikti neįmanoma.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 363843;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural resin obtained from tropical trees, used as a glazing agent to give a shiny, protective coating to certain confectionery products. It is authorised in a very limited number of food categories, which suggests its use is quite specialised and rare. It is generally considered safe at the levels used in food, though detailed long-term safety studies are limited compared to more common additives.', opinion_lt = 'Tai natūrali derva, gaunama iš tropinių medžių, naudojama kaip glazūravimo medžiaga – ji suteikia blizgų, apsauginį sluoksnį kai kuriems konditerijos gaminiams. Leidžiama naudoti labai mažame skaičiuje maisto kategorijų, todėl jos naudojimas yra gana specifinis ir retas. Manoma, kad maiste naudojamais kiekiais ji yra saugi, nors ilgalaikių saugumo tyrimų yra mažiau nei apie dažniau vartojamus priedus.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 364170;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural plant-based thickener and stabiliser, derived from the seeds of leguminous plants. It helps give foods a smooth, gel-like texture and prevents ingredients from separating. It is authorised in a very limited number of food categories, so you are unlikely to encounter it often. It is generally considered safe and well-tolerated, with no significant controversies surrounding its use.', opinion_lt = 'Tai natūralus, augalinės kilmės tirštiklis ir stabilizatorius, gaunamas iš ankštinių augalų sėklų. Jis suteikia maistui švelnią, gelio tipo tekstūrą ir neleidžia ingredientams atsiskirti. Leidžiamas naudoti labai ribotame skaičiuje maisto kategorijų, tad susidursite su juo retai. Laikomas saugiu ir gerai toleruojamu, jokių reikšmingų kontraversijų dėl jo naudojimo nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 364216;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a magnesium salt of citric acid, used as a nutrient supplement to add magnesium to food and drinks. It is synthetic but derived from natural components, and both magnesium and citric acid are substances naturally found in the body and in foods. It appears in very few product categories, so you are unlikely to encounter it often. It is generally considered safe, and magnesium itself is an essential mineral we all need.', opinion_lt = 'Tai citrinų rūgšties magnio druska, naudojama kaip maisto papildas magnio kiekiui padidinti maiste ir gėrimuose. Ji yra sintetinė, tačiau pagaminta iš natūraliai pasitaikančių medžiagų — magnio ir citrinų rūgšties, kurios randamos ir žmogaus organizme, ir maiste. Leidžiama labai nedaugelyje maisto kategorijų, tad vargu ar dažnai su ja susidursite. Laikoma saugia, o magnis pats savaime yra būtinas mineralas, reikalingas kiekvienam.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 1753801;
UPDATE aggregate.eu_additives SET opinion_en = 'This refers to a broad category of food additives that are permitted at ''quantum satis'' levels — meaning manufacturers can use them in reasonable amounts without a fixed maximum, as long as good manufacturing practice is followed. These are generally the most widely accepted additives, considered safe for the general population and approved across dozens of food categories from dairy products to spreads and pickled vegetables. Because this is a group rather than a single substance, the safety profile varies by individual additive, but all have passed EU regulatory review. If you want to know about a specific one, checking the product label for its individual name or E-number is the best approach.', opinion_lt = 'Tai plati maisto priedų grupė, kurią leidžiama naudoti vadinamuoju ''quantum satis'' principu — tai reiškia, kad gamintojai gali dėti tiek, kiek technologiškai būtina, laikydamiesi geros gamybos praktikos. Visi šios grupės priedai yra praėję ES saugos vertinimą ir laikomi saugiais plačiajai visuomenei — jų randama pieno produktuose, tepuose, marinuotuose daržovuose ir kitur. Kadangi tai ne vienas priedas, o grupė, konkreti sudėtis priklauso nuo produkto. Norėdami sužinoti daugiau, patikrinkite etiketę ir ieškokite konkretaus priedo pavadinimo ar E numerio.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 2718175;
UPDATE aggregate.eu_additives SET opinion_en = 'This is not a single additive but a regulatory grouping of several synthetic colours that share a combined maximum permitted limit in food. When multiple dyes from this group are used together in a product, their total amount cannot exceed a set threshold. These colours are found in things like flavoured cheeses, ice cream, mustard, soups, batters, and cider. Some colours in this group — such as sunset yellow or tartrazine — have been linked in some studies to hyperactivity in children, which is why products containing them in Europe must carry a warning label.', opinion_lt = 'Tai ne vienas priedas, o reguliavimo grupė kelių sintetinių dažiklių, kuriems nustatytas bendras maksimalus kiekis maiste. Kai viename produkte naudojami keli šios grupės dažikliai, jų bendras kiekis negali viršyti nustatytos ribos. Šie dažikliai randami sūriuose, ledų gaminiuose, garstyčiose, sultiниuose, tešlos gaminiuose ir sidre. Kai kurie šios grupės dažikliai — pavyzdžiui, saulėlydžio geltonasis ar tartrazinas — tam tikruose tyrimuose susieti su padidėjusiu vaikų aktyvumu, todėl ES produktai, juos turintys, privalo turėti įspėjamąjį užrašą.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 2860631;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural yellow-orange pigment derived from turmeric root — the same spice used in curry. It''s used to give foods a warm golden colour and can be found in cheese, margarines, jams, processed meats, and fish products. It''s one of the more ''clean label'' colourants out there. It''s widely considered safe, and turmeric itself has been studied for potential anti-inflammatory properties, though the amounts used in food colouring are quite small.', opinion_lt = 'Tai natūralus geltonai oranžinis dažiklis, gaunamas iš ciberžolės šaknies — tos pačios prieskoninės žolelės, kuri naudojama kario patiekaluose. Jis suteikia maistui gražią auksinę spalvą ir randamas sūriuose, margarinuose, džemuose, perdirbtoje mėsoje bei žuvies produktuose. Laikomas vienu saugiausių ir natūraliausių maistinių dažiklių. Ciberžolė yra tirta dėl galimų priešuždegiminių savybių, tačiau maiste naudojami kiekiai yra gana maži.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 320157;
UPDATE aggregate.eu_additives SET opinion_en = 'This is vitamin B2 — a naturally occurring nutrient found in eggs, dairy, meat, and leafy greens. When used as a food additive, it acts as a yellow-orange colouring agent, giving foods a warm, bright hue. It''s produced either through fermentation or extracted from natural sources. This is one of the most benign additives on the list — your body actually needs it to function properly. You''ll find it in processed meats, fish products, preserved vegetables, and flavoured wines.', opinion_lt = 'Tai vitaminas B2 — natūraliai maiste randamas maistinė medžiaga, kurios gausu kiaušiniuose, pieno produktuose, mėsoje ir žaliose daržovėse. Maisto pramonėje jis naudojamas kaip geltonai oranžinis dažiklis, suteikiantis produktams ryškesnę spalvą. Gaminamas fermentacijos būdu arba gaunamas iš natūralių šaltinių. Tai vienas iš saugiausių maisto priedų — organizmas šio vitamino net pats negali pagaminti, todėl jį gauti su maistu yra naudinga. Randamas perdirbtoje mėsoje, žuvies produktuose, konservuotose daržovėse ir aromatizuotuose vynuose.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 320436;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic yellow dye used to give foods and drinks a bright yellow or orange colour. You''ll find it in things like flavoured drinks, sweets, snacks, and some processed foods. It is approved for use in many countries and considered safe at normal levels by major food safety authorities. However, it is one of the more controversial food dyes — some studies and the UK''s Food Standards Agency have linked it, along with a few other dyes, to increased hyperactivity in some children. People with aspirin sensitivity may also react to it. It''s worth checking labels if you have young kids or known sensitivities.', opinion_lt = 'Tai sintetinis geltonas dažiklis, naudojamas suteikti ryškią geltoną arba oranžinę spalvą maistui ir gėrimams. Jį rasite saldainiuose, užkandžiuose, gazuotuose gėrimuose ir kai kuriuose perdirbtuose maisto produktuose. Daugumos maisto saugos institucijų jis laikomas saugiu įprastais kiekiais. Tačiau tai vienas prieštaringiausių maistinių dažiklių — kai kurie tyrimai ir Jungtinės Karalystės maisto saugos agentūra jį siejo su padidėjusiu hiperaktyvumu vaikams. Žmonės, jautrūs aspirinui, taip pat gali į jį reaguoti. Jei turite mažų vaikų ar žinomų alergijų — verta tikrinti etiketes.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 320642;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic yellow dye used to give foods a greenish-yellow colour. You''ll find it in mustard, sauces, fish roe, batters, and various drinks like cider. It''s approved in the EU but banned in the US, Australia, and Japan, which reflects ongoing debate about its safety. It belongs to the group of artificial colours that some studies have loosely linked to hyperactivity in children, so parents of young kids may want to keep an eye out for it on labels.', opinion_lt = 'Tai sintetinis geltonas dažiklis, suteikiantis maistui gelsvai žalią spalvą. Jį rasite garstyčiose, padažuose, žuvų ikruose, tešlos gaminiuose ir kai kuriuose alkoholiniuose gėrimuose. ES jis leidžiamas, tačiau JAV, Australijoje ir Japonijoje – draudžiamas, o tai rodo, kad mokslininkų diskusijos dėl jo saugumo dar tęsiasi. Kai kurie tyrimai siejo šį ir panašius dirbtinus dažiklius su padidėjusiu vaikų hiperaktyvumu, tad tėvai gali norėti atkreipti dėmesį į sudėtį.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 320772;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic orange-yellow dye used to give food an appealing colour — you''ll find it in things like mustard, sauces, fish roe, batters, and certain drinks. It''s approved for use across many food categories in the EU, but it comes with a notable catch: it''s one of the six ''Southampton Six'' artificial colours linked in a 2007 study to increased hyperactivity in children. The EU requires products containing it to carry a warning label stating that it ''may have an adverse effect on activity and attention in children''. Adults generally tolerate it well, but parents of young children may prefer to avoid it.', opinion_lt = 'Tai sintetinis oranžiniai geltonas dažiklis, naudojamas maistui suteikti patrauklią spalvą — rasite jį garstyčiose, padažuose, žuvų ikruose, tešlos gaminiuose ir kai kuriuose gėrimuose. ES jis leidžiamas daugelyje maisto kategorijų, tačiau yra svarbus niuansas: tai vienas iš šešių vadinamųjų ''Sautamptono šešetuko'' dirbtinių dažiklių, kuriuos 2007 m. tyrimas susiejo su padidėjusiu vaikų hiperaktyvumu. Todėl ES reikalauja, kad produktai su šiuo dažikliu būtų paženklinti įspėjimu, kad jis ''gali neigiamai veikti vaikų aktyvumą ir dėmesį''. Suaugusiems jis paprastai nekelia problemų, tačiau tėvai, auginantys mažus vaikus, gali norėti jo vengti.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 321290;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural red dye extracted from cochineal insects — yes, actual bugs. It creates vivid pink, red, and purple shades and is widely used in yogurts, fruit drinks, processed meats, cheese products, and some alcoholic beverages. It is one of the more stable and reliable natural colorants available.

For most people it is considered safe, but it is worth knowing that some individuals can have allergic reactions, occasionally severe ones. It is also an animal-derived ingredient, so it is not suitable for vegans or vegetarians. If you follow a kosher or halal diet, check with your relevant authority as opinions differ.', opinion_lt = 'Tai natūralus raudonas dažiklis, gaunamas iš košenilių vabzdžių — taip, iš tikrų vabalėlių. Jis suteikia ryškią rožinę, raudoną ar violetinę spalvą ir naudojamas jogurtuose, vaisių gėrimuose, perdirbtos mėsos gaminiuose, sūriuose ir kai kuriuose alkoholiniuose gėrimuose.

Daugumai žmonių jis laikomas saugiu, tačiau kai kurie gali patirti alerginę reakciją — kartais net stiprią. Kadangi tai gyvūninės kilmės ingredientas, jis netinka veganams ar vegetarams. Jei laikotės košer ar halal mitybos, verta pasitikrinti, nes nuomonės šiuo klausimu skiriasi.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 321786;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic red dye used to give food and drinks an appealing crimson or raspberry-red colour. You''ll find it in processed cheeses, pickled vegetables, flavoured wines, and various other processed foods. It''s one of the so-called ''Southampton six'' artificial colours linked in a 2007 study to increased hyperactivity in children, which led the EU to require a warning label on products containing it. While it remains legally permitted, many manufacturers have voluntarily replaced it with natural alternatives.', opinion_lt = 'Tai sintetinis raudonas dažiklis, suteikiantis maistui ir gėrimams sodrios aviečių arba vyšnių spalvos atspalvį. Jį rasite perdirbtame sūryje, marinuotose daržovėse, aromatizuotuose vynuose ir kituose perdirbtuose produktuose. Šis dažiklis priklauso vadinamajai „Sautamptono šešetukui" — grupei dirbtinių dažiklių, kuriuos 2007 m. tyrimas susiejo su padidėjusiu hiperaktyvumu vaikams. Dėl to ES reikalauja ant tokių produktų etiketės įspėjimo. Nors jis teisiškai leidžiamas, daugelis gamintojų savanoriškai jį keičia natūraliais alternatyvais.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 322188;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic red dye used in a narrow range of products — mainly fish roe, certain alcoholic drinks, and aromatised wines. It gives foods a deep red or purple-red colour. It is one of the most restricted dyes in the EU, banned in the US since the 1970s due to concerns raised in animal studies, though European food safety authorities have not found sufficient evidence of harm at the low levels permitted here. Still, its use is tightly limited for a reason — it is worth being aware of if you prefer to avoid artificial colours.', opinion_lt = 'Tai sintetinis raudonas dažiklis, naudojamas tik labai ribotame maisto produktų sąraše — daugiausia žuvų ikruose, tam tikruose alkoholiniuose gėrimuose ir aromatizuotuose vynuose. JAV šis dažiklis uždraustas nuo aštuntojo dešimtmečio dėl susirūpinimą kėlusių gyvūnų tyrimų rezultatų, tačiau Europos maisto saugos institucijos nerado pakankamai įrodymų, kad leistinosiomis dozėmis jis keltų pavojų sveikatai. Vis dėlto jo naudojimas ES yra griežtai apribotas — jei vengiate dirbtinių dažiklių, verta atkreipti dėmesį į sudėtį.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 322348;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic red food dye used to give products a bright cherry or strawberry-red colour. You''ll find it in things like cured meats, fish roe, flavoured wines, mustard, and various dessert toppings. It has nothing to do with actual cochineal insects — despite the name, it is fully lab-made. It is approved for use in the EU within set limits. However, it is one of the so-called ''Southampton Six'' artificial colours linked in a 2007 study to increased hyperactivity in some children. The EU requires products containing it to carry a warning label stating that the colour ''may have an adverse effect on activity and attention in children''.', opinion_lt = 'Tai sintetinis raudonas maistinis dažiklis, naudojamas suteikti produktams ryškią vyšninę ar braškių spalvą. Jį rasite džiovintose mėsos produktuose, žuvų ikruose, aromatizuotuose vynuose, garstyčiose ir įvairiuose desertų padažuose. Jis neturi nieko bendra su tikrais košenilės vabzdžiais — nepaisant pavadinimo, tai visiškai sintetinis junginys. ES jis leidžiamas naudoti tam tikromis normomis. Tačiau tai vienas iš vadinamųjų ''Sautamptono šešių'' dažiklių, kurie 2007 m. tyrime buvo susieti su padidėjusiu kai kurių vaikų hiperaktyvumu. ES reikalauja, kad produktai su šiuo dažikliu turėtų įspėjamąją etiketę, jog dažiklis ''gali neigiamai paveikti vaikų aktyvumą ir dėmesį''.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 322483;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic red dye used to give certain foods a bright cherry-pink colour. It''s one of the most restricted artificial colours in the world — in the EU it''s only permitted in a single food category, which tells you how cautiously regulators treat it. Some studies have raised concerns about thyroid effects due to its high iodine content, and it''s banned for many uses in several countries. If you''re sensitive to artificial dyes or watching your iodine intake, it''s worth checking labels.', opinion_lt = 'Tai sintetinis raudonas dažiklis, naudojamas ryškiai rausvai spalvai suteikti. ES jis leidžiamas tik vienoje maisto kategorijoje — tai rodo, kad reguliuotojai elgiasi su juo labai atsargiai. Kai kurie tyrimai kėlė susirūpinimą dėl galimo poveikio skydliaukei, nes šiame dažiklyje yra daug jodo. Jei esate jautrus dirbtiniams dažikliams arba stebite jodo kiekį maiste, verta atidžiau skaityti etiketes.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 322967;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic red dye used to give foods a bright red or orange-red colour. You''ll find it in drinks, sweets, snacks, sauces, and some processed meat or fish products. It is one of the so-called ''Southampton Six'' artificial colours that studies linked to increased hyperactivity in children, which led the EU to require a warning label on products containing it. It is considered safe at approved levels by regulators, but many parents and manufacturers choose to avoid it as a precaution.', opinion_lt = 'Tai sintetinis raudonas dažiklis, suteikiantis maistui ryškią raudoną arba oranžinę-raudoną spalvą. Jį rasite gėrimuose, saldainiuose, užkandžiuose, padažuose ir kai kuriuose perdirbtuose mėsos ar žuvies produktuose. Jis priklauso vadinamajai ''Sautamptono šešetukai'' grupei — tyrimai susiejo šiuos dažiklius su padidėjusiu hiperaktyvumu vaikams, todėl ES reikalauja įspėjamojo užrašo ant tokius dažiklius turinčių produktų. Reguliuotojai laiko jį saugiu leidžiamose dozėse, tačiau daugelis tėvų ir gamintojų renkasi jo vengti kaip atsargumo priemonę.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 323019;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic blue dye used to give food a vivid blue or blue-green colour. You might find it in certain preserved or pickled vegetables and fruits, where it helps maintain or enhance visual appeal. It is approved for use in a limited number of food categories in the EU. Some people with aspirin sensitivity or allergies may react to it, and like several other artificial colours, it has been loosely linked to hypersensitivity reactions in susceptible individuals, though it is considered safe for the general population at normal intake levels.', opinion_lt = 'Tai sintetinis mėlynas dažiklis, naudojamas suteikti maistui ryškią mėlyną arba žalsvai mėlyną spalvą. Jį galima rasti kai kuriuose konservuotuose ar marinuotuose vaisiuose ir daržovėse. ES jis leidžiamas tik nedaugelyje maisto kategorijų. Žmonėms, jautriems aspirinui ar turintiems alergijų, jis kartais gali sukelti reakcijas, tačiau bendrai laikomas saugiu įprastomis vartojimo dozėmis.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 323192;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic blue dye used to colour foods and drinks. It belongs to the indigo family and gives products a distinctive blue or blue-green shade. You''ll most likely find it in confectionery, ice cream, and some beverages. It''s authorised in very few food categories, so your exposure to it is likely minimal.', opinion_lt = 'Tai sintetinis mėlynas dažiklis, naudojamas maisto produktų ir gėrimų spalvinimui. Jis suteikia produktams ryškų mėlyną arba mėlynai žalią atspalvį. Dažniausiai randamas saldainiuose, ledų gaminiuose ir kai kuriuose gėrimuose. Leidžiamas tik labai nedaugelyje maisto kategorijų, todėl tikėtina, kad jo suvartojate nedaug.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 323278;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic blue dye used to give food a vivid blue or blue-green colour. It is approved in a limited number of food categories and can appear in processed vegetables, pickled products, and certain preserved foods. It is generally considered safe by major food safety authorities, though like most artificial dyes it has been subject to ongoing scrutiny. People with aspirin sensitivity may want to be cautious, as some individuals report reactions to synthetic colour additives.', opinion_lt = 'Tai sintetinis mėlynas dažiklis, naudojamas ryškiai mėlonai arba žalsvai mėlonai spalvai suteikti. Jis patvirtintas nedaugelyje maisto kategorijų – daugiausia perdirbtuose daržovių produktuose, marinuotuose gaminiuose ir konservuotuose maisto produktuose. Maisto saugos institucijos jį laiko saugiu, tačiau, kaip ir dauguma dirbtinių dažiklių, jis nuolat tiriamas. Žmonėms, jautriems aspirinui, verta būti atidiems – kai kurie asmenys praneša apie reakcijas į sintetinius dažiklius.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 323324;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural green pigment derived from plants — the same substance that makes leaves and grass green. It''s used in food to maintain or enhance green colour in products like preserved vegetables, canned goods, cheeses, and pickled items, where natural colour can fade during processing. It has a long history of safe use and is well tolerated by most people. No significant health concerns are associated with it at the levels used in food.', opinion_lt = 'Tai natūralus žalias pigmentas, gaunamas iš augalų — ta pati medžiaga, kuri suteikia lapams ir žolei žalią spalvą. Maisto pramonėje jis naudojamas žaliai spalvai išlaikyti ar sustiprinti — konservuotuose daržovių produktuose, sūriuose, marinuotuose gaminiuose, kur perdirbimo metu natūrali spalva gali išblukti. Turi ilgą saugaus naudojimo istoriją ir dauguma žmonių jį gerai toleruoja. Esant įprastoms maiste naudojamoms dozėms, jokių reikšmingų sveikatos problemų su šiuo priedu nesiejama.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 323437;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a green colouring agent derived from chlorophyll — the natural pigment that makes plants green — but chemically modified by adding copper to make the colour more stable and vivid. It''s used in products like pickled vegetables, jams, processed fish, and some cheeses to keep them looking appealingly green rather than turning dull or brownish. The copper addition is what makes it synthetic-modified rather than purely natural, though its origin is still plant-based. It''s approved and considered safe at permitted levels, with no significant controversy surrounding it.', opinion_lt = 'Tai žalias dažiklis, pagamintas iš chlorofilo — natūralaus augalų pigmento — tačiau chemiškai modifikuotas pridedant vario, kad spalva būtų stabilesnė ir ryškesnė. Jis naudojamas marinuotose daržovėse, džemuose, perdirbtoje žuvyje ir kai kuriuose sūriuose, kad produktai išliktų gražios žalios spalvos ir nepageltų. Nors žaliava yra augalinės kilmės, vario pridėjimas daro jį iš dalies sintetiniu. Laikomas saugiu leistinomis dozėmis, jokios didesnės kontraversijos moksliniame pasaulyje nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 323572;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic green dye used to give foods an appealing green colour. You''ll find it in things like canned vegetables, jams, and some processed fish products where manufacturers want to maintain or enhance a green appearance. It is not permitted in all countries — it''s banned in the USA, Canada, and Japan, though it remains approved in the EU under regulated limits. While it''s considered safe at permitted levels in Europe, some health-conscious consumers prefer to avoid synthetic dyes in general, especially in products where the colour serves more of a cosmetic than functional purpose.', opinion_lt = 'Tai sintetinis žalias dažiklis, naudojamas suteikti maistui patrauklią žalią spalvą. Jį galima rasti konservuotose daržovėse, džemuose ir kai kuriuose perdirbtų žuvų produktuose. Svarbu žinoti, kad šis dažiklis draudžiamas JAV, Kanadoje ir Japonijoje, nors ES jis leidžiamas, laikantis nustatytų ribų. Laikomas saugiu tokiomis dozėmis, tačiau nemažai vartotojų vengia sintetinių dažiklių apskritai — ypač kai jie naudojami tik dėl išvaizdos, o ne dėl technologinės būtinybės.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 323735;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural brown colouring made by heating sugar — essentially the same process as making caramel at home, just done industrially. It gives foods and drinks a warm brown colour and is found in a fairly limited range of products. It is considered one of the safest caramel colourings, as it is produced without ammonia or sulfites. No significant health concerns are associated with it.', opinion_lt = 'Tai natūralus rudas dažiklis, gaunamas kaitinant cukrų — iš esmės tas pats procesas kaip namuose ruošiant karamelę, tik pramoninio masto. Suteikia maistui ir gėrimams šiltą rudą spalvą ir naudojamas gana nedaugelyje produktų. Laikomas vienu saugiausių karamelės dažiklių, nes gaminamas be amoniako ar sulfitų. Jokių reikšmingų sveikatos problemų su juo nesiejama.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 323839;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a group of brown colouring agents made by heating sugar — essentially controlled burning of sugars, sometimes with the help of acids, alkalis, or ammonium compounds depending on the specific type. It gives foods that familiar dark brown colour and is found in a huge range of products: bread, soft drinks, sauces, processed meats, vinegars, and more. The natural-sounding process is real, but the end result is a highly processed substance, not the caramel you make at home. The type made with ammonium compounds (the d variant) has drawn the most scrutiny — it contains a byproduct called 4-MEI, which some animal studies link to cancer risks, though regulators currently consider levels in food to be safe. If you see this in a long ingredient list, it is mainly there for looks, not flavour or preservation.', opinion_lt = 'Tai rudų dažiklių grupė, gaminama kaitinant cukrų — iš esmės kontroliuojamas deginimas, kartais naudojant rūgštis, šarmus ar amonio junginius, priklausomai nuo tipo. Jie suteikia produktams tamsiai rudą spalvą ir randami labai plačiai: duonoje, gaiviuosiuose gėrimuose, padažuose, perdirbtos mėsos gaminiuose, acte ir kitur. Nors procesas skamba natūraliai, galutinis produktas yra gerokai perdirbta medžiaga — ne tas karamelė, kurią gamintumėte namuose. Labiausiai nagrinėjamas tipas su amonio junginiais (d variantas) — jo gamybos metu susidaro medžiaga 4-MEI, kurią kai kurie gyvūnų tyrimai sieja su vėžio rizika, nors reguliavimo institucijos šiuo metu laiko jos kiekius maiste saugiais. Jei matote šį dažiklį ilgame sudėties sąraše, jis ten daugiausia dėl išvaizdos, o ne skonio ar konservavimo.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 323891;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic brown colouring made by heating sugar with sulphite compounds. It gives food and drinks a deep amber or brown colour and is used in a very limited range of products. It contains sulphites, which can trigger reactions in people who are sensitive to them, particularly those with asthma. Overall, regulators consider it safe at permitted levels, but sensitive individuals should be aware of its presence.', opinion_lt = 'Tai sintetinis rudas dažiklis, gaunamas kaitinant cukrų su sulfitų junginiais. Jis suteikia maistui ir gėrimams tamsią gintaro arba rudą spalvą ir naudojamas labai ribotame produktų skaičiuje. Sudėtyje yra sulfitų, kurie gali sukelti reakcijas jautriems žmonėms, ypač sergantiems astma. Apskritai reguliavimo institucijos mano, kad leidžiamomis dozėmis jis yra saugus, tačiau jautresni žmonės turėtų į tai atkreipti dėmesį.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 324192;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a dark brown colouring made by heating sugar with ammonia compounds. It gives products like breakfast cereals and certain beers their familiar brown colour. It is synthetic in the sense that specific chemicals are added during production. Regulators consider it safe at normal levels, though some animal studies at very high doses raised questions — nothing that applies to realistic food consumption.', opinion_lt = 'Tai tamsiai rudas dažiklis, gaunamas kaitinant cukrų su amoniako junginiais. Jis suteikia produktams, pavyzdžiui, pusryčių dribsniams ar kai kuriems alams, būdingą rudą spalvą. Gamybos metu naudojamos specifinės cheminės medžiagos, todėl laikomas sintetiniu priedu. Reguliavimo institucijos mano, kad įprastais kiekiais jis yra saugus — nors kai kurie gyvūnų tyrimai su labai didelėmis dozėmis kėlė klausimų, tai nėra aktualu realistiniam suvartojimui maiste.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 324243;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a dark brown colouring made by heating sugar with both sulphite and ammonia compounds. It gives soft drinks like cola their characteristic deep brown colour. It is one of the most widely used food colourings in the world. Some studies have raised concerns that a byproduct called 4-MEI, formed during its production, may have carcinogenic potential at high doses, though regulators in Europe consider current exposure levels safe. If you drink a lot of cola, it is worth being aware of.', opinion_lt = 'Tai tamsiai rudas dažiklis, gaunamas kaitinant cukrų su sulfitų ir amoniako junginiais. Jis suteikia kolos gėrimams būdingą tamsią spalvą ir yra vienas iš dažniausiai naudojamų maisto dažiklių pasaulyje. Kai kurie tyrimai kėlė susirūpinimą dėl gamybos metu susidarančio šalutinio produkto 4-MEI, kuris didelėmis dozėmis gali turėti kancerogeninių savybių. Europos reguliavimo institucijos mano, kad dabartinis poveikio lygis yra saugus, tačiau jei geriate daug kolos, verta tai žinoti.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 324321;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a group of caramel colouring agents made by heating sugar — the same basic process that happens when you caramelise sugar at home, though industrial versions use additional chemicals to control the colour and stability. The simplest version is considered quite safe, but the more processed variants, particularly those made with ammonia and sulphites, have raised some questions. One compound that can form during production has been flagged in some studies for potential health concerns, though regulators in most countries still consider typical dietary exposure to be acceptable. You''ll mostly find these in dark-coloured drinks like cola and beer, as well as sauces and baked goods.', opinion_lt = 'Tai karamelinio dažiklio grupė, gaminama kaitinant cukrų — panašiai kaip karamelizavimas namuose, tik pramoninėje gamyboje naudojamos papildomos cheminės medžiagos spalvai ir stabilumui reguliuoti. Paprasčiausias variantas laikomas gana saugiu, tačiau sudėtingesnės versijos, pagamintos su amoniaku ir sulfitais, kelia tam tikrų klausimų. Gamybos metu susidaro vienas junginys, dėl kurio kai kuriuose tyrimuose išreikštas susirūpinimas, nors daugumos šalių reguliuotojai mano, kad įprastas suvartojimas nekelia pavojaus. Dažniausiai šį dažiklį rasite tamsiuose gėrimuose kaip kola ar alus, taip pat padažuose ir kepiniuose.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 364488;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic black food dye used to give products a dark colour. It''s only authorised in a very narrow range of foods in the EU, mainly certain processed fish products. Like several artificial colours, it''s been linked to hyperactivity concerns in children, which is why foods containing it in Europe must carry a warning label stating it ''may have an adverse effect on activity and attention in children''.', opinion_lt = 'Tai sintetinis juodas maistinis dažiklis, naudojamas suteikti produktams tamsią spalvą. ES jis leidžiamas labai siauroje produktų kategorijoje – daugiausia tam tikruose perdirbtų žuvų gaminiuose. Kaip ir kai kurie kiti dirbtiniai dažikliai, jis siejamas su galimais hiperaktyvumo poveikiais vaikams, todėl ES produktai, kuriuose jo yra, privalo turėti įspėjamąjį užrašą, kad gali neigiamai veikti vaikų aktyvumą ir dėmesį.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 324372;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a black colouring made from charred plant material — essentially food-grade charcoal. It gives certain foods a dramatic dark or black appearance, and you might find it in some aged cheeses, processed seafood products, or specialty food preparations. It is a natural-origin additive and is generally considered safe, with no significant health concerns flagged by major food safety bodies. It is approved only in a limited number of food categories, so you won''t encounter it very often.', opinion_lt = 'Tai juodas dažiklis, gaunamas deginant augalinę medžiagą — iš esmės tai maistinio lygio anglis. Jis suteikia maistui ryškią tamsią arba juodą spalvą ir gali pasitaikyti kai kuriuose brandintų sūrių, perdirbtų jūros gėrybių ar specialiuose maisto produktuose. Tai natūralios kilmės priedas, kurį pagrindinės maisto saugos institucijos laiko saugiu — jokių rimtų sveikatos problemų nenustatyta. Leidžiamas tik nedaugelyje maisto kategorijų, todėl kasdieniniame gyvenime su juo susidursite retai.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 324437;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic coal tar dye used to give food a brown colour. It belongs to the same family of artificial dyes that regulators in Europe require to carry a warning label about possible effects on children''s activity and attention. It is authorised in very few food categories, which reflects its limited and cautious use across the industry. Most people consuming a varied diet are unlikely to encounter it often, but those sensitive to artificial colourants — especially parents of young children — may want to check labels.', opinion_lt = 'Tai sintetinis dažiklis, gaunamas iš akmens anglių deguto, naudojamas suteikti maistui rudą spalvą. Jis priklauso tai pačiai dirbtinių dažiklių grupei, kuriai Europos teisės aktai reikalauja uždėti įspėjamąjį užrašą dėl galimo poveikio vaikų elgesiui ir dėmesiui. Leidžiama jį naudoti labai nedaugelyje maisto kategorijų, tai rodo atsargų požiūrį į šį priedą. Dauguma žmonių su juo susiduria retai, tačiau tie, kurie reaguoja į dirbtinius dažiklius — ypač tėvai, auginantys mažus vaikus — turėtų atidžiau skaityti etiketes.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 324529;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural red pigment found abundantly in tomatoes, watermelons, and other red fruits — it''s what gives them their colour. In processed foods, it''s used as a colouring agent to give products a red or pink hue, and it appears in a wide range of items from snacks and confectionery to dairy products and spreads. It can be extracted from natural sources or produced through fermentation.

Beyond its role as a colourant, lycopene is also a well-known antioxidant, and some research links higher dietary intake to potential health benefits. It is widely considered safe, and regulatory bodies like EFSA have approved it across many food categories. There is no significant controversy surrounding this additive.', opinion_lt = 'Tai natūralus raudonas pigmentas, gausiai randamas pomidoruose, arbūzuose ir kituose raudonuose vaisiuose — būtent jis suteikia jiems spalvą. Maisto pramonėje naudojamas kaip dažiklis, suteikiantis gaminiams rausvą ar raudoną atspalvį — jo galima rasti užkandžiuose, saldainiuose, pieno produktuose ir tepuose. Jis gali būti gaunamas iš natūralių žaliavų arba fermentacijos būdu.

Be dažiklio funkcijos, tai ir gerai žinomas antioksidantas, o kai kurie tyrimai sieja didesnį jo kiekį mityboje su galima nauda sveikatai. Laikomas saugiu, EFSA patvirtino jo naudojimą daugelyje maisto kategorijų. Jokios reikšmingos kontraversijos dėl šio priedo nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 325160;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic carotenoid — a pigment closely related to the natural orange and red compounds found in carrots, tomatoes, and other plants. It is used as a colouring agent to give foods an orange or yellow-orange hue, and shows up in processed cheeses, fish products, and certain fruit or vegetable preparations. It is authorised for use only in a limited number of food categories, which reflects a cautious regulatory approach. It is generally considered safe at permitted levels, and as a carotenoid it is chemically similar to substances our bodies already process from plant foods.', opinion_lt = 'Tai sintetinis karotenoidinis dažiklis — artimas natūraliems junginiams, randamiems morkoose, pomidoruose ir kitose daržovėse. Maiste jis naudojamas oranžinei arba gelsvai spalvai suteikti ir aptinkamas perdirbtuose sūriuose, žuvies produktuose bei kai kuriuose vaisių ir daržovių gaminiuose. Leidžiama jį naudoti tik nedaugelyje maisto kategorijų, o tai rodo atsargų reguliavimo požiūrį. Leidžiamomis dozėmis jis laikomas saugiu — chemiškai panašus į junginius, kuriuos mūsų organizmas įprastai gauna iš augalinio maisto.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 325608;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural orange-yellow pigment found in carrots, sweet potatoes, and many other plants. It''s used to give foods a warm yellow or orange colour, and it also acts as a precursor to vitamin A in the body — so it''s not just a colourant, it''s genuinely nutritious. You''ll find it in cheeses, spreads, cereals, and processed meats. It''s one of the most harmless additives on the list, and most health authorities consider it completely safe for all age groups.', opinion_lt = 'Tai natūralus oranžinis-geltonas pigmentas, randamas morkaose, saldžiosiose bulvėse ir daugelyje kitų augalų. Maiste jis naudojamas suteikti gražią gelsvą ar oranžinę spalvą, o be to — tai vitamino A pirmtakas, tad jis ne tik dažo, bet ir turi maistinę vertę. Jo rasite sūriuose, tepuose, dribsniuose ir perdirbtoje mėsoje. Tai vienas saugiausių priedų — visos pagrindinės sveikatos institucijos laiko jį visiškai nekenksmingu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 324589;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural orange-yellow colourant extracted from the seeds of the achiote tree, used to give foods like cheese, butter, and smoked fish their distinctive golden hue. It has a long history of use in traditional cooking across South America and beyond. While generally considered safe, it is one of the few natural colorants linked to allergic reactions in some sensitive individuals, so those with known sensitivities should take note.', opinion_lt = 'Tai natūralus oranžiniai geltonas dažiklis, gaunamas iš achioto medžio sėklų — jis suteikia sūriams, sviestui ir rūkytai žuviai tą būdingą auksinę spalvą. Šis ingredientas turi ilgą istoriją tradicinėje Pietų Amerikos virtuvėje. Nors paprastai laikomas saugiu, tai vienas iš retų natūralių dažiklių, galintis sukelti alerginę reakciją jautresniems žmonėms, tad alergijai linkę vartotojai turėtų atkreipti dėmesį.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 324869;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural colouring extracted from red peppers — it gives food that warm orange-red hue you often see in processed meats, cheese products, snacks, and breakfast cereals. It comes from the same plant that gives paprika its colour, so it''s about as natural as food additives get. Generally considered very safe, with no significant health concerns flagged by food safety authorities. If you''re sensitive to peppers, it''s worth keeping an eye out, but for most people it''s a completely unremarkable ingredient.', opinion_lt = 'Tai natūralus dažiklis, gaunamas iš raudonųjų paprikų — jis suteikia maistui tą šiltą oranžinę-raudoną spalvą, kurią dažnai matome perdirbtoje mėsoje, sūrių gaminiuose, užkandžiuose ir pusryčių dribsniuose. Kadangi jis kilęs iš tos pačios daržovės, kuri duoda paprikai spalvą, tai vienas iš natūraliausių maisto priedų. Maisto saugos institucijos nėra išreiškusios jokio susirūpinimo dėl jo saugumo. Jei esate jautrūs paprikoms, verta atkreipti dėmesį, tačiau daugumai žmonių tai visiškai nekenksmingas ingredientas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 324915;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural orange-red colourant extracted from the seeds of the annatto tree, native to South America. It gives foods that warm golden or orange hue you often see in cheeses, butter, margarines, and snacks. It has been used for centuries in cooking and is generally considered safe. However, some people — particularly those sensitive to aspirin — may experience allergic reactions, and a small number of case reports link it to hives or digestive discomfort, so it is worth noting if you have known sensitivities.', opinion_lt = 'Tai natūralus oranžiniai raudonas dažiklis, gaunamas iš Pietų Amerikoje augančio annato medžio sėklų. Jis suteikia maistui tą gražią auksinę arba oranžinę spalvą, kurią dažnai matome sūriuose, svieste, margarinuose ir užkandžiuose. Naudojamas šimtmečius ir laikomas saugiu. Vis dėlto kai kuriems žmonėms, ypač jautriems aspirinui, jis gali sukelti alerginę reakciją — dilgėlinę ar virškinimo sutrikimus, todėl verta atkreipti dėmesį, jei žinote, kad esate jautrūs natūraliems dažikliams.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 365307;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural orange-yellow colouring extracted from the seeds of the annatto plant, originally from South America. It''s widely used in dairy products like cheese, butter, and ice cream, as well as snacks and confectionery to give that warm golden or orange tone. It is generally considered safe, but it''s worth knowing that some people — particularly those sensitive to certain food dyes — have reported allergic reactions, including skin rashes or digestive discomfort. If you have known food sensitivities, it''s one to watch for on labels.', opinion_lt = 'Tai natūralus oranžiniai geltonas dažiklis, gaunamas iš Pietų Amerikos kilmės achioto augalo sėklų. Jis plačiai naudojamas pieno produktuose — sūriuose, svieste, ledų gamyboje — taip pat užkandžiuose ir saldumynuose, kad suteiktų tą gražią auksinę arba oranžinę spalvą. Paprastai laikomas saugiu, tačiau verta žinoti, kad kai kurie žmonės, jautrūs maisto dažikliams, yra pranešę apie alerginius simptomus — odos bėrimą ar virškinimo sutrikimus. Jei turite žinomą jautrumą maistui, verta atkreipti dėmesį į šio ingrediento buvimą etiketėje.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 365671;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural yellow-orange pigment found in plants like marigold flowers, spinach, and kale. It''s used as a colouring agent to give foods a warm yellow or golden hue, and shows up in products like processed cheese, jams, and fish products. Beyond its role as a food colour, it''s actually a nutrient naturally present in many vegetables and is well-known for supporting eye health. It is widely considered safe and is one of the more benign colouring agents you''ll find on an ingredients list.', opinion_lt = 'Tai natūralus geltonai oranžinis dažiklis, gaunamas iš augalų – pavyzdžiui, medetkų žiedų, špinatų ar lapinių kopūstų. Maiste jis naudojamas siekiant suteikti gražią gelsvą ar auksinę spalvą perdirbtiems sūriams, džemams, žuvies produktams ir panašiems gaminniams. Įdomu tai, kad tai ne tik dažiklis – tai natūralus maistingas junginys, žinomas kaip naudingas akių sveikatai. Laikomas vienu saugiausių maisto dažiklių, todėl rimto pagrindo nerimauti nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 325708;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a carotenoid pigment, related to beta-carotene, used to give foods an orange-red colour. It occurs naturally in some mushrooms, crustaceans, and flamingo feathers, but the version used in food is typically synthetic. It is authorised in a very limited number of food categories, so you are unlikely to encounter it often.', opinion_lt = 'Tai karotenoidinis dažiklis, artimas beta-karotinui, naudojamas suteikti maistui oranžinę-raudoną spalvą. Gamtoje jis randamas kai kuriuose grybuose ir vėžiagyviuose, tačiau maiste naudojama versija dažniausiai yra sintetinė. Jis leidžiamas labai ribotame skaičiuje maisto kategorijų, todėl kasdienėje mityboje su juo susidursite retai.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 325803;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural red pigment extracted from beetroot, used to give foods a vibrant pink or red colour. You''ll find it in products like processed meats, jams, breakfast cereals, and pickled vegetables. It''s one of the more reassuring additives on a label — it comes straight from a vegetable most of us eat without a second thought. There are no significant safety concerns associated with it, and it is well tolerated by the vast majority of people.', opinion_lt = 'Tai natūralus raudonas dažiklis, gaunamas iš burokėlių — jis suteikia maistui ryškią rožinę arba raudoną spalvą. Rasite jį perdirbtos mėsos gaminiuose, džemuose, pusryčių dribsniuose ir marinuotose daržovėse. Iš visų maisto priedų šis tikrai nekelia didelio nerimo: jis išgaunamas iš daržovės, kurią daugelis valgome reguliariai. Reikšmingo poveikio sveikatai nepastebėta, ir didžioji dauguma žmonių jį toleruoja puikiai.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 325849;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural pigment found in berries, red cabbage, grapes, and other deeply coloured plants — it''s what gives them their vibrant red, purple, and blue hues. In food production it''s used as a colouring agent to make products look more appealing or to restore colour lost during processing. You''ll find it in drinks, jams, cereals, dairy products, and more. It''s considered very safe and is actually studied for potential antioxidant benefits, though food-grade amounts are modest. Most people have no reason to be concerned about it at all.', opinion_lt = 'Tai natūralus pigmentas, randamas uogose, raudonuosiuose kopūstuose, vynuogėse ir kitose ryškiaspalvėse augalinėse žaliavose — būtent jis suteikia jiems raudoną, violetinę ar mėlyną spalvą. Maisto pramonėje jis naudojamas kaip dažiklis, kad produktai atrodytų patraukliau arba susigrąžintų perdirbimo metu prarastą spalvą. Jo rasite gėrimuose, uogienėse, dribsniuose, pieno produktuose ir kitur. Laikomas labai saugiu, o mokslas net tiria jo galimą antioksidacinį poveikį. Neturite jokios realios priežasties jo bijoti.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 326046;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally occurring mineral — the same stuff found in chalk, limestone, and eggshells. In food it works as an acidity regulator, anti-caking agent, or white colouring, and it also adds a calcium boost to products like baby foods, juices, and cereals. It shows up in cheeses, processed fish, chocolate products, and more. It is one of the most widely accepted food additives, with no known safety concerns at typical dietary levels. Most health authorities consider it completely safe, and it is even used as a calcium supplement.', opinion_lt = 'Tai natūralios kilmės mineralas — tas pats, iš kurio pagaminta kreida, kalkakmeniai ir kiaušinių lukštai. Maiste jis naudojamas kaip rūgštingumo reguliatorius, sukietėjimą stabdanti medžiaga arba baltas dažiklis, o taip pat papildo produktus kalciu — ypač kūdikių maistą, sultis ir grūdų produktus. Randamas sūriuose, perdirbtuose žuvies produktuose, šokolado gaminiuose ir kitur. Tai vienas labiausiai pripažintų maisto priedų — įprastais kiekiais jokio pavojaus sveikatai nenustatyta. Daugelis sveikatos institucijų laiko jį visiškai saugiu, be to, jis naudojamas kaip kalcio papildas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 326257;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a white pigment used to make foods look brighter and more opaque — think white coatings on sweets or chewing gum. It is synthetic and has no nutritional value whatsoever. The European Food Safety Authority concluded in 2021 that it can no longer be considered safe, as there are concerns about tiny particles potentially accumulating in the body. The EU banned it as a food additive in 2022, though it is still permitted in some other countries.', opinion_lt = 'Tai sintetinis baltas pigmentas, naudojamas tam, kad maistas atrodytų baltesnis ir nepermatomas — pavyzdžiui, saldainių ar kramtomosios gumos dangoje. Jokios maistinės vertės jis neturi. Europos maisto saugos tarnyba 2021 m. nusprendė, kad jo nebegalima laikyti saugiu — kyla susirūpinimas, kad smulkios dalelės gali kauptis organizme. ES jį uždraudė kaip maisto priedą 2022 m., nors kai kuriose kitose šalyse jis vis dar leidžiamas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 326421;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a group of naturally occurring mineral pigments used to add or restore colour in certain foods. They come in shades ranging from yellow and red to black, and are the same compounds found in rust and soil. Approved for use in a limited number of food categories, they are generally considered safe at the levels permitted in food. The body can process small amounts of iron from these compounds, though the quantities from food colouring use are minimal.', opinion_lt = 'Tai natūralios kilmės mineraliniai pigmentai, naudojami kai kurių maisto produktų spalvai suteikti arba atkurti. Jų atspalviai svyruoja nuo geltonos ir raudonos iki juodos — tai tie patys junginiai, kurie sudaro rūdis ir randami dirvožemyje. Leidžiama naudoti tik nedaugelyje maisto kategorijų, ir tokiais kiekiais jie laikomi saugiais. Organizmas gali pasisavinti nedideli kiekį geležies iš šių junginių, tačiau naudojant juos kaip dažiklius, jų kiekiai maiste būna minimalūs.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 326467;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a group of naturally occurring mineral pigments — the same compounds that give rust its red-brown colour and soil its earthy tones. In food, they are used purely as colourants to give products a red, yellow, brown, or black appearance. They are authorised only in a very limited number of food categories, mainly for surface colouring of certain fresh produce like olives. Regulatory bodies consider them safe at permitted levels, and the body handles small amounts of iron compounds quite normally.', opinion_lt = 'Tai natūralios kilmės mineraliniai pigmentai — tie patys junginiai, kurie suteikia rūdims rausvai rudą spalvą, o dirvožemiui — žemišką atspalvį. Maiste jie naudojami išskirtinai kaip dažikliai, suteikiantys raudoną, geltoną, rudą ar juodą spalvą. Leidžiama juos naudoti tik labai ribotose maisto kategorijose, daugiausia kai kurių šviežių produktų, pavyzdžiui, alyvuogių, paviršiaus dažymui. Kompetentingos institucijos laiko juos saugiais leidžiamais kiekiais, o organizmas su nedideliais geležies junginių kiekiais susidoroja visiškai normaliai.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 363563;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a metallic silver pigment used purely for decorative purposes — think shiny coatings on celebration cakes or confectionery. It is only permitted in very specific decorative applications, not in everyday food ingredients, so typical exposure is extremely low. While aluminium accumulation in the body is a genuine long-term health concern discussed in scientific literature, the tiny amounts used in surface decoration are considered acceptable by food safety authorities.', opinion_lt = 'Tai metalinis sidabrinis dažiklis, naudojamas tik dekoravimui — pavyzdžiui, blizgiems dangalams ant šventinių tortų ar saldainių. Jis leidžiamas tik labai konkretiems dekoratyviniams tikslams, todėl kasdienė jo vartojimo dozė yra itin maža. Nors aliuminio kaupimasis organizme mokslinėje literatūroje laikomas realiu ilgalaikiu rūpesčiu, maisto saugos institucijos mano, kad tokie nedideli kiekiai, naudojami paviršiaus puošybai, yra priimtini.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 326563;
UPDATE aggregate.eu_additives SET opinion_en = 'This is actual silver — the precious metal — used in extremely thin layers as an edible decoration on cakes, chocolates, and luxury confectionery, as well as on some spirit drinks. It has no flavour, no nutritional value, and serves a purely aesthetic purpose, giving food a shiny metallic appearance. Its use is strictly limited to decorative applications and is permitted only in very small quantities. Silver is considered biologically inert in the tiny amounts used in food decoration, meaning the body does not absorb it and it passes through without causing harm.', opinion_lt = 'Tai tikras sidabras — taurusis metalas — naudojamas itin ploname sluoksnyje kaip valgomasis dekoratorius ant tortų, šokolado ir prabangių saldainių, taip pat kai kurių stipriųjų gėrimų. Jis neturi jokio skonio ar maistinės vertės — naudojamas tik dėl estetikos, suteikiant maistui blizgantį metalo išvaizdą. Leidžiama naudoti tik labai nedideliais kiekiais ir tik dekoravimo tikslais. Tokiomis mažomis dozėmis sidabras laikomas biologiškai inertišku — organizmas jo neįsisavina ir jis pašalinamas nepakenkęs sveikatai.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 326610;
UPDATE aggregate.eu_additives SET opinion_en = 'This is genuine gold — the same precious metal used in jewellery — used in tiny amounts purely for decorative purposes in food. It adds a shimmering, luxurious appearance to chocolates, confectionery, and certain alcoholic drinks, but has absolutely no flavour or nutritional value. Because gold is chemically inert, it passes through the body without being absorbed or reacting with anything. It is considered completely safe, and the main concern is really just the cost — it is one of the most expensive food additives you will ever encounter.', opinion_lt = 'Tai tikras auksas — tas pats brangus metalas, naudojamas papuošaluose — maiste naudojamas labai mažais kiekiais vien dėl dekoratyvinės išvaizdos. Jis suteikia blizgantį, prabangų efektą šokoladiniams saldainiams, konditerijos gaminiams ir kai kuriems alkoholiniams gėrimams, tačiau neturi jokio skonio ar maistinės vertės. Auksas yra chemiškai inertiškas — jis praeina per organizmą nesireaguodamas ir neįsisavindamas. Laikomas visiškai saugiu, o vienintelis realus rūpestis — kaina, nes tai vienas brangiausių maisto priedų, kurį galite aptikti ant etikečių.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 326683;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic red dye used exclusively on the outer rind of certain cheeses — it never touches the part you actually eat. It is one of the most narrowly permitted food colorants in the EU, approved for just that single decorative purpose. Safety concerns are minimal given how limited the exposure is, and most people simply cut the rind off anyway.', opinion_lt = 'Tai sintetinis raudonas dažiklis, naudojamas tik ant kai kurių sūrių plutelės išorės — jis niekada neliečia tos dalies, kurią iš tikrųjų valgote. ES tai vienas iš labiausiai ribotų maisto dažiklių, leidžiamas naudoti tik šiam vieninteliam dekoratyviniam tikslui. Kadangi kontaktas su šiuo priedu yra labai ribotas, o dauguma žmonių plutelę nupjauna, rimtų sveikatos susirūpinimų nekyla.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 326756;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative used to stop mould, yeast, and bacteria from growing in food. It''s one of the most widely used food preservatives, though the fact it''s only authorised in one food category here suggests a fairly limited use in this particular market context. It''s commonly found in cheese, baked goods, wine, and dried fruits. It''s generally considered safe by major food safety authorities, with no significant health concerns for most people at typical dietary levels.', opinion_lt = 'Tai sintetinis konservantas, naudojamas siekiant sustabdyti pelėsių, mielių ir bakterijų augimą maiste. Tai vienas iš plačiausiai naudojamų maisto konservantų pasaulyje, nors šiame kontekste jis patvirtintas tik vienoje maisto kategorijoje. Dažniausiai randamas sūriuose, kepiniuose, vyne ir džiovintuose vaisiuose. Pagrindinės maisto saugos institucijos laiko jį saugiu, ir esant įprastam vartojimo lygiui didžiajai daliai žmonių jokių reikšmingų sveikatos problemų nekyla.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 326803;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative that stops mould and yeast from growing in food. It''s widely used in products like baked goods, cheese, dried fruit, and soft drinks to extend shelf life. It''s one of the most commonly used preservatives in the food industry. Regulatory bodies like EFSA and the FDA consider it safe at the levels used in food. Some people with sensitivities may experience mild reactions, but this is relatively rare.', opinion_lt = 'Tai sintetinis konservantas, kuris neleidžia pelėsiams ir mielėms augti maiste. Jis plačiai naudojamas kepiniuose, sūryje, džiovintuose vaisiuose ir gaivuosiuose gėrimuose, kad pailgintų galiojimo laiką. Tai vienas dažniausiai naudojamų konservantų maisto pramonėje. Tokios institucijos kaip EFSA ir FDA laiko jį saugiu tokiomis dozėmis, kokiomis jis naudojamas maiste. Kai kurie žmonės, turintys jautrumą, gali patirti lengvas reakcijas, tačiau tai pasitaiko gana retai.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 328248;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the calcium salt form of sorbic acid, a preservative that works by preventing mould, yeast, and bacteria from growing in food. It was once used in certain food products to extend shelf life, but it has since been removed from the approved list of additives in the European Union. Since it is no longer authorised for use in EU food products, you are very unlikely to encounter it on any current ingredient label.', opinion_lt = 'Tai sorbatų šeimos konservantas – kalcio druska, kuri slopina pelėsių, mielių ir bakterijų augimą maiste, taip prailgindama produktų galiojimo laiką. Nors anksčiau jis buvo naudojamas tam tikruose maisto produktuose, Europos Sąjungoje šis priedas buvo išbrauktas iš leistinų medžiagų sąrašo. Todėl šiandien jo praktiškai nerasite jokiame ES rinkoje parduodamame produkto sudėtyje.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 328306;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative that stops the growth of bacteria, yeasts, and moulds, helping food and drinks last longer. It''s most commonly found in soft drinks, fruit juices, and pickled products. While regulatory bodies like EFSA and the FDA consider it safe at permitted levels, some studies suggest that when combined with vitamin C (ascorbic acid), it can form benzene — a known carcinogen — though the amounts detected in foods are generally very small. People with aspirin sensitivity or asthma may also notice reactions to it.', opinion_lt = 'Tai sintetinis konservantas, kuris slopina bakterijų, mielių ir pelėsių augimą, todėl maistas ir gėrimai išsilaiko ilgiau. Dažniausiai jo randama gazuotuose gėrimuose, vaisių sultyse ir marinuotuose produktuose. Nors reguliavimo institucijos laiko jį saugiu leidžiamais kiekiais, kai kurie tyrimai rodo, kad susijungęs su vitaminu C jis gali susidaryti benzeną — kancerogeną, nors tokių kiekių maiste paprastai būna labai mažai. Žmonės, jautrūs aspirinui ar sergantys astma, kartais pastebi reakcijas į šią medžiagą.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 328361;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative that stops the growth of bacteria, yeast, and mould — mainly used in acidic drinks like fizzy sodas, fruit juices, and squashes. It keeps products shelf-stable and prevents spoilage. One thing worth knowing: when combined with vitamin C (ascorbic acid) in a drink, it can form benzene, a compound linked to cancer risk. The amounts detected are usually tiny, but it is a real concern that some manufacturers have responded to by reformulating their products.', opinion_lt = 'Tai sintetinis konservantas, kuris slopina bakterijų, mielių ir pelėsių augimą — dažniausiai naudojamas rūgščiuose gėrimuose kaip gazuoti saldainiai, vaisių sultys ir sirupai. Jis pailgina produktų galiojimo laiką. Vienas svarbus dalykas: kai šis priedas susijungia su vitaminu C gėrime, gali susidaryti benzenas — medžiaga, siejama su vėžio rizika. Kiekiai paprastai būna labai maži, tačiau tai tikra problema, dėl kurios dalis gamintojų jau pakeitė savo receptūras.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 328740;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative that works by stopping the growth of bacteria, yeasts, and moulds in food. It is the potassium salt form of benzoic acid and is found in some beverages and condiments, though it is authorised in very few food categories. One concern worth noting: when it comes into contact with ascorbic acid (vitamin C), it can form benzene, a known carcinogen. This reaction is more likely in acidic drinks that also contain vitamin C.', opinion_lt = 'Tai sintetinis konservantas, kuris apsaugo maistą nuo bakterijų, mielių ir pelėsių augimo. Jis naudojamas kai kuriuose gėrimuose ir padažuose, tačiau leidžiamas tik labai nedaugelyje maisto kategorijų. Svarbu žinoti: kai šis konservantas susiliečia su askorbo rūgštimi (vitaminu C), gali susidaryti benzenas — žinoma kancerogeninė medžiaga. Ši reakcija dažniau pasitaiko rūgščiuose gėrimuose, kuriuose taip pat yra vitamino C, todėl verta atidžiai skaityti etiketes.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 328794;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative that works by stopping the growth of bacteria, yeasts, and moulds, helping drinks and foods stay fresh longer. It is only authorised in a very limited number of food categories, so you won''t encounter it often. Like its close relative sodium benzoate, there are some concerns that it may form small amounts of benzene when combined with vitamin C, and some studies have linked benzoate preservatives to hyperactivity in children. It is generally considered safe at the low levels used in food, but people who are sensitive to benzoates may prefer to avoid it.', opinion_lt = 'Tai sintetinis konservantas, kuris slopina bakterijų, mielių ir pelėsių augimą, taip pailgindamas produktų galiojimo laiką. Jis leidžiamas labai nedaugelyje maisto kategorijų, tad kasdieniniuose produktuose jį sutikti nelabai tikėtina. Kaip ir jo giminaitis natrio benzoatas, šis priedas kelia tam tikrų klausimų — kartu su vitaminu C jis gali sudaryti nedideles benzeno kiekius, o kai kurie tyrimai siejo benzoatus su padidėjusiu hiperaktyvumu vaikams. Nedideliais kiekiais jis laikomas saugiu, tačiau žmonės, jautrūs benzoatams, gali norėti jo vengti.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 328848;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative from the paraben family, used to stop mould and bacteria from growing in food. It''s only approved in a very narrow range of food products in the EU. Parabens as a group have faced scientific scrutiny over potential hormonal effects, though food regulators consider the low levels used in food to be safe. If you prefer to avoid parabens, checking ingredient labels is the way to go.', opinion_lt = 'Tai sintetinis konservantas iš parabenų šeimos, naudojamas siekiant apsaugoti maistą nuo pelėsių ir bakterijų. ES jis patvirtintas tik labai siauram maisto produktų ratui. Parabenai kaip grupė sulaukė mokslininkų dėmesio dėl galimo poveikio hormonams, tačiau maisto saugos institucijos mano, kad tokiais kiekiais, kokie naudojami maiste, jie yra saugūs. Jei norite jų vengti, tiesiog atidžiai skaitykite sudėties etiketes.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 328901;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative from the paraben family, used to stop mould and bacteria from growing in food. It is only authorised in a very small number of food categories, which suggests its use is quite restricted. Some researchers have raised concerns about parabens in general — they can weakly mimic oestrogen in the body — though regulatory agencies consider it safe at permitted levels. Still, if you prefer to avoid parabens, checking ingredient labels is a good habit.', opinion_lt = 'Tai sintetinis konservantas iš parabenų šeimos, naudojamas tam, kad maiste nesivestų pelėsiai ir bakterijos. Jis leidžiamas tik labai nedaugelyje maisto produktų kategorijų, todėl jo vartojimas yra gana ribotas. Kai kurie mokslininkai yra išreiškę susirūpinimą dėl parabenų apskritai — jie gali silpnai imituoti estrogeno veikimą organizme — tačiau reguliavimo institucijos laiko jį saugiu leidžiamomis dozėmis. Vis dėlto, jei norite parabenų vengti, verta įpratinti save skaityti sudėties etiketes.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 329004;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative from the paraben family, used to prevent mould and bacteria growth in food. It appears in very few food categories — mostly in some confectionery or flavourings where microbial control is needed. Parabens have been studied extensively in cosmetics and food; some research raises questions about mild hormonal effects at high doses, though regulatory bodies like EFSA consider it safe at the low levels permitted in food.', opinion_lt = 'Tai sintetinis konservantas iš parabenų grupės, naudojamas siekiant apsaugoti maistą nuo pelėsio ir bakterijų. Leidžiamas tik labai nedaugelyje maisto kategorijų — daugiausia kai kuriuose konditerijos gaminiuose ar aromato medžiagose. Parabenai plačiai tyrinėti kosmetikos ir maisto srityse; kai kurie tyrimai kelia klausimų dėl galimo silpno hormoninio poveikio didelėmis dozėmis, tačiau EFSA ir kitos institucijos laiko jį saugiu leidžiamais kiekiais.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 329058;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative from the paraben family, used to stop mould and bacteria from growing in food. It is only authorised in a very small number of food categories, which tells you it has quite limited use in the food supply. Some studies have raised questions about parabens and hormonal activity, though the amounts found in food are considered low. Regulatory bodies currently regard it as safe at permitted levels, but it is worth being aware of if you prefer to limit paraben exposure.', opinion_lt = 'Tai sintetinis konservantas iš parabenų šeimos, naudojamas siekiant sustabdyti pelėsių ir bakterijų augimą maiste. Jis leidžiamas tik labai nedaugelyje maisto kategorijų, todėl maisto pramonėje naudojamas gana retai. Kai kurie tyrimai kėlė klausimų dėl parabenų poveikio hormonų sistemai, tačiau kiekiai, randami maiste, laikomi mažais. Reguliavimo institucijos šiuo metu laiko jį saugiu leistinosiomis dozėmis, tačiau jei norите riboti parabenų vartojimą, verta atkreipti į tai dėmesį.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 329112;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative that stops mould, bacteria, and yeast from growing, and also prevents browning in foods. It is most commonly found in dried fruits, wine, and some fruit juices. It has been used in food preservation for centuries and is generally considered safe for most people. However, it can trigger asthma attacks, breathing difficulties, and allergic reactions in sensitive individuals — particularly those with asthma — so its presence must always be declared on labels.', opinion_lt = 'Tai sintetinis konservantas, kuris saugo maistą nuo pelėsio, bakterijų ir mielių, taip pat apsaugo nuo patamsėjimo. Dažniausiai randamas džiovintuose vaisiuose, vyne ir kai kuriuose vaisių sultyse. Naudojamas jau šimtmečius ir laikomas saugiu daugumai žmonių. Tačiau jautriems asmenims, ypač sergantiems astma, gali sukelti kvėpavimo sunkumų ar alerginių reakcijų — todėl jo buvimas produkte privalo būti nurodytas etiketėje.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 329166;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative that works by preventing oxidation and stopping the growth of bacteria and moulds. It belongs to the sulphite family, which are widely used to keep food and drinks looking fresh and lasting longer. You might find it in a very limited range of products, as it is only authorised in one food category.

The main concern with sulphites as a group is that some people — particularly those with asthma — can react to them, sometimes quite noticeably. For most healthy people they pose little risk at the levels used in food, but sensitive individuals are advised to check labels carefully.', opinion_lt = 'Tai sintetinis konservantas, kuris apsaugo maistą nuo oksidacijos ir stabdo bakterijų bei pelėsių augimą. Jis priklauso sulfitų šeimai — medžiagų, plačiai naudojamų maisto ir gėrimų šviežumui bei ilgaamžiškumui palaikyti. Šis priedas leidžiamas tik vienoje maisto kategorijoje, todėl susidursite su juo retai.

Pagrindinė baimė dėl sulfitų yra ta, kad kai kurie žmonės — ypač astma sergantys — gali į juos reaguoti. Daugumai sveikų žmonių tokiomis dozėmis, kurios naudojamos maiste, jie nekelia didelės rizikos, tačiau jautriems asmenims rekomenduojama atidžiai skaityti etiketes.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 330046;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative that works by preventing the growth of bacteria, mold, and yeast, and also stops food from browning. It belongs to the sulphite family and is used in a very limited range of food products. Some people, particularly those with asthma, can be sensitive or allergic to sulphites and may experience reactions like breathing difficulties. For most healthy people it poses little concern at normal levels, but it must be declared on labels when present above certain thresholds.', opinion_lt = 'Tai sintetinis konservantas, kuris stabdo bakterijų, pelėsių ir mielių augimą bei neleidžia maistui patamsėti. Jis priklauso sulfitų grupei ir leidžiamas tik labai nedaugelyje maisto kategorijų. Kai kurie žmonės, ypač astmatikai, gali būti jautrūs sulfitams ir patirti reakcijų, pavyzdžiui, sunkumą kvėpuojant. Daugumai sveikų žmonių įprastais kiekiais jis nekelia didelės rizikos, tačiau etiketėje privalo būti nurodytas, kai jo koncentracija viršija tam tikrą ribą.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 330092;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative that stops food from browning and prevents the growth of bacteria and moulds. It belongs to the sulphite family and is commonly found in dried fruits, wines, and some seafood products. Most people tolerate it well, but it can trigger asthmatic reactions or allergic responses in sensitive individuals, particularly those with sulphite sensitivity. Its use is tightly regulated, and products containing it must carry a warning label.', opinion_lt = 'Tai sintetinis konservantas, kuris stabdo maisto ruduonį ir apsaugo nuo bakterijų bei pelėsių augimo. Jis priklauso sulfitų šeimai ir dažniausiai randamas džiovintuose vaisiuose, vyne ir kai kuriuose jūros gėrybių produktuose. Dauguma žmonių jį toleruoja gerai, tačiau jautriems asmenims, ypač turintiems sulfitų netoleranciją, jis gali sukelti astmos priepuolius ar alerginę reakciją. Jo naudojimas griežtai reglamentuotas, o produktai, kuriuose jis yra, privalo turėti įspėjamąjį ženklinimą.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 330138;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative that stops food and drinks from browning and going off, and also prevents unwanted bacteria and yeast from growing. It releases sulphur dioxide when dissolved, which does the actual preservation work. You''ll most likely encounter it in wines and dried fruits, though it''s authorised in very few food categories overall. People with asthma or sulphite sensitivity should be cautious — sulphites can trigger reactions in sensitive individuals, which is why their presence must be labelled.', opinion_lt = 'Tai sintetinis konservantas, kuris apsaugo maistą ir gėrimus nuo patamsėjimo bei gedimo, taip pat slopina nepageidaujamas bakterijas ir mieles. Ištirpęs vandenyje, jis išskiria sieros dioksidą, kuris ir atlieka pagrindinį konservavimo darbą. Dažniausiai jį rasite vynuose ir džiovintuose vaisiuose, nors leidžiamas tik labai nedaugelyje maisto kategorijų. Astma sergantys žmonės ar tie, kurie jautrūs sulfitams, turėtų būti atsargūs — sulfitai gali sukelti reakcijas, todėl jų buvimas etiketėje privalo būti nurodytas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 330184;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative that works by releasing sulphur dioxide, which kills bacteria and moulds and slows spoilage. It is authorised in very few food categories, so most people rarely encounter it. It belongs to the sulphite family, which can trigger reactions in people with sulphite sensitivity or asthma — food labels must warn about this. For the general population, it is considered safe at the low levels permitted in food.', opinion_lt = 'Tai sintetinis konservantas, kuris veikia išskirdamas sieros dioksidą — jis naikina bakterijas, pelėsius ir lėtina maisto gedimą. Leidžiamas labai nedaugelyje maisto kategorijų, todėl dauguma žmonių su juo retai susiduria. Priklauso sulfitų grupei, kuri gali sukelti reakcijas žmonėms, jautriems sulfitams arba sergantiems astma — apie tai privalo būti įspėjama ant etiketės. Plačiajai visuomenei, vartojant leidžiamus kiekius, laikomas saugiu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 330230;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative that works by releasing sulphur dioxide, which stops bacteria and moulds from growing and also prevents discolouration in food. It is only authorised in a very small number of food categories, which reflects its quite limited use in modern food production. People with asthma or sulphite sensitivity should be cautious, as sulphite-based preservatives can trigger reactions in sensitive individuals. For most people, it is considered safe at the low levels found in food.', opinion_lt = 'Tai sintetinis konservantas, kuris veikia išskirdamas sieros dioksidą — jis slopina bakterijų ir pelėsių augimą bei apsaugo maistą nuo patamsėjimo. Leidžiama jį naudoti tik labai mažame skaičiuje maisto kategorijų, todėl praktiškai jis sutinkamas retai. Astma sergantys žmonės ar tie, kurie jautrūs sulfitams, turėtų būti atsargūs — sulfitai gali sukelti reakcijas jautriems asmenims. Daugumai žmonių tokiais kiekiais, kokie randami maiste, jis laikomas saugiu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 330276;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative that works by releasing sulphur dioxide, which stops bacteria and mould from growing and also prevents browning in food. It is authorised in very few food categories, meaning most people encounter it rarely. Sulphite compounds like this one can trigger reactions in sensitive individuals, particularly those with asthma or sulphite intolerance, so labels must declare it when present above certain levels.', opinion_lt = 'Tai sintetinis konservantas, kuris veikia išskirdamas sieros dioksidą — jis slopina bakterijų bei pelėsių augimą ir neleidžia maistui patamsėti. Šis priedas leidžiamas labai nedaugelyje maisto kategorijų, tad dauguma žmonių su juo susiduria retai. Sulfit junginiai gali sukelti reakcijas jautriems asmenims, ypač turintiems astmą ar sulfit netoleranciją, todėl gamintojai privalo jį nurodyti etiketėje, kai jo kiekis viršija nustatytą ribą.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 330322;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural antimicrobial peptide produced by a strain of lactic acid bacteria — the same type of bacteria used in traditional food fermentation. It works as a preservative, stopping the growth of harmful bacteria like Listeria and Clostridium in dairy products, processed eggs, and desserts. It is one of the few naturally derived antibiotics approved for use in food. Regulatory bodies including EFSA consider it safe at permitted levels, and it has been used in food production for decades without major concern.', opinion_lt = 'Tai natūralios kilmės antimikrobinis junginys, gaminamas pieno rūgšties bakterijų — tokių pat, kurios naudojamos tradiciniame maisto fermentavime. Jis veikia kaip konservantas: slopina kenksmingų bakterijų, pavyzdžiui, Listeria ir Clostridium, augimą sūriuose, perdirbtose kiaušinių produktuose ir desertuose. Tai vienas iš nedaugelio natūralios kilmės antimikrobinių medžiagų, leidžiamų naudoti maiste. EFSA ir kitos reguliavimo institucijos laiko jį saugiu leidžiamomis dozėmis, o dešimtmečius trunkantis naudojimas nekelia didelio susirūpinimo.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 330368;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural antifungal substance produced by a soil bacterium, used to prevent mould and yeast from growing on the surface of foods like cured meats and ripened cheeses. It is typically applied as a surface treatment or coating, not mixed throughout the food itself. Regulatory authorities in the EU and elsewhere consider it safe at the levels used, and because it targets fungi rather than bacteria, it does not affect the beneficial bacteria involved in cheese ripening. Some consumer groups raise questions about antibiotic-like compounds in food, but current evidence does not suggest it poses a health risk at normal dietary exposure.', opinion_lt = 'Tai natūralios kilmės priešgrybelinė medžiaga, gaminama dirvožemio bakterijų. Ji naudojama siekiant apsaugoti tokius produktus kaip vytinta mėsa ar brandinti sūriai nuo pelėsio ir mielių augimo, dažniausiai apdorojant tik paviršių. Europos Sąjungos maisto saugos institucijos laiko ją saugia tokiais kiekiais, kokiais ji naudojama maisto gamyboje. Nors kai kurie vartotojai nerimauja dėl antibiotikams artimų medžiagų maiste, esami tyrimai nerodo, kad įprastas jos kiekis maiste keltų pavojų sveikatai.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 330493;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative used in a very narrow range of foods — specifically certain ripened cheeses. It works by slowly releasing formaldehyde, which inhibits the growth of mould and bacteria on the cheese surface. Because of that formaldehyde connection, it is banned in many countries, including the US, and its use in the EU is tightly restricted to just one specific product type. People with sensitivities or those wishing to avoid synthetic chemical preservatives may want to check labels carefully.', opinion_lt = 'Tai sintetinis konservantas, naudojamas labai siauroje maisto produktų grupėje — tam tikruose brandintų sūrių rūšyse. Veikia išskirdamas formaldehydą, kuris slopina pelėsių ir bakterijų augimą sūrio paviršiuje. Dėl šio ryšio su formaldehidu jis uždraustas daugelyje šalių, įskaitant JAV, o ES jo naudojimas griežtai apribotas tik viena konkrečia produktų kategorija. Žmonės, norintys vengti sintetinių cheminių konservantų, turėtų atidžiai skaityti etiketes.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 330597;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative and sterilising agent used in beverages — mainly wines, ciders, flavoured drinks, and some alcoholic mixtures. It works by killing off yeasts and bacteria in the drink, preventing unwanted fermentation or spoilage without the need for heat treatment. The clever part is that it breaks down into tiny amounts of methanol and carbon dioxide after doing its job, so very little residue remains in the final product. Regulatory bodies like EFSA consider it safe at authorised levels, and it is not widely considered controversial.', opinion_lt = 'Tai sintetinis konservantas ir sterilizavimo priemonė, naudojama gėrimuose — daugiausia vynuose, sidruose, aromatizuotuose gėrimuose ir kai kuriuose alkoholiniuose mišiniuose. Jis sunaikina mieles ir bakterijas, neleisdamas gėrimui rūgti ar gesti, ir tam nereikia kaitinti skysčio. Gudriausia tai, kad atlikęs darbą jis suyra į labai mažus metanolio ir anglies dvideginio kiekius, todėl galutiniame produkte beveik nelieka jokių liekanų. Europos maisto saugos institucija (EFSA) laiko jį saugiu leidžiamomis dozėmis, ir didelių diskusijų dėl šios medžiagos nekyla.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 330644;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic antimicrobial preservative used to prevent bacterial growth, particularly on the surface of processed meat products like cooked hams and sausages. It works by disrupting the cell membranes of harmful bacteria, extending shelf life and improving food safety. It is approved in the EU but only for a very limited range of products. Regulatory bodies consider it safe at the low levels permitted, and it is not widely controversial among food scientists.', opinion_lt = 'Tai sintetinis antimikrobinis konservantas, naudojamas siekiant sulėtinti bakterijų augimą termiškai apdorotuose mėsos gaminiuose, pavyzdžiui, virtos kumpis ar dešrų paviršiuje. Jis veikia ardydamas kenksmingų bakterijų ląstelių membranas, taip pailgindamas produktų galiojimo laiką. ES jis leidžiamas tik labai ribotam produktų sąrašui. Leidžiamomis mažomis dozėmis reguliavimo institucijos laiko jį saugiu, ir tarp maisto mokslininkų jis nesukelia didelių ginčų.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 363516;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural-type emulsifier derived from fats and sugars, used to help ingredients blend smoothly and improve texture in drinks and other food products. It appears in beverages like beer and flavoured drinks. It has a very limited authorisation scope, and there is little public controversy around it. It is generally considered safe at the levels used in food.', opinion_lt = 'Tai natūralios kilmės emulsiklis, gaunamas iš riebalų ir cukrų, padedantis ingredientams geriau susimaišyti ir pagerinantis gėrimų bei kitų produktų tekstūrą. Randamas aluje ir skoniuose gėrimuose. Leidžiamas tik ribotose maisto kategorijose, didelio visuomenės susidomėjimo ar diskusijų nesukelia. Tokiais kiekiais, kokiais naudojamas maiste, laikomas saugiu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 365142;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative used in cured and processed meats to prevent the growth of dangerous bacteria, including the one that causes botulism. It also gives cured meats their characteristic pink colour and distinctive flavour. It is authorised in a very limited number of food categories, which reflects how carefully its use is controlled. At high doses it can be harmful, and there is ongoing scientific debate about whether regular consumption of nitrite-cured meats may increase cancer risk over the long term. Most health agencies consider it safe at permitted levels, but many nutritionists recommend limiting processed meat intake generally.', opinion_lt = 'Tai sintetinis konservantas, naudojamas vytintoje ir perdirbtoje mėsoje, kad būtų apsaugota nuo pavojingų bakterijų, įskaitant sukeliančias botulizmą. Jis taip pat suteikia vytintai mėsai būdingą rausvą spalvą ir skonį. Leidžiamas tik labai mažame maisto produktų kategorijų skaičiuje – tai rodo, kaip griežtai kontroliuojamas jo naudojimas. Didelės dozės gali būti žalingos, o mokslininkai vis dar diskutuoja, ar reguliarus nitritais konservuotos mėsos vartojimas ilgainiui gali didinti vėžio riziką. Daugelis sveikatos institucijų laiko jį saugiu leistinosiose ribose, tačiau mitybos specialistai dažnai rekomenduoja apriboti perdirbtos mėsos vartojimą.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 330813;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative used mainly in cured and processed meats like bacon, ham, hot dogs, and salami. It prevents the growth of dangerous bacteria, including those that cause botulism, and gives cured meats their characteristic pink colour and flavour. It is one of the most effective tools food producers have against serious foodborne illness. However, at high temperatures — such as frying bacon — it can form nitrosamines, compounds linked to increased cancer risk in some studies. Regulatory bodies consider it safe at permitted levels, but many health guidelines suggest limiting processed meat consumption overall.', opinion_lt = 'Tai sintetinis konservantas, naudojamas daugiausia vytintose ir perdirbtose mėsos produktuose — šonkauliuose, kumpyje, dešrelėse ir saliamiuose. Jis saugo maistą nuo pavojingų bakterijų, įskaitant botulizmo sukėlėją, ir suteikia vytintai mėsai būdingą rausvą spalvą ir skonį. Tačiau aukštoje temperatūroje, pavyzdžiui, kepant mėsą keptuvėje, gali susidaryti nitrozaminai — junginiai, kai kurių tyrimų siejami su padidėjusia vėžio rizika. Reguliavimo institucijos laiko jį saugiu leistinomis dozėmis, tačiau daugelis mitybos rekomendacijų pataria apriboti perdirbtų mėsos gaminių vartojimą.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 331075;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative used primarily in cured and processed meats to prevent the growth of dangerous bacteria, including the one responsible for botulism. It also helps maintain that characteristic pink colour in products like cured ham or salami. It is authorised in only a very limited range of foods. While it is considered safe at regulated levels, there is ongoing scientific discussion about the potential health effects of nitrates and nitrites from processed meats when consumed frequently over a long period.', opinion_lt = 'Tai sintetinis konservantas, naudojamas daugiausia vytintoje ir perdirbtoje mėsoje, kad būtų išvengta pavojingų bakterijų, įskaitant sukeliančias botulizmą. Jis taip pat padeda išlaikyti būdingą rožinę spalvą kumpyje ar saliamyje. Leidžiamas tik labai siauroje maisto produktų kategorijoje. Nors reguliuojamais kiekiais jis laikomas saugiu, mokslininkų diskusijos apie galimą ilgalaikį nitratų ir nitritų poveikį sveikatai, ypač dažnai vartojant perdirbtą mėsą, vis dar tęsiasi.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 331121;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a salt-based preservative, synthetic in origin, used mainly in cured and processed meats like salami, bacon, or dry-cured ham. It works by inhibiting the growth of harmful bacteria, including the one responsible for botulism, and also helps preserve that characteristic pink colour in cured meats. It is authorised in only one food category, meaning its use is quite restricted. Regulatory bodies consider it safe at permitted levels, but some research links nitrates in processed meats to increased health risks with very high long-term consumption, so moderation is the sensible approach.', opinion_lt = 'Tai sintetinės kilmės konservantas, naudojamas daugiausia vytintoje ir perdirbtoje mėsoje — salamoje, šoninėje, džiovintoje kumpyje. Jis slopina pavojingų bakterijų augimą, įskaitant botulizmą sukeliantį mikroorganizmą, ir padeda išlaikyti tą būdingą rausvoką spalvą. Leidžiamas tik vienoje maisto produktų kategorijoje, todėl jo vartojimas griežtai ribotas. Reguliavimo institucijos laiko jį saugiu leistinosiomis normomis, tačiau kai kurie tyrimai sieja didelį perdirbtų mėsos gaminių vartojimą su tam tikra sveikatos rizika — tad saikingumas čia yra geriausias pasirinkimas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 331426;
UPDATE aggregate.eu_additives SET opinion_en = 'This is plain acetic acid — the same compound that gives vinegar its sharp, sour taste. It occurs naturally through fermentation and has been used to preserve food for thousands of years. In processed foods it acts as an acidity regulator and mild preservative, helping to slow the growth of bacteria and mold. You''ll find it in pickled vegetables, some breads, cheeses, and meat preparations. It''s one of the least concerning additives on the list — your body handles it easily, and it''s essentially the same thing you''d add to a salad dressing.', opinion_lt = 'Tai acto rūgštis — ta pati medžiaga, kuri suteikia actui aštrų, rūgštų skonį. Ji susidaro natūraliai fermentacijos metu ir naudojama maistui konservuoti jau tūkstančius metų. Perdirbtuose maisto produktuose ji veikia kaip rūgštingumą reguliuojanti medžiaga ir švelnus konservantas, padedantis sulėtinti bakterijų ir pelėsių augimą. Rasite ją marinuotose daržovėse, kai kuriose duonose, sūriuose ir mėsos gaminiuose. Tai vienas iš mažiausiai nerimą keliančių priedų — organizmas ją lengvai apdoroja, ir iš esmės tai tas pats, ką įpiltumėte į salotų padažą.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 331472;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the potassium salt of acetic acid — essentially the same acid found in vinegar, just in a more concentrated, stable form. It works as a preservative and acidity regulator, helping to extend shelf life and maintain the right pH in foods like canned vegetables, bread, and some meat products. It is synthetically produced but closely related to naturally occurring compounds. It is generally considered safe for most people, though those on a potassium-restricted diet (for example, people with kidney disease) may want to keep an eye on their intake from multiple sources.', opinion_lt = 'Tai acto rūgšties kalio druska — iš esmės ta pati rūgštis, kaip ir acte, tik stabilesnė ir koncentruotesnė forma. Maiste ji naudojama kaip konservantas ir rūgštingumo reguliatorius: padeda ilgiau išlikti šviežiems konservuotiems daržovėms, duonai ar mėsos gaminiams. Gaminama sintetiškai, tačiau panaši į natūraliai maiste randamas medžiagas. Daugumai žmonių ji laikoma saugia, tačiau tiems, kurie dėl inkstų ligų ar kitų priežasčių riboja kalio kiekį mityboje, verta atkreipti dėmesį į bendrą jo suvartojimą.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 331606;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the sodium salt of acetic acid — essentially the same acid that gives vinegar its sharp taste, just in a more stable, powdery form. It works as a preservative and acidity regulator, helping food last longer and keeping the pH balanced. You''ll find it in bread, processed meats, canned vegetables, and some snack foods. It''s a synthetic additive, though acetic acid itself occurs naturally in fermented foods. It''s widely considered safe, with no significant health concerns flagged by European or international food safety authorities.', opinion_lt = 'Tai acto rūgšties natrio druska — iš esmės ta pati rūgštis, kuri suteikia actui aštrų skonį, tik stabilesnės, miltelinės formos. Naudojama kaip konservantas ir rūgštingumo reguliatorius: padeda maistui ilgiau išlikti šviežiam ir palaiko tinkamą pH lygį. Randama duonoje, perdirbtuose mėsos produktuose, konservuotose daržovėse ir kai kuriuose užkandžiuose. Tai sintetinis priedas, nors pati acto rūgštis natūraliai susidaro fermentuotame maiste. Europos ir tarptautinės maisto saugos institucijos šio priedo nelaiko pavojingu — jis laikomas saugiu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 331705;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic sodium salt of acetic acid — essentially a combination of vinegar and baking soda in powder form. It acts as a preservative and acidity regulator, helping to prevent mould and bacterial growth while also giving a mild vinegar-like tang to certain foods. You''ll most commonly find it in snack foods like crisps and crackers. It is authorised in very few food categories, which reflects its quite limited use. Regulatory bodies consider it safe at the levels permitted in food.', opinion_lt = 'Tai sintetinė natrio druska, gauta iš acto rūgšties — iš esmės kaip acto ir kepimo sodos mišinys miltelių pavidalu. Naudojama kaip konservantas ir rūgštingumą reguliuojanti medžiaga: saugo maistą nuo pelėsio bei bakterijų ir suteikia lengvą acto skonį. Dažniausiai randama traškučiuose ir krekersiuose. Leidžiama tik labai mažame skaičiuje maisto kategorijų, todėl naudojama gana retai. Maisto saugos institucijos šį priedą laiko saugiu įprastomis koncentracijomis.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 366104;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the calcium salt of acetic acid — essentially vinegar combined with calcium. It works as a preservative, acidity regulator, and stabilizer, helping food maintain its texture and stay fresh longer. You''ll find it in canned fruits and vegetables, certain breads, processed cereals, and meat preparations. It''s a synthetically produced compound, though acetic acid itself occurs naturally in vinegar. Regulatory bodies like EFSA consider it safe at the levels used in food, and it even contributes a small amount of calcium to your diet.', opinion_lt = 'Tai acto rūgšties kalcio druska — paprasčiau tariant, kažkas panašaus į actą, sujungtą su kalciu. Maiste ji veikia kaip konservantas, rūgštingumo reguliatorius ir stabilizatorius — padeda išlaikyti tekstūrą ir ilgiau nesugesti. Dažniausiai randama konservuotuose vaisiuose ir daržovėse, tam tikrose duonose, perdirbtuose grūdų produktuose ir mėsos pusgaminiuose. Nors junginys gaminamas sintetiškai, pati acto rūgštis natūraliai yra akte. EFSA ir kitos institucijos laiko šią medžiagą saugia įprastais kiekiais, o kaip papildomas privalumas — ji suteikia šiek tiek kalcio.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 331813;
UPDATE aggregate.eu_additives SET opinion_en = 'This is essentially a stabilised form of vinegar — acetic acid buffered with sodium to control acidity and act as a preservative. It helps keep foods fresh, prevents bacterial growth, and maintains a consistent texture and flavour in products like fresh pasta, canned vegetables, cheeses, and processed meats. It is derived from natural fermentation but processed further to create a more neutral, controlled version of regular vinegar. It is widely considered safe by food safety authorities, and the amounts used in food are well within accepted limits for everyday consumption.', opinion_lt = 'Tai iš esmės yra stabilizuota acto rūgšties forma — natriu buferuota, kad reguliuotų rūgštingumą ir veiktų kaip konservantas. Ji padeda išlaikyti maisto šviežumą, stabdo bakterijų augimą ir išlaiko nuoseklią tekstūrą bei skonį tokiuose produktuose kaip šviežios makaronai, konservuotos daržovės, sūriai ir perdirbta mėsa. Gaunama natūralaus fermentacijos proceso metu, tačiau papildomai apdorojama, kad taptų neutralesnė ir stabilesnė nei įprastas actas. Maisto saugos institucijos ją laiko saugia, o maiste naudojami kiekiai yra gerai toleruojami kasdienio vartojimo metu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 366242;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally occurring organic acid produced by fermentation — the same process that makes yogurt tangy and gives sourdough bread its characteristic flavor. It acts as a preservative and acidity regulator, helping to extend shelf life and control pH in foods like cheese, pasta, jams, bread, and canned vegetables. It is also naturally present in our muscles and digestive system, making it one of the most body-friendly additives on the market. There is no meaningful controversy around it, and it is widely considered safe for all age groups.', opinion_lt = 'Tai natūraliai fermentacijos būdu gaunama organinė rūgštis — tas pats procesas, kuris suteikia jogurtui rūgštelį skonį ir kvapą raugintai duonai. Maiste ji naudojama kaip konservantas ir rūgštingumo reguliatorius — padeda ilgiau išsilaikyti sūriams, makaronams, uogienėms, duonai ir konservuotoms daržovėms. Ši medžiaga natūraliai randama mūsų raumenyse ir virškinimo sistemoje, todėl laikoma vienu draugiškiausių organizmui priedų. Jokių reikšmingų kontraversijų nėra — ji plačiai pripažįstama saugia visoms amžiaus grupėms.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 331921;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally occurring organic acid found in some cheeses and fermented foods, though the version used in food production is synthetically made. It works as a preservative, mainly preventing mould and bacterial growth. You''ll find it most commonly in packaged bread and other baked goods. It''s authorised in a very limited number of food categories, which reflects its quite specific use. Regulatory bodies consider it safe at the levels used in food.', opinion_lt = 'Tai natūraliai gamtoje randama organinė rūgštis, aptinkama kai kuriuose sūriuose ir fermentuotuose produktuose, tačiau maisto pramonėje naudojama jos sintetinė versija. Ji veikia kaip konservantas — stabdo pelėsių ir bakterijų augimą. Dažniausiai ją rasite supakuotoje duonoje ir kepiniuose. Leidžiama naudoti labai nedaugelyje maisto kategorijų, kas rodo gana siaurą jos paskirtį. Maisto saugos institucijos laiko ją saugia tomis dozėmis, kuriomis ji naudojama maiste.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 332220;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative — the sodium salt of propionic acid — used to slow down mould and bacterial growth in food. It is only permitted in a very limited range of products, which suggests regulators keep its use quite restricted. It is generally considered safe at the levels used in food, and propionic acid itself is actually produced naturally in small amounts during digestion. No significant health concerns have been established for most people at typical dietary exposure levels.', opinion_lt = 'Tai sintetinis konservantas — propiono rūgšties natrio druska — naudojamas sulėtinti pelėsių ir bakterijų augimą maiste. Jis leidžiamas tik labai siauroje produktų kategorijoje, o tai rodo, kad reguliuotojai jo vartojimą gerokai riboja. Bendrai laikomas saugiu tokiais kiekiais, kokiais naudojamas maiste — be to, propiono rūgštis natūraliai susidaro žarnyne virškinimo metu. Esant įprastam poveikiui per maistą, didesnio pavojaus sveikatai nenustatyta.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 332412;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative used in baked goods — mainly bread and other bakery products — to stop mould and bacterial growth, extending shelf life. It is one of the most common preservatives in commercially baked bread. Regulatory bodies like EFSA and FDA consider it safe at the levels used in food. Some parents and researchers have raised concerns about possible links to behavioural issues in children, but the evidence remains limited and inconclusive.', opinion_lt = 'Tai sintetinis konservantas, naudojamas kepiniuose — daugiausia duonoje ir kituose kepyklos gaminiuose — kad sustabdytų pelėsio ir bakterijų augimą bei pailgintų galiojimo laiką. Tai vienas dažniausių konservantų pramoninėje duonoje. Maisto saugos institucijos, tokios kaip EFSA ir FDA, mano, kad jo kiekiai maiste yra saugūs. Kai kurie tėvai ir mokslininkai iškėlė klausimą dėl galimo ryšio su vaikų elgesio sutrikimais, tačiau įrodymai kol kas riboti ir nepakankamai patikimi.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 332458;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative used to stop mould and bacteria from growing in food. It''s only authorised in a very limited number of food categories, which means you won''t encounter it often. It works similarly to its close relative used in bread and baked goods, keeping products fresh for longer. It is generally considered safe at the levels used in food, and regulatory bodies like EFSA have not raised significant concerns about it.', opinion_lt = 'Tai sintetinis konservantas, kuris apsaugo maistą nuo pelėsio ir bakterijų augimo. Jis leidžiamas tik labai ribotame maisto produktų kategorijų skaičiuje, tad kasdieniniame gyvenime su juo susidursite retai. Veikia panašiai kaip jo artimas analogas, naudojamas duonos ir kepinių gamyboje. Maisto saugos institucijos, įskaitant EFSA, neišreiškė didelių susirūpinimų dėl jo naudojimo įprastomis dozėmis — jis laikomas saugiu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 332504;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally occurring inorganic compound used as a preservative in a very narrow range of products — essentially just certain fish roe, like sturgeon caviar. It prevents bacterial and mold growth, extending shelf life. Its use in food is tightly restricted precisely because it is not something to take lightly — the body does not break it down easily, and it can accumulate with repeated exposure. Regulatory bodies permit it only at low levels in that one niche application, and most people will rarely if ever encounter it.', opinion_lt = 'Tai natūraliai gamtoje randamas neorganinis junginys, naudojamas kaip konservantas labai siauroje produktų grupėje — iš esmės tik tam tikruose žuvų ikruose, pavyzdžiui, eršketo ikruose. Jis slopina bakterijų ir pelėsių augimą, prailgindamas galiojimo laiką. Šios medžiagos naudojimas maiste yra griežtai ribojamas, nes organizmas jos lengvai neskaido ir ji gali kauptis reguliariai vartojant. Valdžios institucijos leidžia ją naudoti tik mažomis dozėmis toje vienoje siauroje srityje, todėl dauguma žmonių su ja praktiškai nesusiduria.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 332550;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic inorganic salt used as a preservative in a very narrow range of foods — essentially just certain fish roe products. It has a long history of use in some food traditions, but it is banned or heavily restricted in many countries, including the US, due to concerns about potential toxicity with regular consumption. In the EU it is permitted only in that single, limited category under strict conditions. It is not something most people will encounter in everyday foods.', opinion_lt = 'Tai sintetinė neorganinė druska, naudojama kaip konservantas labai siauroje maisto produktų grupėje — iš esmės tik tam tikruose žuvų ikruose. Ji turi ilgą vartojimo istoriją kai kuriose maisto kultūrose, tačiau daugelyje šalių, įskaitant JAV, yra uždrausta arba griežtai ribojama dėl galimo toksiškumo reguliariai vartojant. ES ji leidžiama tik toje vienoje, ribotoje kategorijoje ir griežtomis sąlygomis. Dauguma žmonių su šiuo priedu kasdieniame gyvenime nesusidurs.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 332597;
UPDATE aggregate.eu_additives SET opinion_en = 'This is simply carbon dioxide — the same natural gas that gives sparkling water and fizzy drinks their bubbles. It is also used to preserve packaged foods by displacing oxygen, which slows down spoilage and bacterial growth. You will find it in carbonated beverages, sparkling wine, beer, and modified-atmosphere food packaging. It is entirely natural, produced both by living organisms and industrial processes, and is one of the safest additives used in food.', opinion_lt = 'Tai paprastas anglies dioksidas — tas pats gamtinis dujas, kuris suteikia putojančiam vandeniui ir gazuotiems gėrimams burbuliukus. Jis taip pat naudojamas maisto produktams konservuoti, išstumdamas deguonį iš pakuočių ir taip sulėtindamas gendimą. Rasite jį gazuotuose gėrimuose, putojančiuose vynuose, aluje ir sandariose maisto pakuotėse. Tai visiškai natūralus junginys, vienas saugiausių maisto priedų — nėra jokios priežasties jo bijoti.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 332644;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally occurring organic acid found in apples, cherries, and many other fruits — in fact, it''s responsible for that pleasant tart bite in a crisp apple. When added to food, it works as an acidity regulator and flavour enhancer, giving products a fruity, slightly sour taste while also helping to preserve freshness. You''ll find it in fruit juices, jams, jellies, and processed fruit and vegetable products. It is generally considered safe, well-tolerated by most people, and is one of the less controversial additives on the list.', opinion_lt = 'Tai natūraliai gamtoje randama organinė rūgštis, kurios gausu obuoliuose, vyšniose ir daugelyje kitų vaisių — būtent ji suteikia obuoliui tą malonų rūgštoką skonį. Maiste ji naudojama kaip rūgštingumo reguliatorius ir skonio stipriklis, suteikiantis produktams vaisišką, lengvai rūgštelėjantį skonį ir padedantis išsaugoti šviežumą. Ją rasite vaisių sultyse, džemuose, dželė ir perdirbtų vaisių bei daržovių gaminiuose. Laikoma saugia, daugumos žmonių gerai toleruojama medžiaga — vienas ramesnių priedų ilgame E numerių sąraše.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 2894650;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally occurring organic acid found in small amounts in some plants and fungi, though the version used in food is synthetically produced. It works as an acidity regulator and flavour enhancer, giving a tart, slightly fruity sourness to products like chewing gum, flavoured drinks, desserts, and confectionery. It is also used to extend shelf life by lowering pH. Regulatory bodies including EFSA consider it safe at the levels permitted in food, and there is no significant controversy surrounding it.', opinion_lt = 'Tai organinė rūgštis, kuri gamtoje randama nedideliais kiekiais kai kuriuose augaluose ir grybuose, tačiau maistui naudojama jos sintetinė versija. Ji reguliuoja rūgštingumą ir suteikia aštrų, lengvai vaisišką rūgštelėjimą kramtomajai gumai, skoniui skirtiems gėrimams, desertams ir saldumynams. Be to, ji padeda pailginti produktų galiojimo laiką, mažindama pH. Europos maisto saugos institucija (EFSA) ir kitos reguliavimo institucijos laiko ją saugia leistinose dozėse, o didesnių kontraversijų dėl jos nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 332842;
UPDATE aggregate.eu_additives SET opinion_en = 'This is simply vitamin C — a natural antioxidant found in citrus fruits, berries, and many vegetables. It''s added to foods like frozen produce, jams, bread, and canned goods to prevent browning and slow down spoilage. It also helps preserve colour and freshness. There is nothing controversial here — it''s one of the most well-studied and widely accepted food additives, and your body uses it just like the vitamin C from an orange.', opinion_lt = 'Tai paprasčiausiai vitaminas C — natūralus antioksidantas, randamas citrusinių vaisių, uogų ir daržovių. Maiste jis naudojamas tam, kad produktai nepajuoduotų, ilgiau išliktų šviežios spalvos ir negerėtų greičiau nei reikia. Rasite jį šaldytose daržovėse, uogienėse, duonoje, konservuotuose produktuose. Jokio pavojaus čia nėra — tai vienas geriausiai ištirtų ir saugiausių maisto priedų, o jūsų organizmas jį naudoja kaip bet kokį kitą vitamino C šaltinį.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 492635;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the sodium salt form of vitamin C — a naturally derived antioxidant used to prevent food from browning, going rancid, or losing colour. You''ll find it in cured meats, frozen fish, canned vegetables, beer, and fresh pasta. It also helps the body absorb iron from food. It''s considered very safe and is essentially a form of a vitamin most people already consume daily. No significant health concerns are associated with normal dietary intake.', opinion_lt = 'Tai vitamino C natrio druskos forma — natūralios kilmės antioksidantas, kuris neleidžia maistui rudėti, tamsėti ar prarasti spalvos. Randamas vytintoje mėsoje, šaldytoje žuvyje, konservuotose daržovėse, aluje ir šviežiose makaronų gaminiuose. Be to, jis padeda organizmui geriau įsisavinti geležį. Laikomas labai saugiu — iš esmės tai vitaminas, kurį dauguma žmonių ir taip vartoja kasdien. Jokio reikšmingo pavojaus sveikatai įprastais kiekiais nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 492987;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural-origin additive — it''s simply vitamin C bound to calcium, making it both an antioxidant and a mild source of two nutrients. It prevents browning and spoilage in foods like fresh-cut vegetables, canned fruit, fish, and bread. Because it comes from vitamin C, it has a very strong safety record and is widely accepted by food regulators worldwide. Most people have no reason to be concerned about it.', opinion_lt = 'Tai natūralios kilmės priedas — iš esmės vitaminas C, sujungtas su kalciu, todėl jis veikia kaip antioksidantas ir kartu suteikia nedidelį kiekį dviejų maistinių medžiagų. Jis neleidžia pajuosti ir gesti supjaustytoms daržovėms, konservuotiems vaisiams, žuviai ir duonai. Kadangi pagrindas yra vitaminas C, šio priedo saugumas yra labai gerai pagrįstas ir pripažintas visame pasaulyje. Daugumai žmonių jis visiškai nekelia jokio rūpesčio.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 1855764;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a fat-soluble form of vitamin C, made by combining ascorbic acid with fatty acids. It works as an antioxidant, meaning it helps prevent fats and oils from going rancid and protects colour and flavour in foods like bread, oils, and some infant formulas. Because it comes from vitamin C, it is generally considered very safe and is even used in baby foods. No significant health concerns are associated with it at normal dietary levels.', opinion_lt = 'Tai riebaluose tirpstanti vitamino C forma, gauta sujungus askorbo rūgštį su riebalinėmis rūgštimis. Ji veikia kaip antioksidantas – apsaugo riebalus ir aliejus nuo apkartimo bei padeda išlaikyti maisto spalvą ir skonį duonoje, aliejuose ir kai kuriuose kūdikių mišiniuose. Kadangi šis priedas gaminamas iš vitamino C, jis laikomas visiškai saugiu ir netgi naudojamas kūdikių maiste. Esant įprastam vartojimo kiekiui, jokių žinomu sveikatos problemų su juo nesiejama.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 333847;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural antioxidant derived from vegetable oils, essentially a concentrated form of vitamin E. It is used to prevent fats and oils from going rancid, extending shelf life without synthetic chemicals. It is commonly found in edible oils, margarines, and notably in baby foods and infant formulas. Being a natural-origin additive and a recognised nutrient, it is widely considered safe and even beneficial at normal dietary levels.', opinion_lt = 'Tai natūralus antioksidantas, gaunamas iš augalinių aliejų – iš esmės tai koncentruota vitamino E forma. Jis naudojamas, kad riebalai ir aliejai neapkartų, taip prailginant produktų galiojimo laiką be sintetinių priedų. Dažniausiai randamas valgomajame aliejuje, margarinuose ir kūdikių maiste bei mišiniuose. Kadangi tai natūralios kilmės priedas ir pripažinta maistinė medžiaga, jis laikomas saugiu ir net naudingas įprastais kiekiais.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 334020;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic form of vitamin E, an antioxidant that prevents fats and oils from going rancid. It''s found in cooking oils, baby formulas, and processed cereals, where it protects the product''s quality and shelf life. Because it''s essentially vitamin E, your body treats it just like the natural version found in nuts and seeds. It''s widely regarded as safe and even beneficial at typical food levels.', opinion_lt = 'Tai sintetinė vitamino E forma – antioksidantas, kuris apsaugo riebalus ir aliejus nuo apkartimo. Randamas maistiniuose aliejuose, kūdikių mišiniuose ir perdirbtose javainių kruopelėse – tiesiog padeda produktui išlikti šviežiam ilgiau. Kadangi tai iš esmės yra vitaminas E, organizmas jį priima kaip ir natūralų, gaunamą iš riešutų ar sėklų. Laikomas saugiu ir net naudingas įprastais kiekiais maiste.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 334119;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic form of vitamin E, a natural antioxidant that your body actually needs. It''s used in fats, oils, and baby foods to prevent them from going rancid — essentially slowing down the oxidation that makes oils taste bad and lose nutritional value. The naturally occurring version is found in many vegetable oils and nuts. The synthetic form works the same way but is considered slightly less potent than the natural alpha-tocopherol form. It''s widely regarded as safe, and its use in infant products is tightly regulated.', opinion_lt = 'Tai sintetinė vitamino E forma — natūralus antioksidantas, kurio mūsų organizmui tikrai reikia. Maiste jis naudojamas tam, kad riebalai ir aliejai nesiteptų ir neprarūgtų — kitaip tariant, jis sulėtina oksidaciją, dėl kurios aliejus tampa nemalonus ir nebevertingas mitybos požiūriu. Natūrali šio junginio forma randama daugelyje augalinių aliejų ir riešutų. Laikomas saugiu, o jo naudojimas kūdikių maiste yra griežtai reglamentuotas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 334223;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally occurring form of vitamin E, found in various plant oils and foods. It acts as an antioxidant, meaning it helps prevent fats and oils from going rancid and protects the nutritional quality of food during storage. You''ll find it in edible oils, fats, and notably in baby foods and infant formulas. It is generally considered safe and even beneficial, since vitamin E is an essential nutrient the body needs.', opinion_lt = 'Tai natūraliai augaluose randama vitamino E forma, veikianti kaip antioksidantas — ji apsaugo riebalus ir aliejus nuo gedimo bei padeda išsaugoti maisto kokybę laikymo metu. Šio priedo galima rasti valgomajame aliejuje, riebaluose ir ypač kūdikių bei mažų vaikų maiste ir mišiniuose. Laikomas saugiu ir netgi naudingas, nes vitaminas E yra būtina maistinė medžiaga, reikalinga organizmui.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 334322;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic antioxidant used to prevent fats and oils from going rancid. It''s found in products like chewing gum, vegetable oils, and some processed foods with high fat content. It''s only authorised in a very limited number of food categories, which reflects a cautious regulatory approach. Some animal studies have raised questions about its safety at high doses, though the amounts used in food are considered low and generally safe by European food authorities.', opinion_lt = 'Tai sintetinis antioksidantas, naudojamas tam, kad riebalai ir aliejai nesutepkėtų. Jį galima rasti kramtomojoje gumoje, augaliniuose aliejuose ir kai kuriuose perdirbtų produktuose su dideliu riebalų kiekiu. Jis leidžiamas tik labai nedaugelyje maisto kategorijų, o tai rodo atsargų reguliavimo požiūrį. Kai kurie gyvūnų tyrimai kėlė klausimų dėl saugos didelėmis dozėmis, tačiau maiste naudojami kiekiai laikomi mažais ir Europos maisto saugos institucijų vertinami kaip iš esmės saugūs.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 334421;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic antioxidant that was used to prevent fats and oils from going rancid, helping extend the shelf life of fatty foods. It has since been removed from the approved list of food additives in the European Union, meaning it can no longer legally be used in EU food products. Its removal reflects growing regulatory caution rather than a proven crisis, but consumers in the EU do not need to worry about encountering it in compliant products.', opinion_lt = 'Tai sintetinis antioksidantas, kuris anksčiau buvo naudojamas, kad riebalai ir aliejai neapkartų, taip pailginant riebių maisto produktų galiojimo laiką. Europos Sąjungoje šis priedas buvo pašalintas iš leistinų maisto priedų sąrašo, todėl jo nebegalima teisėtai naudoti ES maisto produktuose. Pašalinimas atspindi didėjantį reguliavimo atsargumą, o ne įrodytą pavojų, tačiau ES vartotojai, perkantys taisykles atitinkančius produktus, su šiuo priedu nesusidurs.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 334822;
UPDATE aggregate.eu_additives SET opinion_en = 'This was a synthetic antioxidant once used to prevent fats and oils from going rancid in food products. It has since been removed from the approved list of food additives in the European Union, meaning it can no longer be legally used in EU food products. Its removal suggests that safety or necessity concerns outweighed its usefulness.', opinion_lt = 'Tai buvo sintetinis antioksidantas, kuris anksčiau naudotas tam, kad riebalai ir aliejai maiste ilgiau nesugeitų. Europos Sąjungoje jis buvo išbrauktas iš leistinų maisto priedų sąrašo, todėl dabar jo negalima naudoti ES maisto produktuose. Tai rodo, kad saugumo ar kiti klausimai lėmė jo pašalinimą iš rinkos.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 334872;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic antioxidant closely related to vitamin C, though it has no vitamin activity itself. It is mainly used in meat and fish products to prevent colour loss and slow down oxidation, keeping food looking fresh for longer. It is generally considered safe and is widely approved by food authorities around the world. Most people have no reason to be concerned about it.', opinion_lt = 'Tai sintetinis antioksidantas, labai panašus į vitamino C struktūrą, tačiau paties vitamino funkcijų neatliekantis. Dažniausiai naudojamas mėsos ir žuvies produktuose – apsaugo nuo spalvos pokyčių ir lėtina oksidaciją, kad maistas ilgiau atrodytų šviežias. Laikomas saugiu ir plačiai patvirtintas maisto saugos institucijų visame pasaulyje. Paprastam vartotojui didelių priežasčių nerimauti nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 334922;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic antioxidant closely related to vitamin C, though it has no vitamin activity itself. It is mainly used in meat and fish products to prevent colour loss and slow down oxidation, keeping food looking fresh for longer. It is also used alongside nitrites in cured meats to speed up their curing process. It is generally considered safe and well-tolerated, with no significant health concerns flagged by major food safety authorities.', opinion_lt = 'Tai sintetinis antioksidantas, artimas vitamino C struktūrai, nors pats jokios vitamininės vertės neturi. Dažniausiai naudojamas mėsos ir žuvies gaminiuose, kad išsaugotų spalvą ir sulėtintų oksidaciją – produktai ilgiau atrodo šviežiai. Rūkytoje ir vytintoje mėsoje jis taip pat padeda pagreitinti brandinimo procesą kartu su nitritais. Pagrindinės maisto saugos institucijos šį priedą laiko saugiu ir nesukelia didelių sveikatos rūpesčių.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 335030;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic antioxidant used to prevent fats and oils from going rancid, extending the shelf life of processed foods. You''ll find it in things like crackers, microwave popcorn, frozen foods, and fast food packaging. It''s approved for use at low levels by food safety authorities in many countries, though it''s only permitted in a very limited range of food categories in the EU. Some consumer groups have raised concerns about it at high doses in animal studies, but the amounts found in food are well below levels considered harmful.', opinion_lt = 'Tai sintetinis antioksidantas, naudojamas tam, kad riebalai ir aliejai nesutepkintų — taip prailginamas perdirbto maisto galiojimo laikas. Galima jį rasti krekerių, užšaldytų patiekalų ar greitojo maisto sudėtyje. ES jis leidžiamas tik labai nedaugelyje maisto kategorijų. Gyvūnų tyrimai didelėmis dozėmis kėlė tam tikrų klausimų, tačiau maiste jo kiekiai yra kur kas mažesni ir laikomi saugiais.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 335138;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic antioxidant used to prevent fats and oils from going rancid, extending the shelf life of food. You''ll find it in things like crisps, baked goods, chewing gum, and some meat products, though it''s authorised in very few food categories in the EU. There is ongoing debate about its safety — some animal studies have raised concerns about potential carcinogenicity at high doses, and it is listed as a possible human carcinogen by some health organisations. The doses found in food are far lower than those used in animal studies, but many consumers and manufacturers choose to avoid it out of caution.', opinion_lt = 'Tai sintetinis antioksidantas, naudojamas tam, kad riebalai ir aliejai nesuteptų ir maistas ilgiau išsilaikytų. Jį galima rasti traškučiuose, kepiniuose, kramtomojoje gumoje ir kai kuriuose mėsos produktuose, nors ES jis leidžiamas tik labai nedaugelyje maisto kategorijų. Kyla tam tikrų diskusijų dėl jo saugumo — kai kurie tyrimai su gyvūnais didelėmis dozėmis parodė galimą kancerogeninį poveikį, o kai kurios sveikatos organizacijos jį laiko galimai pavojingu žmonėms. Maiste esančios dozės yra daug mažesnės nei naudotos tuose tyrimuose, tačiau daugelis vartotojų ir gamintojų vengia jo iš atsargumo.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 335188;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic antioxidant used to prevent fats and oils from going rancid, extending shelf life in products like margarine, cooking oils, and some spreads. It stops the oxidation process that makes fats smell and taste bad. In the EU it is approved for a very limited number of food categories, which means your exposure through food is generally low. Some animal studies at high doses have raised questions about potential health effects, but regulatory bodies like EFSA consider it safe at the levels found in food.', opinion_lt = 'Tai sintetinis antioksidantas, kuris neleidžia riebalams ir aliejams tapti apkartusiems, taip prailginant tokių produktų kaip margarinas ar aliejiniai tepiniai galiojimo laiką. Jis stabdo oksidacijos procesą, dėl kurio riebalai įgauna nemalonų skonį ir kvapą. ES šis priedas leidžiamas tik labai nedaugelyje maisto kategorijų, todėl jo poveikis paprastai būna minimalus. Kai kurie tyrimai su gyvūnais didelėmis dozėmis kėlė klausimų dėl galimo poveikio sveikatai, tačiau tokios institucijos kaip EFSA laiko jį saugiu tomis koncentracijomis, kurios randamos maiste.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 335238;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural emulsifier, most commonly derived from soybeans or sunflower seeds, though it can also come from egg yolks. It helps fat and water mix together smoothly, which is why it''s widely used in chocolate, baked goods, margarine, and infant formula. It''s one of the most well-studied and widely accepted food additives in the world. Regulatory bodies globally consider it safe for all age groups, including babies. People with soy allergies should check the source, but the highly processed form typically doesn''t trigger reactions.', opinion_lt = 'Tai natūralus emulgatorius, dažniausiai gaunamas iš sojos pupelių arba saulėgrąžų sėklų, nors kartais išgaunamas ir iš kiaušinių trynių. Jis padeda riebalams ir vandeniui susilierti į vienodą masę — todėl jo gausu šokolade, kepiniuose, margarinuose ir net kūdikių mišiniuose. Tai vienas geriausiai ištirtų ir plačiausiai priimtų maisto priedų pasaulyje. Žmonės, turintys sojos alergiją, turėtų pasitikrinti kilmę, tačiau stipriai perdirbta forma dažniausiai alergijos nesukelia.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 335298;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural emulsifier derived from oats, used to help fat and water mix smoothly in food — most commonly in chocolate products. It keeps chocolate from becoming grainy or separating, giving it that silky texture. It is a plant-based alternative to the more common soy or egg lecithin, making it suitable for people avoiding those ingredients. Generally considered safe and well-tolerated.', opinion_lt = 'Tai natūralus emulgatorius, gaunamas iš avižų — jis padeda sujungti riebalus ir vandenį į vienalytę masę. Dažniausiai naudojamas šokolado gamyboje, kad šokoladas būtų švelnus ir nelūžinėtų. Tai augalinės kilmės alternatyva sojos ar kiaušinių lecitinui, tinkanti tiems, kas vengia tų ingredientų. Laikomas saugiu ir gerai toleruojamu priedu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 366334;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the sodium salt of lactic acid — a naturally occurring acid produced during fermentation, found in yogurt, sauerkraut, and other fermented foods. In processed products it acts mainly as a preservative and acidity regulator, helping extend shelf life and keep moisture balanced. You''ll find it in bread, canned vegetables, and meat preparations. It''s generally considered safe and well-tolerated by most people, with no significant controversy surrounding it.', opinion_lt = 'Tai natrio druska pieno rūgšties — natūraliai fermentacijos metu atsirandančios rūgšties, randamos jogurte, raugintame kopūste ir kituose fermentuotuose produktuose. Maisto pramonėje ji naudojama kaip konservantas ir rūgštingumo reguliatorius — padeda ilgiau išlaikyti šviežumą ir subalansuoti drėgmę. Sutiksite ją duonoje, konservuotose daržovėse ir mėsos gaminiuose. Laikoma saugia ir gerai toleruojama — jokios rimtesnės diskusijos dėl šio priedo nekyla.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 335475;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the potassium salt of lactic acid — a naturally occurring acid found in fermented foods like yogurt and sauerkraut. It works as a preservative and acidity regulator, helping extend shelf life in products like bread, canned vegetables, and meat preparations. It also helps retain moisture in processed meats. It is considered safe by major food safety authorities, with no significant controversies. People on a low-potassium diet (for example, those with kidney disease) may want to be mindful of their total potassium intake from multiple sources.', opinion_lt = 'Tai pieno rūgšties kalio druska — natūraliai fermentuotuose produktuose, pavyzdžiui, jogurte ar raugintose kopūstuose, randamas junginys. Maiste jis naudojamas kaip konservantas ir rūgštingumo reguliatorius: pratęsia galiojimo laiką duonoje, konservuotose daržovėse bei mėsos gaminiuose, taip pat padeda išlaikyti drėgmę. Pagrindinės maisto saugos institucijos laiko jį saugiu, o didesnių kontraversijų dėl jo nėra. Žmonėms, kurie dėl inkstų ligų turi riboti kalio kiekį, verta atkreipti dėmesį į bendrą kalio suvartojimą iš įvairių šaltinių.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 335583;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the calcium salt of lactic acid — a naturally occurring acid found in fermented foods like yogurt and cheese. It works as an acidity regulator and firming agent, helping fruits and vegetables keep their texture in canned goods, and it also acts as a dough conditioner in bread. It''s also a source of calcium. You''ll find it in jams, canned vegetables, bread, and even baby foods. It''s widely considered safe and is approved for use in many sensitive food categories, including products for infants.', opinion_lt = 'Tai pieno rūgšties kalcio druska — natūraliai fermentuotuose maisto produktuose, pavyzdžiui, jogurte ar sūryje, randamas junginys. Maiste jis naudojamas kaip rūgštingumą reguliuojanti ir tekstūrą palaikanti medžiaga: padeda vaisiams ir daržovėms išlaikyti tvirtumą konservuose, taip pat pagerina duonos tešlą. Be to, tai papildomas kalcio šaltinis. Rasite jį džemuose, konservuotuose daržovių produktuose, duonoje ir net kūdikių maiste. Laikomas saugiu ir patvirtintas net jautrioms maisto kategorijoms.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 335691;
UPDATE aggregate.eu_additives SET opinion_en = 'This is citric acid — a completely natural substance found abundantly in lemons, limes, and other citrus fruits. It''s used in food to add a pleasantly sour taste, preserve freshness, and prevent discolouration. You''ll find it in jams, soft drinks, canned vegetables, dairy products, pasta, and countless other everyday foods. It''s one of the safest and most well-understood additives out there — your own body produces it naturally as part of normal metabolism. No serious health concerns are associated with normal dietary intake, though in very large amounts it can irritate tooth enamel, like any acidic substance.', opinion_lt = 'Tai citrinų rūgštis — visiškai natūrali medžiaga, kurios gausu citrinose, laimeose ir kituose citrusinių šeimos vaisiuose. Maiste ji naudojama suteikti malonų rūgštoką skonį, pailginti galiojimo laiką ir apsaugoti produktus nuo patamsėjimo. Rasite ją uogienėse, gaivuosiuose gėrimuose, konservuotose daržovėse, pieno produktuose, makaronuose ir daugybėje kitų kasdienių produktų. Tai vienas saugiausių ir geriausiai ištirtų maisto priedų — jūsų paties organizmas ją gamina natūraliai. Rimtų grėsmių sveikatai nenustatyta, tik labai dideliais kiekiais, kaip ir bet kuri rūgštis, ji gali šiek tiek ardyti dantų emalį.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 335851;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the sodium salt of citric acid — a naturally derived compound originally found in citrus fruits, though the version used in food is typically produced through fermentation. It works as an acidity regulator, emulsifier, and preservative, helping foods maintain stable texture, flavor, and shelf life. You''ll find it in dairy products, jams, canned vegetables, seafood, and processed foods.

It is widely considered safe and is approved across a very large number of food categories. The body processes it just like regular citric acid. There is no significant controversy around this additive — most health authorities regard it as one of the more benign options in the food additive toolkit.', opinion_lt = 'Tai natrio druska, gauta iš citrinos rūgšties — natūraliai aptinkamos citrusinių vaisių sudėtyje, nors maisto pramonėje naudojama versija paprastai gaminama fermentacijos būdu. Ji reguliuoja rūgštingumą, padeda emulguoti ir konservuoti, todėl maistas išlaiko tekstūrą, skonį ir ilgesnį galiojimo laiką. Randama pieno produktuose, dželė, konservuotose daržovėse, jūros gėrybėse ir perdirbtame maiste.

Laikoma saugia — patvirtinta labai daugelyje maisto kategorijų visame pasaulyje. Organizmas ją perdirba kaip įprastą citrinos rūgštį. Jokių rimtų kontraversijų aplink šį priedą nėra — dauguma sveikatos institucijų jį laiko vienu nekenksmingesnių maisto priedų.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 336277;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the potassium salt of citric acid, a naturally derived compound originally found in citrus fruits. It works as an acidity regulator and stabiliser, helping to control pH, prevent spoilage, and improve texture in a wide range of foods — from canned vegetables and frozen fruit to infant formula and dairy products. It also adds a small amount of potassium, which is an essential mineral. It is widely considered safe and is approved for use even in baby food, which is a good indicator of its low-risk profile.', opinion_lt = 'Tai natūralios kilmės medžiaga — citrusinių vaisių citrinos rūgšties kalio druska. Maiste ji naudojama kaip rūgštingumo reguliatorius ir stabilizatorius: padeda palaikyti tinkamą pH, ilgina galiojimo laiką ir pagerina tekstūrą. Randama konservuotose daržovėse, šaldytuose vaisiuose, pieno produktuose ir net kūdikių mišiniuose. Laikoma saugia — tai, kad ji leidžiama kūdikių maiste, gerai parodo, kad kalbama apie mažos rizikos priedą.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 336624;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the calcium salt of citric acid — a naturally derived compound found in citrus fruits. It serves multiple roles in food: as an acidity regulator, stabiliser, and firming agent, helping foods maintain texture and freshness. You''ll find it in jams, canned or frozen fruits and vegetables, fish products, and spreads. It also contributes a small amount of dietary calcium. This additive is widely considered safe by food safety authorities worldwide, with no notable health concerns for the general population. It''s one of the more reassuring additives you might spot on a label.', opinion_lt = 'Tai citrinų rūgšties kalcio druska — natūralios kilmės junginys, gaunamas iš citrusinių vaisių. Maiste jis atlieka kelis vaidmenis: reguliuoja rūgštingumą, stabilizuoja ir padeda išlaikyti tekstūrą bei šviežumą. Rasite jį džemuose, konservuotuose ar šaldytuose vaisiuose ir daržovėse, žuvies produktuose bei tepuose. Be to, jis suteikia šiek tiek kalcio organizmui. Pasaulinės maisto saugos institucijos šį priedą laiko saugiu — jokių rimtų sveikatos problemų su juo nesiejama. Tai vienas iš tų priedų etiketėje, kurių tikrai nereikia bijoti.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 336880;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally occurring organic acid found in grapes, tamarind, and other fruits. It''s used as an acidulant — meaning it adds a tart, sour taste and helps regulate acidity in foods. You''ll find it in chocolate products, canned fruits, pasta, gnocchi, and even tabletop sweetener tablets. It also acts as an antioxidant, helping to preserve freshness and prevent discoloration. It''s generally considered safe and well-tolerated by most people, though very large amounts could cause digestive discomfort — something you''re extremely unlikely to encounter from normal food consumption.', opinion_lt = 'Tai natūraliai gamtoje randama organinė rūgštis, aptinkama vynuogėse, tamarinde ir kituose vaisiuose. Maiste ji naudojama kaip rūgštiklis — suteikia aštrų, rūgštoką skonį ir padeda palaikyti tinkamą rūgštingumą. Rasite ją šokolado gaminiuose, konservuotuose vaisiuose, makaronuose, gnocchi ir net saldintuvo tabletėse. Ji taip pat veikia kaip antioksidantas, padedantis išsaugoti šviežumą. Paprastai laikoma saugia ir gerai toleruojama — nebent vartotumėte labai dideli kiekius, o tai kasdieniniame maiste beveik neįmanoma.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 2447429;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the sodium salt of tartaric acid, a naturally occurring acid found in grapes and wine. It acts as an acidity regulator and stabiliser, helping to maintain the right texture and taste balance in processed foods. You''ll find it in canned or bottled fruits and vegetables, as well as some baby foods and cereal-based products for infants. It has a limited number of approved uses compared to many other additives, which reflects a cautious regulatory approach, especially given its presence in foods for young children. It is generally considered safe at the levels permitted in food.', opinion_lt = 'Tai natrio druska, gauta iš vynomedžių rūgšties — natūralaus junginio, randamo vynuogėse ir vyne. Maiste ji naudojama kaip rūgštingumo reguliatorius ir stabilizatorius, padedantis išlaikyti tinkamą tekstūrą ir skonio balansą konservuotuose produktuose. Šį priedą galima rasti konservuotuose vaisiuose ir daržovėse, taip pat kai kuriuose kūdikių maisto produktuose. Tai, kad jis patvirtintas tik keliose maisto kategorijose, rodo atsargų reguliavimo požiūrį — ypač kalbant apie maistą mažiems vaikams. Bendrai laikoma, kad leidžiamomis dozėmis šis priedas yra saugus.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 337301;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally derived salt of tartaric acid, which itself comes from grapes and winemaking byproducts. It acts as an acidity regulator and stabiliser, helping to control pH and improve texture in certain foods. You''ll find it in preserved fruits and vegetables, tabletop sweeteners, and some baby foods. It has a long history of safe use and is not considered controversial — regulatory bodies worldwide regard it as safe at the levels used in food.', opinion_lt = 'Tai natūralios kilmės druska, gauta iš vynomedžių rūgšties — šalutinio vyno gamybos produkto. Ji naudojama kaip rūgštingumo reguliatorius ir stabilizatorius: padeda palaikyti tinkamą pH lygį ir gerinti tekstūrą. Tokį priedą galima rasti konservuotuose vaisiuose ir daržovėse, stalo saldintuose bei kai kuriuose kūdikių maisto produktuose. Jis laikomas saugiu — nėra jokių reikšmingų ginčų ar nerimą keliančių tyrimų, susijusių su šiuo priedu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 337400;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a salt derived from tartaric acid, a natural acid found in grapes and other fruits. It acts as a stabilizer and acidity regulator, helping to maintain texture and flavor in preserved foods. You will mainly find it in canned or bottled fruits and vegetables, where it is used in small amounts. It has a long history of safe use and is not considered a concern for most people.', opinion_lt = 'Tai druska, gauta iš vynoakmenio rūgšties – natūralios rūgšties, randamos vynuogėse ir kituose vaisiuose. Ji naudojama kaip stabilizatorius ir rūgštingumo reguliatorius, padedantis išsaugoti konservuotų produktų tekstūrą ir skonį. Dažniausiai randama konservuotuose vaisiuose ir daržovėse, kur jos dedama nedaug. Turi ilgą saugaus naudojimo istoriją ir daugumai žmonių nekelia jokio susirūpinimo.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 337499;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic acid used to give foods and drinks a sharp, tangy taste — it''s the reason cola drinks have that distinctive bite. It also acts as an acidity regulator, helping control pH and extend shelf life. You''ll find it mostly in carbonated soft drinks, but it''s also permitted in some infant and follow-on formulas at strictly controlled levels. There is ongoing debate among researchers about whether high consumption may affect calcium absorption and bone density over time, so moderation — especially for children — is sensible.', opinion_lt = 'Tai sintetinė rūgštis, naudojama suteikti maistui ir gėrimams aštrų, gaivų skonį — būtent ji atsakinga už charakteringą kolos skonį. Ji taip pat reguliuoja rūgštingumą ir prailgina produktų galiojimo laiką. Dažniausiai randama gazuotuose gėrimuose, tačiau tam tikrais griežtai kontroliuojamais kiekiais leidžiama ir kai kuriuose kūdikių bei mažų vaikų maisto produktuose. Mokslininkai diskutuoja, ar didelės šios medžiagos dozės gali paveikti kalcio įsisavinimą ir kaulų tankį, todėl saikingumas — ypač vaikams — yra protingas pasirinkimas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 337546;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic salt derived from phosphoric acid, used mainly as an acidity regulator, emulsifier, and stabiliser. You''ll find it in processed meats, dairy drinks, infant formulas, and cereal-based baby foods, where it helps maintain texture and shelf life. Phosphates are naturally present in many foods anyway, so small amounts from additives are generally considered safe. However, people with kidney disease are often advised to watch their total phosphate intake, as the kidneys regulate phosphate levels in the body.', opinion_lt = 'Tai sintetinė druska, pagaminta iš fosforo rūgšties — naudojama kaip rūgštingumo reguliatorius, emulsiklis ir stabilizatorius. Ją rasite perdirbtos mėsos produktuose, pieno gėrimuose, kūdikių mišiniuose ir grūdų pagrindu pagamintuose kūdikių maisto produktuose. Fosfatų natūraliai yra daugelyje maisto produktų, todėl nedideli kiekiai iš priedų paprastai laikomi saugiais. Vis dėlto žmonėms, turintiems inkstų problemų, rekomenduojama stebėti bendrą fosfatų kiekį maiste, nes inkstai yra atsakingi už jų reguliavimą organizme.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 338791;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a group of synthetic salts used mainly as acidity regulators and stabilisers — they help control pH, prevent clumping, and keep texture consistent in processed foods. You''ll find them in infant formula, baby cereals, processed cheeses, and some dairy drinks. They also provide a small amount of potassium and phosphorus, which are essential minerals. For most healthy people, the amounts used in food are considered safe by European food authorities. However, people with kidney disease are often advised to watch their phosphate intake from all sources, including food additives.', opinion_lt = 'Tai sintetinės druskos, naudojamos kaip rūgštingumo reguliatoriai ir stabilizatoriai — jos padeda palaikyti tinkamą pH, neleidžia produktui sukepti ir išlaiko vienodą tekstūrą. Randamos kūdikių mišiniuose, kūdikių kruopelių produktuose, lydytame sūryje ir kai kuriuose pieno gėrimuose. Be to, suteikia nedidelį kiekį kalio ir fosforo — svarbių mineralų organizmui. Sveikiems žmonėms tokiais kiekiais, kokie naudojami maiste, laikoma saugia priedų grupe. Tačiau sergantys inkstų ligomis turėtų atkreipti dėmesį į bendrą fosfatų kiekį maiste, įskaitant ir priedus.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 338944;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a calcium salt of phosphoric acid — a mineral compound used mainly as an anti-caking agent, acidity regulator, or calcium supplement in food. It appears naturally in bones and dairy, but the food-grade version is synthetically produced. It is most commonly found in infant formulas, follow-on formulas, and processed cereal-based baby foods, where it serves both a functional and nutritional role by boosting calcium content. It is generally considered safe, and regulatory bodies including EFSA have evaluated it as appropriate for use even in products for infants.', opinion_lt = 'Tai kalcio druska, gauta iš fosforo rūgšties — mineralinis junginys, naudojamas kaip sukietėjimo prevencijos priemonė, rūgštingumo reguliatorius arba kalcio šaltinis maiste. Natūraliai jis randamas kauluose ir pieno produktuose, tačiau maisto pramonėje naudojama sintetiškai pagaminta forma. Dažniausiai sutinkamas kūdikių mišiniuose, tolesnio maitinimo formulėse ir grūdų pagrindu pagamintuose kūdikių maisto produktuose — čia jis atlieka ir technologinę, ir mitybinę funkciją, padėdamas padidinti kalcio kiekį. Laikomas saugiu, o tokios institucijos kaip EFSA jį įvertino kaip tinkamą naudoti net kūdikiams skirtuose produktuose.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 362202;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a mineral salt derived from calcium and phosphoric acid, used mainly as an anti-caking agent, leavening agent, or acidity regulator. It helps powdered products stay free-flowing and gives baked goods a better rise. You''ll find it in powdered sweeteners, baby cereals, and some baked products. It''s considered safe and actually contributes calcium and phosphorus — nutrients your body needs anyway. No significant safety concerns are associated with normal dietary exposure.', opinion_lt = 'Tai mineralinė druska, gauta iš kalcio ir fosforo rūgšties — naudojama kaip sukietėjimą stabdanti medžiaga, rauginimo agentas arba rūgštingumo reguliatorius. Ji padeda milteliniams produktams likti biriems ir pagerina kepinių kilimą. Randama milteliniuose saldintuose, kūdikių dribsniuose ir kai kuriuose kepiniuose. Laikoma saugia, be to, suteikia organizmui kalcio ir fosforo — elementų, kurių ir taip mums reikia. Esant įprastam suvartojimui, jokio žymesnio pavojaus sveikatai nenustatyta.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 339071;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a mineral salt made from magnesium and phosphoric acid. It works mainly as an anti-caking agent, keeping powdered and granulated foods from clumping together. It is only permitted in a very limited range of food products. Both magnesium and phosphates are naturally found in the body and in many foods, so this additive is generally considered safe at the low levels used in food.', opinion_lt = 'Tai mineralinė druska, gauta iš magnio ir fosforo rūgšties. Daugiausia naudojama kaip sukepimo inhibitorius — neleidžia milteliams ar granuliuotiems produktams sulipti. Leidžiama tik labai ribotame skaičiuje maisto produktų kategorijų. Kadangi ir magnis, ir fosfatai natūraliai randami žmogaus organizme bei daugelyje maisto produktų, šis priedas laikomas saugiu tokiais kiekiais, kokie naudojami maiste.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 339161;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a magnesium salt of citric acid, used in food supplements to deliver magnesium to the body. It is synthetic but made from natural-origin components. It acts as a source of mineral nutrition rather than a preservative or flavour agent. Generally considered safe when used as directed in supplement doses.', opinion_lt = 'Tai magnio druska, gauta iš citrinų rūgšties, naudojama maisto papilduose kaip magnio šaltinis. Nors sintetinė, pagaminta iš natūralios kilmės medžiagų. Ji neatlieka konservanto ar skonio stipriklio funkcijos – tiesiog tiekia organizmui magnį. Laikoma saugia, kai vartojama rekomenduojamomis dozėmis.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 1754010;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the sodium salt of malic acid, a naturally occurring acid found in apples and many other fruits. It works as an acidity regulator and humectant — helping to control tartness and keep foods from drying out. You''ll mostly find it in jams, jellies, and fruit spreads. It is considered safe by European food authorities and raises no significant health concerns for the general population.', opinion_lt = 'Tai natrio druska obuolių rūgšties, kuri natūraliai randama obuoliuose ir daugelyje kitų vaisių. Maiste ji naudojama kaip rūgštingumą reguliuojanti ir drėgmę išlaikanti medžiaga — padeda subalansuoti rūgštumą ir neleidžia produktui išdžiūti. Dažniausiai sutinkama džemuose, dželė ir vaisių pastuose. Europos maisto saugos institucijos laiko ją saugia, ir rimtesnio susirūpinimo sveikatai ji nekelia.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 339207;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the potassium salt of malic acid, a naturally occurring acid found in apples and many other fruits. It works as an acidity regulator, helping to balance and stabilise the pH in food products. It is authorised in very few food categories, so you won''t encounter it often. It is generally considered safe, with no significant concerns raised by major food safety authorities.', opinion_lt = 'Tai yra obuolių ir daugelyje kitų vaisių natūraliai randamos obuolių rūgšties kalio druska. Maiste ji naudojama kaip rūgštingumo reguliatorius — padeda palaikyti stabilų pH. Leidžiama naudoti labai nedaug maisto kategorijų, tad su šiuo priedu susidursite retai. Pagrindinės maisto saugos institucijos neišreiškė jokių reikšmingų susirūpinimų dėl jo saugumo.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 339280;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the calcium salt of malic acid — a naturally occurring acid found in apples and many other fruits. It works as an acidity regulator, helping to balance and stabilise the taste of food products. It appears in very few food categories, meaning most people encounter it rarely. It is generally considered safe, with no significant health concerns associated with normal dietary intake.', opinion_lt = 'Tai obuoliuose ir daugelyje kitų vaisių natūraliai randamos obuolių rūgšties kalcio druska. Ji naudojama kaip rūgštingumo reguliatorius — padeda išlaikyti tinkamą skonio balansą maisto produktuose. Leidžiama tik labai nedaug maisto kategorijų, todėl dauguma žmonių su ja susiduria retai. Laikoma saugia, ir esant įprastam suvartojimui jokių rimtų sveikatos rizikų nenustatyta.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 339326;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic acid used in winemaking to prevent the formation of tartrate crystals — those harmless but visually unappealing deposits that can appear in wine. It works by temporarily stabilising the wine, though its effect fades over time, so it is mainly used in wines meant for early consumption. It is authorised in a very narrow range of products and is considered safe at the levels used.', opinion_lt = 'Tai sintetinė rūgštis, naudojama vyno gamyboje, kad nesusidarytų tartrato kristalai — nekenksmingi, bet neišvaizdūs nuosėdos, kurios kartais atsiranda vyne. Ji laikinai stabilizuoja vyną, tačiau jos poveikis ilgainiui silpnėja, todėl daugiausia naudojama vynuose, skirtuose greitam vartojimui. Leidžiama labai siauroje produktų grupėje ir laikoma saugia naudojamais kiekiais.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 339372;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the calcium salt of tartaric acid, a natural compound found in grapes and wine. It acts as a stabiliser and acidity regulator in food, helping to maintain texture and balance sourness. It is authorised in very few food categories, meaning you rarely encounter it. It is generally considered safe with no significant health concerns associated with normal consumption.', opinion_lt = 'Tai kalcio druska, gauta iš vynomedžių rūgšties – natūralaus junginio, randamo vynuogėse ir vyne. Maiste ji naudojama kaip stabilizatorius ir rūgštingumo reguliatorius, padedantis išlaikyti tekstūrą bei subalansuoti rūgštumą. Leidžiama labai nedaug maisto kategorijų, todėl su ja susiduriate retai. Laikoma saugia – jokių reikšmingų sveikatos problemų, susijusių su įprastu vartojimu, nenustatyta.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 339432;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic organic acid used as an acidity regulator and leavening agent in food. It gives a mild, smooth tartness and helps control pH in products like powdered desserts and baking mixes. It is authorised in only a very limited range of food categories. Regulatory bodies including EFSA consider it safe at the levels used in food, and there is no significant controversy surrounding it.', opinion_lt = 'Tai sintetinė organinė rūgštis, naudojama kaip rūgštingumo reguliatorius ir kepimo priemonė maiste. Ji suteikia švelnų, malonų rūgštumą ir padeda palaikyti tinkamą pH tokiuose produktuose kaip milteliniai desertai ar kepimo mišiniai. Leidžiama tik labai ribotame maisto kategorijų skaičiuje. Europos maisto saugos institucija (EFSA) ir kitos reguliavimo įstaigos laiko ją saugia tokiomis dozėmis, kokiomis ji naudojama maiste, ir didesnio susidomėjimo ar diskusijų dėl jos nekyla.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 339479;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the sodium salt of adipic acid, used as an acidity regulator and buffering agent — it helps keep the pH of food stable. It is a synthetic additive found in very few food products, as its authorisation covers only a narrow range of categories. It is generally considered safe at the levels used in food, and regulatory bodies like EFSA have not raised significant concerns about it.', opinion_lt = 'Tai adipino rūgšties natrio druska, naudojama kaip rūgštingumo reguliatorius — ji padeda palaikyti stabilų maisto pH lygį. Tai sintetinis priedas, leidžiamas labai nedaugelyje maisto kategorijų, todėl su juo susiduriama retai. Maisto saugos institucijos, įskaitant EFSA, šio priedo nelaiko pavojingu naudojamais kiekiais.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 339636;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the potassium salt of adipic acid, used as a food additive that can act as an acidity regulator or flavour enhancer. It is synthetic but derived from adipic acid, which is also found naturally in small amounts in beets and other foods. It is authorised in very few food categories, meaning you are unlikely to encounter it often.', opinion_lt = 'Tai adipinės rūgšties kalio druska, naudojama kaip rūgštingumo reguliatorius arba skonio stipriklis maisto produktuose. Ji yra sintetinės kilmės, nors pati adipinė rūgštis natūraliai randama nedideliuose kiekiuose burokėliuose ir kituose maisto produktuose. Leidžiama naudoti labai nedaug maisto kategorijų, tad su šia medžiaga greičiausiai susidursite retai. Šiuo metu nėra rimtų saugumo susirūpinimų, susijusių su šiuo priedu, vartojamu įprastais kiekiais.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 339682;
UPDATE aggregate.eu_additives SET opinion_en = 'This is an organic acid that occurs naturally in many foods like meat, vegetables, and some fermented products. It is used mainly as an acidity regulator and flavour enhancer, giving food a mild, slightly sour or savory taste. You might find it in soups, flavoured dairy products, desserts, and drinks. It is synthetically produced for food use, though its natural form exists widely in living organisms. It is generally considered safe at the levels used in food, and there is little controversy surrounding it.', opinion_lt = 'Tai organinė rūgštis, natūraliai randama daugelyje maisto produktų — mėsoje, daržovėse, fermentuotuose produktuose. Maisto pramonėje ji naudojama kaip rūgštingumą reguliuojanti medžiaga ir skonio stipriklis, suteikiantis švelnų, lengvai rūgštelėjantį ar sotų skonį. Galite ją rasti sriubose, skoniuose pieno produktuose, desertuose ir gėrimuose. Maistui naudojama sintetinė versija, nors pati medžiaga natūraliai gausiai paplitusi gamtoje. Laikoma saugia įprastais naudojimo kiekiais, ir didelių diskusijų dėl jos nekyla.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 339728;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the ammonium salt of citric acid, used as an acidity regulator and emulsifier in a very narrow range of food products — mainly edible caseinates, which are milk-protein ingredients used in processed foods. It is synthetic but closely related to naturally occurring citric acid. It is considered safe at the low levels permitted, and its use is tightly restricted by food regulations.', opinion_lt = 'Tai citrinų rūgšties amonio druska, naudojama kaip rūgštingumo reguliatorius ir emulsiklis labai siauroje maisto produktų grupėje — daugiausia valgomajame kazeinате, kuris yra pieno baltymo ingredientas, naudojamas perdirbtuose maisto produktuose. Medžiaga yra sintetinė, tačiau artima natūraliai randamai citrinų rūgščiai. Laikoma saugia leidžiamomis nedidelėmis dozėmis, o jos naudojimas griežtai ribojamas maisto teisės aktais.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 339827;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic preservative and stabiliser used mainly to prevent food from changing colour, going rancid, or losing texture. It works by binding to metal ions that would otherwise speed up spoilage — you''ll find it in canned vegetables, fish products, sauces, and some meat products. It is generally considered safe at the levels used in food, and regulators in the EU have approved it for specific categories with strict limits. Some concerns have been raised about it potentially enhancing absorption of heavy metals in the gut, but at typical dietary doses this is not considered a meaningful risk for most people.', opinion_lt = 'Tai sintetinis konservantas ir stabilizatorius, naudojamas tam, kad maistas nekeistų spalvos, netaptų apkartęs ar neprarastų tekstūros. Jis veikia surišdamas metalo jonus, kurie kitaip pagreitintų gedimą — rasite jį konservuotose daržovėse, žuvies produktuose, padažuose ir kai kuriuose mėsos gaminiuose. ES reguliuotojai jį yra patvirtinę konkrečioms maisto kategorijoms su griežtais limitais, ir įprastais kiekiais jis laikomas saugiu. Kai kurie mokslininkai atkreipė dėmesį, kad jis gali šiek tiek sustiprinti sunkiųjų metalų įsisavinimą žarnyne, tačiau tipinėmis dietinėmis dozėmis tai nelaikoma reikšminga rizika daugumai žmonių.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 339874;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural antioxidant derived from rosemary herb, used to slow down the oxidation of fats and oils — essentially preventing rancidity and extending shelf life. You''ll find it in products like cooking oils, baked goods, processed nuts, mustard, chewing gum, and egg products. It does the same job as many synthetic preservatives, but comes straight from a plant most of us already cook with. It is widely considered safe, and there are no notable health controversies surrounding it.', opinion_lt = 'Tai natūralus antioksidantas, gautas iš rozmarino žolės — jis naudojamas tam, kad riebalai ir aliejai neapkarptų ir produktai ilgiau išliktų švieži. Rasite jį valgomajame aliejuje, kepiniuose, perdirbtuose riešutuose, garstyčiose, kramtomojoje gumoje ir kiaušinių produktuose. Jis atlieka tą patį darbą kaip ir daugelis sintetinių konservantų, tačiau gaunamas iš augalo, kurį dažnai naudojame virtuvėje. Laikomas saugiu, jokios rimtos diskusijos dėl jo nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 339986;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural substance extracted from brown seaweed, used as a thickener and stabiliser in food. It helps give products a smooth, gel-like texture and holds ingredients together. It is approved for very limited use — mainly in certain processed foods for infants and young children. It is generally considered safe, and its natural seaweed origin makes it one of the less concerning additives you might come across.', opinion_lt = 'Tai natūrali medžiaga, išgaunama iš rudųjų jūros dumblių, naudojama kaip tirštiklis ir stabilizatorius maiste. Ji padeda suteikti produktams švelnią, gelio tipo tekstūrą ir sulaiko ingredientus kartu. Leidžiama naudoti labai ribotai — daugiausia tam tikruose perdirbtų grūdų pagrindu pagamintuose maisto produktuose kūdikiams ir mažiems vaikams. Paprastai laikoma saugia, o tai, kad ji kilusi iš natūralių dumblių, daro ją vienu iš mažiau nerimą keliančių priedų.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 340464;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural substance derived from brown seaweed, used as a thickener and stabiliser in food. It helps give creamy products a smooth texture, keeps processed foods from separating, and is even used in baby foods and meat preparations. It has a long history of safe use and is not considered controversial. Most people consume it without any issues, and it is generally well tolerated.', opinion_lt = 'Tai natūralus priedas, gaunamas iš rudųjų jūros dumblių, naudojamas kaip tirštiklis ir stabilizatorius maiste. Jis padeda grietinėlei ir kitiems produktams išlikti vienodos tekstūros, neleidžia jiems sluoksniuotis. Naudojamas net kūdikių maiste ir mėsos gaminiuose. Laikomas saugiu, nekeliantis didelio susirūpinimo, ir dauguma žmonių jį toleruoja be jokių problemų.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 340579;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural substance derived from brown seaweed, used as a thickener and stabiliser to improve texture in foods like cream, meat preparations, and certain baby foods. It helps ingredients bind together and prevents separation. It is closely related to other alginates and is generally considered safe by food safety authorities. No major health concerns are associated with it at the levels used in food.', opinion_lt = 'Tai natūrali medžiaga, gaunama iš rudųjų jūros dumblių, naudojama kaip tirštiklis ir stabilizatorius – ji pagerina tekstūrą kremų, mėsos gaminių ir kai kurių kūdikių maisto produktų sudėtyje. Padeda ingredientams sulipti ir neleidžia jiems atsiskirti. Maisto saugos institucijos ją laiko saugia, o vartojamais kiekiais jokio didelio pavojaus sveikatai nenustatyta.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 340713;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural-derived thickener and stabiliser extracted from brown seaweed, then processed with ammonium compounds. It helps food hold its shape and retain moisture, and is only permitted in a very narrow range of products — essentially certain meat preparations. It is one of the least commonly encountered alginate variants in the food supply. It is generally considered safe at the levels used in food, with no significant health concerns flagged by major regulatory bodies.', opinion_lt = 'Tai natūralios kilmės tirštiklis ir stabilizatorius, gaunamas iš rudųjų jūros dumblių, apdorojant juos amonio junginiais. Maiste jis padeda išlaikyti formą ir sulaikyti drėgmę — leidžiamas tik labai siauroje produktų kategorijoje, iš esmės tam tikruose mėsos gaminiuose. Tai vienas rečiausiai sutinkamų alginatų maisto pramonėje. Tokiais kiekiais, kokiais naudojamas maiste, laikomas saugiu — didžiosios reguliavimo institucijos jokių rimtų sveikatos problemų nėra įvardijusios.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 340799;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural substance derived from brown seaweed, used as a thickener and gelling agent to improve texture and help food hold its shape. You might find it in certain meat products or processed foods for infants and young children. It is generally considered safe and is approved for use in a limited number of food categories, including some baby foods, which reflects a cautious regulatory approach. No significant health concerns are associated with it at typical dietary levels.', opinion_lt = 'Tai natūralios kilmės medžiaga, gaunama iš rudųjų jūros dumblių — naudojama kaip tirštiklis ir gelio formuotojas, kad maistas įgautų tinkamą tekstūrą ir išlaikytų formą. Galima rasti tam tikruose mėsos produktuose ar perdirbtame maiste kūdikiams ir mažiems vaikams. Laikoma saugia — tai, kad ji leista naudoti ir kūdikių maiste, rodo griežtą reguliavimą. Esant įprastoms maisto sudėties normoms, jokių rimtų sveikatos problemų su šia medžiaga nesiejama.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 340850;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier and stabiliser derived from alginic acid — a natural substance found in brown seaweed — that has been chemically modified with propylene glycol. It helps mix ingredients that would otherwise separate, like oil and water, and keeps textures smooth and consistent. You''ll find it in salad dressings, ice cream, bakery products, sauces, and even some specialised medical foods. Regulatory bodies like EFSA consider it safe at the levels used in food, though it is a processed, synthetic compound rather than a purely natural ingredient.', opinion_lt = 'Tai sintetinis emulgatorius ir stabilizatorius, pagamintas iš ruduosiuose jūros dumbliuose esančios algino rūgšties, kuri chemiškai modifikuota propilenglikoliu. Jis padeda sumaišyti aliejų ir vandenį bei išlaikyti produktų tekstūrą vienodą ir kremingą. Dažniausiai randamas salotų padažuose, ledų gaminiuose, kepiniuose, padažuose ir kai kuriuose specialios paskirties medicinos produktuose. Europos maisto saugos institucija (EFSA) jį laiko saugiu naudojamomis dozėmis, tačiau verta žinoti, kad tai chemiškai apdorotas, sintetinis ingredientas, o ne grynai natūralus.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 340923;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural gelling agent derived from red seaweed, used to thicken and stabilize foods like jams, jellies, dairy products, and spreads. It works similarly to gelatin but is completely plant-based, making it popular in vegetarian and vegan products. It has been used in food and cooking for centuries, particularly in Asian cuisine. Regulatory bodies worldwide consider it safe, and there are no notable controversies surrounding its use.', opinion_lt = 'Tai natūralus tirštiklis ir želifikatorius, gaunamas iš raudonųjų jūros dumblių. Jis naudojamas uogienėse, drebučiuose, pieno produktuose ir įvairiuose tepuose, kad suteiktų jiems tinkamą konsistenciją. Skirtingai nuo želatinos, šis ingredientas yra augalinės kilmės, todėl tinkamas vegetarams ir veganams. Jis naudojamas maiste šimtmečius, ypač Azijos virtuvėje, ir laikomas saugiu — jokių rimtų kontraversijų dėl jo nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 341231;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural thickener and gelling agent extracted from red seaweed, widely used in dairy products, processed meats, infant formulas, and desserts to improve texture and consistency. It has been approved by food safety authorities globally, but it has also attracted some scientific debate — certain animal studies suggested potential gut inflammation, though regulators maintain it is safe at typical dietary levels. If you have a sensitive digestive system, it may be worth paying attention to how your body responds to products containing it.', opinion_lt = 'Tai natūralus tirštiklis ir gelifikuojanti medžiaga, gaunama iš raudonųjų jūros dumblių. Ji plačiai naudojama pieno produktuose, perdirbtos mėsos gaminiuose, kūdikių mišiniuose ir desertuose, kad pagerintų tekstūrą ir konsistenciją. Ši medžiaga patvirtinta maisto saugos institucijų visame pasaulyje, tačiau apie ją vyksta tam tikros mokslinės diskusijos — kai kurie tyrimai su gyvūnais rodė galimą žarnyno dirginimą, nors reguliuotojai laiko ją saugia įprastais kiekiais. Jei turite jautrų virškinamąjį traktą, verta stebėti, kaip jaučiatės vartodami produktus su šiuo priedu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 341317;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural seaweed-based thickener and gelling agent, closely related to carrageenan but processed differently. It is used to improve texture and hold moisture in meat products. It is generally considered safe for most people, though some digestive sensitivity has been reported in individuals with irritable bowel conditions. Overall, it is one of the more natural options among food stabilisers.', opinion_lt = 'Tai natūralios kilmės tirštiklis ir želiavimo medžiaga, gaminama iš jūros dumblių – artima karaginanui, tik kitaip apdorota. Naudojama mėsos gaminiuose, kad pagerintų tekstūrą ir išlaikytų drėgmę. Daugumai žmonių laikoma saugia, tačiau kai kurie asmenys, turintys jautrią virškinimo sistemą, gali jausti diskomfortą. Apskritai tai vienas natūralesniųjų maisto stabilizatorių.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 341490;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural thickener and stabiliser made from the seeds of the carob tree, which grows around the Mediterranean. It helps give foods a smooth, creamy texture and prevents ingredients from separating. You''ll find it in dairy products, ice cream, jams, baby foods, and diet products. It''s also used in infant formula, which reflects how well-tolerated it generally is. Most food safety authorities consider it safe, and it even acts as a dietary fibre in the gut — a mild bonus.', opinion_lt = 'Tai natūralus tirštiklis ir stabilizatorius, gaunamas iš Viduržemio jūros regione augančio ceratonijos medžio sėklų. Jis suteikia maistui kremingą tekstūrą ir neleidžia ingredientams atsiskirti. Rasite jį pieno produktuose, ledų gamyboje, džemuose, kūdikių maiste ir dietiniuose produktuose. Maisto saugos institucijos šį priedą laiko saugiu — jis netgi veikia kaip maistinė skaidula žarnyne, todėl papildomos naudos tikrai nėra ko bijoti.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 341537;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural thickener and stabilizer derived from guar beans, a legume grown mainly in India and Pakistan. It works by absorbing water and creating a gel-like texture, making it useful in dairy products, ice cream, sauces, baked goods, and even baby foods. It is generally considered safe and well-tolerated, and some research suggests it may even have mild digestive benefits as a source of soluble fiber. No major health concerns are associated with normal dietary intake.', opinion_lt = 'Tai natūralus tirštiklis ir stabilizatorius, gaunamas iš gvaro pupelių – ankštinių augalų, auginamų daugiausia Indijoje ir Pakistane. Jis sugeria vandenį ir suteikia maistui tirštą, gelišką tekstūrą – todėl plačiai naudojamas pieno produktuose, ledų gamyboje, padažuose, kepiniuose ir net kūdikių maiste. Paprastai laikomas saugiu, gerai toleruojamu, o kai kurie tyrimai rodo, kad kaip tirpių skaidulų šaltinis jis gali teigiamai veikti virškinimą. Rimtesnių sveikatos rizikų, vartojant įprastais kiekiais, nenustatyta.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 341741;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural gum obtained from the dried sap of a thorny shrub native to the Middle East and Central Asia. It has been used for centuries as a thickener and stabiliser in food, helping to give products a smooth, consistent texture. You''ll find it in liquid and powdered tabletop sweeteners, as well as some meat preparations. It is one of the oldest food additives known and is generally considered safe for most people. Allergic reactions are rare but have been reported in some individuals.', opinion_lt = 'Tai natūralus dervas, gaunamas iš Viduriniuose Rytuose ir Centrinėje Azijoje augančio dyglėto krūmo išdžiovintos sulčių. Žmonės jį naudoja jau šimtmečius kaip tirštiklį ir stabilizatorių, suteikiantį maistui vientisą, lygią tekstūrą. Rasite jį skystose ir miltelių pavidalo saldintuose ant stalo, taip pat kai kuriuose mėsos gaminiuose. Laikomas vienu seniausių maisto priedų ir daugumą žmonių yra saugus. Alerginės reakcijos pasitaiko retai, tačiau atskiri atvejai buvo užfiksuoti.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 341958;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural gum harvested from the sap of acacia trees, making it one of the oldest food ingredients known to humans. It acts as a stabiliser, thickener, and emulsifier — keeping ingredients from separating and giving products a smooth texture. You''ll find it in chocolate, soft drinks, beer, baby foods, and tabletop sweeteners. It also acts as a prebiotic fibre, which is generally seen as a benefit for gut health. It has a long safety record and is widely considered safe even for young children and infants.', opinion_lt = 'Tai natūralus dervos išskyrimas iš akacijų medžių — vienas seniausių žmogaus naudojamų maisto ingredientų. Maiste jis naudojamas kaip stabilizatorius, tirštiklis ir emulsiklis — neleidžia ingredientams atsiskirti ir suteikia produktams švelnesnę tekstūrą. Jo galima rasti šokolade, gaivuosiuose gėrimuose, aluje, kūdikių maiste ir stalo saldintuose. Kaip prebiotinė skaidula jis papildomai naudingas žarnyno mikroflorai. Laikomas saugiu net kūdikiams ir mažiems vaikams — jo saugumas patvirtintas ilga naudojimo istorija.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 342040;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural-origin thickener and stabilizer produced by fermenting sugar with a specific type of bacteria. It gives foods a smooth, gel-like texture and prevents ingredients from separating — you''ll find it in salad dressings, gluten-free baked goods, dairy alternatives, sauces, and baby foods. It''s one of the most widely used thickeners in modern food production. It is generally considered safe and well-tolerated by most people. Those with very sensitive digestive systems may occasionally notice mild bloating, but this is uncommon at the amounts typically found in food.', opinion_lt = 'Tai natūralios kilmės tirštiklis ir stabilizatorius, gaunamas fermentuojant cukrų specialiomis bakterijomis. Jis suteikia maistui švelnią, kreminę tekstūrą ir neleidžia ingredientams atsiskirti — rasit jį salotų padažuose, be glitimo kepiniuose, pieno alternatyvose, padažuose ir kūdikių maiste. Laikomas saugiu ir gerai toleruojamu. Žmonės su jautriu virškinimo traktu kartais gali pajusti lengvą pūtimą, tačiau įprastais kiekiais maiste tai pasitaiko retai.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 342170;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural gum harvested from the sap of Sterculia trees native to India and Pakistan. It works as a thickener, stabiliser, and binding agent — helping sauces stay smooth, keeping fillings from separating, and giving chewing gum its texture. You''ll find it in desserts, snack coatings, processed nuts, and food supplements. It''s been used in food and traditional medicine for centuries. It is generally considered safe for most people, though those with known sensitivities to tree resins may occasionally experience mild digestive discomfort. Regulatory bodies including EFSA have assessed it as acceptable for use in the approved food categories.', opinion_lt = 'Tai natūralios kilmės guma, gaunama iš Sterculia medžių sakų — šie medžiai auga Indijoje ir Pakistane. Maiste ji naudojama kaip tirštiklis ir stabilizatorius: padeda padažams išlikti vienodiems, neleidžia įdarams atsiskirti, suteikia kramtomosios gumos tekstūrą. Rasite ją desertuose, užkandžių dengikliuose, perdirbtuose riešutuose ir maisto papilduose. Ji naudojama jau šimtmečius ir laikoma saugia didžiajai daliai žmonių. Tik tie, kurie jautrūs medžių sakams, kartais gali pajusti lengvą diskomfortą virškinant. Europos maisto saugos institucija (EFSA) yra įvertinusi šią medžiagą kaip tinkamą naudoti leistinose maisto kategorijose.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 342361;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural thickener and stabiliser made from the seeds of the tara plant, a tree native to South America. It works similarly to guar gum or locust bean gum, helping to give foods a smooth, consistent texture. You are unlikely to encounter it often, as it is currently approved for use in only a very limited number of food categories. It is generally considered safe and well-tolerated by most people.', opinion_lt = 'Tai natūralus tirštiklis ir stabilizatorius, gaunamas iš Pietų Amerikoje augančio taros medžio sėklų. Jis veikia panašiai kaip guarų arba saldžiavaisčių pupmedžio derva – padeda suteikti maistui vienodą, švelnią tekstūrą. Su šiuo priedu susidursite retai, nes jis leidžiamas naudoti tik labai ribotame skaičiuje maisto produktų kategorijų. Daugumai žmonių jis nesukelia jokių problemų ir laikomas saugiu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 342525;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural gum produced by bacterial fermentation, used as a gelling and thickening agent in foods. It helps create firm, smooth textures in products like jams, spreads, and liquid sweeteners. It is authorised in a relatively small number of food categories, which suggests its use is quite targeted. It is generally considered safe, with no significant health concerns raised by major food safety authorities.', opinion_lt = 'Tai natūralus tirštiklis ir gelinimo medžiaga, gaunama bakterijų fermentacijos būdu. Jis naudojamas džemuose, tepuose ir skystuose saldikliuose, kad suteiktų produktams tvirtą, vienodą tekstūrą. Leidžiamas tik keliose maisto kategorijose, todėl jo naudojimas gana ribotas. Pagrindinės maisto saugos institucijos šiai medžiagai rimtų sveikatos priekaištų nereiškia – ji laikoma saugia.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 342571;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a sugar alcohol that occurs naturally in some fruits like apples and pears, though the version used in food is usually made from glucose. It works as a sweetener and humectant — meaning it helps food retain moisture and stay soft. You''ll find it in sugar-free gum, diabetic-friendly sweets, and some baked goods. It provides fewer calories than regular sugar and doesn''t spike blood sugar as sharply, which is why it''s popular in low-sugar products. In large amounts it can cause digestive discomfort like bloating or a laxative effect, so moderation is wise.', opinion_lt = 'Tai cukraus alkoholis, natūraliai randamas kai kuriuose vaisiuose, pavyzdžiui, obuoliuose ir kriaušėse, nors maiste naudojama versija dažniausiai gaminama iš gliukozės. Jis naudojamas kaip saldintojas ir drėgmę išlaikanti medžiaga — padeda produktams išlikti minkštiems ir neišdžiūti. Dažniausiai jį rasite besukrije gumoje, diabetikams skirtuose saldainiuose ir kai kuriuose kepiniuose. Suteikia mažiau kalorijų nei įprastas cukrus ir mažiau kelia cukraus kiekį kraujyje. Tačiau vartojant dideliais kiekiais gali sukelti pilvo pūtimą ar vidurius laisvinantį poveikį, tad geriau neperžengti saiko.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 342657;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a sugar alcohol that occurs naturally in some fruits, vegetables, and fungi. It acts as a sweetener and bulking agent, and is poorly absorbed by the body, so it provides fewer calories than regular sugar. Because it is authorised only in a very limited number of food categories, it is rarely encountered in everyday products. It is generally considered safe, though consuming larger amounts can have a laxative effect.', opinion_lt = 'Tai cukraus alkoholis, natūraliai randamas kai kuriuose vaisiuose, daržovėse ir grybuose. Jis naudojamas kaip saldiklis ir užpildas, o organizmas jo beveik nepasisavina, todėl jame yra mažiau kalorijų nei įprastame cukruje. Kadangi šis priedas leidžiamas tik labai nedaugelyje maisto kategorijų, kasdienėje maisto produktuose jis pasitaiko retai. Paprastai laikomas saugiu, tačiau suvartojus didesnį kiekį gali sukelti viduriavimą.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 342707;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally occurring compound found in fats and oils, and it''s also produced synthetically for food use. It acts as a humectant — meaning it helps food retain moisture and stay soft — and it can also be used as a sweetener or thickener in small amounts. You''ll find it mainly in chocolate products and liquid tabletop sweeteners. It''s widely considered safe at the levels used in food, and your body actually produces it naturally when breaking down fats.', opinion_lt = 'Tai natūraliai riebaluose ir aliejuose randamas junginys, kuris maisto pramonėje taip pat gaminamas sintetiškai. Jis veikia kaip drėgmę išlaikanti medžiaga — neleidžia maistui išdžiūti ir išlieka minkštas — taip pat gali būti naudojamas kaip saldiklis ar tirštiklis nedideliais kiekiais. Dažniausiai jo rasite šokolado gaminiuose ir skystuose staliniuose saldintuose. Laikomas saugiu tokiais kiekiais, kokiais naudojamas maiste, be to, jūsų organizmas pats jį gamina skaidydamas riebalus.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 342757;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a modified form of gum arabic — a natural plant-based substance derived from acacia trees — that has been chemically treated to improve its ability to mix oil and water together. It acts as an emulsifier and stabiliser, helping sauces, coatings, and flavoured drinks stay smooth and well-blended instead of separating. It is found in a fairly small number of food categories, which reflects its quite specific technical use. Regulatory bodies consider it safe at the levels used in food, and there is no significant controversy surrounding it.', opinion_lt = 'Tai modifikuota gumos arabikos forma — natūralios medžiagos, gaunamos iš akacijų medžių — chemiškai apdorotos tam, kad geriau jungtų riebalus ir vandenį. Ji veikia kaip emulsiklis ir stabilizatorius, padedantis padažams, glajams ir skoniui suteiktiems gėrimams išlikti vienodos konsistencijos ir nesisluoksniuoti. Naudojama gana nedaugelyje maisto kategorijų, nes turi gana specifinę techninę paskirtį. Maisto saugos institucijos laiko ją saugia tokiais kiekiais, kokie naudojami maisto pramonėje, ir jokio reikšmingo susirūpinimo dėl jos nekyla.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 362275;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural thickener and gelling agent derived from the konjac plant, native to Asia. It creates a very firm, rubbery gel and is used in a small number of food products such as certain noodles and diet foods. It has an exceptionally high ability to absorb water and is sometimes valued for its dietary fibre content. Its use in food is quite restricted in the EU, partly due to choking hazard concerns, particularly for children and the elderly.', opinion_lt = 'Tai natūralus tirštiklis ir gelio formuotojas, gaunamas iš Azijoje augančio konjako augalo. Jis sukuria labai tvirtą, guminę konsistenciją ir naudojamas nedaugelyje maisto produktų, pavyzdžiui, tam tikrose makaronų rūšyse ir dietiniuose maisto produktuose. ES jo naudojimas maiste yra gana griežtai ribojamas – iš dalies dėl užspringimo pavojaus, ypač vaikams ir vyresnio amžiaus žmonėms.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 342817;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural dietary fibre extracted from soybean hulls. It acts as an emulsifier and stabiliser, helping ingredients blend together and preventing products from separating or becoming sticky. You''ll find it in processed potato products, egg-based foods, decorative coatings, and liquid food supplements. It''s approved in a relatively small number of food categories, meaning it''s not especially widespread.', opinion_lt = 'Tai natūralus maistinių skaidulų priedas, gaunamas iš sojos lukštų. Jis veikia kaip emulgatorius ir stabilizatorius – padeda sumaišyti ingredientus ir neleidžia produktams sluoksniuotis ar lipti. Rasite jį perdirbtų bulvių produktuose, kiaušinių gaminiuose, dekoratyviniuose dengiamuose sluoksniuose ir skystuose maisto papilduose. Laikomas saugiu, tačiau alergiškiems sojai žmonėms verta atkreipti dėmesį – žaliava yra sojos kilmės.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 342863;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural thickener and gelling agent derived from the seeds of the Cassia obtusifolia plant, related to cinnamon. It works similarly to locust bean gum and is used to give foods a smooth, creamy texture or to prevent ice crystals from forming. You''ll find it in processed cheeses, ice cream, sauces, meat products, and desserts. It''s considered safe by European food authorities, though it is approved for a relatively limited number of food categories compared to more common gums.', opinion_lt = 'Tai natūralus tirštiklis ir želifikuojanti medžiaga, gaminama iš Cassia obtusifolia augalo sėklų — augalo, giminingo cinamonui. Ji naudojama tam, kad maistas įgautų švelnią, kremišką tekstūrą arba kad ledų gamyboje nesusidarytų ledo kristalai. Rasite ją perdirbtame sūryje, ledų, padažų, mėsos gaminių ir desertų sudėtyje. Europos maisto saugos institucijos šią medžiagą laiko saugia, nors ji patvirtinta mažesniam maisto kategorijų skaičiui nei kiti panašūs tirštikliai.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 342962;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier made by combining stearic acid (a common fatty acid) with ethylene oxide. It helps fats and water mix smoothly, preventing separation in food products. It is authorised in very few food categories, so most people will rarely encounter it. It is considered safe at the levels permitted in food, though as with most synthetic emulsifiers, some researchers suggest long-term gut health effects deserve more study.', opinion_lt = 'Tai sintetinis emulgatorius, gaminamas sujungiant riebalinę rūgštį su etileno oksidu. Jo paskirtis – padėti riebalams ir vandeniui susimaikyti, kad maistas nesidalintų į sluoksnius. Leidžiamas labai nedaugelyje maisto kategorijų, tad dauguma žmonių su juo beveik nesusiduria. Laikomas saugiu leidžiamomis dozėmis, nors kai kurie mokslininkai siūlo plačiau ištirti, kaip sintetiniai emulgatoriai veikia žarnyno mikroflorą ilgalaikėje perspektyvoje.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 343100;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier — it helps water and oil mix smoothly, which is useful in certain processed foods and cosmetics. It''s authorised in very few food categories, so most people encounter it rarely in what they eat. Regulatory bodies like EFSA consider it safe at the levels used in food. No major health controversies surround it, though like most synthetic additives, some people prefer to avoid it out of caution.', opinion_lt = 'Tai sintetinis emulgatorius — jis padeda vandeniui ir riebalams susimaišyti, todėl naudojamas kai kuriuose perdirbtuose maisto produktuose. Maiste jis leidžiamas labai nedaugelyje kategorijų, tad dauguma žmonių su juo susiduria retai. Europos maisto saugos institucija (EFSA) laiko jį saugiu tokiais kiekiais, kokiais jis naudojamas maiste. Didelių kontraversijų dėl jo nėra, nors kai kurie vartotojai sintetinius priedus vengia iš atsargumo.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 343146;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier — it helps oil and water mix together smoothly, preventing separation in foods like ice cream, sauces, and baked goods. It''s authorised in very few food categories, so most people encounter it rarely. It is generally considered safe by major food safety authorities, though some animal studies have raised questions about its effects on gut bacteria at high doses. For most consumers eating normal amounts, it is not a cause for concern.', opinion_lt = 'Tai sintetinis emulgatorius — jis padeda maišytis riebalams ir vandeniui, neleidžia masėms atsiskirti ledų, padažų ar kepinių gamyboje. Leidžiamas labai nedaugelyje maisto kategorijų, tad dauguma žmonių su juo susiduria retai. Pagrindinės maisto saugos institucijos jį laiko saugiu, nors kai kurie tyrimai su gyvūnais kėlė klausimų dėl galimo poveikio žarnyno bakterijoms didelėmis dozėmis. Įprastai vartojant įprastus kiekius, susirūpinti nėra rimto pagrindo.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 343508;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier — it helps water and oils mix together smoothly so foods don''t separate. It''s only approved in a very narrow range of food products, which suggests regulators have kept its use quite limited. At typical levels found in food, it''s generally considered safe by major food authorities. Some animal studies have raised questions about effects on gut bacteria at high doses, but these doses are far above what you''d encounter in everyday eating.', opinion_lt = 'Tai sintetinis emulsiklis — jis padeda vandeniui ir riebalams susimaišyti, kad maistas neatsiskirtų. Leidžiamas tik labai nedaugelyje maisto produktų kategorijų, vadinasi, reguliuotojai jo naudojimą gana griežtai apribojo. Įprastais kiekiais, randamais maiste, pagrindinės maisto saugos institucijos laiko jį nekenksmingu. Kai kurie gyvūnų tyrimai kėlė klausimų dėl poveikio žarnyno bakterijoms didelėmis dozėmis, tačiau tos dozės gerokai viršija tai, ką suvalgytumėte kasdieniniame gyvenime.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 343554;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier — it helps water and fats blend together smoothly, preventing separation in foods. You''ll mostly find it in baked goods, whipped toppings, and some desserts. It''s generally considered safe by food authorities, though some animal studies at very high doses have raised questions about gut microbiome effects. At the tiny amounts used in food, it''s not considered a concern for most people.', opinion_lt = 'Tai sintetinis emulgatorius — jis padeda vandeniui ir riebalams susijungti į vienodą masę, kad produktas nesidalintų į sluoksnius. Dažniausiai randamas kepiniuose, plaktuose kreminiuose desertuose ir panašiuose produktuose. Maisto saugos institucijos jį laiko saugiu, nors kai kurie tyrimai su gyvūnais didelėmis dozėmis kėlė klausimų dėl žarnyno mikrobiomo. Tokiais mažais kiekiais, kokie naudojami maiste, jis laikomas nekenksmingu daugumai žmonių.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 343600;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier — it helps fat and water mix together smoothly, preventing separation in products like ice cream and whipped toppings. It''s authorised in very few food categories, so most people encounter it rarely. It''s generally considered safe at the levels used in food, and regulatory bodies like EFSA have reviewed it without major concerns. Some people prefer to avoid synthetic emulsifiers altogether, which is a reasonable personal choice.', opinion_lt = 'Tai sintetinis emulgatorius — jis padeda riebalams ir vandeniui susimišti, todėl produktai, pavyzdžiui, ledai ar plakamieji kremai, nesisluoksniuoja. Leidžiamas labai nedaugelyje maisto kategorijų, tad daugelis žmonių su juo susiduria retai. Reguliavimo institucijos, tokios kaip EFSA, jį išnagrinėjo ir rimtų saugumo klausimų nekėlė. Kas nori vengti sintetinių emulgatorių — tai visiškai suprantamas asmeninis pasirinkimas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 343646;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural gelling agent extracted from the cell walls of fruits — especially apples and citrus peels. It''s what makes jams and jellies set, and it''s also used to thicken yogurts, fruit spreads, and some confectionery. You''ve likely eaten it your whole life without knowing. It''s considered very safe, has no known controversy, and is even classified as a dietary fibre with potential digestive health benefits. A genuinely reassuring additive.', opinion_lt = 'Tai natūralus želifavimo agенtas, gaunamas iš vaisių ląstelių sienelių — dažniausiai iš obuolių ar citrusinių vaisių žievelių. Kaip tik jis verčia uogienes ir dželė sutirštėti, taip pat naudojamas jogurtuose, vaisių pastuose ir kai kuriuose saldainiuose. Laikomas visiškai saugiu, jokių kontraversijų nėra. Dar geriau — tai maistinė skaidula, galinti teigiamai veikti virškinimą. Vienas iš tų priedų, dėl kurių tikrai nereikia nerimauti.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 343692;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier made from ammonium salts of phosphatidic acids, often derived from rapeseed oil. Its main job is to help fat and water mix smoothly in chocolate and confectionery, keeping the texture silky and preventing cocoa butter from separating. You will find it mostly in chocolate bars, coatings, and sweet fillings. It is closely related to lecithin and does a very similar job. Regulatory bodies in Europe and elsewhere consider it safe at the levels used in food, and it is not considered controversial.', opinion_lt = 'Tai sintetinis emulgatorius, gaminamas iš amonio fosfatidų druskų, dažniausiai išgautų iš rapso aliejaus. Jo pagrindinė užduotis – padėti riebalams ir vandeniui susijungti į vienodą masę šokolade bei saldainiuose, kad tekstūra būtų švelni ir kakavos sviestas neatsiskirtų. Rasite jį daugiausia šokoladiniuose batonėliuose, glasūruose ir saldžiuose įdarymuose. Jis labai panašus į lecitną ir atlieka beveik tokią pačią funkciją. Europos maisto saugos institucija laiko šį priedą saugiu tokiais kiekiais, kokiais jis naudojamas maiste, ir jis nelaikomas prieštaringu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 343939;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic ester made from sugar (sucrose) combined with acetic and isobutyric acids. It acts as an emulsifier and stabiliser, mainly used to keep flavour oils evenly distributed in drinks rather than floating to the top. You''ll find it in flavoured beverages and some alcoholic mixed drinks. It has a very limited range of approved uses compared to most additives, and regulatory bodies like EFSA have evaluated it as safe at the levels used in these specific products.', opinion_lt = 'Tai sintetinis junginys, pagamintas iš cukraus (sacharozės), acto ir izosviestas rūgščių. Jis naudojamas kaip emulsiklis ir stabilizatorius — padeda skonio aliejams tolygiai pasiskirstyti gėrimuose, o ne plūduriuoti paviršiuje. Rasite jį aromatinguose gėrimuose ir kai kuriuose alkoholiniuose kokteilių mišiniuose. Lyginant su daugeliu priedų, šio leidžiamas naudojimas yra labai ribotas, o tokios institucijos kaip EFSA jį įvertino kaip saugų tose produktų kategorijose, kur jis leidžiamas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 344012;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier and stabiliser made from wood resin — the sticky substance found in pine and other conifer trees. It''s chemically processed to help oils and water mix together, and to keep cloudy drinks looking evenly cloudy rather than separating. You''ll find it mainly in flavoured soft drinks, some alcoholic beverages, and occasionally in confectionery. It''s approved for use in the EU and generally considered safe at the levels found in food, with no major health concerns flagged by regulators.', opinion_lt = 'Tai sintetinis emulsiklis ir stabilizatorius, pagamintas iš medžių dervos — lipnios medžiagos, randamos pušyse ir kituose spygliuočiuose. Jis chemiškai apdorojamas tam, kad aliejai ir vanduo geriau susimaišytų, o debesyti gėrimai išliktų tolygiai drumsti ir nesiskirstytų. Dažniausiai jį rasite skoniuotuose gaivaliuosiuose gėrimuose, kai kuriuose alkoholiniuose gėrimuose ir kartais saldainiuose. ES jis leidžiamas naudoti ir naudojamais kiekiais laikomas saugiu — reguliuotojai rimtesnių sveikatos rizikų nėra nustatę.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 344072;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic mineral salt made from magnesium and phosphate. It works as a leavening agent in baked goods, helping dough rise, and can also act as a stabiliser or acidity regulator. You will find it in things like noodles, batters, breads, and flour mixes. It is authorised in a relatively small number of food categories, which suggests its use is quite specific. Generally considered safe at the levels used in food. Phosphate additives as a broad group are sometimes discussed in relation to kidney health when consumed in very high amounts, but typical dietary exposure from processed foods is not a cause for concern for most healthy people.', opinion_lt = 'Tai sintetinė mineralinė druska, pagaminta iš magnio ir fosfato. Ji naudojama kaip kildinimo medžiaga kepiniuose – padeda tešlai pakilti – taip pat gali veikti kaip stabilizatorius ar rūgštingumo reguliatorius. Randama makaronuose, tešlose, duonoje ir miltų mišiniuose. Leista naudoti palyginti nedaugelyje maisto kategorijų, tad jos taikymas gana specifinis. Laikoma saugia tokiais kiekiais, kokie naudojami maiste. Fosfatų grupės priedai kartais minimi kalbant apie inkstų sveikatą, kai jų vartojama labai daug, tačiau įprastas tokių priedų kiekis maiste sveikiems žmonėms problemų nesukelia.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 364262;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a group of synthetic phosphate salts used mainly as leavening agents in baked goods, helping dough rise and giving bread a consistent texture. They also prevent discolouration in processed fish and help control moisture in cereal-based foods. Phosphates are naturally present in many foods we eat daily, so small additional amounts from additives are generally considered safe for most people. However, people with kidney disease should be mindful of total phosphate intake from all sources, as impaired kidneys struggle to filter excess phosphate.', opinion_lt = 'Tai sintetinių fosfatų grupė, daugiausia naudojama kaip kildiklis kepiniuose — padeda tešlai kilti ir suteikia duonai tolygią tekstūrą. Jie taip pat saugo perdirbtą žuvį nuo pajuodimo ir padeda kontroliuoti drėgmę grūdų produktuose. Fosfatai natūraliai randami daugelyje kasdienių maisto produktų, todėl nedideli papildomi kiekiai iš priedų laikomi saugiais daugumai žmonių. Tačiau žmonėms, turintiems inkstų problemų, verta atkreipti dėmesį į bendrą fosfatų kiekį maiste, nes pažeisti inkstai sunkiau pašalina jų perteklių.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 344180;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic phosphate salt used mainly as a moisture-retaining agent and stabiliser. It helps seafood and processed fish hold water during freezing and thawing, improving texture and reducing weight loss. It is authorised in a limited number of food categories and considered safe at approved levels by major food safety bodies. People with kidney disease are generally advised to watch overall phosphate intake from all food sources.', opinion_lt = 'Tai sintetinis fosfatų druskas, naudojamas daugiausia kaip drėgmę sulaikantis ir stabilizuojantis priedas. Jis padeda žuvies ir jūros gėrybių produktams išlaikyti vandenį šaldymo ir atšildymo metu, todėl gerėja tekstūra ir mažiau prarandama svorio. Pagrindinės maisto saugos institucijos laiko jį saugiu, kai naudojamas leistinais kiekiais. Žmonėms, turintiems inkstų problemų, patariama stebėti bendrą fosfatų kiekį iš visų maisto šaltinių.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 344279;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic salt derived from phosphoric acid, used mainly to help seafood and fish products retain moisture during processing and freezing. It stops the proteins from drying out, so the final product looks fresher and has a better texture. It is generally considered safe at normal dietary levels. However, eating too much phosphate overall — from many processed foods combined — may put strain on kidneys, particularly for people with kidney disease.', opinion_lt = 'Tai sintetinis druskos junginys, gaunamas iš fosforo rūgšties, dažniausiai naudojamas žuvies ir jūros gėrybių produktuose, kad šie išlaikytų drėgmę apdorojimo ir šaldymo metu. Taip produktas atrodo šviežesnis ir turi geresnę tekstūrą. Paprastai laikomas saugiu įprastais kiekiais. Vis dėlto fosfatų perteklius maiste — ypač jei vartojate daug perdirbtų produktų — gali apkrauti inkstus, todėl žmonės, turintys inkstų problemų, turėtų į tai atkreipti dėmesį.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 344330;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic potassium salt used specifically in winemaking to prevent the formation of tartrate crystals — those harmless but visually unappealing crystal deposits that can appear in wine bottles. It works by stabilising the wine without the need for cold treatment, making the process more energy-efficient. Its use is very narrowly approved, essentially only in wine, and it is considered safe at the levels permitted. There is little controversy surrounding it.', opinion_lt = 'Tai sintetinė kalio druska, naudojama beveik išskirtinai vyno gamyboje — ji neleidžia susidaryti vyninės rūgšties kristalams, kurie kartais nusėda butelio dugne ar šonuose. Šie kristalai patys savaime nekenksmingi, bet atrodo neestetiškai. Šis priedas leidžia stabilizuoti vyną be šaldymo proceso, taupant energiją. Jo naudojimas labai siaurai reglamentuotas, ir jis laikomas saugiu leistinomis dozėmis. Didelio ginčo dėl jo nekyla.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 364670;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic salt used in winemaking as a stabiliser. Its job is to prevent the formation of tartrate crystals — those harmless but visually unappealing white deposits that can appear in wine bottles. It is authorised only for use in wine and is considered safe at the low levels used. Research on its long-term effects is still relatively limited compared to older, more established additives.', opinion_lt = 'Tai sintetinė druska, naudojama vynininkystėje kaip stabilizatorius. Jos paskirtis — apsaugoti vyną nuo tartrato kristalų susidarymo, t. y. tų nekenksmingų, bet nepatraukliai atrodančių baltų nuosėdų, kurios kartais atsiranda vyno buteliuose. Leidžiama naudoti tik vyne ir laikoma saugia tomis mažomis dozėmis, kuriomis ji naudojama. Ilgalaikiai tyrimai kol kas yra kuklesni nei apie senesnius, geriau ištirtus priedus.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 364763;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally derived sugar molecule shaped like a tiny hollow ring, originally found in starch. In food, it acts as a carrier — it wraps around flavour or active compounds to protect them, control their release, or mask unwanted tastes and smells. You''ll find it in things like breath-freshening sweets, flavoured drinks, and dietary supplements. It is authorised in the EU but only in a limited number of food categories, which reflects a cautious approach. It is generally considered safe at the levels used in food, and there are no major controversies surrounding it.', opinion_lt = 'Tai natūralios kilmės cukraus molekulė, susidaranti iš krakmolo — jos forma panaši į mažytį tuščiavidurį žiedą. Maiste ji naudojama kaip nešiklis: apgaubia aromato ar veikliosios medžiagos molekules, apsaugo jas, kontroliuoja jų išsiskyrimą arba paslėpia nemalonų skonį ar kvapą. Dažniausiai randama kvapų neutralizavimo saldainiuose, aromatizuotuose gėrimuose ir maisto papilduose. ES ji leidžiama tik keliose maisto kategorijose, o tai rodo atsargų požiūrį. Rimtų kontraversijų nėra — esant įprastiems kiekiams laikoma saugia.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 344381;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a plant-derived fiber made by mechanically processing wood pulp or cotton into a very fine powder. It is used mainly as an anti-caking agent, bulking agent, or texturizer — helping tablets hold their shape and preventing powders from clumping. It passes through the body largely undigested, so it contributes no calories. It is widely considered safe, with no significant controversies attached to it.', opinion_lt = 'Tai augalinės kilmės pluoštas, gaunamas mechaniškai apdorojant medienos masę arba medvilnę į labai smulkius miltelius. Maiste jis naudojamas kaip sukietėjimą stabdanti medžiaga, piltuvėlis ar tekstūros gerintojas — padeda tabletėms išlaikyti formą ir neleidžia milteliams sukepti. Organizme jis praktiškai nesuvirškinamas, todėl kalorijų nesuteikia. Laikomas saugiu priedu, rimtų ginčų dėl jo nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 364597;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural substance derived from plant fibers — essentially purified cellulose, the same structural material found in all plants. It''s used as a bulking agent, stabilizer, and anti-caking agent in foods like low-fat dairy products, powdered sweeteners, cheese, and spice blends. It helps give texture and prevent clumping.

Your body cannot digest it, so it passes through without being absorbed — much like dietary fiber. It''s considered very safe and has no meaningful controversy around it. If you see it on a label, there''s no real cause for concern.', opinion_lt = 'Tai natūralios kilmės medžiaga, gauta iš augalinių skaidulų — iš esmės tai išgrynintas celiuliozė, tokia pat, kokia randama visuose augaluose. Maiste ji naudojama kaip pildiklis, stabilizatorius ir sukietėjimą neleidžianti medžiaga — pavyzdžiui, mažai riebalų turinčiuose pieno produktuose, miltelių pavidalo saldintuose, sūriuose ir prieskonių mišiniuose.

Organizmas jos negali virškinti, todėl ji praeina per virškinamąjį traktą nepasisavinta — panašiai kaip maistinės skaidulos. Laikoma labai saugia, jokios rimtos kontraversijos nėra. Jei matote ją sudėtyje, nėra priežasties nerimauti.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 1487061;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic fibre made by chemically modifying cellulose from plant material. It acts as a thickener and binder, helping powdered or tablet sweeteners hold their shape and flow properly. It is used in a very limited range of products, so most people consume very little of it. It is generally considered safe and passes through the digestive system largely unabsorbed, similar to dietary fibre.', opinion_lt = 'Tai sintetinis pluoštas, pagamintas chemiškai apdorojant augalinę celiuliozę. Jis naudojamas kaip tirštiklis ir rišiklis – padeda miltelių ar tablečių pavidalo saldintuose išlaikyti formą ir nesulipti. Vartojamas labai nedaugelyje produktų, tad dauguma žmonių jo suvalgo tikrai nedaug. Laikomas saugiu – organizme beveik nesisavina ir išsiskiria panašiai kaip maistinės skaidulos.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 344627;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic substance derived from cellulose — the natural fibre found in plant cell walls. It acts as a bulking agent and binder, helping to give structure or controlled release to certain food supplements and encapsulated ingredients. It is authorised in very few food categories, so most people rarely encounter it in everyday foods. Regulatory bodies consider it safe at permitted levels, and it passes through the body largely undigested.', opinion_lt = 'Tai sintetinis junginys, gautas iš celiuliozės — natūralaus augalų ląstelių sienelių pluošto. Jis naudojamas kaip pildiklis ir rišiklis, padedantis suformuoti struktūrą arba užtikrinti kontroliuojamą medžiagų išsiskyrimą maisto papilduose ir kapsulėse. Leidžiamas labai nedaugelyje maisto produktų kategorijų, todėl eilinis vartotojas jį sutinka retai. Maisto saugos institucijos jį laiko saugiu leistinomis dozėmis, o organizme jis praktiškai nesuvirškinamas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 344687;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic, modified form of cellulose — the same natural fibre found in plant cell walls — that has been chemically tweaked to change how it behaves in water. It is mainly used as a binder and disintegrant in solid food supplements like tablets and capsules, helping them hold their shape and then break apart properly when swallowed. Its use is very limited and tightly restricted to this one category. It is generally considered safe at the levels used, and the body does not absorb it — it passes through the digestive system largely unchanged.', opinion_lt = 'Tai sintetiškai modifikuota celiuliozės forma — tos pačios natūralios skaidulos, kuri randama augalų ląstelių sienelėse — chemiškai pakeista, kad kitaip elgtųsi vandenyje. Naudojama daugiausia kaip rišiklis ir dezintegrantas kietuose maisto papilduose, pavyzdžiui, tabletėse ir kapsulėse: padeda joms išlaikyti formą ir tinkamai suirti nuryjus. Jos naudojimas yra labai ribotas ir griežtai apribotas tik šia viena kategorija. Paprastai laikoma saugia vartojamais kiekiais, o organizmas jos nepasisavina — ji praeina per virškinimo sistemą praktiškai nepakitusi.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 365049;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a modified form of cellulose — the natural fibre found in plant cell walls — that has been chemically tweaked to dissolve better in water. It works as a thickener, binder, and stabiliser, helping powders stick together into tablets or keeping liquids smooth. You''ll mainly find it in sweetener tablets and solid food supplements. It''s not absorbed by the body and passes through the digestive system, so it''s generally considered very safe with no significant health concerns.', opinion_lt = 'Tai chemiškai modifikuota celiuliozė — natūralus augalinių ląstelių sienelių pluoštas, pritaikytas geriau tirpti vandenyje. Maiste ji veikia kaip tirštiklis ir rišiklis: padeda supresuoti miltelius į tabletes arba išlaikyti skysčių vienodą konsistenciją. Dažniausiai randama saldintuklių tabletėse ir kieto pavidalo maisto papilduose. Organizmas jos nepasisavina — ji tiesiog praeina per virškinimo sistemą, todėl laikoma visiškai saugia ir jokių rimtų sveikatos problemų su ja nesiejama.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 344733;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic modification of cellulose — the natural fibre found in plant cell walls. It acts as a thickener, stabiliser, and coating agent, helping products hold their shape or texture. You''ll find it in tabletop sweeteners and as a coating on fresh fruit and vegetables to extend shelf life. It passes through the digestive system largely unabsorbed, similar to dietary fibre, and is generally considered safe by major food safety authorities.', opinion_lt = 'Tai sintetiškai modifikuota celiuliozė — natūrali skaidula, randama augalų ląstelių sienelėse. Ji naudojama kaip tirštiklis, stabilizatorius ir dangos medžiaga, padedanti produktams išlaikyti formą ar tekstūrą. Rasite ją stalo saldikliuose ir kaip dangą ant šviežių vaisių bei daržovių, kad ilgiau išliktų šviežūs. Organizmas jos praktiškai neįsisavina — ji elgiasi panašiai kaip maistinės skaidulos, todėl laikoma saugia ir nesukelia susirūpinimo.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 344828;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic substance derived from cellulose — the natural material found in plant cell walls. It acts as a thickener and stabiliser, helping liquid or powder products hold their texture and consistency. You''ll mainly find it in tabletop sweetener products, so most people encounter it rarely and in very small amounts. It is generally considered safe by food authorities, and there is no notable controversy surrounding it.', opinion_lt = 'Tai sintetinis junginys, gautas iš celiuliozės — natūralios medžiagos, randamos augalų ląstelių sienelėse. Jis naudojamas kaip tirštiklis ir stabilizatorius, padedantis skystiems ar miltelių pavidalo produktams išlaikyti tinkamą tekstūrą. Dažniausiai jį rasite staliniuose saldintuose — skystuose, miltelių ar tablečių pavidalo. Kadangi vartojamas retai ir labai mažais kiekiais, maisto saugos institucijos jį laiko saugiu, o jokių reikšmingų kontraversijų dėl šios medžiagos nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 344923;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic thickener and stabiliser made by chemically modifying natural cellulose — the same fibrous material found in plant cell walls. It helps give foods a smooth, consistent texture and prevents ingredients from separating, so you''ll find it in creams, diet sweeteners, and fruit drinks. Regulatory bodies like EFSA and the FDA consider it safe for consumption at approved levels. It passes through the digestive system largely unabsorbed, so it has no caloric value and is generally well tolerated, though very high amounts could cause mild digestive discomfort in sensitive individuals.', opinion_lt = 'Tai sintetinis tirštiklis ir stabilizatorius, pagamintas chemiškai apdorojant natūralią celiuliozę — tą pačią medžiagą, kuri sudaro augalų ląstelių sieneles. Jis suteikia produktams vienodą, sklandžią tekstūrą ir neleidžia ingredientams atsisluoksniuoti, todėl randamas grietinėlėje, saldikliuose ir vaisių nektaruose. EFSA ir FDA pripažįsta šią medžiagą saugia leidžiamose dozėse. Organizmas jos praktiškai neįsisavina, todėl kalorijų neturi ir paprastai gerai toleruojama, nors labai dideliai kiekiai jautresniems žmonėms gali sukelti lengvą virškinimo diskomfortą.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 344996;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic additive made from cellulose — the same natural material found in plant cell walls — that has been chemically modified to help it hold its shape and resist breaking down. It acts as a binder and stabiliser, mainly used in tablet-form products like sweetener tablets and solid food supplements to keep them compressed and intact. It is authorised in only a handful of product types and is considered safe by European food authorities at the levels used. There is no notable controversy surrounding it.', opinion_lt = 'Tai sintetinis priedas, pagamintas iš celiuliozės — tos pačios medžiagos, kuri natūraliai randama augalų ląstelių sienelėse — tik chemiškai modifikuotas, kad geriau išlaikytų formą. Jis naudojamas kaip rišiklis ir stabilizatorius — daugiausia tabletėse, pavyzdžiui, saldintuose ar maisto papilduose, kad jie išliktų suspausti ir nesudužtų. Leidžiamas tik labai nedaugelyje produktų kategorijų ir Europos maisto saugos institucijų laikomas saugiu. Jokio reikšmingo visuomeninio ar mokslinio ginčo dėl šio priedo nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 345134;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a modified form of plant-based cellulose that has been broken down by enzymes, making it more soluble and effective as a thickener or stabiliser in food. It helps improve texture and consistency in products. Being authorised in only one food category suggests its use is quite limited and specific. It is generally considered safe, with no notable controversies surrounding it.', opinion_lt = 'Tai augalinės kilmės celiuliozės modifikuota forma, fermentų pagalba suskaidyta į smulkesnes dalis, kad geriau tirptų ir veiktų kaip tirštiklis ar stabilizatorius maiste. Jis naudojamas tekstūrai ir konsistencijai pagerinti. Kadangi leidžiamas tik vienoje maisto produktų kategorijoje, jo naudojimas yra labai ribotas. Šis priedas laikomas saugiu, jokių reikšmingų diskusijų ar kontraversijų dėl jo nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 345216;
UPDATE aggregate.eu_additives SET opinion_en = 'This additive is made from fatty acids — the same building blocks found in natural fats and oils — combined with minerals like sodium, potassium, or calcium. It acts mainly as an anti-caking agent, helping powders and tablets stay free-flowing and not clump together. You''ll find it in tablet-form sweeteners and spice blends. It''s synthetic in processing but derived from natural fat sources, and regulatory bodies consider it safe at the levels used in food.', opinion_lt = 'Šis priedas pagamintas iš riebalų rūgščių — tų pačių, iš kurių sudaryti natūralūs riebalai ir aliejai — sujungtų su mineralais, tokiais kaip natris, kalis ar kalcis. Jis daugiausia naudojamas kaip antikietėjimo priemonė: neleidžia milteliams ar tabletėms sulipti ir sukelti gumuliukus. Rasite jį saldiklių tabletėse ir prieskonių mišiniuose. Nors jis gaminamas pramoniškai, žaliavos kyla iš natūralių riebalų, o reguliavimo institucijos laiko jį saugiu tokiais kiekiais, kokiais jis naudojamas maiste.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 345262;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic additive made by combining magnesium with fatty acids, which are fats found naturally in foods like vegetable oils. It acts as an anti-caking agent, helping compressed tablets hold their shape and stop them from clumping together. You''ll mainly find it in sweetener tablets — the kind you drop into tea or coffee. It''s authorised in very few food categories and used in tiny amounts. Regulatory bodies consider it safe at the levels permitted.', opinion_lt = 'Tai sintetinis priedas, gaunamas jungiant magnį su riebalų rūgštimis, kurios natūraliai randamos augaliniuose aliejuose ir kituose riebaluose. Jis veikia kaip sukietėjimo ir sulipimo inhibitorius — padeda presuotoms tabletėms išlaikyti formą ir nelipti viena prie kitos. Daugiausia jį rasite saldintuvo tabletėse, kurias beriate į arbatą ar kavą. Naudojamas labai mažais kiekiais, leidžiamas nedaugelyje maisto kategorijų. Reguliavimo institucijos laiko jį saugiu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 345322;
UPDATE aggregate.eu_additives SET opinion_en = 'This is an emulsifier made from fatty acids — the same building blocks as natural fats found in vegetable oils or animal fats. It helps water and oil mix smoothly, giving baked goods, chocolate, margarine, and pasta a better texture and longer shelf life. It is found in a huge range of everyday products including bread, cream, spreads, and cocoa products. It is considered safe by major food safety authorities worldwide, and most people consume it regularly without any issues. Those avoiding animal-derived ingredients should note it can be sourced from either plant or animal fats, and labelling rarely specifies which.', opinion_lt = 'Tai emulsiklis, pagamintas iš riebalų rūgščių — tokių pat, kaip natūralūs riebalai augaliniuose aliejuose ar gyvūninėse riebalų produktuose. Jis padeda sumaišyti vandenį ir aliejų, suteikia geresnę tekstūrą duonai, šokoladui, margarinui ir makaronams bei prailgina jų galiojimo laiką. Jo randama labai daugelyje kasdienių produktų. Pagrindinės maisto saugos institucijos laiko jį saugiu, ir dauguma žmonių jį vartoja be jokių problemų. Tiems, kurie vengia gyvūninės kilmės ingredientų, verta žinoti, kad šis priedas gali būti gaminamas tiek iš augalinių, tiek iš gyvūninių riebalų, o tai ant etikečių dažniausiai nenurodoma.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 345369;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier made by combining fats (from plant or animal sources) with acetic acid — the same acid found in vinegar. It helps bread and baked goods hold their shape, stay soft, and mix ingredients that wouldn''t normally blend well. You''ll find it mainly in breads, pre-cooked cereals, and some baby foods. It is approved in the EU but only in a limited number of food categories, which suggests regulators consider it acceptable in specific uses. It is generally regarded as safe at the levels used in food production.', opinion_lt = 'Tai sintetinis emulsiklis, gaminamas iš riebalų (augalinių arba gyvūninių) ir acto rūgšties — tos pačios, kuri yra įprastame acte. Jis padeda duonai ir kepiniams išlaikyti formą, minkštumą ir sujungia ingredientus, kurie paprastai nesimaiša. Dažniausiai randamas duonoje, iš anksto viruose javų produktuose ir kai kuriuose kūdikių maisto produktuose. ES jis leidžiamas tik nedaugelyje maisto kategorijų, o tai rodo, kad reguliuotojai jį laiko priimtinu tik konkretiems tikslams. Įprastomis dozėmis laikomas saugiu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 345694;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier made by combining fats with lactic acid. It helps mix ingredients that wouldn''t normally blend together, improving texture and shelf life in processed foods. It''s found in very few food categories — mainly certain processed cereal-based foods and baby foods under strict EU regulations. At the levels permitted, it is considered safe by food safety authorities, and its use in baby food is tightly controlled.', opinion_lt = 'Tai sintetinis emulgatorius, gaminamas sujungiant riebalus su pieno rūgštimi. Jis padeda sumaišyti ingredientus, kurie paprastai nesijungtų, gerina tekstūrą ir ilgina galiojimo laiką perdirbtuose maisto produktuose. Leidžiamas tik labai nedaugelyje maisto kategorijų — daugiausia tam tikruose perdirbtų grūdų produktuose ir kūdikių maiste pagal griežtus ES reglamentus. Leistinosiomis dozėmis maisto saugos institucijos jį laiko saugiu, o jo naudojimas kūdikių maiste yra ypač griežtai kontroliuojamas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 345767;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier made by combining fats with citric acid — the same acid found naturally in citrus fruits. It helps oil and water mix smoothly, improves texture, and extends shelf life in products like chocolate, margarines, and baked goods. It is also approved for use in infant and follow-on formulas, where strict safety standards apply. Regulatory bodies like EFSA consider it safe at permitted levels, and there is no significant controversy surrounding it.', opinion_lt = 'Tai sintetinis emulsiklis, gaminamas sujungiant riebalus su citrinos rūgštimi — ta pačia rūgštimi, kuri natūraliai randama citrusiniuose vaisiuose. Jis padeda sumaišyti aliejų su vandeniu, gerina tekstūrą ir ilgina galiojimo laiką tokiuose produktuose kaip šokoladas, margarinas ir kepiniai. Taip pat leidžiamas naudoti kūdikių ir mažų vaikų maiste, kuriam taikomi griežti saugos reikalavimai. Europos maisto saugos institucija (EFSA) laiko jį saugiu leidžiamomis dozėmis, ir didelių diskusijų dėl jo nekyla.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 345814;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier made by combining fatty acids (from animal or vegetable fats) with tartaric acid. It helps dough hold together better, improves texture, and keeps bread soft for longer. You''ll mostly find it in commercial bread products. It has a very narrow authorisation — essentially limited to basic breads — which means regulators keep its use quite restricted. It is generally considered safe at the levels used in food, and there are no major controversies surrounding it.', opinion_lt = 'Tai sintetinis emulgatorius, gaminamas sujungiant riebalų rūgštis (iš gyvulinių arba augalinių riebalų) su vyno rūgštimi. Jis padeda tešlai geriau sulipti, pagerina tekstūrą ir ilgiau išlaiko duoną minkštą. Dažniausiai jį rasite pramoninės gamybos duonos produktuose. Jo naudojimas yra labai siaurai reglamentuotas — iš esmės leidžiamas tik paprastoje duonoje. Laikomas saugiu tokiais kiekiais, kokiais naudojamas maiste, ir didelių kontraversijų dėl jo nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 345986;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier made by combining fatty acids (usually from vegetable oils) with tartaric acid. It helps dough hold together better, gives bread a softer texture, and extends shelf life — basically a dough conditioner used by commercial bakers. It''s authorised in very few food categories, mainly plain breads with minimal ingredients. Regulatory agencies consider it safe at the levels used in food, and there are no major controversies surrounding it.', opinion_lt = 'Tai sintetinis emulsiklis, pagamintas sujungus riebalų rūgštis (dažniausiai iš augalinių aliejų) su vyno rūgštimi. Jis padeda tešlai geriau laikytis kartu, suteikia duonai minkštesnę tekstūrą ir prailgina galiojimo laiką — iš esmės tai tešlos gerintojas, naudojamas pramoninėje kepykloje. Leidžiamas labai nedaugelyje maisto kategorijų, daugiausia paprastose duonose su minimaliu ingredientų skaičiumi. Maisto saugos institucijos laiko jį saugiu naudojamais kiekiais, ir didelių kontraversijų dėl jo nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 346033;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier made by combining fats with acetic and tartaric acids. It helps bread dough hold together better, improves texture, and gives bread a softer crumb and better volume. You''ll mainly find it in industrially produced breads and baked goods. It''s approved for use in the EU and is generally considered safe at the levels used in food production. No significant health concerns are associated with it.', opinion_lt = 'Tai sintetinis emulgatorius, pagamintas sujungiant riebalus su acto ir vyno rūgštimis. Jis padeda duonos tešlai geriau sulipti, pagerina tekstūrą ir suteikia duonai minkštesnį minkštimą bei geresnį tūrį. Dažniausiai jį rasite pramoninės gamybos duonoje ir kepiniuose. ES jis yra patvirtintas naudoti maiste ir laikomas saugiu tomis dozėmis, kuriomis naudojamas gamyboje. Jokių reikšmingų sveikatos problemų su juo nesiejama.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 346080;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier made by combining sugar (sucrose) with fatty acids from vegetable oils. It helps mix water and fat together, giving foods a smooth, stable texture. You''ll find it in infant formula, follow-on formula, and milk-based drinks for young children, as well as some baked goods and confectionery. It is generally considered safe by European food authorities, and its use in baby products is tightly regulated with strict limits to protect the youngest consumers.', opinion_lt = 'Tai sintetinis emulgatorius, gaminamas jungiant cukrų (sacharozę) su riebalų rūgštimis iš augalinių aliejų. Jis padeda sujungti vandenį ir riebalus, suteikdamas produktams vienodą, stabilią tekstūrą. Dažniausiai randamas kūdikių mišiniuose, tolesnio maitinimo mišiniuose ir pieno gėrimuose mažiems vaikams. Europos maisto saugos institucijos jį laiko saugiu, o naudojimas kūdikių produktuose yra griežtai reglamentuotas, siekiant apsaugoti mažiausius vartotojus.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 346127;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier made by combining sucrose (table sugar) and fats. It helps oil and water mix together smoothly, improving texture in certain foods. It is only authorised in a very limited number of food categories, which reflects its quite narrow use in the industry. It is generally considered safe at the levels permitted, and there is no significant controversy surrounding it.', opinion_lt = 'Tai sintetinis emulsiklis, gaminamas sujungiant sacharozę (paprastą cukrų) su riebalais. Jis padeda sklandžiai sujungti aliejų ir vandenį, gerinant tam tikrų produktų tekstūrą. Leidžiamas tik labai nedaugelyje maisto produktų kategorijų, todėl pramonėje naudojamas gana retai. Laikomas saugiu leidžiamomis dozėmis, ir jokio reikšmingo ginčo dėl jo nekyla.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 346644;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier made by combining glycerol (a common food ingredient) with fatty acids derived from vegetable or animal fats. Its main job is to help water and oil mix together smoothly, improve texture, and extend shelf life in products like chocolates, baked goods, chewing gum, spreads, and desserts. It also helps doughs stay soft and prevents fat from separating.

Regulatory bodies like EFSA and the FDA consider it safe at the levels used in food. There is no significant controversy surrounding it, and it is generally well tolerated. People who follow vegan or halal diets may want to check the source of the fatty acids, as they can sometimes come from animal fats.', opinion_lt = 'Tai sintetinis emulgatorius, gaminamas iš glicerolio ir riebalų rūgščių, kurios gaunamos iš augalinių arba gyvūninių riebalų. Jo pagrindinė funkcija – padėti vandeniui ir riebalams susijungti į vienarūšę masę, pagerinti tekstūrą ir prailginti galiojimo laiką tokiuose produktuose kaip šokoladas, kepiniai, kramtomoji guma, tepieji riebalai ir desertai. Jis taip pat padeda tešlai išlikti minkštai ir neleidžia riebalams atsiskirti.

EFSA ir kitos maisto saugos institucijos laiko šį priedą saugiu tokiomis dozėmis, kokios naudojamos maiste. Reikšmingų kontraversijų dėl jo nėra, ir jis paprastai gerai toleruojamas. Veganiškos ar halal mitybos besilaikantys žmonės turėtų atkreipti dėmesį į riebalų rūgščių kilmę – kartais jos gali būti gyvūninės kilmės.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 346690;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier made from glycerol and castor oil fatty acids. Its main job is to reduce the viscosity of chocolate, making it flow more smoothly and evenly during production — which also allows manufacturers to use less cocoa butter, cutting costs. You''ll find it in chocolate bars, chocolate coatings, sauces, and spreads. Regulatory bodies like EFSA and FDA consider it safe at the levels used in food, and there is no significant controversy surrounding it.', opinion_lt = 'Tai sintetinis emulgatorius, gaminamas iš glicerolio ir ricinos aliejaus riebalų rūgščių. Jis dažniausiai naudojamas šokolade — sumažina masės klampumą, todėl šokoladas geriau teka gamybos metu ir galima sutaupyti kakavos sviesto. Rasite jį šokoladiniuose batoniukuose, glazūrose, padažuose ir tepamose riebalinėse masėse. Europos maisto saugos tarnyba (EFSA) ir kitos institucijos laiko jį saugiu vartoti įprastais kiekiais, ir didesnio ginčo dėl šio priedo nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 1486594;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier made by combining propylene glycol with fatty acids. It helps mix fats and water together smoothly, improving texture in products like ice cream, baked goods, desserts, chewing gum, and dairy alternatives. It is widely used across the food industry to keep products stable and give them a consistent, appealing consistency. It is generally considered safe at levels found in food, and regulatory bodies like EFSA have approved its use. Sensitive individuals should note it contains propylene glycol, which in very large amounts can cause issues, but normal dietary exposure is well within safe limits.', opinion_lt = 'Tai sintetinis emulgatorius, pagamintas sujungus propilenglikolį su riebalų rūgštimis. Jis padeda sumaišyti riebalus ir vandenį, suteikdamas kremišką tekstūrą ledams, kepiniams, desertams, kramtomajai gumai ir pieno pakaitalams. Plačiai naudojamas maisto pramonėje, kad produktai būtų stabilūs ir turėtų vienodą konsistenciją. Laikomas saugiu tokiais kiekiais, kokie randami maiste — Europos maisto saugos institucija (EFSA) jį yra patvirtinusi. Įprastas vartojimas nekelia susirūpinimo, tačiau produkto sudėtyje esantis propilenglikolis labai dideliais kiekiais gali sukelti problemų.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 347041;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier made by heating soybean oil together with mono and diglycerides — a process that chemically bonds them into a new compound. It helps fats and water mix smoothly, keeping products like margarine and fat-based spreads stable and uniform. It is approved in the EU but only for a very narrow range of products, which suggests regulators have kept its use tightly controlled. It is generally considered safe at the levels used, though it is a heavily processed ingredient with little public awareness.', opinion_lt = 'Tai sintetinis emulgatorius, gaminamas kaitinant sojos aliejų kartu su mono ir digliceridais — šio proceso metu susidaro naujas cheminis junginys. Jis padeda riebalams ir vandeniui susimaišyti, todėl margarinas ir kiti riebaliniai tepiniai išlieka vienalytės konsistencijos. ES jis leidžiamas tik labai siaurame produktų spektre, o tai rodo, kad reguliuotojai jo naudojimą griežtai kontroliuoja. Laikomas saugiu naudojamais kiekiais, tačiau tai stipriai perdirbtas ingredientas, apie kurį visuomenė mažai žino.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 347228;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier made from stearic acid (a natural fatty acid) and lactic acid. It helps mix ingredients that normally separate, like fat and water, and is widely used in baked goods to keep bread soft and improve texture. You will mainly find it in commercial breads, cakes, and pastries. It is considered safe by major food safety authorities and has no significant controversy attached to it. Most people consume it without any issues.', opinion_lt = 'Tai sintetinis emulsiklis, pagamintas iš stearino rūgšties (natūralios riebalų rūgšties) ir pieno rūgšties. Jis padeda sumaišyti ingredientus, kurie paprastai nesimaiša, pavyzdžiui, riebalus ir vandenį, todėl plačiai naudojamas kepiniuose – duonai minkštinti ir tekstūrai gerinti. Dažniausiai jį rasite pramoninėje duonoje, pyragaičiuose ir konditerijos gaminiuose. Pagrindinės maisto saugos institucijos laiko jį saugiu, jokių reikšmingų kontraversijų nėra. Dauguma žmonių jį vartoja be jokių problemų.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 347275;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier made from stearic acid (a fatty acid), lactic acid, and calcium. It helps bread and baked goods stay soft, improves dough stability, and keeps the texture consistent. You might find it in some baked products, though it''s authorised in very few food categories. It is generally considered safe by food regulators, and there are no significant health concerns associated with normal dietary exposure.', opinion_lt = 'Tai sintetinis emulsiklis, pagamintas iš riebalų rūgšties, pieno rūgšties ir kalcio. Jis padeda duonai ir kepiniams išlikti minkštiems, gerina tešlos stabilumą ir išlaiko vienodą tekstūrą. Šį priedą galima rasti kai kuriuose kepiniuose, nors jis leidžiamas labai nedaugelyje maisto kategorijų. Maisto saugos institucijos jį laiko saugiu, ir įprastas jo kiekis maiste nesukelia žinomų sveikatos problemų.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 347621;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier made by combining stearyl alcohol with tartaric acid. It is mainly used in baked goods to improve dough stability and give bread a better texture and volume. It is authorised in very few food categories, so most people rarely encounter it. Regulatory bodies consider it safe at levels used in food production.', opinion_lt = 'Tai sintetinis emulgatorius, gaunamas sujungiant stearilo alkoholį su vyno rūgštimi. Jis daugiausia naudojamas kepiniuose — pagerina tešlos stabilumą, duonos tekstūrą ir tūrį. Leidžiamas labai nedaugelyje maisto produktų kategorijų, todėl dauguma žmonių su juo retai susiduria. Maisto saugos institucijos mano, kad naudojamais kiekiais jis yra saugus.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 347667;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier made by combining sorbitol (a sugar alcohol) with stearic acid (a fatty acid). It helps fat and water mix together smoothly, and is often used in baked goods, cake mixes, and some confectionery to improve texture and shelf life. It is authorised in very few food categories, meaning you won''t encounter it often. Regulatory bodies like EFSA consider it safe at the levels used in food.', opinion_lt = 'Tai sintetinis emulsiklis, gaunamas sujungus sorbitolį (cukraus alkoholį) su stearino rūgštimi (riebalų rūgštimi). Jis padeda riebalams ir vandeniui susimaišyti, todėl naudojamas kepiniuose, pyragų mišiniuose ir kai kuriuose saldainiuose – gerina tekstūrą ir ilgina galiojimo laiką. Leidžiamas labai nedaugelyje maisto kategorijų, tad retai jį sutiksite. Europos maisto saugos institucija (EFSA) laiko jį saugiu tomis kiekiais, kurie naudojami maiste.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 347753;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier made from sorbitol and stearic acid — it helps fats and liquids mix smoothly and prevents chocolate from blooming (that white dusty appearance). You''ll find it mostly in chocolate products, candy coatings, and decorative cake fillings. It is approved for use in a limited number of food categories and is generally considered safe at the levels used in food. There is no significant controversy around it, and regulatory bodies like EFSA have not raised concerns about its use.', opinion_lt = 'Tai sintetinis emulgatorius, pagamintas iš sorbitolio ir stearino rūgšties — jis padeda riebalams ir skysčiams gerai susimaišyti bei neleidžia šokoladui „žydėti" (kai ant jo atsiranda balta danga). Daugiausia jo rasite šokoladiniuose gaminiuose, saldainių apvalkalamuose ir tortų dekoracijose. Leidžiamas naudoti tik keliose maisto kategorijose ir tokiais kiekiais laikomas saugiu. Jokių rimtų mokslinių ginčų dėl šios medžiagos nėra, o Europos maisto saugos tarnyba (EFSA) nereiškė susirūpinimo dėl jo vartojimo.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 348054;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier — it helps oil and water mix together smoothly and stops products from separating. It''s found in very few food categories, mainly certain jams and similar spreads. Regulatory bodies like EFSA consider it safe at the levels used in food. It''s not a widely debated additive and most people consume very little of it.', opinion_lt = 'Tai sintetinis emulsiklis — jis padeda sumaišyti riebalus ir vandenį bei neleidžia produktui sluoksniuotis. Leidžiama naudoti labai nedaug maisto kategorijų, daugiausia tam tikruose džemuose ir panašiuose tepuose. Europos maisto saugos institucija (EFSA) laiko jį saugiu tomis dozėmis, kurios naudojamos maiste. Tai nėra priedas, apie kurį daug diskutuojama, ir dauguma žmonių jo suvartoja labai nedaug.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 348127;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier, meaning it helps oil and water mix together smoothly in food products. It is derived from sorbitol and oleic acid. You will mostly find it in very specific, niche food applications — it is authorised in only one food category, which limits how often most people encounter it. It is generally considered safe by food safety authorities at the levels used in food.', opinion_lt = 'Tai sintetinis emulsiklis, kuris padeda sujungti riebalus ir vandenį, kad produktas būtų vientisas ir tolygios tekstūros. Jis gaminamas iš sorbitolio ir oleino rūgšties. Kadangi leidžiamas tik vienoje maisto produktų kategorijoje, su juo susiduriama gana retai. Maisto saugos institucijos šį priedą laiko saugiu, kai jis naudojamas leistinosiomis dozėmis.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 348174;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic emulsifier made from sorbitol and palmitic acid (a fatty acid found in palm oil). It helps fats and water mix together smoothly, preventing separation in food products. It is authorised in a very limited number of food categories, which means you will rarely encounter it. Regulatory bodies consider it safe at the levels used in food.', opinion_lt = 'Tai sintetinis emulgatorius, pagamintas iš sorbitolio ir palmitinolio rūgšties (riebalų rūgšties, randamos palmių aliejuje). Jis padeda riebalams ir vandeniui sumaišyti, neleidžia jiems atsiskirti maisto produktuose. Leidžiama naudoti labai nedaugelyje maisto kategorijų, tad vargu ar dažnai jį sutiksite. Maisto saugos institucijos laiko jį saugiu tomis dozėmis, kurios naudojamos maiste.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 348220;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally derived substance extracted from plant oils, belonging to a family of compounds called plant sterols. It is used in very limited food applications, primarily to help manage the texture or stability of certain products. Plant sterols in general are well-studied and are widely recognized for their ability to help reduce LDL cholesterol levels when consumed regularly. At the low levels used as a food additive, it is considered safe for most people, though those with a rare condition called sitosterolemia should avoid plant sterol-enriched products.', opinion_lt = 'Tai natūralios kilmės medžiaga, gaunama iš augalinių aliejų — ji priklauso augalinių sterolių grupei. Maisto pramonėje naudojama labai ribotai, daugiausia tam tikruose alkoholiniuose gėrimuose. Augaliniai steroliai apskritai yra gerai ištirti ir žinomi dėl gebėjimo mažinti „blogojo" LDL cholesterolio kiekį kraujyje. Tokiomis mažomis dozėmis, kokios naudojamos maisto gamyboje, ji laikoma saugia, tačiau žmonės, turintys retą sitosterolemijos ligą, turėtų vengti produktų, praturtintų augaliniais steroliais.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 362679;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a simple mineral salt — baking soda and its close relatives — that has been used in cooking and food production for centuries. It acts as a leavening agent (helps dough rise), acidity regulator, and anti-caking agent, showing up in baked goods, processed foods, and even some meat or seafood products. It is considered very safe for general use, with no notable health controversies. Most people already consume it regularly without any issues.', opinion_lt = 'Tai paprastas mineralinis druska — kepimo soda ir jos artimi giminaičiai — naudojami maisto gaminime šimtmečius. Maiste jis veikia kaip kildiklis (padeda kilti tešlai), rūgštingumo reguliatorius ir sukietėjimo prevencijos priemonė — randamas kepiniuose, perdirbtame maiste, kai kuriuose mėsos ar jūros gėrybių produktuose. Laikomas labai saugiu, jokių reikšmingų sveikatos diskusijų dėl jo nėra. Dauguma žmonių jį vartoja reguliariai ir visiškai be problemų.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 348266;
UPDATE aggregate.eu_additives SET opinion_en = 'This is baking soda — yes, the exact same stuff you probably have at home. It''s a simple mineral salt used as a leavening agent or acidity regulator in food, helping doughs rise and balancing pH in certain dairy products. It''s one of the most harmless additives you''ll encounter in a food label.', opinion_lt = 'Tai yra paprastas kepimo soda — tas pats, kurį tikriausiai turite namuose. Tai mineralinė druska, naudojama kaip kildiklis arba rūgštingumo reguliatorius maiste — padeda tešlai kilti ir reguliuoja pH kai kuriuose pieno produktuose. Tai vienas iš saugiausių priedų, kurį galite rasti ant produkto etiketės.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 364381;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally occurring mineral salt used mainly as an acidity regulator and raising agent in food. It helps control pH levels and can make doughs softer and more workable — it''s historically used in certain breads, noodles, and gingerbread. You''ll also find it in tabletop sweeteners and some processed cereals. It is generally considered safe at the levels used in food, and regulatory bodies like EFSA have not raised significant concerns about its use in approved categories.', opinion_lt = 'Tai natūraliai gamtoje randama mineralo druska, naudojama kaip rūgštingumo reguliatorius ir kildinimo priemonė maiste. Ji padeda palaikyti pH balansą ir minkština tešlą — istoriškai naudojama tam tikrose duonose, makaronuose ir meduoliuose. Taip pat aptinkama stalo saldintuose ir kai kuriuose perdirbtų grūdų produktuose. Laikoma saugia tokiomis dozėmis, kokios naudojamos maiste, ir Europos maisto saugos institucija (EFSA) didelių susirūpinimų dėl jos nekėlė.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 348524;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a simple inorganic salt that acts as a leavening agent and acidity regulator in food. It releases carbon dioxide when heated or mixed with acids, helping baked goods rise. It is a synthetic compound but chemically very similar to naturally occurring bicarbonate salts. Used in very limited food categories, so most people rarely encounter it directly.', opinion_lt = 'Tai paprastas neorganinis druskos junginys, naudojamas kaip kildiklis ir rūgštingumo reguliatorius maiste. Kaitinamas arba sumaišytas su rūgštimis, išskiria anglies dvideginį, todėl kepiniai puikiai kyla. Nors tai sintetinis junginys, jis labai panašus į natūraliai randamas bikarbonato druskas. Leidžiamas tik labai ribotose maisto kategorijose, tad dauguma žmonių su juo tiesiogiai beveik nesusiduria.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 364441;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic leavening agent — it helps baked goods rise by releasing carbon dioxide and ammonia gas when heated. The ammonia evaporates completely during baking, so it doesn''t remain in the finished product. It''s found in certain biscuits, crackers, and some processed foods for infants. Regulatory authorities consider it safe at the levels used in food, and there''s no significant controversy surrounding it.', opinion_lt = 'Tai sintetinis kildiklis — jis padeda kepiniams pakilti, nes kaitinamas išskiria anglies dioksidą ir amoniako dujas. Kepant amoniakas visiškai išgaruoja, todėl galutiniame produkte jo nelieka. Randamas tam tikruose sausainiuose, krekersiuose ir kai kuriuose kūdikių maisto produktuose. Maisto saugos institucijos laiko jį saugiu naudojamais kiekiais, ir reikšmingų ginčų dėl šio priedo nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 348706;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally derived mineral compound used mainly as an acidity regulator and anti-caking agent — it keeps powdered foods like salt from clumping together. You''ll find it in certain cheeses, salt, and edible protein products. It is generally considered safe, with no significant health concerns at typical food use levels. Magnesium itself is an essential mineral your body needs, so this additive carries very little risk.', opinion_lt = 'Tai natūralios kilmės mineralinis junginys, naudojamas kaip rūgštingumo reguliatorius ir sukietėjimo prevencijos priemonė — neleidžia biriems produktams, pavyzdžiui, druskos, sulipti į gumuliukus. Randamas tam tikruose sūriuose, druskoje ir valgomųjų baltymų produktuose. Laikomas saugiu, esant įprastoms dozėms maiste nekeliama jokių rimtų sveikatos rizikų. Magnis yra būtinas organizmui mineralas, todėl šis priedas kelia labai mažai susirūpinimo.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 348792;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a strong acid that might sound alarming, but it''s actually the same acid your stomach naturally produces to digest food. In food processing, it''s used in very small amounts to adjust acidity levels — for example, in the production of certain starch-based or dairy-based products. It doesn''t remain as free acid in the final product; it gets neutralised during processing. Authorised use is strictly limited, especially in baby and young child foods, where safety standards are among the tightest in the industry.', opinion_lt = 'Tai stipri rūgštis, kurios pavadinimas gali nuskambėti baugiai, tačiau iš tikrųjų tai ta pati rūgštis, kurią jūsų skrandis natūraliai gamina maistui virškinti. Maisto pramonėje ji naudojama labai mažais kiekiais rūgštingumui reguliuoti — pavyzdžiui, gaminant tam tikrus krakmolo ar pieno pagrindu pagamintus produktus. Galutiniame produkte laisvos rūgšties nelieka — ji neutralizuojama gamybos proceso metu. Leidžiamas naudojimas yra griežtai ribojamas, ypač kūdikių ir mažų vaikų maiste, kur taikomi vieni griežčiausių saugos standartų.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 348891;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a simple mineral salt — the potassium version of ordinary table salt. It''s used mainly as a salt substitute or flavor enhancer in low-sodium foods, helping reduce sodium content while keeping a salty taste. You''ll find it in reduced-salt products, diet foods, and sometimes sports drinks. It''s a naturally occurring mineral and is considered very safe at the levels used in food. Some people notice a slightly bitter or metallic aftertaste compared to regular salt.', opinion_lt = 'Tai paprastas mineralinis druska — kalio versija, panaši į įprastą valgomąją druską. Naudojama pirmiausia kaip druskos pakaitalas maiste su mažiau natrio — padeda išlaikyti sūrų skonį, bet su mažiau natrio. Rasite ją sumažinto druskingumo produktuose ir dietiniuose maisto produktuose. Tai natūraliai gamtoje randamas mineralas, laikomas visiškai saugiu tomis dozėmis, kurios naudojamos maiste. Kai kurie žmonės pastebi lengvą kartumą ar metalinį prieskonį, lyginant su įprasta druska.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 348964;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a simple mineral salt — calcium chloride — that occurs naturally and is also made synthetically for food use. It serves several purposes: keeping canned fruits and vegetables firm, helping cheese curds form properly, and preventing clumping in dried milk. It is essentially a source of calcium, the same mineral found in dairy products. Regulatory authorities worldwide consider it safe, and it has no notable controversy attached to it. Most people consume it without any issues.', opinion_lt = 'Tai paprastas mineralinis druska — kalcio chloridas — randamas gamtoje ir taip pat gaminamas sintetiškai maisto pramonei. Jis naudojamas keliems tikslams: kad konservuoti vaisiai ir daržovės išliktų tvirti, kad sūrio gamyboje tinkamai susiformuotų varškė, ir kad džiovinto pieno milteliai nesusigumuliuotų. Iš esmės tai kalcio šaltinis — tas pats mineralas, kurio gausu pieno produktuose. Reguliavimo institucijos visame pasaulyje laiko jį saugiu, ir jokios reikšmingos kontroversiškos diskusijos apie jį nėra. Dauguma žmonių jį vartoja be jokių problemų.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 349010;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally occurring mineral salt used in very limited food applications — mainly as a firming agent or processing aid. It''s the same compound found in seawater and is commonly used in traditional tofu production to help the soy protein set properly. It also serves as a magnesium supplement in some contexts. There''s no meaningful safety concern here — it''s a well-understood, straightforward mineral with a long history of safe use in food.', opinion_lt = 'Tai natūraliai gamtoje randamas mineralinis junginys, naudojamas labai ribotai maisto pramonėje — dažniausiai kaip kietinimo medžiaga arba perdirbimo pagalbinė priemonė. Jis plačiai žinomas iš tradicinės tofu gamybos, kur padeda sojos baltymams sukietėti. Tai tas pats junginys, kuris randamas jūros vandenyje. Nėra jokios rimtos priežasties jo bijoti — tai gerai ištirtas mineralas, saugiai naudojamas maiste jau labai seniai.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 349135;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic tin-based compound used in very small amounts to prevent discolouration in canned or bottled fruits and vegetables, keeping them looking fresh rather than turning grey or brown. Its use is quite limited — you''ll really only encounter it in specific canned produce. It is authorised in the EU but only in one narrow food category, which suggests regulators consider it acceptable at low levels for that specific purpose. Most people consume it rarely, if at all.', opinion_lt = 'Tai sintetinis, alavu pagrįstas junginys, naudojamas labai mažais kiekiais, kad konservuoti arba buteliuose supakuoti vaisiai ir daržovės neprarastų spalvos ir neatrodytų pilkšvi ar rusvai parudavę. Jo naudojimas yra labai ribotas — susidursite su juo tik tam tikruose konservuotuose produktuose. ES jis leidžiamas tik vienoje siauroje maisto kategorijoje, o tai rodo, kad reguliuotojai laiko jį priimtinu mažomis dozėmis šiam konkrečiam tikslui. Dauguma žmonių jo suvalgo retai arba visai nevalgo.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 349182;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a strong industrial acid used in very small amounts during food processing — mainly to adjust the acidity level in certain products. It is not something that stays in the final food in any meaningful quantity; it reacts or gets neutralised during production. It is authorised in only one food category, which reflects how limited and specific its use is.

Despite sounding alarming, the trace amounts potentially present pose no known health risk. Food safety authorities consider it acceptable at the levels permitted. That said, it is a synthetic industrial chemical, so some consumers prefer to avoid products where processing aids like this are used.', opinion_lt = 'Tai stipri pramoninė rūgštis, naudojama labai mažais kiekiais maisto gamybos metu — daugiausia rūgštingumo lygiui sureguliuoti. Galutiniame produkte ji praktiškai nelieka, nes gamybos proceso metu sureaguoja arba neutralizuojama. Leidžiama tik vienoje maisto kategorijoje, kas rodo, koks ribotas ir specifinis jos naudojimas.

Nors pavadinimas skamba bauginančiai, tokiuose mažuose kiekiuose ji nelaikoma pavojinga sveikatai. Maisto saugos institucijos ją laiko priimtina leidžiamais kiekiais. Vis dėlto tai sintetinė pramoninė medžiaga, todėl kai kurie vartotojai renkasi vengti produktų, kurių gamyboje naudojami tokie pagalbiniai perdirbimo agentai.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 349229;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic salt derived from sulfuric acid, used mainly as an acidity regulator or processing aid in food production. It rarely ends up in finished products in meaningful amounts, and its permitted use is limited to just one food category, making consumer exposure very low. It is generally considered safe at the levels found in food. Most people will never need to think twice about it.', opinion_lt = 'Tai sintetinė druska, gauta iš sieros rūgšties, naudojama daugiausia kaip rūgštingumo reguliatorius arba pagalbinė medžiaga maisto gamyboje. Ji retai patenka į galutinį produktą reikšmingais kiekiais, o jos naudojimas leidžiamas tik vienoje maisto kategorijoje, todėl vartotojų poveikis yra labai mažas. Laikoma saugia tomis dozėmis, kurios aptinkamos maiste. Dauguma žmonių apie šį priedą niekada net nepagalvos.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 349275;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a potassium salt of sulphuric acid, used mainly as a stabiliser or acidity regulator in food. It helps control the pH and texture of certain products. It is authorised in very few food categories, meaning you are unlikely to encounter it often. It is generally considered safe at the levels used in food, and regulatory bodies like EFSA have not raised significant concerns about it.', opinion_lt = 'Tai kalio druska, gaunama iš sieros rūgšties, naudojama maiste kaip rūgštingumo reguliatorius arba stabilizatorius. Ji padeda palaikyti tinkamą pH lygį ir tekstūrą tam tikruose produktuose. Leidžiama labai nedaug maisto kategorijų, tad kasdienėje mityboje su ja susidursite retai. Europinės maisto saugos institucijos (EFSA) šio priedo nenurodo kaip keliančio rimtesnį susirūpinimą, ir jis laikomas saugiu tokiais kiekiais, kokiais naudojamas maiste.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 349321;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally occurring mineral compound used mainly as a firming agent or stabiliser in food. It helps maintain texture and structure, and is also used as a calcium supplement in some products. You might find it in tofu, baked goods, or certain dietary foods. It is authorised in very few food categories, meaning its use is quite limited.', opinion_lt = 'Tai natūralios kilmės mineralinis junginys, naudojamas maiste kaip kietiklis arba stabilizatorius. Jis padeda išlaikyti produkto tekstūrą ir struktūrą, o kartais naudojamas ir kaip kalcio šaltinis. Galite jį rasti tofu, kepiniuose ar kai kuriuose dietiniuose produktuose. Leidžiama jį naudoti labai nedaug maisto kategorijų, tad jo vartojimas gana ribotas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 349367;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic inorganic salt used mainly as a flour treatment agent and dough conditioner in baking. It helps yeast work more efficiently and improves the texture of bread. It is authorised in very few food categories, meaning your exposure through food is quite limited. Regulatory authorities consider it safe at the low levels used in food production.', opinion_lt = 'Tai sintetinė neorganinė druska, dažniausiai naudojama kepiniuose kaip miltų pagerintojas ir tešlos kondicionierius. Ji padeda mielėms veikti efektyviau ir gerina duonos tekstūrą. Leidžiama labai nedaugelyje maisto kategorijų, todėl su maistu jo suvartojate tikrai nedaug. Maisto saugos institucijos laiko jį saugiu tomis nedidelėmis dozėmis, kurios naudojamos maisto gamyboje.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 349413;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic inorganic salt used as a firming agent, helping food hold its texture and structure during processing. It is authorised in a very narrow range of products — mainly processed egg products — so most people will rarely encounter it. There is ongoing scientific discussion about dietary aluminium intake in general, as aluminium can accumulate in the body over time. At the low levels permitted in food, regulators consider it safe, but those wishing to minimise aluminium exposure may want to check product labels.', opinion_lt = 'Tai sintetinis neorganinis druskas, naudojamas kaip kietinimo medžiaga — padeda maistui išlaikyti tekstūrą ir formą perdirbimo metu. Leidžiama jį naudoti labai siauroje produktų grupėje, daugiausia perdirbtų kiaušinių produktuose, tad dauguma žmonių su juo susidurs retai. Mokslininkų tarpe vyksta diskusijos apie bendrą aliuminio kiekį mityboje, nes aliuminis gali kauptis organizme. Esant leistinam maisto lygiui, reguliavimo institucijos laiko jį saugiu, tačiau norintys riboti aliuminio vartojimą turėtų atkreipti dėmesį į produktų etiketes.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 349459;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic salt combining aluminium, sodium, and sulphate. It acts as a firming agent and acidity regulator, sometimes used in baking powders or pickled vegetables to keep texture crisp. It is authorised in very few food categories, so most people rarely encounter it. The aluminium content draws some attention, as high aluminium intake over time is a topic of ongoing scientific discussion, but at permitted levels in food it is considered safe by European food authorities.', opinion_lt = 'Tai sintetinė druska, jungianti aliuminį, natrį ir sulfatą. Ji naudojama kaip kietiklis ir rūgštingumo reguliatorius — kartais kepimo milteliuose ar marinuotuose produktuose, kad išlaikytų traškią tekstūrą. Leidžiama labai mažame maisto kategorijų skaičiuje, tad dauguma žmonių su ja retai susiduria. Aliuminio kiekis šiame junginyje kelia tam tikrų mokslinių diskusijų dėl ilgalaikio poveikio, tačiau leidžiamomis dozėmis Europos maisto saugos institucijos jį laiko saugiu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 349565;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a mineral salt — a combination of aluminium, potassium, and sulphate — used as an acidity regulator and firming agent. It helps keep certain foods firm and stable, and is only permitted in a very narrow range of products. Because it contains aluminium, some health bodies recommend limiting overall dietary aluminium intake, particularly for vulnerable groups like children and people with kidney issues. At the tiny amounts used in food, most regulatory agencies consider it safe for the general population.', opinion_lt = 'Tai mineralinė druska — aliuminio, kalio ir sulfato junginys — naudojama kaip rūgštingumo reguliatorius ir standumo palaikymo priemonė. Ji leidžiama tik labai nedaugelyje maisto produktų kategorijų. Kadangi sudėtyje yra aliuminio, kai kurios sveikatos institucijos rekomenduoja riboti bendrą aliuminio kiekį mityboje, ypač vaikams ir žmonėms, turintiems inkstų problemų. Tačiau tokiais mažais kiekiais, kokie naudojami maiste, dauguma reguliavimo institucijų laiko jį saugiu plačiajai visuomenei.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 349611;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic mineral salt used as a firming agent and stabiliser in food. It helps food hold its shape and texture, and can also act as an acidity regulator. It is only authorised in a very limited number of food categories, so most people rarely encounter it. At the low levels permitted in food, it is generally considered safe, though aluminium-containing additives are monitored with some caution due to ongoing research into aluminium accumulation in the body over time.', opinion_lt = 'Tai sintetinė mineralinė druska, naudojama kaip kietiklis ir stabilizatorius maiste. Ji padeda išlaikyti produktų formą ir tekstūrą, taip pat gali reguliuoti rūgštingumą. Leidžiama naudoti labai ribotame skaičiuje maisto kategorijų, todėl dauguma žmonių su ja beveik nesusiduria. Leidžiamomis dozėmis laikoma saugia, tačiau aliuminio junginiai maiste stebimi atsargiai, nes mokslininkai toliau tiria, kaip ilgalaikis aliuminio kaupimasis organizme gali paveikti sveikatą.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 349657;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a strong alkaline compound — commonly known as lye — used in food processing to adjust acidity levels and treat surfaces of certain foods. It helps give some breads and pretzels their characteristic chewy crust, and is also used to regulate pH in jams, spreads, and dairy products. It is not typically present in the final product in significant amounts, as it reacts during processing. Regulatory authorities consider it safe at the levels used in food production.', opinion_lt = 'Tai stipri šarminė medžiaga, paprastai vadinama šarmu arba soda kaustine, naudojama maisto perdirbime rūgštingumui reguliuoti ir kai kurių produktų paviršiui apdoroti. Ji suteikia kai kurioms duonos rūšims ir precelkėms būdingą traškią plutelę, taip pat naudojama džemuose, užtepuose ir pieno produktuose pH lygiui palaikyti. Galutiniame produkte jos paprastai lieka labai mažai, nes ji sureaguoja perdirbimo metu. Maisto saugos institucijos šią medžiagą laiko saugia tokiais kiekiais, kokie naudojami maisto gamyboje.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 349703;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a strong alkaline compound used in food processing mainly to adjust acidity levels — it helps create the right pH in certain foods rather than being a flavour or preservative ingredient. You''ll find it in products like processed baby foods, milk-based drinks for young children, and edible caseinates, where precise acidity control matters for safety and texture. Because it''s used in small, carefully regulated amounts and largely neutralises during processing, it doesn''t pose a concern for most consumers. Regulatory authorities consider it safe at the permitted levels.', opinion_lt = 'Tai stipri šarminė medžiaga, naudojama maisto pramonėje daugiausia rūgštingumo lygiui koreguoti — ji padeda pasiekti tinkamą pH, o ne suteikia skonį ar konservuoja produktą. Tokią sudedamąją dalį galima rasti perdirbtuose kūdikių maisto produktuose, pieno pagrindu pagamintuose gėrimuose mažiems vaikams ir valgomiesiems kazeinatuose, kur tikslus rūgštingumas svarbus saugumui ir tekstūrai. Kadangi ji naudojama mažais, griežtai reglamentuotais kiekiais ir perdirbimo metu iš esmės neutralizuojasi, daugumai vartotojų ji nekelia susirūpinimo. Reguliavimo institucijos laiko ją saugu leistinosiomis dozėmis.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 349879;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a simple mineral compound — basically lime dissolved in water — that has been used in food preparation for centuries. It helps adjust acidity, firm up textures, and is a key ingredient in traditional nixtamalisation, the ancient process of treating corn to make tortillas and similar foods. It is also used in a handful of specialised products like processed cereals and caseinates. Considered very safe at the low levels found in food, and it even contributes a small amount of dietary calcium.', opinion_lt = 'Tai paprastas mineralinis junginys — iš esmės vandenyje ištirpintos kalkės — naudojamas maisto ruošimoje jau šimtmečius. Jis reguliuoja rūgštingumą, suteikia produktams standesnę tekstūrą ir yra svarbi nixtamalizacijos proceso dalis — senos tradicijos, kai kukurūzai apdorojami gaminant tortiljas ir panašius patiekalus. Naudojamas ir keliuose specializuotuose produktuose, pavyzdžiui, perdirbtų javų maiste ir kazeinatuose. Tokiais kiekiais, kokiais jis aptinkamas maiste, laikomas visiškai saugiu, be to, suteikia šiek tiek kalcio.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 349978;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic alkaline compound — essentially ammonia dissolved in water — used to regulate acidity in food processing. It helps adjust pH levels so that proteins and other ingredients behave correctly during manufacturing. It is permitted in a very limited range of products, mainly edible caseinates, which are milk-derived proteins used in processed foods. At the low levels used in food production, it is considered safe by major food authorities, and it does not remain in significant amounts in the final product.', opinion_lt = 'Tai sintetinis šarminis junginys — iš esmės amoniakas, ištirpintas vandenyje — naudojamas rūgštingumui reguliuoti maisto gamyboje. Jis padeda sureguliuoti pH lygį, kad baltymai ir kiti ingredientai tinkamai elgtųsi perdirbimo metu. Leidžiamas labai ribotame produktų sąraše, daugiausia valgomajame kazeinате — pieno baltymuose, naudojamuose perdirbtuose maisto produktuose. Tokiais mažais kiekiais, kokie naudojami maisto gamyboje, pagrindinės maisto saugos institucijos jį laiko saugiu, o galutiniame produkte jo beveik nelieka.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 350064;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally occurring mineral compound used in very few food products — mainly as an acidity regulator in edible caseinates, which are protein-based food ingredients. It works by neutralising acids and controlling pH levels during processing. It is the same compound found in many antacid medicines and milk of magnesia. Regulatory bodies consider it safe at the levels used in food, and there is no significant controversy surrounding it.', opinion_lt = 'Tai natūralios kilmės mineralinis junginys, naudojamas labai nedaugelyje maisto produktų — daugiausia kaip rūgštingumo reguliatorius kazeinatuose, kurie yra baltymų pagrindu pagaminti maisto ingredientai. Jis neutralizuoja rūgštis ir kontroliuoja pH lygį perdirbimo metu. Tas pats junginys randamas daugelyje nuo rėmenų skirtų vaistų. Maisto saugos institucijos laiko jį saugiu tokiais kiekiais, kokiais jis naudojamas maiste, ir jokių reikšmingų diskusijų dėl jo nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 350115;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a mineral compound, commonly known as quicklime, used in very limited food applications as an acidity regulator. It helps control the pH of certain foods during processing, ensuring texture and stability. It is authorised in only one food category, meaning most people will rarely encounter it in everyday products. At the tiny levels permitted in food, it is generally considered safe by food safety authorities.', opinion_lt = 'Tai mineralinis junginys, paprastai žinomas kaip negesintos kalkės, naudojamas labai ribotose maisto srityse kaip rūgštingumo reguliatorius. Jis padeda palaikyti tinkamą pH tam tikruose maisto produktuose perdirbimo metu, užtikrinant tekstūrą ir stabilumą. Leidžiamas tik vienoje maisto kategorijoje, todėl dauguma žmonių jo beveik nesutiks kasdienėse prekėse. Tokiomis mažomis kiekiais, kokios leidžiamos maiste, maisto saugos institucijos jį laiko saugiu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 350166;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally derived mineral compound used as an anti-caking agent, meaning it stops powders and granulated products like salt or cocoa from clumping together. It has a long history of safe use and is even found in antacid medicines and dietary supplements. Approved for use in a very limited range of food categories, so you won''t encounter it often. Considered safe at the low levels used in food.', opinion_lt = 'Tai natūralios kilmės mineralinis junginys, naudojamas kaip sukietėjimą stabdanti medžiaga – jis neleidžia druskos ar kakavos miltelių susigumuliuoti. Turi ilgą saugaus naudojimo istoriją, be to, randamas ir vaistiniuose antacidiniuose preparatuose bei maisto papilduose. Leidžiamas tik labai ribotose maisto kategorijose, tad susidursite su juo retai. Tokiais kiekiais, kokiais jis naudojamas maiste, laikomas saugiu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 350212;
UPDATE aggregate.eu_additives SET opinion_en = 'This is an iron supplement used in salt and salt substitutes to help fortify foods with iron, an essential mineral many people lack in their diets. It is a synthetic compound, but iron itself is a natural and necessary nutrient. Its use is quite limited and specific, so most people encounter it rarely. It is generally considered safe at the levels permitted in food.', opinion_lt = 'Tai geležies papildas, naudojamas druskoje ir druskos pakaitaluose, siekiant praturtinti maistą geležimi — mineraline medžiaga, kurios daugeliui žmonių trūksta. Junginys yra sintetinis, tačiau pati geležis yra natūralus ir būtinas maistingoji medžiaga. Šis priedas naudojamas labai ribotai, tad dauguma žmonių su juo susiduria retai. Leidžiamais kiekiais maiste laikomas saugiu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 362573;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic salt used in tiny amounts as an anti-caking agent, meaning it stops salt crystals from clumping together. You''ll find it almost exclusively in table salt and some salt-based seasoning products. Despite its intimidating name containing the word ''cyanide'', the cyanide is tightly bound and not released in normal conditions — it is not the same as toxic cyanide compounds. Regulatory bodies in Europe consider it safe at the very low levels permitted in food.', opinion_lt = 'Tai sintetinis junginys, naudojamas kaip sukietėjimo (sukepimo) inhibitorius — jis neleidžia druskos kristalams sulipti į gumuliukus. Rasite jį beveik išskirtinai valgomojoje druskoje ir kai kuriuose prieskonių mišiniuose. Nepaisant bauginančio pavadinimo su žodžiu ''cianidas'', čia cianidas yra labai tvirtai surištas ir normaliomis sąlygomis neišsiskiria — tai visiškai kitoks junginys nei nuodingieji cianidai. Europos maisto saugos institucijos mano, kad tokiais mažais kiekiais jis yra saugus.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 350272;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic anti-caking agent, meaning it stops salt from clumping together and keeps it free-flowing. It is authorised for use in salt only, and the amounts permitted are very small. Despite its intimidating chemical name containing the word ''cyanide'', it is a stable compound and the cyanide is tightly bound — it does not behave like the toxic form. Regulatory bodies in the EU consider it safe at permitted levels.', opinion_lt = 'Tai sintetinis priedas, naudojamas druskoje, kad ji nesusigumuluotų ir liktų biri. Nors pavadinime yra žodis „cianidas", tai stabili cheminė medžiaga — laisvų toksiškų cianidų ji neišskiria. Leistini kiekiai yra labai maži. ES maisto saugos institucijos šį priedą laiko saugiu, kai jo naudojama pagal normas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 350380;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic anti-caking agent, meaning it stops salt from clumping together and keeps it flowing freely. You''ll find it used in table salt and certain salt-based products — that''s essentially the only food category it''s approved for. Despite the intimidating name containing "cyano," the ferrocyanide form is chemically stable and considered safe at the tiny amounts used. Regulatory bodies like EFSA have evaluated it and found no significant health concern at normal dietary exposure.', opinion_lt = 'Tai sintetinis sukietėjimą stabdantis priedas — jo užduotis paprasta: neleidžia druską sulipti ir palaiko ją birioje. Rasite jį beveik išimtinai valgomojoje druskoje ir kai kuriuose druskos produktuose — tai vienintelė maisto kategorija, kurioje jis leidžiamas. Pavadinimas su žodžiu „ciano" skamba baugiai, tačiau ferrocianido forma yra chemiškai stabili ir tokiais mažais kiekiais nekelia grėsmės sveikatai. Europos maisto saugos institucija EFSA įvertino šį priedą ir nerado reikšmingos rizikos įprastoje mityboje.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 350426;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic leavening agent used in baking — it helps dough rise and gives baked goods a lighter texture. You''ll mainly find it in cakes, muffins, pancake mixes, and similar fine bakery products. The concern here is aluminium content, as regular dietary aluminium exposure has been linked to health questions, particularly regarding kidney function and neurological effects in vulnerable groups. Regulators consider it safe at approved levels, but some health bodies recommend minimising aluminium intake where possible.', opinion_lt = 'Tai sintetinis kildiklis, naudojamas kepiniuose — jis padeda tešlai kilti ir suteikia gaminiams lengvesnę tekstūrą. Dažniausiai randamas pyragaičiuose, keksukuose, blynų milteliuose ir panašiuose kepinių gaminiuose. Nerimą kelia aliuminio kiekis: nuolatinis aliuminio vartojimas maiste siejamas su klausimais dėl inkstų funkcijos ir galimo poveikio nervų sistemai, ypač pažeidžiamoms grupėms. Reguliuotojai laiko jį saugiu leidžiamomis dozėmis, tačiau kai kurios sveikatos institucijos rekomenduoja kiek įmanoma mažinti aliuminio patekimą į organizmą.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 350472;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic mineral compound — basically a very fine, powdery form of silica, the same material found naturally in sand and quartz. In food, it works as an anti-caking agent, keeping powdered or granulated products from clumping together. You will find it in things like powdered spices, salt, and chewing gum. It is considered safe by major food authorities worldwide, passes through the body without being absorbed, and there is no significant controversy around its use at permitted levels.', opinion_lt = 'Tai sintetinis mineralinis junginys — iš esmės labai smulki silicio dioksido miltelių forma, panaši į medžiagą, randamą smėlyje ar kvarcе. Maiste ji naudojama kaip sukietėjimą stabdanti medžiaga — neleidžia milteliams ar granuliuotiems produktams sulipti. Rasite ją maltuose prieskonuose, druskoje, kramtomojoje gumoje. Pagrindinės maisto saugos institucijos visame pasaulyje ją laiko saugia — organizmas jos nepasisavina ir ji paprasčiausiai pasišalina. Jokių reikšmingų kontraversijų dėl šio priedo leidžiamose dozėse nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 350519;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic mineral compound used as an anti-caking agent — it keeps powdered and granulated foods from clumping together. In chewing gum, it helps maintain texture and consistency during production and storage. It is authorised in very few food categories, so most people encounter it rarely. It is generally considered safe at the levels used in food, and regulatory bodies worldwide have not raised significant concerns about it.', opinion_lt = 'Tai sintetinis mineralinis junginys, naudojamas kaip sukietėjimo inhibitorius — jis neleidžia miltelių ar granulių pavidalo produktams susigumuliuoti. Kramtomojoje gumoje jis padeda išlaikyti tekstūrą ir konsistenciją gamybos bei laikymo metu. Leidžiamas tik labai nedaugelyje maisto kategorijų, tad dauguma žmonių su juo susiduria retai. Naudojamais kiekiais jis laikomas saugiu, o pasaulinės reguliavimo institucijos rimtesnio susirūpinimo dėl jo nereiškia.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 350648;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic mineral compound used as an anti-caking agent — it keeps powdered or solid ingredients from clumping together. You''ll mainly find it in chewing gum, where it helps maintain texture and prevent sticking during production. It is not absorbed by the body and simply passes through the digestive system. Regulatory agencies consider it safe at the levels used in food.', opinion_lt = 'Tai sintetinis mineralinis junginys, naudojamas kaip sukietėjimą stabdanti medžiaga — ji neleidžia milteliniams ar kietiems ingredientams sulipti. Dažniausiai randamas kramtomojoje gumoje, kur padeda išlaikyti tekstūrą ir apsaugo nuo lipimo gamybos metu. Organizmas jo nepasisavina — jis tiesiog praeina per virškinimo sistemą. Maisto saugos institucijos laiko jį saugiu tokiais kiekiais, kokie naudojami maiste.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 350696;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally occurring mineral — a very fine white powder used in food mainly as an anti-caking agent and coating, helping products stay dry, free-flowing, and non-sticky. You''ll find it in chewing gum coatings, processed meats, grain products, and egg products. It keeps surfaces smooth and prevents clumping during production and storage. It is generally considered safe for use in food at authorised levels by European regulators. However, it is a mineral with no nutritional value, and some health discussions exist around industrial talc in non-food contexts, though food-grade versions are held to strict purity standards.', opinion_lt = 'Tai natūralios kilmės mineralas — labai smulkūs balti milteliai, naudojami maiste kaip priešsulipimo priemonė ir dangalas. Jis padeda produktams išlikti sausiems, biriais ir nelipniems. Rasit jį kramtomojoje gumoje, perdirbtoje mėsoje, grūdiniuose produktuose ir kiaušinių gaminiuose. Europos reguliuotojai šį priedą laiko saugiu, kai naudojamas leistinomis dozėmis. Verta žinoti, kad tai mineralas be jokios maistinės vertės, tačiau maistui skirtos jo rūšys atitinka griežtus grynumo reikalavimus, todėl nerimo dėl kasdienio vartojimo nėra pagrindo.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 350744;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic anti-caking agent, meaning its only job is to stop powdered or granular products like salt from clumping together on the shelf. It works by absorbing moisture and keeping the particles free-flowing. You''ll find it mainly in table salt and some other powdered food products. It contains aluminium, which has been a subject of ongoing scientific discussion regarding long-term dietary exposure, but at the very low levels used in salt, regulatory bodies like EFSA consider it safe for general use.', opinion_lt = 'Tai sintetinis sukietėjimą stabdantis priedas — jo vienintelė užduotis yra neleisti druske ar kitiem biriais produktais sukepti laikant parduotuvėje. Jis sugeria drėgmę ir palaiko birių dalelių laisvą tekėjimą. Randamas daugiausia valgomojoje druskoje. Sudėtyje yra aliuminio, dėl kurio ilgalaikio poveikio mokslinėse diskusijose vis dar diskutuojama, tačiau tokiais mažais kiekiais, kokie naudojami druskoje, Europos maisto saugos institucija (EFSA) jį laiko saugiu vartoti.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 350866;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a mineral-based anti-caking agent, meaning it stops powdery foods from clumping together. It is synthetic but closely related to naturally occurring minerals. You''ll most likely find it in table salt or powdered food products where free-flowing texture matters. It is authorised in very few food categories, so exposure is quite limited. Regulatory bodies consider it safe at the levels used in food.', opinion_lt = 'Tai mineralinės kilmės priedas, kuris neleidžia milteliams sulipti į gumuliukus. Jis sintetinis, tačiau artimas gamtoje randamiems mineralams. Dažniausiai jį rasite valgomojoje druskoje ar milteliniuose produktuose, kuriems svarbu likti biriais. Leidžiamas tik labai nedaugelyje maisto kategorijų, tad jo vartojama tikrai nedaug. Reguliavimo institucijos laiko jį saugiu tokiais kiekiais, kokiais jis naudojamas maiste.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 350913;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic anti-caking agent, meaning it stops powdered or granulated foods from clumping together. It is made from calcium, aluminium, and silicon compounds. You would typically find it in table salt or certain powdered food products to keep them free-flowing. It is authorised in only one food category, so your exposure to it is likely very limited. It is generally considered safe at the low levels used in food, though some people prefer to limit aluminium-containing additives out of general caution.', opinion_lt = 'Tai sintetinis sukietėjimą stabdantis priedas – jo užduotis yra neleisti milteliams ar grūdeliams sulipti. Jis gaminamas iš kalcio, aliuminio ir silicio junginių. Dažniausiai jo galima rasti valgomojoje druskoje ar kai kuriuose miltelių pavidalo produktuose. Leidžiamas tik vienoje maisto kategorijoje, tad kasdienė jo dozė paprastai būna labai maža. Manoma, kad toks kiekis yra saugus, nors kai kurie žmonės iš atsargumo stengiasi apriboti aliuminio turinčius priedus savo mityboje.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 350959;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally occurring clay mineral used as a clarifying and filtering agent in winemaking. It helps remove proteins and other unwanted particles from wine, leaving it clear and stable. It is not actually present in the final product — it is filtered out before the wine reaches the bottle. Considered safe, as consumers are not exposed to any meaningful residues.', opinion_lt = 'Tai natūralios kilmės molio mineralas, naudojamas vyno gamyboje kaip filtravimo ir grynimo priemonė. Jis pašalina baltymus ir kitas nepageidaujamas daleles iš vyno, padarydamas jį skaidrų ir stabilų. Galutiniame produkte jo nelieka — prieš pilstant vyną į butelius jis išfiltruojamas. Laikomas saugiu, nes vartotojas su jo likučiais praktiškai nesusiduria.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 351005;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally occurring mineral, a type of fine white clay, used as an anti-caking agent to keep powdered or granulated foods flowing freely and prevent clumping. It is authorised in very few food categories, mainly certain types of hard-coated confectionery. At the low levels used in food, it is generally considered safe by regulatory bodies like EFSA.', opinion_lt = 'Tai natūralios kilmės mineralas — smulki balta molis, naudojama kaip sukietėjimą stabdanti medžiaga, kad milteliai ar granulės nesusigumuluotų ir laisvai birstų. Maiste ji leidžiama labai nedaugelyje kategorijų, daugiausia tam tikruose cukraus glaistu dengtuose saldainiuose. Tokiomis mažomis dozėmis, kokios naudojamos maiste, reguliavimo institucijos, pavyzdžiui, EFSA, laiko ją saugia.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 351051;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a group of naturally occurring substances derived from fats, used mainly as an anti-caking agent or glazing agent in food. It helps keep powdered or solid foods from clumping together and gives certain products a smooth surface finish. You might find it in chewing gum, some tablet-form supplements, or confectionery coatings. It is authorised in only a very limited number of food categories, which reflects its narrow, specific use.', opinion_lt = 'Tai natūralios kilmės medžiagos, gaunamos iš riebalų, naudojamos maiste daugiausia kaip sukietėjimą stabdantis arba glazūravimo priedas. Jos padeda milteliams ar kietiems produktams nesusigumuliuoti ir suteikia kai kuriems gaminiams lygų paviršių. Tokio priedo galima rasti kramtomojoje gumoje, kai kuriuose maisto papilduose tabletėse ar saldainių dangaluose. Jis leidžiamas tik labai ribotame maisto kategorijų skaičiuje, o tai rodo siaurą ir specifinį jo naudojimą.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 351097;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a mild organic acid that occurs naturally in honey, fruit, and wine. In food, it is used as an acidity regulator, helping to control pH and improve texture in certain products. It is authorised in a very limited number of food categories, which reflects its narrow practical use. It is generally considered safe, with no notable health concerns associated with normal dietary exposure.', opinion_lt = 'Tai švelni organinė rūgštis, natūraliai randama meduje, vaisiuose ir vyne. Maisto pramonėje ji naudojama kaip rūgštingumo reguliatorius – padeda palaikyti tinkamą pH ir pagerinti kai kurių produktų tekstūrą. Ji leidžiama labai nedaugelyje maisto kategorijų, ką atspindi ir ribotas jos praktinis pritaikymas. Paprastai laikoma saugia – jokių žinomų sveikatos problemų, susijusių su įprastu vartojimu, nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 351143;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally occurring substance derived from glucose — it acts as a gentle acidifier and leavening agent in food. When it dissolves, it slowly releases a mild acid, which is useful for setting cheeses, firming tofu, preserving canned vegetables, and giving fresh pasta its structure. It is also found in tabletop sweetener products as a bulking or stabilising agent. It is generally considered safe by food safety authorities, has a clean label reputation, and does not raise significant health concerns for most people.', opinion_lt = 'Tai natūralios kilmės medžiaga, gaunama iš gliukozės — maiste ji naudojama kaip švelnus rūgštiklis ir kildiklis. Tirpdama ji lėtai išskiria silpną rūgštį, kuri padeda sutirštinti sūrius, kietinti tofū, konservuoti daržoves ir suteikti struktūrą šviežioms makaronų gaminiams. Taip pat randama staliniuose saldintuose kaip stabilizuojanti medžiaga. Maisto saugos institucijos ją laiko saugia, ji neturi prieštaringos reputacijos ir didžiajai daliai žmonių nekelia jokio susirūpinimo.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 351189;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the sodium salt of gluconic acid, a naturally occurring acid found in fruit, honey, and wine. It acts as a sequestrant, meaning it binds to minerals in food to prevent unwanted reactions, and also works as a flavour enhancer or acidity regulator in small amounts. It appears in very few food products — mainly powdered and tablet sweeteners. It is generally considered safe, with no significant controversy around it at normal dietary exposure levels.', opinion_lt = 'Tai gliukoninės rūgšties natrio druska — ši rūgštis natūraliai randama vaisiuose, meduje ir vyne. Maiste ji veikia kaip sekvestrantas, t. y. suriša mineralus ir neleidžia jiems sukelti nepageidaujamų reakcijų, taip pat gali šiek tiek koreguoti skonį ar rūgštingumą. Sutinkama labai retai — daugiausia miltelių arba tablečių pavidalo saldintuose. Laikoma saugia, jokių reikšmingų diskusijų ar susirūpinimo dėl šio priedo nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 351366;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the potassium salt of gluconic acid, a naturally occurring organic acid found in fruits and honey. It is used mainly as a mineral supplement and mild buffering agent, helping to stabilise acidity in foods. You will mostly find it in tabletop sweetener products. It is generally considered safe, with no significant health concerns at typical dietary levels.', opinion_lt = 'Tai gliukono rūgšties kalio druska — gliukono rūgštis natūraliai randama vaisiuose ir meduje. Ši medžiaga naudojama kaip mineralinis priedas ir švelnus rūgštingumą stabilizuojantis agentas. Dažniausiai ją rasite staliniuose saldintuose — tabletėse ar miltelių pavidalo. Laikoma saugia, rimtesnių sveikatos keliamų susirūpinimų nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 351426;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a calcium salt of gluconic acid, a naturally derived compound formed through the fermentation of glucose. It acts as a firming agent, acidity regulator, and mineral supplement in food. You''ll mostly find it in tabletop sweetener products, where it helps give the powder or tablet its stable, consistent texture. It is generally considered safe and is even used medically to treat calcium deficiency, which gives a good indication of its low risk profile.', opinion_lt = 'Tai kalcio druska, gauta iš gliukoninės rūgšties — natūralaus junginio, kuris susidaro fermentuojant gliukozę. Maiste ji naudojama kaip rūgštingumo reguliatorius, kietinimo medžiaga ir mineralinis priedas. Dažniausiai ją rasite stalo saldiklių milteliuose ar tabletėse, kur ji padeda išlaikyti stabilią tekstūrą. Ši medžiaga laikoma saugia — ji netgi naudojama medicinoje kalcio trūkumui gydyti, todėl kasdienėse maisto produktų dozėse jokio pavojaus nekelia.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 351486;
UPDATE aggregate.eu_additives SET opinion_en = 'This is an iron salt used primarily to preserve and stabilise the dark colour of certain olives and pickled vegetables. It''s a synthetic compound but iron-based, so it''s sometimes seen as a mineral supplement too. It''s found mainly in canned or bottled olives and brined vegetables. Regulators consider it safe at approved levels, and it''s used in a very narrow range of foods, so most people encounter it rarely.', opinion_lt = 'Tai geležies druska, naudojama tam tikrų alyvuogių ir marinuotų daržovių tamsiai spalvai išlaikyti ir stabilizuoti. Junginys sintetinis, tačiau geležies pagrindu, todėl kartais laikomas ir mineralų šaltiniu. Dažniausiai randamas konservuotose arba sūryme laikytose alyvuogėse ir daržovėse. Reguliuotojai laiko jį saugiu leidžiamomis dozėmis, o kadangi naudojamas labai siauroje maisto produktų grupėje, dauguma žmonių su juo susiduria retai.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 351546;
UPDATE aggregate.eu_additives SET opinion_en = 'This is an iron salt derived from lactic acid, used to help preserve the colour of certain pickled or canned vegetables and fruits — keeping them looking fresh and green rather than dull. It also adds a small amount of iron to the food, which is a mineral your body needs. It is found in a narrow range of products, mainly pickled or brined vegetables and canned fruit. It is considered safe at the levels permitted in food and is not associated with any significant health concerns for most people.', opinion_lt = 'Tai geležies druska, gauta iš pieno rūgšties — naudojama tam, kad marinuotos ar konservuotos daržovės ir vaisiai išlaikytų gražią, ryškią spalvą ir neatrodytų blyškiai. Be to, ji į maistą įneša nedidelį kiekį geležies — mineralinės medžiagos, kurios mūsų organizmui reikia. Randama siauroje produktų grupėje: daugiausia marinuotose daržovėse, sūryme ar konservuotuose vaisiuose. Leidžiamose dozėse laikoma saugia ir didesniam susirūpinimui priežasties nekelia.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 351606;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic compound used specifically to prevent browning and discolouration in fresh shellfish like shrimp, lobster, and crabs. Without it, the shells and flesh can turn an unappetising grey or black colour very quickly after harvest. It is authorised in the EU but only for this one narrow use. Safety evaluations have generally found it acceptable at permitted levels, though it is not widely studied compared to more common additives.', opinion_lt = 'Tai sintetinis junginys, naudojamas tam, kad šviežių jūros gėrybių — krevetių, omarų, krabų — lukštai ir mėsa nepajuoduotų ar nepilkėtų po sugavimo. Be jo jūros gėrybės greitai praranda patrauklią išvaizdą. ES jis leidžiamas tik šiai vienai konkrečiai paskirčiai. Saugumo vertinimai leidžiamose dozėse paprastai nedaro rimtų priekaištų, tačiau tai nėra itin plačiai tyrinėtas priedas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 351666;
UPDATE aggregate.eu_additives SET opinion_en = 'This is an amino acid that occurs naturally in many protein-rich foods like meat, cheese, tomatoes, and mushrooms. It acts as a flavour enhancer, giving food that savoury, mouth-filling taste often called umami. The synthetic form used as an additive works the same way. It is authorised in very few food categories, so you won''t encounter it often. Regulatory bodies consider it safe for the general population at normal dietary levels.', opinion_lt = 'Tai aminorūgštis, natūraliai randama daugelyje baltymingų maisto produktų – mėsoje, sūryje, pomidoruose, grybуose. Maisto pramonėje ji naudojama kaip skonio stipriklis, suteikiantis patiekalams sodrų, vadinamąjį umami skonį. Sintetinė jos forma veikia lygiai taip pat kaip natūrali. Kadangi leidžiama naudoti labai nedaug maisto kategorijų, retai ją rasite sudėtyje. Reguliavimo institucijos laiko ją saugia įprastomis vartojimo dozėmis.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 351713;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a flavour enhancer — a sodium salt of glutamic acid — that makes savoury foods taste richer and more satisfying. It occurs naturally in tomatoes, parmesan, and soy sauce, but the additive form is produced by fermentation. It''s common in instant noodles, soups, snacks, and fast food seasoning. There has been long-running debate about sensitivity reactions like headaches, but large-scale reviews by food safety authorities have not confirmed a clear causal link at normal dietary levels.', opinion_lt = 'Tai skonio stipriklis — glutamo rūgšties druskos pavidalu — kuris verčia sūrius patiekalus skonyti sodresnius ir apetitingiau. Natūraliai jis randamas pomidoruose, parmezane ir sojos padaže, tačiau maisto priedas gaminamas fermentacijos būdu. Dažniausiai sutinkamas greitai paruošiamų makaronų, sriubų, užkandžių ir greito maisto prieskonių sudėtyje. Jau seniai diskutuojama apie galimas reakcijas — galvos skausmus ar taip vadinamą „kinų restorano sindromą" — tačiau maisto saugos institucijų atliktose apžvalgose aiškaus priežastinio ryšio esant įprastoms dozėms nerasta.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 351828;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the potassium salt form of glutamic acid, a naturally occurring amino acid found in many foods. It works as a flavour enhancer, boosting the savoury, umami taste in food — similar to its more famous cousin, monosodium glutamate, but with potassium instead of sodium. It is authorised in very few food categories, so you are unlikely to encounter it often. It is generally considered safe, though people sensitive to glutamates may prefer to limit intake.', opinion_lt = 'Tai glutamo rūgšties kalio druskos forma — glutamo rūgštis yra natūraliai randama aminorūgštis, esanti daugelyje maisto produktų. Šis priedas stiprina skonį, ypač umami pojūtį, ir veikia panašiai kaip žinomesnis mononatrio glutamatas, tik su kaliu vietoje natrio. Jis leidžiamas labai nedaugelyje maisto kategorijų, tad retai sutiksite jį sudėtyje. Laikomas saugiu, tačiau žmonės, jautrūs glutamatams, gali norėti riboti jo vartojimą.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 351878;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the calcium salt form of glutamic acid, a naturally occurring amino acid found in many proteins. It works as a flavour enhancer, boosting the savoury, meaty taste known as umami — similar in effect to monosodium glutamate but with calcium instead of sodium. It appears in very few food categories, meaning it is not widely used.

It is generally considered safe by food safety authorities. People who report sensitivity to glutamates may wish to take note, though scientific evidence for so-called "MSG sensitivity" remains inconclusive.', opinion_lt = 'Tai glutamo rūgšties kalcio druska — aminorūgšties, natūraliai randamos daugelyje baltymų, forma. Ji naudojama kaip skonio stipriklis, suteikiantis vadinamąjį umami — sodrų, mėsišką skonį. Veikia panašiai kaip glutamatas natrio, tik vietoje natrio yra kalcis. Leidžiama labai mažame maisto produktų skaičiuje, tad plačiai nenaudojama.

Maisto saugos institucijos ją laiko saugia. Žmonės, kurie mano jautriai reaguojantys į glutamatus, gali į tai atkreipti dėmesį, nors mokslinis tokio jautrumo pagrindimas kol kas nėra įrodytas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 351928;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the ammonium salt form of glutamic acid, used as a flavour enhancer — it boosts the savoury, meaty taste known as umami in processed foods. It works similarly to its more famous cousin, monosodium glutamate, just with ammonium instead of sodium. It appears in very few food categories, so most people rarely encounter it. Like other glutamate-based enhancers, it has been linked anecdotally to headaches or sensitivity in some people, though large-scale evidence for this remains weak.', opinion_lt = 'Tai glutamo rūgšties amonio druskos forma, naudojama kaip skonio stipriklis — jis sustiprina tą sodų, mėsišką skonį, kurį japonai vadina umami. Veikia panašiai kaip žymesnis giminaitis — mononatrio glutamatas, tik vietoje natrio čia yra amonijus. Leidžiamas labai nedaugelyje maisto kategorijų, tad daugelis žmonių su juo beveik nesusiduria. Kaip ir kiti glutamatai, kartais siejamas su galvos skausmais ar jautrumu, tačiau moksliniai įrodymai tam kol kas nėra įtikinamai stiprūs.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 351978;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the magnesium salt of glutamic acid, a naturally occurring amino acid found in many protein-rich foods. It works as a flavour enhancer, boosting the savoury, umami taste in food — much like its more famous relative, monosodium glutamate. It appears in very few food categories, so most people will rarely encounter it. It is generally considered safe, though people who are sensitive to glutamates may want to take note.', opinion_lt = 'Tai glutamo rūgšties magnio druska — amino rūgšties, kuri natūraliai randama daugelyje baltymingų maisto produktų. Naudojama kaip skonio stipriklis, suteikiantis maistui sodresni, vadinamąjį umami skonį — panašiai kaip geriau žinomas monosodio glutamatas. Leidžiama labai nedaugelyje maisto kategorijų, tad dauguma žmonių su ja susiduria retai. Laikoma saugia, tačiau tiems, kurie jautrūs glutamatams, verta atkreipti dėmesį.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 352028;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a flavour enhancer — a nucleotide naturally found in foods like meat, fish, mushrooms, and yeast. It works similarly to MSG, boosting the savoury ''umami'' taste in food. Because it''s authorised in very few food categories, you''re unlikely to encounter it often. It''s generally considered safe for most people, but those with gout should be cautious, as it can raise uric acid levels.', opinion_lt = 'Tai skonio stipriklis — nukleotidas, natūraliai randamas mėsoje, žuvyje, grybose ir mielėse. Jis veikia panašiai kaip MSG: sustiprina sodrų ''umami'' skonį maiste. Kadangi leidžiamas labai nedaugelyje maisto kategorijų, vargu ar dažnai su juo susidursite. Daugumai žmonių laikomas saugiu, tačiau sergantiems podagra reikėtų būti atsargiems — jis gali didinti šlapimo rūgšties kiekį kraujyje.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 352078;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a flavour enhancer derived from fish, dried mushrooms, or produced by fermentation — it boosts the savoury, meaty taste known as umami. It is almost always used alongside another enhancer and rarely appears alone in products. You might find it in snacks, instant noodles, soups, and seasonings. It is generally considered safe for most people, but those who are sensitive to purines — such as gout sufferers — are advised to be mindful, as it breaks down into purines in the body.', opinion_lt = 'Tai skonio stipriklis, gaunamas iš žuvies, džiovintų grybų arba fermentacijos būdu — jis sustiprina vadinamąjį umami, sotų ir mėsingą skonį. Beveik visada naudojamas kartu su kitais skonio stiprikliais, retai vienas. Jį galima rasti užkandžiuose, greitai paruošiamuose makaronuose, sultinius ir prieskonių mišiniuose. Laikomas saugiu daugumai žmonių, tačiau tiems, kurie jautrūs purinams — pavyzdžiui, sergantiems podagra — verta atkreipti dėmesį, nes šis priedas organizme skaidosi į purinus.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 352197;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a flavour enhancer derived from guanylic acid, used to boost the savoury, meaty taste in processed foods — it works similarly to MSG but is often used in smaller amounts alongside it. You''ll find it mostly in soups, snacks, seasoning mixes, and instant noodles. It''s synthetic but based on naturally occurring compounds found in fish and mushrooms. It''s considered safe for most people, though those with gout should be cautious as it breaks down into purines.', opinion_lt = 'Tai skonio stipriklis, gautas iš gvanilo rūgšties — jis sustiprina sotų, mėsišką skonį perdirbtuose maisto produktuose, panašiai kaip MSG, tik dažnai naudojamas mažesniais kiekiais kartu su juo. Dažniausiai randamas sriubose, užkandžiuose, prieskonių mišiniuose ir greito paruošimo makaronuose. Sintetinis, bet sukurtas pagal natūraliai žuvyse ir grybose esančius junginius. Laikomas saugiu daugumai žmonių, tačiau sergantys podagra turėtų būti atsargesni, nes šis priedas skaidosi į purinus.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 352247;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the calcium salt of guanylic acid, a flavour enhancer that boosts savoury, meaty or umami taste in food. It works similarly to MSG but is usually used alongside other flavour enhancers rather than alone. You''ll rarely encounter it, as it''s authorised in very few food categories. It is generally considered safe for most people, though those who need to limit purines — such as people with gout — should be aware that guanylates are purine-based compounds.', opinion_lt = 'Tai guanilo rūgšties kalcio druska — skonio stipriklis, kuris sustiprina umami, mėsinį ar sotų skonį maiste. Veikia panašiai kaip MSG, bet paprastai naudojamas kartu su kitais skonio stiprikliais. Susidursite su juo retai, nes leidžiamas tik labai nedaugelyje maisto kategorijų. Daugumai žmonių laikomas saugiu, tačiau tie, kurie turi riboti purinų kiekį — pavyzdžiui, sergantys podagra — turėtų žinoti, kad guanilatai yra purinų junginiai.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 352297;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally occurring compound found in meat and fish, where it contributes to the savory, umami taste. As a food additive, it works as a flavor enhancer, often used alongside similar compounds to boost the meaty or brothy taste in processed foods. It appears in very few food categories, so most people encounter it rarely. It is generally considered safe for the population at large, though people with gout or high uric acid levels are sometimes advised to limit foods containing such compounds.', opinion_lt = 'Tai natūraliai mėsoje ir žuvyje randamas junginys, suteikiantis sotų, vadinamąjį umami skonį. Maisto pramonėje jis naudojamas kaip skonio stipriklis – dažniausiai kartu su panašiomis medžiagomis, siekiant sustiprinti mėsiško ar sultinio skonį perdirbtuose produktuose. Leidžiamas labai nedaug produktų kategorijų, tad dauguma žmonių su juo susiduria retai. Paprastai laikomas saugiu, tačiau žmonėms, sergantiems podagra ar turintiems padidėjusį šlapimo rūgšties kiekį, rekomenduojama riboti tokių junginių vartojimą.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 352347;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic flavour enhancer, closely related to the nucleotide compounds found naturally in meat and fish. It works by boosting savoury, umami taste and is almost always used alongside glutamates to multiply the flavour effect rather than being used on its own. You''ll find it in snack foods, instant noodles, soups, and seasoning mixes. It''s generally considered safe by food authorities, but people avoiding purines — such as those with gout — should be aware, as it can raise uric acid levels.', opinion_lt = 'Tai sintetinis skonio stipriklis, artimas junginiais, kurie natūraliai randami mėsoje ir žuvyje. Jis sustiprina sūrų, umami skonį ir beveik visada naudojamas kartu su glutamatais, kad skonio efektas būtų keleriopai stipresnis. Dažniausiai jo yra užkandžiuose, greitai paruošiamuose makaronuose, sriubose ir prieskonių mišiniuose. Maisto saugos institucijos laiko jį saugiu, tačiau žmonės, sergantys podagra ar vengiantys purinų, turėtų atkreipti dėmesį — šis priedas gali didinti šlapimo rūgšties kiekį kraujyje.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 352397;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic flavour enhancer that boosts the savoury, meaty taste known as umami. It works best when combined with glutamates, and together they can make processed foods taste much more intense than they actually are. You''ll mostly find it in snacks, instant noodles, soups, and seasonings. It is authorised in very few food categories, so it''s not widely used. It''s generally considered safe for most people, though those sensitive to purines — such as people with gout — may want to watch their intake.', opinion_lt = 'Tai sintetinis skonio stipriklis, kuris sustiprina vadinamąjį umami — sultingą, mėsišką skonį. Jis ypač efektyvus kartu su glutamatais, ir kartu jie gali priversti perdirbtus produktus skonis kur kas intensyviau nei turėtų. Dažniausiai randamas užkandžiuose, greito paruošimo makaronuose, sriubose ir prieskonių mišiniuose. Leidžiamas tik labai nedaugelyje maisto kategorijų, tad nėra plačiai vartojamas. Paprastai laikomas saugiu, tačiau žmonėms, jautriems purinams — pavyzdžiui, sergantiems podagra — verta stebėti jo suvartojimą.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 352447;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic flavour enhancer, closely related to MSG, that boosts the savoury, meaty taste in food — the so-called umami flavour. It is often used in combination with other flavour enhancers to multiply their effect, meaning less of each is needed. It appears in a very limited range of food products, as it holds authorisation in only one food category. It is generally considered safe at the levels used in food, and regulatory bodies have not raised significant health concerns about it.', opinion_lt = 'Tai sintetinis skonio sustiprintojas, artimas MSG, kuris sustiprina sotų, mėsišką skonį maiste — vadinamąjį umami. Dažnai naudojamas kartu su kitais skonio stiprintojais, nes jų derinys veikia daug efektyviau, todėl kiekvieno reikia mažiau. Šis priedas leidžiamas labai ribotame produktų sąraše — tik vienoje maisto kategorijoje. Reguliavimo institucijos jo saugumu esant įprastoms dozėms rimtai neabejoja.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 352497;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a flavour enhancer — a calcium salt derived from ribonucleotides, compounds naturally found in living cells. It works similarly to MSG, boosting the savoury, umami taste in foods. You''ll mostly find it in processed snacks, soups, and seasonings. It''s authorised in only one food category, so exposure is quite limited. It is generally considered safe, though people with gout should be cautious, as nucleotides can raise uric acid levels.', opinion_lt = 'Tai skonio stipriklis — kalcio druska, gauta iš ribonukleotidų, junginių, natūraliai randamų gyvose ląstelėse. Veikia panašiai kaip MSG: sustiprina sotų, umami skonį maiste. Dažniausiai randamas perdirbtuose užkandžiuose, sriubose ir prieskonių mišiniuose. Leidžiamas tik vienoje maisto kategorijoje, tad su juo susiduriama retai. Laikomas saugiu, tačiau sergantys podagra turėtų būti atsargūs — nukleotidai gali didinti šlapimo rūgšties kiekį kraujyje.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 352547;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic flavour enhancer — a combination of two nucleotides (disodium inosinate and disodium guanylate) that work together to boost savoury, umami taste. It''s often used alongside MSG to amplify the meaty or brothy flavour in snacks, instant noodles, soups, and seasonings. Very small amounts are needed, which is why it appears so low on ingredient lists. It is generally considered safe for most people, but those sensitive to purines — such as people with gout — should be aware, as nucleotides can raise uric acid levels.', opinion_lt = 'Tai sintetinis skonio stipriklis — dviejų nukleotidų derinys, kuris sustiprina umami, t. y. mėsišką, sodrų skonį. Dažniausiai naudojamas kartu su MSG traškučiuose, greitai paruošiamuose makaronuose, sriubose ir prieskonių mišiniuose. Reikia labai mažų kiekių, todėl etiketėse jis dažnai paslepiamas sąrašo gale. Daugumai žmonių laikomas saugiu, tačiau sergantys podagra ar turintys problemų dėl purino apykaitos turėtų būti atsargūs — nukleotidai gali didinti šlapimo rūgšties kiekį kraujyje.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 352597;
UPDATE aggregate.eu_additives SET opinion_en = 'This is an amino acid — one of the building blocks of protein — that occurs naturally in the body and in many protein-rich foods. It is used as a flavour enhancer and mild sweetener, mainly in tabletop sweetener products. Because it is a naturally occurring compound in human metabolism, it is generally considered safe at the levels used in food. There is no significant controversy surrounding it.', opinion_lt = 'Tai aminorūgštis — vienas iš baltymų statybinių blokų — natūraliai randama žmogaus organizme ir daugelyje baltymingų maisto produktų. Maiste ji naudojama kaip skonio stipriklis ir švelnus saldintojas, daugiausia stalo saldiklių gaminiuose. Kadangi tai natūraliai organizme sutinkamas junginys, laikoma, kad naudojamais kiekiais ji yra saugi. Jokių reikšmingų diskusijų dėl šios medžiagos nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 352647;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally occurring amino acid — one of the building blocks of protein found in meat, dairy, eggs, and many plant foods. In food products, it is used as a flow agent or filler in compressed tablet-form sweeteners, helping the tablets hold their shape and come out of moulds cleanly. It has a very limited authorised use and is not a widespread additive. It is generally considered safe, as the body already processes it as a normal part of protein digestion.', opinion_lt = 'Tai natūraliai randama aminorūgštis — vienas iš baltymų statybinių blokų, kuris yra mėsoje, pieno produktuose, kiaušiniuose ir daugelyje augalinių maisto produktų. Maisto pramonėje ji naudojama kaip pagalbinė medžiaga pressuotose saldiklių tabletėse — padeda joms išlaikyti formą ir lengvai iškristi iš formų. Jos naudojimas yra labai ribotas. Paprastai laikoma saugia, nes organizmas ją įprastai apdoroja kaip baltymų virškinimo dalį.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 363377;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic zinc salt used in very specific products — mainly chewing gum — where it helps control bad breath and may support oral health by reducing bacteria in the mouth. It also acts as a flavour compound, contributing a mild astringent taste. Zinc itself is an essential mineral the human body needs, so small amounts from this source are not a concern. It is one of the most narrowly authorised additives in food, approved in just one product category.', opinion_lt = 'Tai sintetinė cinko druska, naudojama labai siaurame produkte — daugiausia kramtomojoje gumoje — kur padeda kovoti su blogu burnos kvapu ir gali slopinti bakterijas burnoje. Ji taip pat suteikia lengvą sutraukiantį skonį. Cinkas yra būtinas organizmui mineralas, todėl tokiais kiekiais jis nekelia susirūpinimo. Tai vienas iš labiausiai ribotų maisto priedų — leidžiamas tik vienoje maisto produktų kategorijoje.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 352720;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic silicone-based compound used as an anti-foaming agent — it stops bubbles and foam from forming during food production and cooking. You''ll find it in cooking oils, canned foods, jams, soups, batters, and even chewing gum, usually in tiny amounts. It works behind the scenes in food manufacturing more than in your kitchen. Regulatory bodies like EFSA and the FDA consider it safe at permitted levels, and it passes through the body without being absorbed, so health concerns are minimal.', opinion_lt = 'Tai sintetinis silikonas, naudojamas kaip putų slopintojas — jis neleidžia susidaryti burbulams ir putoms maisto gamybos metu. Rasite jį aliejuose, konservuotuose vaisiuose ir daržovėse, dželatuose, sriubose, tešlose ir net kramtomojoje gumoje — dažniausiai labai mažais kiekiais. Europos maisto saugos institucija (EFSA) ir kiti reguliuotojai laiko šį priedą saugiu leidžiamose dozėse. Organizmas jo nepasisavina, todėl realus poveikis sveikatai laikomas minimaliu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 352767;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural wax produced by honeybees, used mainly as a glazing and coating agent to give foods a shiny appearance and to protect them from drying out or sticking together. You''ll find it on chocolate products, candies, chewing gum, processed nuts, and baked goods. It is considered very safe — it passes through the body essentially undigested and has no known health concerns for most people. Those with bee allergies should be aware, though reactions to this wax are extremely rare.', opinion_lt = 'Tai natūralus bičių vaškas, naudojamas kaip glazūravimo ir dengimo priemonė — suteikia maistui blizgesį ir apsaugo nuo išdžiūvimo ar sulipimo. Rasite jį ant šokolado gaminių, saldainių, kramtomosios gumos, apdorotų riešutų ir kepinių. Laikomas labai saugiu — organizmas jo praktiškai nesuvirškinamas, ir jokių žinomų sveikatos problemų nesukeliančiu. Turintys alergiją bitėms turėtų žinoti apie jo kilmę, nors reakcijos į šį vašką pasitaiko itin retai.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 352992;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural plant-based wax derived from a shrub native to northern Mexico. It works as a glazing agent and surface coating — giving chocolate, sweets, chewing gum, nuts, and fresh produce that polished, shiny appearance while also helping to lock in moisture and extend shelf life. You''ll find it in a surprisingly wide range of products, from fine chocolates to coated snacks and even fresh fruits and vegetables in the supermarket. It is also used in food supplements in solid form.', opinion_lt = 'Tai natūralus augalinės kilmės vaškas, gaunamas iš Šiaurės Meksikoje augančio krūmo. Maiste jis naudojamas kaip glazūravimo priemonė — suteikia šokoladui, saldainiams, kramtomajai gumai, riešutams ir net šviežiems vaisiams bei daržovėms blizgų išvaizdą, taip pat padeda išsaugoti drėgmę ir prailginti galiojimo laiką. Paprastai laikomas saugiu — jokių reikšmingų kontraversijų ar sveikatos įspėjimų su šiuo priedu nesusijęs. Žmonėms, vengiančioms gyvulinės kilmės produktų, verta žinoti, kad šis vaškas — augalinis, todėl tinka veganams, skirtingai nei bičių vaškas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 353178;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural wax harvested from the leaves of a Brazilian palm tree, used as a glazing and coating agent. It gives candies, chocolates, chewing gum, and even coffee beans that shiny, polished look while also helping to protect the surface from moisture and sticking. It is also used on nuts, snacks, and food supplement tablets. Regulatory agencies worldwide consider it safe at the levels used in food, and it passes through the body without being absorbed. There is no significant controversy around this one — it is one of the more straightforward additives.', opinion_lt = 'Tai natūralus vaškas, gaunamas iš Brazilijos palmių lapų — naudojamas kaip glazūravimo ir dengimo medžiaga. Jis suteikia saldainiams, šokoladui, kramtomajai gumai ir net kavos pupelėms blizgų, poliruotą išvaizdą, taip pat apsaugo paviršių nuo drėgmės ir sulipimo. Naudojamas ir riešutuose, užkandžiuose bei maisto papildų tabletėse. Laikomas saugiu — organizmas jo nepasisavina, jis tiesiog praeina per virškinimo sistemą. Jokio reikšmingo ginčo dėl šio priedo nėra — tai vienas paprasčiausių ir nekenksmingesnių maisto priedų.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 353342;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural resin secreted by the lac bug, an insect found mainly in Asia. It''s used as a glazing agent to give a shiny coating to sweets, chocolate products, nuts, and even some bakery items — that glossy finish you see on jelly beans or chocolate-covered nuts often comes from this. It''s been used for centuries and is generally considered safe by food authorities. Vegetarians and vegans should be aware it comes from an insect source, and some people avoid it on those grounds.', opinion_lt = 'Tai natūralus derva, kurią gamina vabzdžiai — lakų skydamarės, gyvenančios daugiausia Azijoje. Maisto pramonėje jis naudojamas kaip glazūravimo medžiaga — suteikia blizgų paviršių saldainiams, šokolado gaminiams, riešutams, kai kuriems kepiniams. Tas gražus blizgesys ant želė saldainių ar glazūruotų riešutų dažniausiai ir yra šis priedas. Maisto institucijos laiko jį saugiu. Vegetarai ir veganai turėtų žinoti, kad tai gyvūninės (vabzdžių) kilmės produktas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 353542;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a highly refined mineral oil derived from petroleum, used as a coating or glazing agent to give certain foods a shiny appearance and prevent them from sticking together or drying out. It is only authorised in a very limited number of food categories, typically for surface treatment of fresh fruits and vegetables or certain confectionery. Regulatory bodies consider it safe at the low levels permitted, as the high viscosity form is poorly absorbed by the body. That said, some consumer groups remain cautious about petroleum-derived substances in food, which is a reasonable personal consideration.', opinion_lt = 'Tai labai išgrynintas mineralinis aliejus, gaunamas iš naftos, naudojamas kaip dengimo arba glazūravimo medžiaga — suteikia maistui blizgesį ir neleidžia produktams sulipti ar išdžiūti. Leidžiama jį naudoti tik labai ribotoje maisto kategorijų grupėje, dažniausiai šviežių vaisių, daržovių ar kai kurių saldumynų paviršiui apdoroti. Reguliavimo institucijos laiko jį saugiu leidžiamomis nedidelėmis dozėmis, nes šio tipo aliejus praktiškai nesisurbia organizme. Vis dėlto kai kurie vartotojai vengia naftos kilmės medžiagų maiste — tai suprantama asmeninė pozicija.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 362156;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a highly refined petroleum-derived wax used as a coating and glazing agent. It creates a protective, shiny surface on things like sweets, chewing gum, and fresh fruit and vegetables, helping to extend shelf life and prevent moisture loss. It is not digested or absorbed by the body — it simply passes through. Regulatory bodies in Europe consider it safe at the levels used in food, and there is no significant controversy surrounding it.', opinion_lt = 'Tai iš naftos gaunamas labai išgrynintas vaškas, naudojamas kaip dangos ir glazūravimo priemonė. Jis sukuria apsauginį blizgų paviršių ant saldainių, kramtomosios gumos bei šviežių vaisių ir daržovių, padėdamas pailginti galiojimo laiką ir išlaikyti drėgmę. Organizmas jo nevirškina ir nepasisavina — jis tiesiog praeina per virškinimo traktą. Europos reguliavimo institucijos laiko jį saugiu tomis dozėmis, kuriomis jis naudojamas maiste, ir didesnių kontraversijų dėl jo nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 353737;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic wax-like substance used as a glazing agent and surface coating in food. It gives products a shiny appearance and helps protect them from moisture and sticking together. You will find it on dried fruits, candies, chewing gum, and decorative coatings on confectionery. It is considered safe by European food authorities at the levels currently used, and since it is not absorbed by the body, it passes through without being digested.', opinion_lt = 'Tai sintetinė, vaško pobūdžio medžiaga, naudojama kaip glajus ar paviršiaus danga maiste. Ji suteikia produktams blizgesį ir apsaugo juos nuo drėgmės bei sukibimo. Galite ją rasti džiovintų vaisių, saldainių, kramtomosios gumos ir konditerijos gaminių dangose. Europos maisto saugos institucijos ją laiko saugia dabartiniais naudojimo kiekiais, o kadangi organizmas jos nepasisavina, ji tiesiog praeina per virškinamąjį traktą neįsisavinta.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 353832;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic wax coating used to give fruits and vegetables a shiny appearance and slow down moisture loss, helping produce stay fresh longer on store shelves. It is derived from lignite (brown coal) and processed into a wax ester. It is only authorised in a very narrow range of food applications — surface treatment of certain fruits. Regulatory bodies consider it safe at the levels used, though it is one of the lesser-studied additives and most people have never heard of it.', opinion_lt = 'Tai sintetinis vaškas, naudojamas vaisiams ir daržovėms padengti — suteikia blizgesį ir sulėtina drėgmės praradimą, kad produktai ilgiau išliktų šviežūs parduotuvių lentynose. Jis gaunamas iš lignito (rudosios anglies) ir chemiškai apdorojamas. Leidžiamas naudoti labai siauroje maisto produktų kategorijoje — tik kai kurių vaisių paviršiaus apdorojimui. Reguliavimo institucijos laiko jį saugiu naudojamomis dozėmis, tačiau tai vienas mažiau ištirtų priedų, apie kurį dauguma vartotojų tiesiog nežino.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 353918;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic wax coating applied to the surface of fresh fruit and vegetables to make them look shinier and last longer on shelves. It helps prevent moisture loss and protects the skin during transport and storage. It is authorised for use in very few food categories, essentially just whole fresh produce. Regulatory bodies consider it safe at the levels used, and since it sits on the surface and is not absorbed into the food, actual exposure is minimal.', opinion_lt = 'Tai sintetinis vaškas, užtepamas ant šviežių vaisių ir daržovių paviršiaus, kad jie atrodytų blizgesni ir ilgiau išliktų šviežūs parduotuvių lentynose. Jis padeda sulaikyti drėgmę ir apsaugo žievelę gabenimo bei laikymo metu. Leidžiamas naudoti labai nedaugelyje maisto kategorijų — iš esmės tik nepjaustytiems švieziems vaisiams ir daržovėms. Reguliavimo institucijos mano, kad toks naudojimas yra saugus, o kadangi vaškas lieka tik paviršiuje ir į maistą nepatenka, realus poveikis organizmui yra minimalus.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 353964;
UPDATE aggregate.eu_additives SET opinion_en = 'This is an amino acid — a natural building block of protein — used mainly as a dough conditioner in bread and bakery products. It makes dough softer and easier to work with, speeding up industrial baking. It can be sourced from human hair, duck feathers, or produced via fermentation, which raises ethical questions for some consumers. It''s approved for use in a limited number of food categories, mainly flours and some processed cereal foods.', opinion_lt = 'Tai aminorūgštis — natūrali baltymų sudedamoji dalis — naudojama daugiausia kaip tešlos kondicionierius duonos ir kepinių gamyboje. Ji minkština tešlą ir palengvina pramoninį kepimą. Gali būti gaminama iš žmogaus plaukų, ančių plunksnų arba fermentacijos būdu, kas kai kuriems vartotojams kelia etiškumo klausimų. Leidžiama naudoti tik keliose maisto kategorijose — daugiausia miltuose ir kai kuriuose perdirbtuose grūdų produktuose.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 354011;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic chemical used as a bleaching and oxidising agent in food processing. It is authorised in only one food category — typically for treating flour to whiten it and improve baking properties. It is not a common additive you will encounter on everyday labels. Regulatory bodies permit its use at controlled levels, but it remains a fairly restricted substance due to its reactive nature.', opinion_lt = 'Tai sintetinė cheminė medžiaga, naudojama kaip baliklis ir oksiduojantis agentas maisto perdirbimo procese. Ji leidžiama tik vienoje maisto kategorijoje — dažniausiai miltams balinti ir kepimo savybėms pagerinti. Kasdienėse produktų etiketėse jos sutiksite retai. Reguliavimo institucijos leidžia ją naudoti kontroliuojamais kiekiais, tačiau dėl reaktyvaus pobūdžio ji išlieka gana griežtai ribojama medžiaga.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 363331;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic compound — essentially urea — used in chewing gum to help soften and maintain the texture of the gum base. It is authorised only in a very limited number of food products, which reflects how narrowly its use is defined. At the levels permitted in chewing gum, it is considered safe by food safety authorities. It is not a common additive and most consumers will rarely encounter it outside of gum products.', opinion_lt = 'Tai sintetinis junginys — iš esmės karbamidas (šlapalas) — naudojamas kramtomojoje gumoje, kad ji išliktų minkšta ir tinkamos tekstūros. Jis leidžiamas tik labai ribotoje produktų kategorijoje, o tai rodo, kiek siaurai apibrėžtas jo naudojimas. Tokiais kiekiais, kokiais jis leidžiamas kramtomojoje gumoje, maisto saugos institucijos jį laiko saugiu. Tai nėra plačiai paplitęs priedas, ir dauguma vartotojų su juo susidurs tik kramtydami gumą.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 354071;
UPDATE aggregate.eu_additives SET opinion_en = 'This is simply argon — a naturally occurring, completely inert noble gas that makes up about 1% of the air we breathe. In food, it is used as a packaging gas to displace oxygen and prevent spoilage, oxidation, or unwanted reactions. It does not interact with food at all. You will find it used in packaging for wine, coffee, or other sensitive products where freshness matters. It is considered entirely safe — there is no controversy around it whatsoever.', opinion_lt = 'Tai paprasčiausias argonas — natūraliai gamtoje esantis, visiškai inertiškas taurusis dujos, sudarančios apie 1% oro, kuriuo kvėpuojame. Maisto pramonėje jis naudojamas pakuotėse vietoj deguonies, kad produktas nesugytų ir neoksiduotųsi. Su maistu jis visiškai nesireaguoja. Dažniausiai sutinkamas vyno, kavos ar kitų jautrių produktų pakuotėse. Laikomas visiškai saugiu — jokių kontraversijų ar abejonių dėl jo nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 354118;
UPDATE aggregate.eu_additives SET opinion_en = 'This is helium — the same inert gas used in balloons. In food, it is authorised as a packaging gas, meaning it can be used to fill the space inside sealed food containers to protect the contents. It is completely non-reactive and does not interact with food in any way. There are no safety concerns whatsoever — helium is entirely harmless.', opinion_lt = 'Tai helis — tas pats neaktyvus dujas, kurį naudojame balionams pripūsti. Maisto pramonėje jis leidžiamas kaip pakavimo dujos: juo gali būti užpildyta hermetiškų pakuočių vidaus erdvė, kad apsaugotų produktą. Helis visiškai nereaguoja su maistu ir niekaip jo nekeičia. Jokio pavojaus sveikatai nėra — tai visiškai nekenksmingas elementas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 354165;
UPDATE aggregate.eu_additives SET opinion_en = 'This is simply nitrogen gas — the same gas that makes up about 78% of the air we breathe. In food, it is used as a packaging gas to flush out oxygen, keeping products like coffee, crisps, or nuts fresh for longer without the food oxidising or going stale. It is completely inert and has no taste, colour, or smell. There is no safety concern whatsoever — it is one of the most harmless substances used in food production.', opinion_lt = 'Tai paprasčiausias azoto dujas — tas pats dujas, kuris sudaro apie 78% oro, kurį kvėpuojame. Maisto pramonėje jis naudojamas pakuotėse, kad išstumtų deguonį ir ilgiau išlaikytų produktus — kavą, traškučius ar riešutus — šviežius ir nepažeistus oksidacijos. Azotas yra visiškai inertiškas: be skonio, spalvos ir kvapo. Jokio pavojaus sveikatai nėra — tai viena nekenksmingesnių medžiagų maisto gamyboje.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 354212;
UPDATE aggregate.eu_additives SET opinion_en = 'This is nitrous oxide — the same gas used in medical and dental settings as a mild anaesthetic. In food, it works as a propellant, most commonly in whipped cream canisters, helping push cream out and giving it that light, airy texture. It is not an additive that stays in the food itself; it simply does its job and disperses. It is authorised in a very limited number of food categories, reflecting its narrow, specific use.', opinion_lt = 'Tai yra dujotas junginys, plačiai žinomas medicinoje kaip lengvas anestetikas. Maisto pramonėje jis naudojamas kaip propelentas — dažniausiai plakamosios grietinėlės balionėliuose, kur padeda išstumti grietinėlę ir suteikti jai purią tekstūrą. Pats dujas į maistą nepatenka — jos paprasčiausiai išsisklaido ore. Leidžiama naudoti labai ribotoje produktų grupėje, nes jo paskirtis yra siaura ir konkreti.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 354259;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a hydrocarbon gas used as a propellant in spray products — it helps push oil out of the can in a fine mist. You will find it in cooking oil sprays designed for coating pans before frying or baking. It is synthetic and derived from petroleum, but it does not remain in the food itself — it disperses into the air on contact. Regulatory authorities consider it safe in this very limited use, and exposure from food is essentially negligible.', opinion_lt = 'Tai angliavandenilių dujos, naudojamos kaip propelentas purškiamuosiuose produktuose — jos padeda aliejui išeiti iš skardinės smulkių lašelių pavidalu. Tokias dujas rasite kepimo aliejaus purškaluose, skirtų keptuvėms ar skardoms sutepti prieš kepimą. Tai sintetinis, iš naftos gautas produktas, tačiau jis nelieka maiste — išsisklaidydamas ore nebekelia jokios rizikos. Reguliavimo institucijos šį priedą laiko saugiu, nes jo poveikis per maistą yra iš esmės nereikšmingas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 354306;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic gas used as a propellant — it helps push product out of spray cans, like cooking oil sprays. It does not end up in the food itself in any meaningful amount; it simply evaporates into the air after use. It is authorised in a very limited range of products and is generally considered safe at the tiny levels involved.', opinion_lt = 'Tai sintetinės kilmės dujos, naudojamos kaip propelentas – jos padeda išstumti produktą iš purkštuko, pavyzdžiui, aliejaus purškikliuose. Į maistą pats propelentas nepatenka jokiu reikšmingu kiekiu – jis tiesiog išgaruoja ore po naudojimo. Leidžiamas labai ribotam produktų ratui ir laikomas saugiu tokiomis mažomis dozėmis.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 354353;
UPDATE aggregate.eu_additives SET opinion_en = 'This is propane — yes, the same gas used in barbecue grills. In food use, it acts as a propellant in cooking sprays, helping push the oil out of the can as a fine mist. It does not remain in the food itself in any meaningful amount. It is considered safe at the levels used in food applications, and regulatory authorities permit it in very limited contexts like pan sprays.', opinion_lt = 'Tai propanas — taip, tas pats dujas, kurias naudojame griliuje. Maisto pramonėje jis naudojamas kaip propeliantas purškiamuosiuose aliejuose — padeda išstumti aliejų iš balionėlio smulkia dulksna. Pačiame maiste jo praktiškai nelieka. Laikomas saugiu tokiomis mažomis dozėmis, o valdžios institucijos leidžia jį naudoti tik labai ribotame kontekste, pavyzdžiui, kepimo purškikliuose.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 354400;
UPDATE aggregate.eu_additives SET opinion_en = 'This is simply pure oxygen — the same gas we breathe every day. It is used in food packaging or processing to keep certain products fresh or to help with specific industrial food processes. With authorisation in just one food category, its use is very limited. There is nothing concerning here — it is as natural as it gets.', opinion_lt = 'Tai paprasčiausias grynas deguonis — tas pats dujos, kurią kvėpuojame kasdien. Maisto pramonėje jis naudojamas pakavimo ar perdirbimo procesuose, kad kai kurie produktai išliktų šviežesni arba tam tikriems technologiniams tikslams. Kadangi leidžiamas tik vienoje maisto kategorijoje, jo naudojimas labai ribotas. Visiškai nėra ko nerimauti — natūraliau jau nebūna.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 354447;
UPDATE aggregate.eu_additives SET opinion_en = 'This is simply hydrogen gas, the lightest and most basic element in existence. It is authorised as a packaging gas, meaning it can be used in very limited contexts to create a protective atmosphere around food. It is naturally occurring and non-toxic. Given how rarely it appears in food products, there is essentially no safety concern for consumers.', opinion_lt = 'Tai paprasčiausias vandenilio dujas, lengviausias elementas gamtoje. Jis leidžiamas naudoti kaip pakavimo dujos – tai reiškia, kad tam tikrais atvejais gali būti naudojamas apsauginei atmosferai aplink maistą sukurti. Vandenilis yra natūraliai egzistuojantis ir netoksiškas. Kadangi jis itin retai pasitaiko maisto produktuose, vartotojams iš esmės nėra jokios priežasties nerimauti.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 354494;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic, calorie-free sweetener roughly 200 times sweeter than sugar. It is heat-stable, which makes it popular in baked goods, drinks, chewing gum, dairy products, and a wide range of diet or sugar-reduced foods. It is often blended with other sweeteners to improve taste. Approved by major food safety authorities including EFSA and FDA, it is generally considered safe at typical intake levels. Some consumers and researchers have raised questions about long-term effects, but current evidence does not establish harm at normal dietary amounts.', opinion_lt = 'Tai sintetinis, kalorijų neturintis saldiklis, maždaug 200 kartų saldesnis už cukrų. Jis atsparus karščiui, todėl plačiai naudojamas kepiniuose, gėrimuose, kramtomojoje gumoje, pieno produktuose ir įvairiuose dietiniuose arba sumažinto cukraus kiekio maisto produktuose. Dažnai derinamas su kitais saldikliais, kad skonis būtų geresnis. Tiek EFSA, tiek FDA jį laiko saugiu įprastais vartojimo kiekiais. Kai kurie vartotojai ir mokslininkai kelia klausimų dėl ilgalaikio poveikio, tačiau esami įrodymai nekelia nerimo vartojant įprastais kiekiais.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 354541;
UPDATE aggregate.eu_additives SET opinion_en = 'This is an artificial sweetener — about 200 times sweeter than sugar, so only a tiny amount is needed. It''s widely used in diet sodas, sugar-free gum, low-calorie yogurts, and many ''light'' or ''zero'' products. It contains phenylalanine, so people with phenylketonuria (PKU) must avoid it — that''s why products must carry a warning. The controversy around it is real: in 2023 the WHO''s cancer research agency classified it as ''possibly carcinogenic'', though at the same time food safety regulators (EFSA, FDA) maintained that current acceptable daily intake levels remain safe for most people. The science is genuinely unsettled, so moderation is reasonable.', opinion_lt = 'Tai dirbtinis saldiklis — maždaug 200 kartų saldensnis už cukrų, todėl jo reikia labai mažai. Randamas dietiniuose gaziuotuose gėrimuose, becukrėje kramtomojoje gumoje, mažakaloriniuose jogurtuose ir įvairiuose ''light'' ar ''zero'' produktuose. Jame yra fenilalanino, todėl žmonės, sergantys fenilketonurija (PKU), jo vartoti negali — ant pakuočių privalomas įspėjimas. Diskusijų tikrai yra: 2023 m. PSO vėžio tyrimų agentūra jį priskyrė prie ''galbūt kancerogeninių'' medžiagų, tačiau maisto saugos institucijos (EFSA, FDA) patvirtino, kad leistinos paros normos išlieka saugios daugumai žmonių. Mokslas dar nesako paskutinio žodžio, tad protingas saikingumas — geras pasirinkimas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 355109;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic artificial sweetener — about 30 to 50 times sweeter than sugar — used to reduce or replace sugar in foods and drinks. You''ll find it in diet sodas, sugar-free sweets, tabletop sweeteners, flavoured yoghurts, jams, and desserts. It''s often combined with other sweeteners like saccharin to improve the overall taste. It was banned in the USA in 1969 after a study linked it to bladder cancer in rats, and it remains prohibited there to this day. However, the EU, WHO, and most other food safety authorities have reviewed the evidence and consider it safe at approved levels — the rat study used doses far beyond what humans would ever consume.', opinion_lt = 'Tai sintetinis dirbtinis saldiklis — maždaug 30–50 kartų saldesnis už cukrų — naudojamas cukrui sumažinti arba pakeisti maiste ir gėrimuose. Rasite jį dietiniuose gazuotuose gėrimuose, beicukriniuose saldainiuose, stalo saldintuose, jogurtuose, dželė ir deserto gaminiuose. Dažnai derinamas su kitais saldikliais, pavyzdžiui, sacharina, kad skonis būtų geresnis. 1969 m. JAV jis buvo uždraustas po tyrimo, susiejusio jį su šlapimo pūslės vėžiu žiurkėms, ir ten draudimas galioja iki šiol. Tačiau ES, PSO ir dauguma kitų maisto saugos institucijų išnagrinėjo įrodymus ir laiko jį saugiu leistinosiose ribose — tyrime naudotos dozės buvo daug kartų didesnės nei žmogus kada nors suvartotų.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 355672;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a sugar substitute made from regular sugar (sucrose), but processed so the body absorbs it slowly and it has far fewer calories. It is often used in sugar-free candies, chewing gums, and diabetic-friendly products because it does not spike blood sugar the way regular sugar does. Like most sugar alcohols, eating larger amounts can cause bloating, gas, or a laxative effect in some people, so moderation is sensible.', opinion_lt = 'Tai cukraus pakaitalas, pagamintas iš įprasto cukraus, tačiau perdirbtas taip, kad organizmas jį įsisavina lėtai ir jis turi daug mažiau kalorijų. Dažnai naudojamas be cukraus saldainiuose, kramtomosiose gumose ir produktuose diabetikams, nes nepadidina cukraus kiekio kraujyje taip, kaip įprastas cukrus. Kaip ir dauguma cukraus alkoholių, vartojant didesnius kiekius, kai kuriems žmonėms gali sukelti pilvapūtę ar viduriavimą, tad geriau nepersistengti.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 356012;
UPDATE aggregate.eu_additives SET opinion_en = 'This is one of the oldest artificial sweeteners, discovered in the late 1800s. It provides sweetness with virtually no calories, making it popular in diet products, chewing gum, tabletop sweeteners, and even some savoury foods like mustard and sauces. It has a slightly bitter or metallic aftertaste that many people notice. In the 1970s, studies linked high doses to bladder cancer in rats, causing real concern — but later research found the mechanism does not apply to humans, and regulatory agencies worldwide consider it safe at normal consumption levels. Some people prefer to limit it out of personal caution, which is a reasonable choice.', opinion_lt = 'Tai vienas seniausių dirbtinių saldiklių, atrastas dar XIX amžiaus pabaigoje. Suteikia saldumą beveik be kalorijų, todėl naudojamas dietiniuose produktuose, kramtomojoje gumoje, stalo saldintuose ir netgi kai kuriuose pikantiniuose maisto produktuose, pavyzdžiui, garstyčiose ar padažuose. Daugelis jaučia lengvą kartoką ar metalinį prieskonį. Aštuntajame dešimtmetyje tyrimai su žiurkėmis sukėlė susirūpinimą dėl vėžio rizikos, tačiau vėliau nustatyta, kad tas mechanizmas žmonėms negalioja, ir pasaulinės maisto saugos institucijos šiuo metu laiko jį saugiu įprastomis dozėmis. Kas nori jo vengti iš atsargumo — suprantamas pasirinkimas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 356062;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic, zero-calorie sweetener made from regular sugar — but chemically altered so the body barely absorbs it. It''s roughly 600 times sweeter than sugar, which is why only tiny amounts are needed. You''ll find it in diet drinks, sugar-free desserts, chewing gum, and surprisingly in things like flavoured yogurts and breakfast cereals. It''s widely approved and generally considered safe by major food safety authorities. Some studies have raised questions about potential effects on gut bacteria and blood sugar response, but the evidence is not conclusive. Moderate consumption is unlikely to be a concern for most people.', opinion_lt = 'Tai sintetinis, kalorijų neturintis saldiklis, pagamintas iš paprastojo cukraus, tačiau chemiškai pakeistas taip, kad organizmas jo beveik nepasisavina. Jis maždaug 600 kartų saldesnis už cukrų, todėl reikia tik labai mažų kiekių. Rasite jį dietiniuose gėrimuose, be cukraus desertų, kramtomojoje gumoje, o kartais ir jogurtuose ar pusryčių dribsniuose. Pagrindinės maisto saugos institucijos jį laiko saugiu. Vis dėlto kai kurie tyrimai kelia klausimus dėl galimo poveikio žarnyno bakterijoms ir cukraus kiekiui kraujyje — tačiau aiškių įrodymų kol kas nėra. Saikingas vartojimas daugumai žmonių greičiausiai nekelia problemų.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 356625;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural protein extracted from the katemfe fruit, a West African plant. It is one of the sweetest substances known — thousands of times sweeter than sugar — so only tiny amounts are needed. It works both as a sweetener and a flavour enhancer, making other sweet or fruity flavours taste stronger and more rounded. You''ll find it in chewing gum, ice cream, chocolate products, desserts, and table-top sweeteners. It is generally considered safe, with no significant health concerns raised by major food safety authorities.', opinion_lt = 'Tai natūralus baltymas, išgaunamas iš Vakarų Afrikos katemfės vaisiaus. Jis laikomas viena saldžiausių žinomų medžiagų — tūkstančius kartų saldesnis už cukrų, todėl naudojami labai maži kiekiai. Veikia ir kaip saldiklis, ir kaip skonio stipriklis — padeda vaisių ar saldžioms notoms skambėti ryškiau ir pilniau. Randamas kramtomojoje gumoje, ledų produktuose, šokolade, desertuose ir staliniuose saldikliuose. Pagrindinės maisto saugos institucijos šiam priedui rimtesnių sveikatos rizikų nekelia.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 357202;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a semi-synthetic sweetener derived from a natural compound found in bitter oranges. It is intensely sweet — several hundred to over a thousand times sweeter than sugar — so only tiny amounts are needed. You''ll find it in a wide range of products including dairy desserts, ice cream, chewing gum, chocolate, and pickled vegetables, often combined with other sweeteners. It also has a slight liquorice or menthol aftertaste, which is sometimes used intentionally to mask bitterness in foods. It is approved for use in the EU and is generally considered safe at the levels used in food, with no major controversies surrounding it.', opinion_lt = 'Tai pusiau sintetinis saldiklis, pagamintas iš karčiųjų apelsinų žievelėse randamos natūralios medžiagos. Jis yra itin saldus — kelis šimtus ar net tūkstantį kartų saldesnis už cukrų — todėl maiste naudojami labai maži kiekiai. Jį rasite pieno desertuose, ledų gaminiuose, kramtomojoje gumoje, šokolade ir marinavimuose. Turi lengvą salmiakinį ar mentolišką poskonį, kuris kartais tyčia naudojamas kartumui maskuoti. ES jis yra patvirtintas kaip maisto priedas ir laikomas saugiu vartoti įprastais kiekiais — didelių prieštaravimų ar kontraversijų aplink šį priedą nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 357464;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural-origin sweetener extracted from the leaves of the Stevia plant, which has been used for centuries in South America. It provides intense sweetness — hundreds of times sweeter than sugar — with virtually no calories, making it popular in diet drinks, fruit nectars, flavoured dairy products, and meal replacements. It is generally considered safe by major food safety authorities including EFSA and the FDA. Some people notice a slightly bitter or liquorice-like aftertaste, but that is a matter of taste preference rather than a safety concern.', opinion_lt = 'Tai natūralios kilmės saldiklis, gaunamas iš stevijos augalo lapų, kuris Pietų Amerikoje naudojamas jau šimtmečius. Jis yra kelis šimtus kartų saldesnis už cukrų ir praktiškai neturi kalorijų, todėl dažnai randamas dietiniuose gėrimuose, vaisių nektaruose, skoniuose pieno produktuose ir svorio kontrolės maisto pakaitaluose. Pagrindinės maisto saugos institucijos, įskaitant EFSA ir FDA, laiko jį saugiu. Kai kurie žmonės pastebi lengvą kartų ar saldžiašaknių poskonį — tai skonio, o ne saugos klausimas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 728737;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a sweetener derived from the stevia plant, but produced with the help of enzymes to modify its structure. It''s used in low-calorie and sugar-reduced products like flavoured drinks, fruit nectars, ice cream, and meal replacements. Like other stevia-based sweeteners, it provides sweetness without the calories of sugar. It''s generally considered safe by food safety authorities, and its plant-based origin makes it a popular choice for consumers looking to reduce sugar intake.', opinion_lt = 'Tai saldiklis, gaunamas iš stevijos augalo, tačiau fermentų pagalba modifikuojamas jo struktūra. Naudojamas mažai kalorijų turinčiuose ir su mažiau cukraus pagamintuose produktuose – aromatizuotuose gėrimuose, vaisių nektaruose, ledų gamyboje ir maisto pakaitaluose svoriui kontroliuoti. Kaip ir kiti stevija pagrįsti saldikliai, jis suteikia saldumą be cukraus kalorijų. Maisto saugos institucijos jį laiko saugiu, o augalinė kilmė daro jį patraukliu pasirinkimu tiems, kurie nori sumažinti cukraus vartojimą.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 728785;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a modified form of stevia — a plant-based sweetener derived from the Stevia rebaudiana plant, then processed to improve its taste and solubility. The modification (adding glucose molecules) makes it sweeter and reduces the slightly bitter aftertaste that plain stevia can have. You''ll find it in diet drinks, flavoured yoghurts, fruit nectars, and meal replacement products. It contains virtually no calories, making it popular for weight management products. It is considered safe by European food authorities, and its plant origin makes it more appealing to consumers seeking natural alternatives to artificial sweeteners.', opinion_lt = 'Tai modifikuota stevijos forma — augalinės kilmės saldiklis, gautas iš Stevia rebaudiana augalo ir papildomai apdorotas, kad pagerintų skonį ir tirpumą. Pridėjus gliukozės molekulių, jis tampa saldžiau skanus ir mažiau kartus nei įprastas stevijos ekstraktas. Šį priedą rasite dietiniuose gėrimuose, varškės bei jogurto produktuose, vaisių nektaruose ir maisto pakaitaluose svoriui kontroliuoti. Jis beveik nekaloringas, todėl populiarus tarp ieškančių natūralesnių alternatyvų dirbtiniams saldintukai. Europos maisto saugos institucijos jį laiko saugiu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 728835;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural-origin, zero-calorie sweetener derived from the stevia plant, but produced through fermentation rather than direct extraction from leaves. It works by mimicking the sweetness of sugar without adding calories, making it popular in diet drinks, flavoured yoghurts, fruit nectars, and meal replacement products. Regulatory bodies like EFSA and the FDA consider it safe for general consumption within established limits. Some people notice a mild bitter or liquorice-like aftertaste, which is a common personal preference issue rather than a safety concern.', opinion_lt = 'Tai natūralios kilmės, kalorijų neturintis saldiklis, gautas iš stevijos augalo, tačiau ne tiesiogiai iš lapų, o fermentacijos būdu. Jis naudojamas cukraus saldumui imituoti nesuteikiant kalorijų, todėl dažnai randamas dietiniuose gėrimuose, skoniuose jogurtuose, vaisių nektaruose ir produktuose svoriui kontroliuoti. EFSA ir kitos maisto saugos institucijos laiko jį saugiu vartoti laikantis nustatytų normų. Kai kurie žmonės jaučia lengvą kartumą ar saldžiašaknės prieskonį – tai skonio klausimas, o ne saugos problema.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 2542741;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic high-intensity sweetener, roughly 7,000 to 13,000 times sweeter than sugar, so only tiny amounts are needed. It belongs to the same chemical family as aspartame but is considered safe even for people with phenylketonuria, unlike its relative. You''ll find it in diet foods, chewing gum, breakfast cereals, and even some preserved fish products. Regulatory bodies like EFSA and the FDA have approved it as safe at current use levels, though it remains less studied than older sweeteners simply because it''s newer.', opinion_lt = 'Tai sintetinis intensyvus saldiklis, maždaug 7 000–13 000 kartų saldesnis už cukrų, todėl maisto gamybai jo reikia labai mažai. Chemiškai giminingas aspartamui, tačiau skirtingai nei šis, laikomas saugiu net žmonėms, sergantiems fenilketonurija. Galima rasti dietiniuose produktuose, kramtomojoje gumoje, dribsniuose pusryčiams ir net kai kuriuose konservuotuose žuvies produktuose. EFSA ir FDA jį pripažįsta saugiu, nors, palyginti su senesniais saldikliais, mokslinių tyrimų apie jį kol kas yra mažiau – tiesiog todėl, kad jis gana naujas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 358084;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic sweetener — a combination of two well-known artificial sweeteners joined together into one compound. It is used in a wide range of products including chewing gum, ice cream, confectionery, jams, and breakfast cereals to provide sweetness without sugar. It breaks down in the body into its two component sweeteners, plus a small amount of other byproducts.

Because one of its components is aspartame, people with phenylketonuria (PKU) — a rare metabolic condition — must avoid it, and products containing it are required to carry a warning. The acceptable daily intake set by regulators is considered safe for the general population, but some consumers prefer to avoid artificial sweeteners altogether as a personal choice.', opinion_lt = 'Tai sintetinis saldiklis — dviejų gerai žinomų dirbtinių saldiklių junginys, sujungtas į vieną medžiagą. Jis naudojamas labai įvairiuose produktuose: kramtomojoje gumoje, ledų gaminiuose, saldainiuose, uogienėse ir pusryčių dribsniuose, kad suteiktų saldumą be cukraus. Organizme jis suskaidomas į abu savo sudedamuosius saldiklius ir nedidelį kiekį kitų medžiagų.

Kadangi vienas iš jo komponentų yra aspartamas, žmonės, sergantys fenilketonurija (PKU) — reta medžiagų apykaitos liga — turi jo vengti, o ant produktų privalomas įspėjamasis užrašas. Reguliavimo institucijų nustatyta leistina paros dozė laikoma saugia daugumai žmonių, tačiau kai kurie vartotojai asmeniškai renkasi vengti dirbtinių saldiklių apskritai.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 358736;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic sugar alcohol (polyol) used as a bulk sweetener and humectant — it helps keep foods moist and adds sweetness without spiking blood sugar as sharply as regular sugar. You''ll find it in sugar-free or reduced-calorie products like chewing gum, candies, ice cream, jams, and baked goods. It''s generally considered safe by food authorities, though like most polyols, consuming larger amounts can cause a laxative effect or digestive discomfort in some people.', opinion_lt = 'Tai sintetinis cukraus alkoholis (poliolis), naudojamas kaip saldiklis ir drėgmę išlaikanti medžiaga — jis padeda maistui išlikti minkštam ir suteikia saldumą, tačiau mažiau kelia cukraus kiekį kraujyje nei įprastas cukrus. Dažniausiai jį rasite beicukriniuose ar sumažinto kalorijų kiekio produktuose: kramtomojoje gumoje, saldainiuose, ledų desertuose, džemuose ir kepiniuose. Laikomas saugiu, tačiau kaip ir daugelis poliolių, suvalgius didesnį kiekį gali sukelti viduriavimą ar pilvo diskomfortą.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 362348;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a sugar alcohol used as a sweetener and bulking agent. It provides sweetness similar to sugar but with fewer calories, making it popular in sugar-free or reduced-calorie products like chewing gum, candies, and diabetic-friendly foods. It has a low glycaemic index, so it does not spike blood sugar as sharply as regular sugar. However, consuming larger amounts can cause digestive discomfort, bloating, or a laxative effect in some people.', opinion_lt = 'Tai cukraus alkoholis, naudojamas kaip saldiklis ir užpildas maisto produktuose. Jis yra panašaus saldumo kaip cukrus, tačiau turi mažiau kalorijų, todėl dažnai randamas becukriuose ar mažiau kalorijų turinčiuose produktuose, pavyzdžiui, kramtomojoje gumoje, saldainiuose ar diabetikams skirtuose maisto produktuose. Jo glikeminis indeksas žemas, tad cukraus kiekio kraujyje taip stipriai nepakelia. Vis dėlto vartojant didesnius kiekius kai kuriems žmonėms gali atsirasti virškinimo sutrikimų, pūtimas ar viduriavimas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 359541;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a sugar alcohol used as a low-calorie sweetener and bulking agent. It occurs naturally in small amounts in some foods but is commercially produced from lactose, the sugar found in milk. You will mainly find it in sugar-free or reduced-calorie products like diabetic chocolates or chewing gum. It provides about half the sweetness of regular sugar and significantly fewer calories. Like other sugar alcohols, consuming large amounts may cause bloating or a laxative effect in some people, but it is generally considered safe.', opinion_lt = 'Tai cukraus alkoholis, naudojamas kaip mažakalorinis saldiklis ir pūtiklis. Jis gaminamas iš laktozės – pieno cukraus – ir randamas daugiausia produktuose be cukraus, pavyzdžiui, diabetiniame šokolade ar kramtomojoje gumoje. Suteikia maždaug pusę įprastinio cukraus saldumo ir žymiai mažiau kalorijų. Kaip ir kiti cukraus alkoholiai, vartojamas dideliais kiekiais gali sukelti pilvapūtę ar vidurius laisvinantį poveikį, tačiau apskritai laikomas saugiu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 359591;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural sugar alcohol found in small amounts in fruits and vegetables, but commercially produced from birch wood or corn cobs. It is used as a sweetener in sugar-free products like chewing gum, mints, and some diabetic-friendly foods, providing roughly the same sweetness as sugar but with fewer calories and a lower effect on blood sugar. It is generally considered safe for humans. However, it is extremely toxic to dogs, even in small amounts, so keep products containing it well away from pets.', opinion_lt = 'Tai natūralus cukraus alkoholis, randamas nedideliuose kiekiuose vaisiuose ir daržovėse, tačiau pramoniškai gaminamas iš beržo medienos ar kukurūzų burbuolių. Naudojamas kaip saldiklis beciukrėje kramtomojoje gumoje, pastilėse ir kai kuriuose diabetikams skirtuose produktuose – saldina panašiai kaip cukrus, bet turi mažiau kalorijų ir mažiau veikia cukraus kiekį kraujyje. Žmonėms jis laikomas saugiu, tačiau šunims yra itin toksiškas net ir mažais kiekiais, todėl šiuos produktus reikia laikyti toliau nuo augintinių.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 359641;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a sugar alcohol that occurs naturally in small amounts in fruits and fermented foods, though the commercial version is produced by fermenting glucose. It adds sweetness with almost no calories and does not raise blood sugar, making it popular in low-sugar and diabetic-friendly products. Unlike some other sugar alcohols, it is much less likely to cause digestive discomfort. It is generally considered safe and well-tolerated by most people.', opinion_lt = 'Tai cukraus alkoholis, natūraliai randamas nedideliais kiekiais vaisiuose ir fermentuotuose produktuose, tačiau pramoninė versija gaminama fermentuojant gliukozę. Jis suteikia saldumą beveik be kalorijų ir nekelia cukraus kiekio kraujyje, todėl populiarus mažai cukraus turinčiuose ir diabetikams skirtuose produktuose. Skirtingai nei kiti cukraus alkoholiai, jis retai sukelia virškinimo sutrikimų. Laikomas saugiu ir gerai toleruojamu daugumos žmonių.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 359691;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic high-intensity sweetener, roughly 20,000 times sweeter than sugar, so only tiny amounts are needed. It''s used in a wide range of products — from chewing gum and chocolates to table-top sweeteners and even some processed fish products. It''s one of the newer approved sweeteners in the EU, and so far regulators consider it safe at the levels used in food. There isn''t much public controversy around it yet, largely because it''s still relatively unknown to most consumers.', opinion_lt = 'Tai sintetinis stiprus saldiklis — maždaug 20 000 kartų saldesnis už cukrų, todėl maiste jo reikia visai mažai. Randamas kramtomojoje gumoje, šokolade, stalo saldinimo priemonėse ir netgi kai kuriuose perdirbtų žuvies produktų gaminiuose. ES reguliuotojai jį laiko saugiu naudojamais kiekiais, o didelių kontraversijų kol kas nekyla — tiesiog daugelis vartotojų apie šį priedą dar nieko negirdėjo. Jei vengi sintetinių saldiklių, verta patikrinti etiketes.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 2698349;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural extract derived from the bark of the South American quillaia tree. It acts as a foaming agent, helping create and stabilise the froth in drinks like cider and flavoured beverages. Its use is quite limited and approved only in a small number of product categories. It is generally considered safe at the levels permitted in food, though it can be mildly irritating in large amounts — which you would never encounter through normal food consumption.', opinion_lt = 'Tai natūralus ekstraktas, gaunamas iš Pietų Amerikoje augančio kvilajaus medžio žievės. Maiste jis naudojamas kaip putojimo medžiaga — padeda susidaryti ir išsilaikyti putoms gėrimuose, pavyzdžiui, sidre ar aromatizuotuose gėrimuose. Leidžiamas tik keliose maisto kategorijose, tad su juo susiduriama retai. Laikomas saugiu tomis koncentracijomis, kuriomis naudojamas maiste — kasdienėje mityboje jo kiekiai yra visiškai nekenksmingi.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 359742;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural enzyme, originally found in yeast, that breaks down table sugar into simpler sugars — glucose and fructose. It is mainly used in confectionery, particularly to create soft, liquid centres inside chocolates. It has no known safety concerns and is considered completely safe for consumption. Because it is an enzyme, it is used in tiny amounts and does not remain active in the finished product.', opinion_lt = 'Tai natūralus fermentas, randamas mielėse, kuris skaido paprastą cukrų į gliukozę ir fruktozę. Daugiausia naudojamas konditerijos pramonėje — ypač kuriant minkštus, skystus įdarus šokolado saldainiuose. Jokių žinomų saugos problemų nėra, laikomas visiškai saugiu. Kadangi tai fermentas, jo naudojama labai mažai ir galutiniame produkte jis nebeveikia.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 359802;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural enzyme found in egg whites, tears, and even human milk — it''s one of the body''s own antimicrobial tools. In food, it acts as a natural preservative, mainly used in aged cheeses to prevent unwanted bacterial growth and in some wines and beers to extend shelf life. Because it comes from egg whites, people with egg allergies should be aware it may be present, even if not always prominently labelled. Overall it''s considered very safe and is a good example of a preservative derived from nature rather than synthesised in a lab.', opinion_lt = 'Tai natūralus fermentas, randamas kiaušinio baltyme, ašarose ir net žmogaus piene — vienas iš natūralių organizmo apsaugos nuo bakterijų įrankių. Maiste jis naudojamas kaip natūralus konservantas: dažniausiai brandintame sūryje, kad sutrukdytų nepageidaujamoms bakterijoms augti, taip pat kai kuriuose vynuose ir aluje. Kadangi jis gaunamas iš kiaušinio baltymų, žmonės, alergiški kiaušiniams, turėtų į tai atkreipti dėmesį. Apskritai laikomas labai saugiu ir yra puikus pavyzdys konservanto, kilusio iš gamtos, o ne sintetiškai pagaminto.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 359848;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic soluble fiber and low-calorie bulking agent made from glucose. It adds bulk and texture to foods without contributing many calories, and it also has a mild prebiotic effect, meaning it can support gut bacteria. You''ll find it mostly in diet products, sugar-free sweets, and low-calorie beverages. It is generally considered safe, and regulatory bodies worldwide have approved its use with no major health concerns flagged.', opinion_lt = 'Tai sintetinis tirpus skaidulas ir mažakalorė užpildanti medžiaga, gaminama iš gliukozės. Ji suteikia produktams apimtį ir tekstūrą beveik nepridėdama kalorijų, o kartu turi švelnų prebiotinį poveikį – gali palaikyti žarnyno bakterijų augimą. Dažniausiai randama dietiniuose produktuose, be cukraus saldainiuose ir mažakaloriniuose gėrimuose. Laikoma saugia, pasaulinės maisto saugos institucijos ją yra patvirtinusios ir rimtų sveikatos problemų nenustatyta.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 359965;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic polymer used as a binder and stabiliser — it holds compressed tablets together and stops powders from clumping. You''ll mainly find it in tablet-form sweeteners and solid food supplements, not in everyday food products. It passes through the body largely unabsorbed and is considered safe at the low levels used. No significant health concerns have been raised for its approved uses.', opinion_lt = 'Tai sintetinis polimeras, naudojamas kaip rišiklis ir stabilizatorius — jis sulaiko suspaustas tabletes kartu ir neleidžia milteliams sukepti. Daugiausia jo rasite tablet formos saldikliuose ir kietose maisto papildų formose, o ne įprastuose maisto produktuose. Organizme jis praktiškai nesisurbiamas ir laikomas saugiu tokiais mažais kiekiais, kokiais yra naudojamas. Patvirtintam naudojimui jokių rimtų sveikatos problemų nenustatyta.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 360047;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic polymer used as a stabiliser and carrier in compressed tablets — it helps bind ingredients together so a tablet holds its shape and breaks down properly when swallowed. You''ll find it mainly in tablet-form sweeteners and solid food supplements. It passes through the body largely unabsorbed and is considered safe by major food safety authorities. Its use is limited to specific solid-form products, so most people encounter it only rarely.', opinion_lt = 'Tai sintetinis polimeras, naudojamas kaip rišiklis ir stabilizatorius pressuotuose tabletėse — jis padeda ingredientams sulipti į formą ir tinkamai ištirpti ar suirti po prarijimo. Dažniausiai jį rasite stalui skirtų saldiklių tabletėse ir kietuose maisto papilduose. Organizme jis praktiškai nesusigeria ir išsiskiria nepakitęs — pagrindinės maisto saugos institucijos jį laiko saugiu. Kadangi leidžiamas tik keliose specifinėse produktų kategorijose, dauguma žmonių su juo susiduria retai.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 360138;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic polymer used as a coating material — it forms a thin, smooth film on the outside of tablets and capsules, making them easier to swallow and helping to protect the contents from moisture. It is only authorised in a very narrow use case: solid food supplements for adults. Regulatory bodies consider it safe at the levels used, as it is largely not absorbed by the body and passes through the digestive system.', opinion_lt = 'Tai sintetinis polimeras, naudojamas kaip dengimo medžiaga — jis sudaro ploną, lygų sluoksnį ant tablečių ir kapsulių paviršiaus, kad jas būtų lengviau nuryti ir apsaugoti turinį nuo drėgmės. Leidžiama naudoti tik labai siaurame kontekste: kietosios formos maisto papilduose suaugusiesiems. Reguliavimo institucijos mano, kad tokia koncentracija jis yra saugus — organizmas jo praktiškai neįsisavina, ir jis paprasčiausiai išsiskiria per virškinimo sistemą.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 360207;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural polysaccharide — a type of sugar-based polymer — produced by fermentation of a fungus called Aureobasidium pullulans. It forms a thin, edible film and is mainly used as a coating or capsule material in breath mints and food supplement capsules. It has no nutritional value but helps products dissolve cleanly and keeps them shelf-stable. It is considered safe by food safety authorities, with no notable health concerns associated with normal consumption.', opinion_lt = 'Tai natūralios kilmės polisacharidas — cukrų grandinė, gaunama fermentuojant grybą Aureobasidium pullulans. Maiste jis naudojamas kaip plona valgoma plėvelė ar kapsulių apvalkalas — dažniausiai burnos gaivikliuose ir maisto papildų kapsulėse. Jokios maistinės vertės neturi, tačiau padeda produktui gražiai ištirpti ir ilgiau išlikti šviežiam. Maisto saugos institucijos laiko jį saugiu, jokių žinomų sveikatos problemų vartojant įprastais kiekiais nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 360254;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic polymer used as a coating material for tablets and capsules in food supplements. It helps control how and where a supplement dissolves in the digestive system, protecting active ingredients from stomach acid. Its use is very limited — only in solid-form supplements, not in everyday food products. Regulatory authorities consider it safe at the levels used, and it is not absorbed by the body.', opinion_lt = 'Tai sintetinis polimeras, naudojamas kaip dengimo medžiaga maisto papildų tabletėms ir kapsulėms. Jis padeda kontroliuoti, kaip ir kur papildas ištirpsta virškinimo trakte, apsaugodamas veikliąsias medžiagas nuo skrandžio rūgšties. Jo naudojimas labai ribotas — tik kietose maisto papildų formose, ne įprastuose maisto produktuose. Reguliavimo institucijos laiko jį saugiu naudojamomis dozėmis, o organizmas jo nepasisavina.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 360323;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic polymer used as a coating material for tablets and capsules in food supplements. It forms a protective shell around the supplement, helping it survive the acidic environment of the stomach and release its contents in the intestines instead. It is approved in a very narrow range of products and is not something you would find in everyday foods. At the amounts used in supplement coatings, it is considered safe by European food safety authorities.', opinion_lt = 'Tai sintetinis polimeras, naudojamas kaip dangos medžiaga maisto papildų tabletėms ir kapsulėms. Jis sudaro apsauginį sluoksnį, padedantį papildui išlikti skrandyje ir išskirti veikliąsias medžiagas tik žarnyne. Leidžiamas labai siaurai produktų grupei – įprastuose maisto produktuose jo nesutiksite. Europos maisto saugos institucijos mano, kad tokiais kiekiais, kokiais jis naudojamas dangose, jis yra saugus.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 363749;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic polymer used as a coating material for tablets and capsules — mainly in food supplements. It helps control how and where a supplement dissolves in the digestive system, protecting active ingredients from stomach acid. It is authorised in a very narrow range of products, which limits consumer exposure significantly. No major safety concerns have been raised at the levels used, and regulatory bodies consider it acceptable for its specific purpose.', opinion_lt = 'Tai sintetinis polimeras, naudojamas kaip dengimo medžiaga tabletėms ir kapsulėms — daugiausia maisto papilduose. Jis padeda kontroliuoti, kaip ir kur papildas ištirpsta virškinimo trakte, apsaugodamas veikliąsias medžiagas nuo skrandžio rūgšties. Leidžiama naudoti labai siaurame produktų rate, todėl vartotojų poveikis yra minimalus. Esant leidžiamoms dozėms, rimtų saugumo problemų nekyla, ir reguliavimo institucijos laiko jį tinkamu konkrečiam tikslui.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 363796;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic polymer used as a coating or binding agent, mainly in tablet and capsule-form food supplements. It helps pills hold their shape and makes them easier to swallow. Its use is very limited — you''ll only find it in solid supplement products, not in everyday foods. Regulatory bodies consider it safe at the levels used, and it passes through the body without being absorbed.', opinion_lt = 'Tai sintetinis polimeras, naudojamas kaip dengiklis arba rišiklis tabletėse ir kapsulėse — daugiausia maisto papilduose. Jis padeda tabletėms išlaikyti formą ir lengviau jas nuryti. Naudojamas labai ribotai — tik kietų papildų gamyboje, įprastuose maisto produktuose jo nerasite. Reguliavimo institucijos laiko jį saugiu naudojamomis dozėmis, o organizmas jo nepasisavina — jis tiesiog išsiskiria nepakitęs.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 362109;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic polymer used as a coating agent, specifically to create a smooth, protective film on solid food supplement tablets or capsules. It helps the tablet hold its shape, protects ingredients from moisture, and makes the supplement easier to swallow. Its use is very limited — only authorised in solid food supplements for adults. Regulatory authorities consider it safe at the levels used, and because exposure is minimal and infrequent, it poses little concern for most people.', opinion_lt = 'Tai sintetinis polimeras, naudojamas kaip dengimo medžiaga — jis sukuria lygią, apsauginę plėvelę ant kietų maisto papildų tablečių ar kapsulių. Padeda tabletei išlaikyti formą, apsaugo sudedamąsias dalis nuo drėgmės ir palengvina ryjimą. Jo naudojimas labai ribotas — leidžiamas tik kietuose suaugusiųjų maisto papilduose. Reguliavimo institucijos laiko jį saugiu naudojamais kiekiais, o kadangi poveikis yra minimalus ir retas, daugumai žmonių jis nekelia didelio susirūpinimo.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 363610;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic polymer made from acrylic acid, used mainly as a thickening and gelling agent. In food, it appears almost exclusively in dietary supplements — helping tablets hold their shape or giving liquid supplements a smooth, consistent texture. It is not something you would find in everyday foods like bread or drinks. Regulatory bodies have approved it for these specific uses at the levels typically found in supplements, and it is generally considered safe for consumption in those contexts.', opinion_lt = 'Tai sintetinis polimeras, pagamintas iš akrilo rūgšties, naudojamas kaip tirštiklis ir gelio formavimo medžiaga. Maiste jį rasite beveik išskirtinai maisto papilduose — jis padeda tabletėms išlaikyti formą arba suteikia skystiems papildams vienodą, sklandžią tekstūrą. Įprastuose maisto produktuose, kaip duona ar gėrimai, jo nesutiksite. Reguliavimo institucijos yra patvirtinusios jo naudojimą šiems konkretiems tikslams tokiais kiekiais, kokie paprastai randami papilduose, ir jis laikomas saugiu vartoti.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 716805;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a modified starch — regular starch (usually from corn, wheat, or potatoes) that has been treated with a mild oxidising agent to change how it behaves in food. It works as a thickener and stabiliser, helping products like low-fat creams and dairy drinks maintain a smooth, consistent texture. It is a chemically processed ingredient, though it comes from a natural base. It is approved for use in a limited number of food categories, including baby foods, where strict safety standards apply. Regulatory bodies consider it safe at the levels used in food.', opinion_lt = 'Tai modifikuotas krakmolas — įprastas krakmolas (dažniausiai iš kukurūzų, kviečių ar bulvių), chemiškai apdorotas oksidatoriumi, kad keistųsi jo savybės. Maiste jis naudojamas kaip tirštiklis ir stabilizatorius — padeda neriebiems kremams ar pieno gėrimams išlaikyti vienodą, kremišką konsistenciją. Nors žaliava yra natūralios kilmės, pats procesas yra cheminis. Leidžiamas tik keliose maisto kategorijose, tarp jų — kūdikių maiste, kur taikomi ypač griežti saugos reikalavimai. Reguliavimo institucijos laiko jį saugiu, vartojamu įprastais kiekiais.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 360370;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a modified starch — regular plant starch (usually from corn, potato, or wheat) that has been chemically tweaked to make it more stable and better at thickening. It helps food keep a smooth, consistent texture even when heated, frozen, or stored. You''ll find it in low-fat dairy products, baby foods, and cereal-based foods for young children. It is generally considered safe, and regulatory bodies like EFSA have approved its use in specific food categories, including products for infants and young children, at controlled levels.', opinion_lt = 'Tai modifikuotas krakmolas — įprastas augalinis krakmolas (dažniausiai iš kukurūzų, bulvių ar kviečių), chemiškai apdorotas tam, kad geriau tirštintų ir išlaikytų tekstūrą kaitinant, šaldant ar laikant. Randamas mažai riebiuose pieno produktuose, kūdikių maiste ir grūdų pagrindu pagamintuose produktuose mažiems vaikams. Laikomas saugiu — tokios institucijos kaip EFSA patvirtino jo naudojimą konkrečiose kategorijose, įskaitant kūdikių ir mažų vaikų maistą, griežtai kontroliuojamais kiekiais.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 360443;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a modified starch — regular starch that has been chemically treated to make it more stable and better at thickening. It helps food keep a smooth, consistent texture even when heated, frozen, or stored for a long time. You''ll find it mainly in dairy-based products, baby foods, and cereal-based foods for young children. It is generally considered safe, and regulatory bodies have approved it specifically for use in foods intended for infants and young children, though the amounts permitted are carefully controlled.', opinion_lt = 'Tai modifikuotas krakmolas — įprastas krakmolas, chemiškai apdorotas tam, kad geriau tirštintų ir išlaikytų stabilią tekstūrą kaitinant, šaldant ar ilgai laikant. Dažniausiai jį rasite pieno produktuose, kūdikių maiste ir grūdų pagrindu pagamintuose maisto produktuose mažiems vaikams. Jis laikomas saugiu, o reguliavimo institucijos jį patvirtino net kūdikių ir mažų vaikų maistui — tačiau leidžiami kiekiai yra griežtai ribojami.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 360516;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a modified starch — regular starch that has been chemically treated to make it more stable and better at thickening. It helps food keep a smooth, consistent texture even when heated, cooled, or stored. You''ll find it mainly in low-fat dairy products, baby foods, and cereal-based foods for young children. Because it appears in products made for infants and young children, its use is tightly regulated and permitted only in specific, limited amounts set by European food safety authorities. It is generally considered safe at the levels allowed in food.', opinion_lt = 'Tai modifikuotas krakmolas — įprastas krakmolas, chemiškai apdorotas tam, kad būtų stabilesnis ir geriau tirštintų maistą. Jis padeda išlaikyti vientisą, kreminę tekstūrą net kaitinant, šaldant ar laikant ilgiau. Dažniausiai randamas mažo riebumo pieno produktuose, kūdikių maiste ir grūdų pagrindu pagamintuose produktuose mažiems vaikams. Kadangi šis priedas naudojamas kūdikių ir mažų vaikų maiste, jo naudojimas yra griežtai reglamentuotas ir leidžiamas tik konkrečiomis, ribotomis dozėmis pagal Europos maisto saugos taisykles. Leistinosiose normose laikomas saugiu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 360589;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a modified starch — meaning regular starch (often from corn, potato, or wheat) that has been chemically tweaked in a lab to make it more stable, smoother, and resistant to heat, acid, or freezing. It acts as a thickener and texture improver in foods like low-fat dairy products, meat preparations, and baby foods. It helps give products a creamy, consistent texture without breaking down during processing or storage. Regulatory bodies in the EU and globally consider it safe at the levels used in food. Since it appears in baby food categories, it is subject to stricter safety scrutiny — and has passed those checks.', opinion_lt = 'Tai modifikuotas krakmolas — paprastas krakmolas (dažniausiai iš kukurūzų, bulvių ar kviečių), kuriam laboratorijoje atlikti cheminiai pakeitimai, kad jis būtų stabilesnis, vienodesnės tekstūros ir atsparesnis karščiui, rūgštims ar šaldymui. Jis naudojamas kaip tirštiklis ir tekstūros gerintojas mažai riebalingų pieno produktų, mėsos gaminių ir kūdikių maisto sudėtyje. ES maisto saugos institucijos jį laiko saugiu tais kiekiais, kuriais jis dedamas į maistą. Kadangi šis priedas leidžiamas ir kūdikių maiste, jam taikomi griežtesni saugos reikalavimai — ir jis juos atitinka.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 360662;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a modified starch — regular plant starch (usually from corn, wheat, or potato) that has been chemically tweaked with acetic acid to make it more stable and smooth in foods. It acts as a thickener and texture improver, helping products stay creamy and not separate or go watery. It is synthetic in the sense that it undergoes chemical modification, though it starts from a natural source. It appears in a fairly limited range of products, notably low-fat fermented dairy alternatives, baby cereals, and milk-based drinks for young children. Regulatory bodies consider it safe at the levels used, and there is no significant controversy around it.', opinion_lt = 'Tai modifikuotas krakmolas — įprastas augalinis krakmolas (dažniausiai iš kukurūzų, kviečių ar bulvių), chemiškai apdorotas acto rūgštimi, kad taptų stabilesnis ir suteiktų maistui kremingesnę tekstūrą. Jis naudojamas kaip tirštiklis, neleidžiantis produktams išsiskirti į sluoksnius ar tapti vandeningiems. Nors žaliava natūrali, pats procesas yra cheminis. Šis priedas leidžiamas gana siauroje produktų grupėje — mažariebalėse fermentuotose pieno alternatyvose, kūdikių kruopų košėse ir pieno gėrimuose mažiems vaikams. Reguliuotojai laiko jį saugiu naudojamomis dozėmis, ir didesnio ginčo dėl jo nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 360757;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a modified starch — starch that has been chemically tweaked to make it more stable, smoother, and resistant to heat, freezing, and acidity. It works as a thickener and texture improver, helping foods stay creamy and consistent. You''ll find it mainly in low-fat dairy products, baby foods, and children''s drinks. It is synthetic in origin, derived from natural starch but chemically modified. Regulatory bodies in the EU consider it safe at authorised levels, though its use in foods for infants and young children is tightly restricted and monitored.', opinion_lt = 'Tai modifikuotas krakmolas — chemiškai apdorotas, kad būtų stabilesnis, lygesnis ir atsparus karščiui, šaldymui bei rūgštingumui. Jis naudojamas kaip tirštiklis ir tekstūros gerintojas, padedantis maistui išlikti kremingam ir vienodingam. Dažniausiai randamas mažai riebalingų pieno produktuose, kūdikių maiste ir vaikams skirtuose gėrimuose. Kilmė sintetinė — gaminamas iš natūralaus krakmolo, tačiau chemiškai modifikuotas. ES institucijos laiko jį saugiu leidžiamomis dozėmis, tačiau jo naudojimas kūdikių ir mažų vaikų maiste yra griežtai ribojamas ir stebimas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 360830;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a modified starch — starch (usually from corn, potato, or wheat) that has been chemically tweaked to make it more stable and functional in processed foods. It acts as a thickener and texture improver, helping products stay smooth and consistent. It is considered safe by major food safety authorities and is used in a fairly limited range of products. Most people consume it without any issues.', opinion_lt = 'Tai modifikuotas krakmolas — dažniausiai kukurūzų, bulvių ar kviečių — chemiškai apdorotas tam, kad geriau tirštintų ir stabilizuotų maisto produktus. Jis padeda išlaikyti vienodą, kremišką tekstūrą. Pagrindinės maisto saugos institucijos laiko jį saugiu, o jo naudojimas yra gana ribotas. Dauguma žmonių jį vartoja be jokių problemų.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 360903;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a modified starch — a substance derived from natural starch (often corn, potato, or tapioca) that has been chemically treated to make it more stable and consistent in food. It acts as a thickener and stabiliser, helping products like low-fat dairy or meat preparations hold their texture even when heated or frozen. It is synthetic in the sense that it has been chemically modified, though it starts from a natural source. Regulatory bodies in Europe and elsewhere generally consider it safe at the levels used in food, and it is not currently linked to any notable health concerns.', opinion_lt = 'Tai modifikuotas krakmolas — medžiaga, pagaminta iš natūralaus krakmolo (dažniausiai kukurūzų, bulvių ar tapiokos), kuri chemiškai apdorojama, kad taptų stabilesnė ir geriau elgtųsi gamybos metu. Maiste ji veikia kaip tirštiklis ir stabilizatorius — padeda žemų riebalų pieno produktams ar mėsos pusgaminiams išlaikyti tekstūrą net kaitinant ar šaldant. Nors žaliava natūrali, pats procesas yra cheminis, tad tai laikoma sintetiniu priedu. Europos maisto saugos institucija šią medžiagą laiko saugia tokiais kiekiais, kokie naudojami maisto pramonėje, ir šiuo metu ji nesiejama su jokiais reikšmingais sveikatos pavojais.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 360950;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a modified starch — regular plant starch that has been chemically treated to make it behave differently in food. It acts as an emulsifier and thickener, helping oil and water stay mixed together smoothly. You''ll find it in infant formulas, baby foods, medical nutrition products, and some dairy-based drinks. Because it appears in foods for very young children, it has been carefully reviewed by food safety authorities and is considered safe at permitted levels. It is synthetic in the sense that it is chemically modified, though it starts from a natural starch source.', opinion_lt = 'Tai modifikuotas krakmolas — įprastas augalinis krakmolas, chemiškai apdorotas tam, kad geriau atliktų savo funkciją maiste. Jis veikia kaip emulgatorius ir tirštiklis, padedantis riebalams ir vandeniui nesiskirti. Dažniausiai randamas kūdikių mišiniuose, maistui kūdikiams, medicininės paskirties maisto produktuose ir kai kuriuose pieno gėrimuose mažiems vaikams. Kadangi šis priedas naudojamas labai mažų vaikų maiste, jis buvo atidžiai įvertintas maisto saugos institucijų ir laikomas saugiu leidžiamomis dozėmis. Techniškai jis yra sintetiškai modifikuotas, nors pagaminamas iš natūralaus krakmolo.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 361019;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a chemically modified starch — regular starch that has been treated to improve its stability and texture in processed foods. It acts as a thickener and stabiliser, helping products maintain a smooth, consistent texture. You''ll find it in low-fat dairy alternatives and some infant cereal-based foods. Because it''s permitted in baby food categories, it is held to very strict safety standards by European food authorities and is considered safe at the levels used.', opinion_lt = 'Tai chemiškai modifikuotas krakmolas — įprastas krakmolas, apdorotas tam, kad pagerintų jo stabilumą ir tekstūrą perdirbtuose maisto produktuose. Jis naudojamas kaip tirštiklis ir stabilizatorius, padedantis produktams išlaikyti vienodą, švelnią konsistenciją. Galima rasti mažai riebalų turinčiuose pieno pakaitaluose ir kai kuriuose grūdų pagrindu pagamintuose kūdikių maisto produktuose. Kadangi jis leidžiamas kūdikių maistui, Europos maisto saugos institucijos jam taiko labai griežtus saugos reikalavimus, ir esant naudojamoms dozėms jis laikomas saugiu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 361118;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a chemically modified starch used as an emulsifier and coating agent — it helps powders flow freely and prevents clumping. It is authorised only in a very narrow range of food uses, specifically for encapsulating food supplements in powder form. The aluminium content is low, and regulatory bodies like EFSA consider it safe at authorised levels. Still, if you prefer to minimise modified or aluminium-containing additives, checking supplement labels is a reasonable step.', opinion_lt = 'Tai chemiškai modifikuotas krakmolas, naudojamas kaip emulsiklis ir dangos medžiaga — padeda milteliams nesusigumuliuoti ir laisvai bėrėti. Leidžiamas tik labai siaurame maisto produktų sąraše, daugiausia maisto papildų miltelių kapsulių gamyboje. Aliuminio kiekis jame nedidelis, o institucijos kaip EFSA laiko jį saugiu leidžiamomis normomis. Vis dėlto, jei norite vengti modifikuotų ar aliuminio turinčių priedų, verta atidžiau skaityti papildų etiketes.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 361178;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic ester of citric acid — so it''s closely related to a naturally occurring compound. It acts mainly as a stabiliser and carrier solvent, helping ingredients blend together smoothly or keeping coatings and powders from clumping. You''ll find it in processed egg products and solid food supplements. It has a long safety record and is approved in the EU for use in a limited number of product categories. No significant health concerns are associated with it at the levels used in food.', opinion_lt = 'Tai sintetinis citrinų rūgšties darinys — taigi cheminiu požiūriu artimas natūraliai randamoms medžiagoms. Jis naudojamas kaip stabilizatorius ir tirpiklis: padeda ingredientams geriau jungtis, neleidžia milteliams ar dangoms sulipti. Randamas perdirbtų kiaušinių produktuose ir kietosios formos maisto papilduose. Ilgametė naudojimo patirtis rodo, kad šiomis koncentracijomis jis neturi reikšmingo poveikio sveikatai, o ES leidžia jį naudoti tik ribotame produktų sąraše.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 361224;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic ester made by combining glycerol with acetic acid — essentially a close chemical cousin of vinegar and fats. It acts mainly as a solvent and carrier for flavourings, helping them blend evenly into food. You''ll mostly find it in flavouring preparations rather than directly on your plate. It is authorised in very few food categories, which tells you it has a pretty limited role. Regulatory bodies consider it safe at the levels used in food.', opinion_lt = 'Tai sintetinis junginys, gaunamas iš glicerolio ir acto rūgšties — artimas giminaitis tiek actui, tiek riebalams. Maiste jis dažniausiai naudojamas kaip tirpiklis aromatinėms medžiagoms — padeda skoniams tolygiai pasiskirstyti produkte. Pats savaime jo retai rasite tiesiai lėkštėje, jis dažniau slepiasi aromato prieduose. Leidžiamas tik labai nedaugelyje maisto kategorijų, todėl jo vartojimas gana ribotas. Reguliavimo institucijos jį laiko saugiu naudojamais kiekiais.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 361293;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic compound made by combining glycerol with acetic acid — the same acid found in vinegar. It works mainly as a humectant and solvent, helping ingredients blend together and keeping the texture smooth and flexible. You''ll find it most often in chewing gum, where it helps hold the gum base together. It has a long safety record and is generally considered safe at the low levels used in food.', opinion_lt = 'Tai sintetinis junginys, gaunamas iš glicerolio ir acto rūgšties — tos pačios, kuri randama actе. Maiste jis naudojamas kaip drėgmę išlaikanti ir tirpinanti medžiaga, padedanti sumaišyti ingredientus ir išlaikyti minkštą, lankstią tekstūrą. Dažniausiai jo rasite kramtomojoje gumoje, kur jis padeda surišti gumos pagrindą. Saugumo istorija ilga, o naudojamais kiekiais jis laikomas nekenksmingu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 361339;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally occurring alcohol found in many fruits, teas, and flowers, though the version used in food is typically synthetic. It acts as a flavouring agent, adding a faint floral or fruity note, and is authorised in only a very narrow range of food products, meaning most people encounter it rarely in food.', opinion_lt = 'Tai natūraliai gamtoje randamas alkoholis, esantis vaisiuose, arbatose ir gėlėse, tačiau maisto pramonėje dažniausiai naudojamas sintetinis jo variantas. Jis naudojamas kaip aromatinė medžiaga, suteikianti subtilų žiedinį ar vaisinį atspalvį, ir leidžiamas tik labai siauroje maisto produktų kategorijoje, tad dauguma žmonių su juo maiste susiduria retai.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 361386;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic solvent and humectant — it helps keep moisture in food and carries flavours or colours evenly through a product. It''s approved in very few food categories, so you won''t encounter it often. Regulators consider it safe at the low levels permitted in food, and it has a long history of use in both food and pharmaceuticals. Large amounts can be problematic, but the quantities found in food are far below any concerning threshold.', opinion_lt = 'Tai sintetinis tirpiklis ir drėgmę išlaikanti medžiaga — ji neleidžia maistui išdžiūti ir padeda tolygiai paskirstyti skonius ar dažiklius. Leidžiama naudoti labai nedaug maisto kategorijų, tad dažnai jos nepasitaikys. Reguliavimo institucijos laiko ją saugia tokiais kiekiais, kokie leidžiami maiste, o ji jau seniai naudojama tiek maisto pramonėje, tiek farmacijoje. Didelės dozės gali kelti problemų, tačiau maiste jos būna kur kas mažesnės, nei reikėtų susirūpinti.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 361432;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic compound used as a coating or binding agent in tablets and powdered products — it helps ingredients stick together or prevents them from clumping. You''ll find it mainly in sweetener tablets and solid food supplements, where it plays a technical role rather than adding any flavour or nutritional value. It''s approved for use in a small number of food categories and at controlled levels. It''s widely used in pharmaceuticals too, and at the low amounts present in food, it is generally considered safe for most adults.', opinion_lt = 'Tai sintetinis junginys, naudojamas kaip dengimo ar rišamoji medžiaga tabletėse ir milteliniuose produktuose — padeda ingredientams sulipti arba neleidžia jiems sukepti. Dažniausiai jį rasite saldintuvo tabletėse ar kietuose maisto papilduose, kur jis atlieka grynai techninę funkciją ir neprideda jokio skonio ar maistinės vertės. Leidžiama naudoti tik keliose maisto kategorijose ir griežtai kontroliuojamais kiekiais. Šis junginys plačiai taikomas ir farmacijoje, o tokiais mažais kiekiais, kokius galima rasti maiste, daugumui suaugusiųjų laikomas saugiu.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 361478;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a preservative — one of the most widely used in the food industry — that stops mould, yeast, and some bacteria from growing. It''s found in cheeses, fruit products, baked goods, wine, dried fruits, and many other everyday foods. Sorbic acid itself occurs naturally in some berries, though the version used in food is synthetically produced. It''s considered very safe by major food safety authorities worldwide, with a long track record of use and low toxicity. Some people with sensitivities may experience mild reactions, but this is uncommon.', opinion_lt = 'Tai konservantas — vienas dažniausiai naudojamų maisto pramonėje — kuris stabdo pelėsių, mielių ir kai kurių bakterijų augimą. Randamas sūriuose, vaisių produktuose, kepiniuose, vyne, džiovintuose vaisiuose ir daugelyje kitų kasdienių maisto produktų. Rūgštis natūraliai aptinkama kai kuriuose uogiuose, tačiau į maistą dedama jos sintetinė versija. Pagrindinės pasaulio maisto saugos institucijos laiko ją labai saugia — ji naudojama jau seniai ir pasižymi mažu toksiškumu. Kai kurie žmonės su padidėjusiu jautrumu gali pajusti lengvas reakcijas, tačiau tai pasitaiko retai.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 326861;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a group of preservatives — some derived from natural sources (sorbic acid occurs naturally in berries), others synthetic (benzoates). Their job is to stop mould, yeast, and bacteria from growing, which keeps foods like pickles, jams, sauces, fish roe, and dressings fresh for longer. They are widely approved and considered safe at the levels used in food.

The benzoate members of this group have attracted some attention — when combined with ascorbic acid (vitamin C) in drinks, they can form small amounts of benzene, a known carcinogen. Some studies also linked benzoates to hyperactivity in children, which led to stricter labelling rules in the EU. Sorbates are generally viewed as the less controversial option of the two.', opinion_lt = 'Tai konservantų grupė — kai kurie iš jų natūralios kilmės (sorbino rūgštis natūraliai randama uogose), kiti sintetiniai (benzoatai). Jų paskirtis — stabdyti pelėsių, mielių ir bakterijų augimą, todėl produktai kaip marinuotos daržovės, uogienės, padažai, žuvies ikrai ir užtepėlės ilgiau išlieka švieži. Leidžiamomis dozėmis jie laikomi saugiais.

Benzoatai sulaukė daugiau diskusijų — kartu su vitaminu C gėrimuose jie gali susidaryti nedidelį kiekį benzeno, kuris yra kancerogeninis. Kai kurie tyrimai taip pat siejo benzoatus su padidėjusiu vaikų aktyvumu, todėl ES įvedė papildomas ženklinimo taisykles. Sorbatai apskritai laikomi mažiau prieštaringa grupės dalimi.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 327643;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a group of preservatives — sorbic acid and its salts, benzoic acid and its relatives, and parabens. They work by stopping mould, yeast, and bacteria from growing, which helps extend the shelf life of foods like processed meats, confectionery coatings, and liquid sweeteners. Most are synthetic, though sorbic acid does occur naturally in some berries. Regulatory bodies like EFSA and FDA consider them safe at permitted levels. Benzoates have attracted some attention because, combined with certain artificial colours, they may be linked to hyperactivity in children — the evidence is debated, but worth knowing if you have young kids.', opinion_lt = 'Tai konservantų grupė — sorbo rūgštis ir jos druskos, benzoinė rūgštis ir jos junginiai, bei parabenai. Jie slopina pelėsių, mielių ir bakterijų augimą, todėl prailgina produktų galiojimo laiką — rasi juos perdirbtoje mėsoje, saldainių dengiamuosiuose sluoksniuose ir skyste pavidalo saldikliuose. Dauguma jų yra sintetinės kilmės, nors sorbo rūgštis natūraliai aptinkama kai kuriuose uogiuose. EFSA ir kitos institucijos laiko juos saugiais leidžiamomis dozėmis. Benzoatai kiek labiau diskutuojami — kai kurių tyrimų duomenimis, kartu su tam tikrais dirbtiniais dažikliais jie gali sustiprinti hiperaktyvumą vaikams, tačiau mokslininkų nuomonės šiuo klausimu vis dar skiriasi.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 328124;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a group of synthetic preservatives widely used to stop mould, yeast, and bacteria from growing in acidic foods. You''ll find them in pickles, jams, sauces, soft drinks, and some alcoholic beverages. They are one of the most studied preservative groups in food science. The controversy worth knowing: when combined with vitamin C (ascorbic acid), benzoates can form benzene, a known carcinogen — though the amounts detected in foods are typically very small. Some studies also link high intake to hyperactivity in children, which led the EU to require a warning label on products containing certain related additives. Regulatory agencies consider them safe at permitted levels, but sensitive individuals — especially children — may want to limit exposure.', opinion_lt = 'Tai sintetinių konservantų grupė, naudojama tam, kad rūgščiuose maisto produktuose neaugtų pelėsiai, mielės ir bakterijos. Jų rasite marinuotuose agurkuose, džemuose, padažuose, gazuotuose gėrimuose ir kai kuriuose alkoholiniuose gėrimuose. Kontroversija verta dėmesio: sujungus benzoatus su vitaminu C (askorbo rūgštimi), gali susidaryti benzenas — žinomas kancerogenas, nors maiste aptinkami jo kiekiai paprastai yra labai maži. Kai kurie tyrimai taip pat sieja didelį šių medžiagų vartojimą su hiperaktyvumu vaikams — dėl to ES reikalauja specialaus įspėjimo ant tam tikrų produktų etikečių. Reguliavimo institucijos laiko juos saugiais leidžiamomis dozėmis, tačiau jautrūs žmonės, ypač vaikai, galėtų apsvarstyti, ar verta jų per daug suvartoti.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 328415;
UPDATE aggregate.eu_additives SET opinion_en = 'These are synthetic preservatives used to stop mould and bacteria from growing in food. They are approved in very few food categories in the EU, meaning you won''t encounter them often. Some research has raised questions about potential hormonal effects at high doses, though regulatory bodies consider them safe at the low levels permitted in food. If you are cautious, checking ingredient labels is a reasonable habit.', opinion_lt = 'Tai sintetiniai konservantai, naudojami siekiant sulaikyti pelėsių ir bakterijų augimą maiste. ES jie leidžiami labai nedaugelyje maisto kategorijų, tad dažnai su jais nesusidursite. Kai kurie tyrimai kelia klausimų dėl galimo poveikio hormonų sistemai didelėmis dozėmis, tačiau reguliavimo institucijos laiko juos saugiais tokiais kiekiais, kokie leidžiami maiste. Jei esate atsargūs, verta įprasti skaityti sudėties etiketes.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 328955;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a group of synthetic preservatives that have been used in food and winemaking for centuries. They prevent browning, stop mold and bacteria growth, and help foods stay fresh longer — you''ll find them in dried fruits, wine, pickled vegetables, fruit juices, and many processed foods. They are among the most widely used preservatives in the world and are generally considered safe at approved levels. However, they are a known allergen for some people, particularly those with asthma, and can trigger reactions like breathing difficulties or skin irritation. EU law requires products containing them to be clearly labelled, so people who are sensitive can easily avoid them.', opinion_lt = 'Tai sintetinių konservantų grupė, naudojama maiste ir vyno gamyboje jau šimtmečius. Jie neleidžia maistui patamsėti, slopina pelėsių ir bakterijų augimą — todėl dažnai randami džiovintuose vaisiuose, vyne, marinuotuose produktuose, vaisių sultyse ir įvairiuose perdirbtuose maisto produktuose. Apskritai laikomi saugiais leidžiamose dozėse, tačiau kai kuriems žmonėms, ypač sergantiems astma, jie gali sukelti alerginę reakciją — sunkumą kvėpuoti, odos dirginimą ar kitus simptomus. ES teisės aktai reikalauja, kad produktai su šiais priedais būtų aiškiai paženklinti, tad jautrūs žmonės gali jų lengvai išvengti.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 329212;
UPDATE aggregate.eu_additives SET opinion_en = 'These are preservatives used primarily in cured and processed meats like bacon, ham, hot dogs, and salami. They prevent the growth of dangerous bacteria, including Clostridium botulinum, which causes botulism — a potentially fatal illness. Without them, many cured meat products would be significantly less safe to eat. The controversy is real though: when nitrites are exposed to high heat or react with proteins in meat, they can form nitrosamines, which are classified as probable human carcinogens. Health authorities consider current permitted levels safe, but many nutritionists recommend limiting processed meat consumption overall.', opinion_lt = 'Tai konservantai, naudojami daugiausia vytintoje ir perdirbti mėsoje — šoninėje, kumpyje, dešrelėse, saliamyje. Jie apsaugo nuo pavojingų bakterijų, įskaitant botulizmo sukėlėją, kuris gali būti mirtinas. Be jų daug vytintos mėsos produktų būtų kur kas nesaugesnių valgyti. Tačiau kontraversija čia tikra: kai nitritai susiduria su aukšta temperatūra arba reaguoja su mėsos baltymais, gali susidaryti nitrozaminai — junginiai, priskirti prie tikėtinų kancerogenų. Maisto saugos institucijos mano, kad leidžiami kiekiai yra saugūs, tačiau daugelis mitybos specialistų pataria apskritai riboti perdirbtos mėsos vartojimą.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 330859;
UPDATE aggregate.eu_additives SET opinion_en = 'These are curing salts used mainly in processed and cured meats — think bacon, ham, salami, and aged cheeses. They prevent dangerous bacterial growth, including the bacteria responsible for botulism, and help preserve that characteristic pink colour and flavour we associate with cured products. Without them, many traditional cured meats would be significantly less safe to eat.

The controversy is real but worth keeping in perspective. In the body, nitrates can convert into nitrites and then into nitrosamines, some of which are classified as probable carcinogens. Processed meat consumption has been linked to a modestly increased colorectal cancer risk, partly due to these compounds. However, vegetables like spinach and beetroot naturally contain far more nitrates than cured meat — the risk context matters. Eating cured meats occasionally is very different from daily heavy consumption.', opinion_lt = 'Tai druskos, naudojamos daugiausia vytintai ir rūkytai mėsai — šoninei, kumpiai, saliamai, taip pat subrandintiems sūriams. Jos slopina pavojingų bakterijų, įskaitant botulizmo sukėlėją, augimą ir išlaiko tą charakteringą rausvą spalvą bei skonį, kurį siejame su vytintais gaminiais. Be jų daugelis tradicinių mėsos gaminių būtų gerokai nesaugesni.

Kontroversija egzistuoja, bet verta žiūrėti į ją blaiviai. Organizme nitratai gali virsti nitritais, o vėliau — nitrozaminais, kurių dalis laikoma tikėtinais kancerogenais. Perdirbtų mėsos gaminių vartojimas siejamas su šiek tiek padidėjusia žarnyno vėžio rizika. Tačiau daržovės, pavyzdžiui, špinatai ar burokėliai, natūraliai turi kur kas daugiau nitratų nei vytinta mėsa — svarbus kontekstas. Retkarčiais suvalgyta šoninė — tai visai kas kita nei kasdieniai dideli kiekiai.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 2815922;
UPDATE aggregate.eu_additives SET opinion_en = 'These are preservatives — propionic acid and its salts — used mainly to prevent mould and bacterial growth in baked goods like bread, rolls, and fine pastries, as well as in some cheeses. Propionic acid actually occurs naturally in some foods, including certain cheeses where it''s produced during fermentation, so it''s not entirely foreign to our diet. At the levels used in food, regulatory bodies like EFSA consider them safe for the general population. Some individuals report sensitivity, including headaches, but large-scale evidence for harm at typical food doses is lacking.', opinion_lt = 'Tai konservantai — propiono rūgštis ir jos druskos — daugiausia naudojami kepiniuose (duonoje, bandose, pyraguose) bei kai kuriuose sūriuose, kad nesidaugintų pelėsiai ir bakterijos. Propiono rūgštis iš tikrųjų natūraliai susidaro kai kurių sūrių fermentacijos metu, tad ji nėra visiškai svetima medžiaga mūsų mityboje. Maisto saugos institucijos, įskaitant EFSA, laiko juos saugiais tomis dozėmis, kurios naudojamos maisto pramonėje. Retais atvejais žmonės skundžiasi jautrumu ar galvos skausmais, tačiau plačių tyrimų, įrodančių žalą įprastomis dozėmis, kol kas nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 332266;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a group of synthetic antioxidants used to prevent fats and oils from going rancid. You''ll find them in products like cooking oils, margarine, nut butters, processed meats, breakfast cereals, and baked goods — basically anything with a high fat content that needs a longer shelf life. They do a practical job: without them, many fatty foods would spoil much faster.

That said, some of these additives — particularly BHA — have raised questions in scientific research, with some animal studies suggesting possible concerns at high doses. Regulatory bodies in the EU and elsewhere still consider them safe at the levels permitted in food, but a few of them are restricted or banned in certain countries. If you prefer to avoid them, checking ingredient labels on processed and packaged fatty foods is the way to go.', opinion_lt = 'Tai sintetinių antioksidantų grupė, naudojama tam, kad riebalai ir aliejai nesuteptų ir nepageltų. Juos rasite augaliniuose aliejuose, margarinuose, riešutų pastuose, perdirbtoje mėsoje, dribsniuose ir kepiniuose — iš esmės bet kur, kur daug riebalų ir reikia ilgesnio galiojimo laiko. Praktiškai jie atlieka svarbų vaidmenį — be jų daug riebių produktų greitai taptų nebevalgomos.

Vis dėlto kai kurie iš šių priedų, ypač BHA, kėlė klausimų mokslininkams — gyvūnų tyrimai didelėmis dozėmis parodė tam tikrų nerimą keliančių požymių. ES ir kitų šalių reguliavimo institucijos kol kas laiko juos saugiais leistinosiose koncentracijose, tačiau kai kuriose valstybėse jie ribojami arba visai draudžiami. Jei norite jų vengti — verta skaityti sudėčių etiketes ant perdirbtų ir supakuotų riebių produktų.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 334471;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a group of synthetic antioxidants used to prevent fats and oils from going rancid. You''ll find them in things like chewing gum, seasonings, and dietary supplements — basically anywhere fat content needs a longer shelf life. They are effective preservatives that have been used in food for decades.', opinion_lt = 'Tai sintetinių antioksidantų grupė, naudojama tam, kad riebalai ir aliejai nesuteptų ir nesugeltų. Jų rasite kramtomojoje gumoje, prieskoniniuose mišiniuose ir maisto papilduose — ten, kur reikia pailginti riebių produktų galiojimo laiką. Kai kurie iš šių medžiagų, ypač BHA ir BHT, sulaukė mokslininkų dėmesio dėl galimo poveikio sveikatai didelėmis dozėmis, tačiau dabartiniai leistini kiekiai maiste laikomi saugiais. Vis dėlto tie, kurie nori vengti sintetinių priedų, turėtų atkreipti dėmesį į ingredientų sąrašus.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 334727;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a group of acidulants — they add a mild, tart taste to food and help control acidity. Adipic acid occurs naturally in small amounts in beets and some other plants, but the version used in food is synthetically produced. You''ll find it in flavoured yogurts, desserts, flavoured drinks, and decorative cake coatings.

Regulatory bodies like EFSA have reviewed these additives and consider them safe at the levels used in food. They are not among the controversial additives, and there is no significant public debate around them. For most people, the amounts consumed through normal eating are well within acceptable daily intake limits.', opinion_lt = 'Tai rūgštiklių grupė — jie suteikia maistui lengvą, rūgštelėjantį skonį ir padeda reguliuoti rūgštingumą. Adipino rūgštis gamtoje randama nedideliais kiekiais runkeliuose ir kai kuriuose augaluose, tačiau maiste naudojama jos sintetinė versija. Dažniausiai ji aptinkama skoniuose jogurtuose, desertuose, skoniuose gėrimuose ir tortų puošybos masėse.

Europos maisto saugos tarnyba (EFSA) išnagrinėjo šiuos priedus ir laiko juos saugiais tomis dozėmis, kurios naudojamos maiste. Jie nepriskiriami prie kontraversiškų priedų ir didelių diskusijų nekelia. Paprastai valgant jų suvartojamas kiekis neviršija leistinos paros normos.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 339525;
UPDATE aggregate.eu_additives SET opinion_en = 'These are natural substances extracted from brown seaweed, used as thickeners and gelling agents to give foods a smooth, stable texture. You''ll find them in jams, jellies, marmalades, and similar spreads, where they help achieve that perfect consistency. They have a long history of safe use and are generally well-tolerated, with no significant safety concerns flagged by major food authorities.', opinion_lt = 'Tai natūralios medžiagos, gaunamos iš rudųjų jūros dumblių, naudojamos kaip tirštikliai ir želifikuojančios medžiagos, suteikiančios maistui lygią, stabilią tekstūrą. Jų rasite dribiniuose, dželė, marmeladėse ir panašiuose tepaliuose, kur jie padeda pasiekti tinkamą konsistenciją. Šios medžiagos turi ilgą saugaus naudojimo istoriją ir paprastai gerai toleruojamos — jokių rimtų saugumo problemų pagrindinės maisto institucijos nėra užfiksavusios.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 340515;
UPDATE aggregate.eu_additives SET opinion_en = 'These are synthetic emulsifiers — lab-made molecules that help oil and water mix smoothly in food. You''ll find them in ice cream, whipped toppings, baked goods, sauces, and desserts, where they improve texture and prevent separation. They are approved by food safety authorities in the EU and US and are generally considered safe at the levels used in food. Some animal studies at very high doses raised questions about gut microbiome effects, but the amounts people actually consume through food are far below those levels.', opinion_lt = 'Tai sintetiniai emulsikliai — laboratorijoje sukurti junginiai, padedantys sumaišyti riebalus su vandeniu maiste. Jų rasite ledų, plakamų kremų, kepinių, padažų ir desertų sudėtyje — jie gerina tekstūrą ir neleidžia produktui sluoksniuotis. ES ir JAV maisto saugos institucijos juos yra patvirtinusios ir paprastai laikomi saugiais tomis dozėmis, kurios naudojamos maiste. Kai kurie tyrimai su gyvūnais labai didelėmis dozėmis kėlė klausimų dėl žarnyno mikrobiomo, tačiau realiai su maistu suvartojami kiekiai yra gerokai mažesni.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 343192;
UPDATE aggregate.eu_additives SET opinion_en = 'These are emulsifiers made by combining sugar (sucrose) with fatty acids from vegetable oils or animal fats. They help mix water and oil together smoothly, which is why they appear in ice creams, creamy sauces, baked goods, chewing gum, and dairy desserts. They also help extend shelf life and improve texture. Generally considered safe by food safety authorities, including EFSA, with no notable controversies surrounding them. They are semi-synthetic — derived from natural ingredients but chemically processed.', opinion_lt = 'Tai emulsikliai, pagaminti sujungus cukrų (sacharozę) su riebalų rūgštimis iš augalinių aliejų arba gyvulinių riebalų. Jie padeda sumaišyti vandenį ir riebalus į vienalytę masę, todėl naudojami ledų, kreminiuose padažuose, kepiniuose, kramtomojoje gumoje ir pieno produktų desertuose. Gerina tekstūrą ir prailgina galiojimo laiką. Maisto saugos institucijos, įskaitant EFSA, juos laiko saugiais — jokių reikšmingų kontraversijų nėra. Jie yra pusiau sintetiniai: gauti iš natūralių žaliavų, tačiau chemiškai apdoroti.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 346226;
UPDATE aggregate.eu_additives SET opinion_en = 'These are synthetic emulsifiers derived from stearic acid (a common fatty acid) and lactic acid, combined with sodium or calcium salts. They work by helping water and fats mix together smoothly, and they also strengthen dough, improve texture, and extend the shelf life of baked goods. You''ll find them in bread, cakes, cereals, dairy desserts, spreads, and chewing gum.

Regulatory bodies including EFSA and the FDA consider these additives safe at the levels used in food. They are not known to be controversial, and there is no significant body of evidence suggesting harm to the general population. People with dairy sensitivities should note the lactic acid origin, though the finished additive is typically well-tolerated.', opinion_lt = 'Tai sintetiniai emulgatoriai, pagaminti iš stearino rūgšties (dažnos riebalų rūgšties) ir pieno rūgšties, sujungtos su natrio arba kalcio druskomis. Jie padeda riebalams ir vandeniui susiliejti, sustiprina tešlą, pagerina tekstūrą ir prailgina kepinių galiojimo laiką. Jų rasite duonoje, pyragaičiuose, dribsniuose, pieniškuose desertuose, tepuosiuose riebaluose ir kramtomojoje gumoje.

EFSA ir FDA šiuos priedus laiko saugiais tokiais kiekiais, kokiais jie naudojami maiste. Jie nelaikomi kontraversiškais, o rimtų mokslinių įrodymų apie žalą sveikatai nėra. Žmonės, jautrūs pieno produktams, gali atkreipti dėmesį į pieno rūgšties kilmę, nors paprastai šis priedas yra gerai toleruojamas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 347321;
UPDATE aggregate.eu_additives SET opinion_en = 'These are synthetic emulsifiers made from sorbitol (a sugar alcohol) and fatty acids. Their main job is to keep oil and water mixed together smoothly — without them, many products like cake fillings, icings, margarines, and chewing gum would separate or have an unpleasant texture. They are also used in baked goods to improve softness and shelf life. Regulatory bodies like EFSA and the FDA consider them safe at the levels used in food. They are widely approved and have a long history of use without significant safety concerns raised for the general population.', opinion_lt = 'Tai sintetiniai emulsikliai, pagaminti iš sorbitolio (cukraus alkoholio) ir riebalų rūgščių. Jų pagrindinė užduotis – išlaikyti aliejų ir vandenį sumaišytus – be jų tortų įdarai, glajus, margarinas ar kramtomoji guma sluoksniuotųsi arba turėtų blogą tekstūrą. Jie taip pat naudojami kepiniuose, kad būtų minkštesni ir ilgiau išliktų švieži. Europos maisto saugos institucija (EFSA) ir kitos reguliavimo institucijos laiko juos saugiais tomis dozėmis, kurios naudojamos maiste. Jokių rimtų sveikatos susirūpinimų plačiajai visuomenei kol kas nėra užfiksuota.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 347799;
UPDATE aggregate.eu_additives SET opinion_en = 'These are carbonate salts — compounds of sodium, potassium, ammonium, or magnesium — used mainly as leavening agents and acidity regulators in food. They help baked goods rise, balance sourness, and improve texture. You''ll find them most often in cocoa processing, where they''re used to mellow the natural bitterness and darken the colour of cocoa powder. They are considered safe and are found naturally in mineral water and the environment. No significant health concerns are associated with normal dietary intake.', opinion_lt = 'Tai karbonatų druskos — natrio, kalio, amonio arba magnio junginiai — naudojami kaip kėliklis ir rūgštingumo reguliatorius maiste. Jie padeda kepiniams kilti, sušvelnina rūgštumą ir gerina tekstūrą. Dažniausiai sutinkami kakavos perdirbime: jie suminkština natūralų kartumą ir patamsina kakavos miltelių spalvą. Šios medžiagos laikomos saugiomis, natūraliai randamos mineraliniame vandenyje ir aplinkoje. Įprastai vartojant maistą, jokių reikšmingų sveikatos problemų su jais nesiejama.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 348474;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic group of aluminium-based salts used mainly as firming agents or acidity regulators in certain foods. Their use in food is very limited — in most markets they are authorised in only a handful of product categories, such as some confectionery. The concern with aluminium compounds in food is real but measured: health authorities acknowledge that aluminium accumulates in the body over time, and excessive intake from all sources combined is worth keeping an eye on, particularly for people who already consume aluminium from other foods, cookware, or medications. Overall exposure from this additive alone is generally considered low.', opinion_lt = 'Tai sintetinė aliuminio druskų grupė, naudojama maiste kaip kietiklis arba rūgštingumo reguliatorius. Jų naudojimas labai ribotas — daugelyje šalių jie leidžiami tik keliose maisto kategorijose, pavyzdžiui, tam tikruose saldainiuose. Aliuminio junginiai maiste kelia pagrįstą, nors ir nedidelį susirūpinimą: mokslininkų teigimu, aliuminis ilgainiui kaupiasi organizme, todėl verta stebėti bendrą jo suvartojimą iš visų šaltinių — maisto, indų, vaistų. Vien iš šio priedo gaunama dozė paprastai laikoma nedidele.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 349506;
UPDATE aggregate.eu_additives SET opinion_en = 'These are alkaline compounds — essentially strong bases like sodium, potassium, calcium, or magnesium hydroxide — used to adjust the acidity or pH of food. In chocolate and cocoa products, they are used in a process called ''dutching'', which mellows the bitter taste, darkens the colour, and improves solubility. They are not present as active compounds in the final product, as they react during processing and leave behind harmless salts. Authorised use is very limited and tightly regulated, so consumer exposure is minimal.', opinion_lt = 'Tai šarminiai junginiai — stiprios bazės, tokios kaip natrio, kalio, kalcio ar magnio hidroksidas — naudojami maisto rūgštingumui reguliuoti. Kakavos ir šokolado gamyboje jie naudojami vadinamajame ''olandišką apdorojimą'', kuris sušvelnina kartumą, patamsina spalvą ir pagerina tirpumą. Galutiniame produkte šie junginiai aktyvia forma nelieka — jie reaguoja perdirbimo metu ir virsta nekenksmingomis druskomis. Naudojimas griežtai ribojamas ir reguliuojamas, todėl vartotojai jiems praktiškai nėra veikiami.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 349828;
UPDATE aggregate.eu_additives SET opinion_en = 'These are anti-caking agents added to table salt and salt substitutes to keep the grains free-flowing and prevent clumping. Despite the name sounding alarming — containing the word ''cyanide'' — the cyanide is tightly bound to iron and is not released in the body under normal conditions. Regulatory agencies consider them safe at the very low levels used in food. You would consume only tiny trace amounts through everyday salt use.', opinion_lt = 'Tai priedai, naudojami valgomojoje druskoje ir jos pakaitaluose, kad druska nesuliptų ir laisvai bėgtų. Nors pavadinimas skamba bauginančiai — jame yra žodis „cianidas" — iš tikrųjų cianidas čia yra tvirtai surištas su geležimi ir organizme neišsiskiria įprastomis sąlygomis. Maisto saugos institucijos šiuos priedus laiko saugiais tokiais mažais kiekiais, kokiais jie naudojami. Per dieną su druska jų suvartojate tikrai labai nedaug.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 350318;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a group of mineral-based anti-caking agents derived from silicon and oxygen — essentially very fine particles of sand-like material. They are added to powdered and granular foods like salt, powdered sweeteners, grated cheese, and spice mixes to prevent clumping and keep the product free-flowing. They also appear in some confectionery coatings and processed cheese. These substances pass through the body largely unabsorbed and are generally considered safe by food safety authorities worldwide. There is no significant controversy around them, and they have been used in food for decades without notable health concerns.', opinion_lt = 'Tai mineralinės kilmės medžiagų grupė, pagaminta iš silicio ir deguonies — iš esmės labai smulkios, smėliui panašios dalelės. Jos dedamos į miltelinius ir biriuosius produktus — druską, miltelinius saldiklius, tarkuotą sūrį, prieskonių mišinius — kad šie nesusigumuluotų ir liktų birūs. Taip pat naudojamos kai kuriuose saldainių apvalkaluose ir perdirbtame sūryje. Organizmas šių medžiagų beveik nepasisavina, ir maisto saugos institucijos visame pasaulyje jas laiko saugiomis. Jokios rimtos diskusijos dėl jų nekyla, o naudojamos maiste jos jau dešimtmečius — be pastebimų sveikatos problemų.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 363889;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a group of mineral-based anti-caking agents and carriers — think of them as tiny, invisible particles that stop powders from clumping together. You''ll find them in food supplements, powdered spices, grated cheese, and processed foods where a dry, free-flowing texture matters. They''re also used in some spreads and cooking sprays. These substances are considered inert, meaning they pass through the body without being absorbed, and regulatory bodies like EFSA regard them as safe at permitted levels. There''s no significant controversy surrounding them — they''re among the more straightforward additives used in food.', opinion_lt = 'Tai mineralinės kilmės medžiagų grupė, naudojama kaip sukietėjimą stabdantys agentai — paprasčiau tariant, jos neleidžia milteliams sulipti ir palaiko saują, birstančią tekstūrą. Rasite jas maisto papilduose, tarkuotame sūryje, prieskonių mišiniuose ir perdirbtame maiste. Jos taip pat naudojamos kai kuriuose tepuose ir purškiamose aliejaus priemonėse kepimui. Laikomos inertiškomis — organizmas jų nepasisavina, jos tiesiog praeina per virškinamąjį traktą. Europos maisto saugos tarnyba (EFSA) laiko jas saugiomis leidžiamose ribose, ir didesnio ginčo dėl šių medžiagų nėra.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 1855709;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a group of flavor enhancers — compounds that intensify the savory, meaty taste known as umami. They are found naturally in many foods like tomatoes, mushrooms, and aged cheeses, and are added to seasonings, condiments, and meat substitutes to make flavors taste fuller and richer. The synthetic versions work the same way as the naturally occurring ones. There is some ongoing debate about sensitivity in certain people — a cluster of symptoms sometimes called ''Chinese Restaurant Syndrome'' — though large-scale scientific reviews have not confirmed a clear causal link for the general population.', opinion_lt = 'Tai skonį stiprinančių medžiagų grupė, kuri suteikia maistui sotų, mėsišką umami skonį. Šie junginiai natūraliai randami pomidoruose, grybhuose ir brandintame sūryje, o į maistą dedami tam, kad skonis atrodytų pilnesnis ir ryškesnis. Dalis žmonių teigia jaučiantys nemalonias reakcijas juos vartojant, tačiau plačių mokslinių apžvalgų duomenimis, aiškus ryšys bendrai populiacijai nepatvirtintas. Jei pastebite, kad po stipriai pagardintų patiekalų jaučiatės blogiau — verta atkreipti dėmesį į šių medžiagų kiekį etiketėje.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 351763;
UPDATE aggregate.eu_additives SET opinion_en = 'These are flavour enhancers — they work by boosting the savoury, meaty taste known as umami, often used alongside or instead of monosodium glutamate. You''ll find them mostly in seasoning blends, stock cubes, savoury snacks, and meat substitutes. They are derived from natural sources like yeast, fish, or meat, though the commercial versions are typically produced through fermentation or chemical processing. Generally considered safe for most people, but those with gout should be cautious, as these compounds can raise uric acid levels.', opinion_lt = 'Tai skonį stiprinančios medžiagos, kurios sustiprina vadinamąjį umami — tą sodrų, mėsišką skonį. Dažniausiai randamos prieskonių mišiniuose, sultinių kubeliuose, užkandžiuose ir mėsos pakaitaluose. Gaunamos iš natūralių šaltinių kaip mielės, žuvis ar mėsa, tačiau pramoninėje gamyboje paprastai naudojamas fermentacijos arba cheminio apdorojimo būdas. Dauguma žmonių gali jas vartoti be rūpesčio, tačiau sergantieji podagra turėtų būti atsargūs — šie junginiai gali didinti šlapimo rūgšties kiekį kraujyje.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 352128;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally occurring acid found in grapes and wine, used as an acidity regulator and preservative in a wide range of foods. It helps control sourness, stabilise colour, and improve texture in products like baked goods, confectionery, processed meats, and even chewing gum. The salts derived from it serve similar roles and are common in winemaking. It has a long history of safe use and is generally well-tolerated. No significant health concerns are associated with normal dietary exposure.', opinion_lt = 'Tai natūraliai vynuogėse ir vyne randama rūgštis, naudojama kaip rūgštingumo reguliatorius ir konservantas įvairiuose maisto produktuose. Ji padeda kontroliuoti rūgštumą, stabilizuoti spalvą ir gerinti tekstūrą kepiniuose, saldainiuose, perdirbtoje mėsoje ir net kramtomojoje gumoje. Jos druskos atlieka panašias funkcijas ir plačiai naudojamos vyno gamyboje. Ši medžiaga vartojama jau labai seniai ir paprastai gerai toleruojama. Esant įprastam suvartojimui, rimtų sveikatos problemų su ja nesiejama.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 2449293;
UPDATE aggregate.eu_additives SET opinion_en = 'These are preservatives used to stop mould, yeast, and bacteria from growing in food — mainly in processed meats that have been heat-treated. Sorbic acid and potassium sorbate are considered very safe and widely accepted by food safety authorities. The parabens (p-hydroxybenzoates) in this group are more controversial — some studies have raised questions about potential hormonal effects, though regulatory bodies consider them safe at permitted levels. As with all preservatives, they are used in small amounts to extend shelf life and food safety.', opinion_lt = 'Tai konservantai, neleidžiantys pelėsiui, mielėms ir bakterijoms augti maiste — daugiausia termiškai apdorotuose mėsos produktuose. Sorbo rūgštis ir kalio sorbatas laikomi labai saugiais ir plačiai pripažintais ingredientais. Tačiau parabėnai (p-hidroksibenzoestatai) šioje grupėje yra šiek tiek prieštaringesni — kai kurie tyrimai kėlė klausimų dėl galimo poveikio hormonams, nors reguliavimo institucijos juos laiko saugiais leidžiamose dozėse. Kaip ir visi konservantai, jie naudojami nedideliais kiekiais produkto galiojimui ir saugai užtikrinti.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 327592;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a group of phosphate-based additives that serve several functions in food — they act as acidity regulators, stabilisers, emulsifiers, and preservatives. You''ll find them in processed cheeses, deli meats, baked goods, cola drinks, and dairy products. They help improve texture, extend shelf life, and keep ingredients from separating. Phosphates are naturally present in many foods like meat, fish, and dairy, but the synthetic versions added to processed foods can significantly increase your total phosphate intake. For most healthy people this isn''t a concern, but those with kidney disease are often advised to limit phosphate intake, as damaged kidneys struggle to filter excess phosphorus from the blood.', opinion_lt = 'Tai fosfatų grupė — priedai, kurie maiste atlieka kelis vaidmenis: reguliuoja rūgštingumą, stabilizuoja, emulsina ir konservuoja. Jų rasite perdirbtuose sūriuose, dešroje, kepiniuose, kola tipo gėrimuose ir pieno produktuose. Fosfatai natūraliai yra mėsoje, žuvyje ir piene, tačiau sintetiniai priedai perdirbtuose maisto produktuose gali ženkliai padidinti bendrą fosfatų kiekį, kurį suvartojate. Sveikiems žmonėms tai paprastai nekelia problemų, tačiau sergantiems inkstų ligomis rekomenduojama riboti fosfatų vartojimą — pažeisti inkstai sunkiai pašalina fosforo perteklių iš kraujo.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 2885712;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a highly refined petroleum-derived oil used in very limited food applications, primarily as a surface coating or glazing agent — for example, to prevent dried fruits or confectionery from sticking together. It is not digested or absorbed by the body, passing through the gut essentially unchanged. Its authorisation in food is tightly restricted to specific uses and quantities. While it is considered safe at permitted levels, it is worth noting that some concerns exist around certain mineral oil fractions and long-term accumulation in body tissues.', opinion_lt = 'Tai naftos perdirbimo produktas — labai išgrynintas mineralinis aliejus, naudojamas itin ribotai maisto pramonėje. Dažniausiai jis naudojamas kaip paviršiaus danga, pavyzdžiui, kad džiovinti vaisiai ar saldainiai neliptų vienas prie kito. Organizmas jo neskaido ir nepasisavina — jis tiesiog praeina per virškinamąjį traktą. Leistinas tik konkrečiuose produktuose ir griežtai nustatytais kiekiais. Nors laikomas saugiu, kai kurie mokslininkai yra išreiškę susirūpinimą dėl galimo tam tikrų mineralinių aliejų frakcijų kaupimosi audiniuose ilgainiui.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 362527;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural byproduct of wood pulp processing, used as a surface treatment or glazing agent on certain fresh fruits and vegetables to help them retain moisture and look fresh for longer. It is authorised in very few food categories, which reflects its quite narrow, specific use. Regulatory bodies consider it safe at the levels used, and there is no notable public controversy surrounding it.', opinion_lt = 'Tai natūralus medienos masės perdirbimo šalutinis produktas, naudojamas kaip paviršiaus apdorojimo arba glazūravimo priemonė kai kuriems švieži vaisiams ir daržovėms – padeda jiems išlaikyti drėgmę ir ilgiau atrodyti šviežiai. Leidžiama naudoti labai nedaugelyje maisto kategorijų, o tai atspindi labai siaurą, specifinį jo paskirtį. Reguliavimo institucijos laiko jį saugiu naudojamomis dozėmis, ir jokių reikšmingų viešų diskusijų dėl jo nekyla.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 362633;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic mineral salt used as a raising agent in baked goods — it reacts with moisture and heat to release carbon dioxide, helping dough or batter rise. It is only authorised in a very limited number of food categories, which reflects its quite specific technical role. It is generally considered safe at the levels used in food, and the magnesium and phosphate it provides are both naturally present in the human body.', opinion_lt = 'Tai sintetinė mineralinė druska, naudojama kaip kildiklis kepiniuose — reaguodama su drėgme ir karščiu išskiria anglies dioksidą, kuris padeda kilti tešlai. Ji leidžiama tik labai ribotame maisto produktų kategorijų skaičiuje, nes atlieka gana specifinę techninę funkciją. Maiste naudojamais kiekiais laikoma saugia — magnis ir fosfatas, kuriuos ji teikia, yra natūraliai randami žmogaus organizme.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 362731;
UPDATE aggregate.eu_additives SET opinion_en = 'This does not appear to be a recognised food additive with a standard E-number or a well-documented regulatory history in food science. The name ''Safe Tracers'' is not a term commonly found in food additive databases or consumer product labels, so it is difficult to provide a reliable assessment of its function, safety, or typical uses.', opinion_lt = 'Tai nėra plačiai žinomas maisto priedas su standartiniu E-numeriu ar aiškia reguliavimo istorija. Pavadinimas ''Safe Tracers'' nerandamas įprastose maisto priedų duomenų bazėse ar produktų etiketėse, todėl sunku patikimai įvertinti jo funkciją, saugumą ar naudojimo sritis. Jei matote šį pavadinimą ant produkto, verta pasidomėti gamintojo pateikiama informacija.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 364902;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a synthetic compound made by combining vitamin E with polyethylene glycol, used as a solubiliser and emulsifier — it helps fat-soluble substances mix into water-based products. It is authorised in a very limited number of food categories, primarily in specialised nutritional products. It is generally considered safe at the levels permitted, though it is more commonly encountered in pharmaceuticals than in everyday food.', opinion_lt = 'Tai sintetinis junginys, gaminamas iš vitamino E ir polietilenglikolio — naudojamas kaip tirpiklis ir emulsiklis, padedantis riebaluose tirpstančioms medžiagoms susimaišyti su vandeniu. Leidžiamas labai ribotame skaičiuje maisto kategorijų, daugiausia specializuotuose mitybos produktuose. Laikomas saugiu leistinomis dozėmis, nors dažniau sutinkamas farmacijos pramonėje nei įprastuose maisto produktuose.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 365003;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a concentrated plant-based extract high in polyphenols, which are natural compounds found in fruits, vegetables, and other plants. It is used as an antioxidant to help preserve food and may also offer some nutritional benefit. It appears in a very limited range of food products, suggesting it is a niche or recently approved ingredient. Polyphenols are generally considered beneficial and safe, though the specific source plant and concentration always matter.', opinion_lt = 'Tai koncentruotas augalinis ekstraktas, kuriame gausu polifenolių — natūralių junginių, randamų vaisiuose, daržovėse ir kituose augaluose. Maiste jis naudojamas kaip antioksidantas, padedantis išsaugoti produktų kokybę, ir gali turėti papildomos maistinės vertės. Jis leidžiamas labai ribotame skaičiuje maisto kategorijų, todėl greičiausiai tai naujas arba siauros paskirties ingredientas. Polifenoliai paprastai laikomi saugiais ir netgi naudingais, tačiau visada svarbu žinoti, iš kokio augalo jie gauti ir kokios koncentracijos.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 365096;
UPDATE aggregate.eu_additives SET opinion_en = 'This is not a standard approved food additive with a recognised E-number, which makes it difficult to assess precisely. The name suggests it is a compound designed to inhibit the growth of bacteria or mould in food, likely using a carrier molecule to deliver an antimicrobial agent more effectively. It appears in a very limited range of food products. Without clearer regulatory classification, it is hard to give a confident safety verdict — if in doubt, checking the product''s full ingredient list or contacting the manufacturer is the best approach.', opinion_lt = 'Tai nėra standartinis patvirtintas maisto priedas su pripažintu E kodu, todėl jį tiksliai įvertinti sudėtinga. Pavadinimas rodo, kad tai junginys, skirtas stabdyti bakterijų ar pelėsių augimą maiste, tikriausiai naudojant nešiklio molekulę antimikrobinei medžiagai efektyviau pristatyti. Jis naudojamas labai ribotoje maisto produktų grupėje. Nesant aiškios reguliavimo klasifikacijos, sunku pateikti tvirtą nuomonę apie saugumą — abejojant, geriausia patikrinti pilną ingredientų sąrašą arba susisiekti su gamintoju.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 365215;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a chemical compound used in very small amounts as a bleaching and antimicrobial agent in certain foods, most notably some cheeses and flour products. It breaks down quickly into water and oxygen, leaving no significant residue in the final product. It is authorised in only one food category, meaning its use is quite restricted. At the concentrations permitted in food, it is generally considered safe by regulatory bodies.', opinion_lt = 'Tai cheminis junginys, naudojamas labai mažais kiekiais kaip balinimo ir antimikrobinė medžiaga tam tikruose maisto produktuose – dažniausiai kai kuriuose sūriuose ar miltų gaminiuose. Jis greitai suyra į vandenį ir deguonį, todėl galutiniame produkte beveik nelieka jokių liekanų. Leidžiamas tik vienoje maisto kategorijoje, taigi jo naudojimas yra gana ribotas. Reguliavimo institucijos mano, kad leidžiamomis koncentracijomis jis yra saugus.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 363424;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally occurring amino acid found in many protein-rich foods like eggs, meat, and dairy. In food production, it is mainly used as a dough conditioner in bread and bakery products, helping to improve texture and reduce mixing time. It is not a synthetic chemical additive but rather a building block of protein that your body already knows how to handle. It is generally considered safe and well-tolerated by most people.', opinion_lt = 'Tai natūraliai maiste randama aminorūgštis, kurios gausu kiaušiniuose, mėsoje ir pieno produktuose. Maisto pramonėje ji daugiausia naudojama kaip tešlos gerintojas duonos ir kepinių gamyboje — padeda pagerinti tekstūrą ir sutrumpina maišymo laiką. Tai ne sintetinis cheminis priedas, o baltymo sudedamoji dalis, kurią organizmas gerai pažįsta ir lengvai apdoroja. Laikoma saugia ir gerai toleruojama daugumos žmonių.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 363470;
UPDATE aggregate.eu_additives SET opinion_en = 'This is the potassium salt of cinnamic acid, a compound naturally found in cinnamon and some other plants. It acts as a preservative, helping to inhibit the growth of mould and bacteria in food. It is currently authorised in very few food categories, which suggests its use is quite limited and specialised. It is generally considered safe at the levels used in food, though large-scale human safety studies are limited given how rarely it appears in products.', opinion_lt = 'Tai kalio druska, gauta iš cinamono rūgšties – medžiagos, natūraliai randamos ciname ir kai kuriuose kituose augaluose. Maiste ji naudojama kaip konservantas, slopinantis pelėsių ir bakterijų augimą. Leidžiama naudoti labai nedaugelyje maisto kategorijų, todėl jos taikymas yra gana ribotas. Manoma, kad maiste naudojamais kiekiais ji yra saugi, tačiau didelių tyrimų su žmonėmis stokojama dėl retos jos pasirodymo produktuose.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 363657;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural antioxidant compound extracted mainly from Siberian larch trees. It works by slowing down the oxidation of fats and oils in food, helping products stay fresh longer — similar in purpose to better-known antioxidants like vitamin C or vitamin E. It appears in a very limited range of food products, as it is authorised in only one food category. Research into its health effects is ongoing and shows some promise, but it is not yet as thoroughly studied as many other approved food antioxidants.', opinion_lt = 'Tai natūralios kilmės antioksidantas, gaunamas daugiausia iš Sibiro maumedžio medžių. Jo paskirtis — stabdyti riebalų ir aliejų oksidaciją maiste, taip prailginant produktų galiojimo laiką, panašiai kaip vitaminas C ar E. Leidžiamas naudoti labai ribotame maisto produktų asortimente — tik vienoje kategorijoje. Moksliniai tyrimai dėl jo poveikio sveikatai dar tęsiasi ir rodo tam tikrą potencialą, tačiau kol kas jis nėra taip gerai ištirtas kaip kiti plačiau naudojami maisto antioksidantai.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 363703;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a naturally derived blue pigment obtained from the jagua fruit, a tropical plant used for centuries in traditional body paint. It forms its blue colour through a reaction between a compound in the fruit and an amino acid. It is authorised in a very limited number of food categories, meaning you are unlikely to encounter it often. It is considered safe at permitted levels, and its natural origin makes it appealing as an alternative to synthetic blue dyes.', opinion_lt = 'Tai natūralios kilmės mėlynas dažiklis, gaunamas iš jagua vaisiaus — tropinio augalo, šimtmečius naudoto tradiciniams kūno dažams. Mėlyna spalva susidaro vykstant cheminei reakcijai tarp vaisiaus sudedamosios dalies ir aminorūgšties. Šis priedas leidžiamas labai nedaugelyje maisto kategorijų, tad kasdienėje maisto pakuotėje jį sutikti mažai tikėtina. Laikomas saugiu leistinomis dozėmis, o natūrali kilmė daro jį patrauklia alternatyva sintetiniams mėlyniems dažikliams.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 366058;
UPDATE aggregate.eu_additives SET opinion_en = 'This is hydrogen peroxide — a simple chemical compound of water and oxygen. In food production it''s used as a bleaching and sterilising agent, mainly for processing equipment, packaging, and occasionally certain foods like flour or milk. It breaks down into water and oxygen, leaving no harmful residue when used correctly. It is authorised in a very limited number of food categories, so consumer exposure through food itself is minimal.', opinion_lt = 'Tai vandenilio peroksidas — paprastas cheminis junginys iš vandens ir deguonies. Maisto pramonėje jis naudojamas kaip balinimo ir sterilizavimo priemonė — daugiausia įrangai, pakuotėms valyti, kartais miltams ar pienui apdoroti. Teisingai naudojamas, jis suyra į vandenį ir deguonį, nepalikdamas žalingų likučių. Leidžiamas labai nedaugelyje maisto kategorijų, todėl vartotojai su juo susiduria retai.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 366150;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural blue pigment extracted from a type of heat-tolerant microalgae. It is used as a colouring agent to give foods a vivid blue or blue-green hue, and is currently authorised in a very limited range of products. It is considered safe at the levels used in food. Being of natural origin, it appeals to manufacturers looking to replace synthetic blue dyes.', opinion_lt = 'Tai natūralus mėlynas dažiklis, gaunamas iš karščiui atsparių mikrodumblių. Jis naudojamas maisto produktams suteikti ryškią mėlyną arba žalsvai mėlyną spalvą ir šiuo metu leidžiamas tik labai ribotoje produktų kategorijų grupėje. Vartojamais kiekiais laikomas saugiu. Kadangi kilmė natūrali, gamintojai jį renkasi kaip alternatyvą sintetiniams mėlyniems dažikliams.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 366196;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a protein produced by genetically engineered yeast, designed to mimic the iron-containing compound that makes meat look and taste bloody. It''s the key ingredient that gives some plant-based burgers their meat-like appearance and flavour. It is found almost exclusively in certain meat-alternative products.

It''s a relatively new additive with a limited regulatory track record. The US FDA has approved it, but it''s not widely authorised in many other regions. Some consumer groups have raised questions about long-term safety data, since it''s a novel protein humans haven''t traditionally eaten. It appears safe based on available studies, but if you prefer well-established ingredients, this is one to be aware of.', opinion_lt = 'Tai baltymas, gaminamas genetiškai modifikuotų mielių, sukurtas imituoti geležį turintį junginį, dėl kurio mėsa atrodo ir skonis kruvina. Būtent šis ingredientas kai kuriems augalinės kilmės burgeriams suteikia tikros mėsos išvaizdą ir skonį. Randamas beveik išskirtinai tam tikruose mėsos pakaitaluose.

Tai gana naujas priedas, turintis ribotą reguliavimo istoriją. JAV FDA jį patvirtino, tačiau daugelyje kitų šalių jis nėra plačiai leidžiamas. Kai kurios vartotojų grupės kelia klausimus dėl ilgalaikių saugos duomenų, nes tai naujas baltymas, kurio žmonės tradiciškai nevalgė. Pagal turimus tyrimus jis atrodo saugus, tačiau jei teikiate pirmenybę gerai ištirti priedams, verta apie jį žinoti.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 366288;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural substance found in the cell walls of all plants — it''s literally the fiber in vegetables, fruits, and grains. In processed foods, it acts as a bulking agent or stabilizer, helping products hold their shape or texture without adding calories. It passes through the digestive system largely undigested, much like dietary fiber. It has a very long history of safe use and raises no significant health concerns for most people.', opinion_lt = 'Tai natūrali medžiaga, randama visų augalų ląstelių sienelėse — iš esmės tai tas pats skaidulinis pluoštas, kurį gauname valgydami daržoves, vaisius ir grūdus. Maisto pramonėje ji naudojama kaip apimtį didinanti arba stabilizuojanti medžiaga, padedanti produktams išlaikyti formą ar tekstūrą be papildomų kalorijų. Organizmas jos praktiškai nevirškina — ji praeina per virškinimo sistemą panašiai kaip maistinės skaidulos. Ši medžiaga naudojama labai seniai ir didžiajai daugumai žmonių nekelia jokios rimtos grėsmės sveikatai.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 1486767;
UPDATE aggregate.eu_additives SET opinion_en = 'This is a natural-origin sweetener extracted from the leaves of the stevia plant, originally from South America. It is intensely sweet — many times sweeter than sugar — so only tiny amounts are needed. You''ll find it in diet drinks, low-calorie desserts, yoghurts, breakfast cereals, sauces, and table-top sweeteners. It contains virtually no calories, which makes it popular in products aimed at people managing weight or blood sugar levels. It is generally considered safe by major food safety authorities including EFSA and the FDA. Some people notice a slightly bitter or liquorice-like aftertaste, but this is a matter of personal taste rather than a safety concern.', opinion_lt = 'Tai natūralios kilmės saldiklis, gaunamas iš stevijos augalo lapų — originaliai augančio Pietų Amerikoje. Jis yra daug kartų saldesnis už cukrų, todėl reikia labai mažų kiekių. Rasite jį dietiniuose gėrimuose, mažakalorių desertų, jogurtuose, pusryčių dribsniuose, padažuose ir stalo saldintuose. Kadangi jame praktiškai nėra kalorijų, jis populiarus tarp žmonių, kurie kontroliuoja svorį ar cukraus kiekį kraujyje. Pagrindinės maisto saugos institucijos, įskaitant EFSA ir FDA, laiko jį saugiu. Kai kurie žmonės jaučia lengvą kartumą ar saldžiašaknio prieskonį, tačiau tai skonio, o ne saugos klausimas.', opinion_generated_at = '2026-04-07 13:05:08' WHERE id = 2692440;
